def mid_reject(reason: str) -> str:
    """Return a registry key for any reject/block/skip reason (never raises)."""
    try:
        r = (reason or "").strip().lower()
        if not r:
            return "not_enough_data"
        token = r.split()[0].strip().strip(";:,.()[]{}")

        # Prefix-style legacy reasons
        # e.g. "symbol_timeout_10s" -> candles_unavailable
        if token.startswith("symbol_timeout"):
            return "candles_unavailable"

        key = MID_REJECT_ALIASES.get(token) or MID_REJECT_ALIASES.get(r)
        if key and key in MID_REJECT_REASONS:
            return key
        # If already a valid key, keep it.
        if token in MID_REJECT_REASONS:
            return token
        if r in MID_REJECT_REASONS:
            return r
        return "not_enough_data"
    except Exception:
        return "not_enough_data"


# --- MID stage flow (rolling window, for /health) ---
# STAGE FLOW (last 15m): scanned / passed_ta / created_pending / triggered / rejected
MID_STAGE_EVENTS: list[tuple[float, str]] = []
MID_STAGE_MAX_EVENTS = 200000

def _mid_stage_add(stage: str, n: int = 1) -> None:
    """Best-effort add to rolling stage window (never raises)."""
    global MID_STAGE_EVENTS
    try:
        st = (stage or "").strip().lower()
        if not st:
            return
        ts = time.time()
        cnt = max(1, int(n or 1))
        for _ in range(min(cnt, 50)):
            MID_STAGE_EVENTS.append((ts, st))
        if len(MID_STAGE_EVENTS) > MID_STAGE_MAX_EVENTS:
            MID_STAGE_EVENTS = MID_STAGE_EVENTS[-MID_STAGE_MAX_EVENTS:]
    except Exception:
        pass

def _mid_stage_counts(window_sec: int = 900) -> dict:
    """Counts of stages within last window_sec."""
    try:
        now = time.time()
        cutoff = now - float(window_sec)
        out = defaultdict(int)
        # prune old
        global MID_STAGE_EVENTS
        if MID_STAGE_EVENTS:
            # keep only relevant tail (events are append-only, ts non-decreasing in practice)
            i = 0
            for i, (ts, _) in enumerate(MID_STAGE_EVENTS):
                if ts >= cutoff:
                    break
            else:
                i = len(MID_STAGE_EVENTS)
            if i > 0:
                MID_STAGE_EVENTS = MID_STAGE_EVENTS[i:]
        for ts, st in MID_STAGE_EVENTS:
            if ts >= cutoff:
                out[st] += 1
        return dict(out)
    except Exception:
        return {}
# --- MID reject digest (rolling window, for /health) ---
# Tracks top reasons across stages: candles_unavailable / not_enough_data / pending_wait / etc.
MID_REJECT_EVENTS = []  # list[(ts, reason_key)]
MID_REJECT_MAX_EVENTS = 50000


def _mid_reject_key(reason: str) -> str:
    """Normalize reject reason into a registry key (see MID_REJECT_REASONS)."""
    return mid_reject(reason)

def _mid_reject_add(reason: str, n: int = 1) -> None:

    """Best-effort add to rolling reject window (never raises)."""
    global MID_REJECT_EVENTS
    try:
        k = _mid_reject_key(reason)
        if not k:
            return
        ts = time.time()
        cnt = max(1, int(n or 1))
        for _ in range(min(cnt, 20)):
            MID_REJECT_EVENTS.append((ts, k))
        # cap memory
        if len(MID_REJECT_EVENTS) > MID_REJECT_MAX_EVENTS:
            MID_REJECT_EVENTS = MID_REJECT_EVENTS[-MID_REJECT_MAX_EVENTS:]
    except Exception:
        pass

def _mid_reject_digest_top(topn: int = 3) -> list[dict]:
    """Return top reject reasons within the rolling window (safe)."""
    try:
        try:
            window_sec = int(float(os.getenv("MID_REJECT_WINDOW_SEC", "900") or 900))
        except Exception:
            window_sec = 900
        window_sec = max(30, min(window_sec, 24 * 3600))
        now = time.time()
        cutoff = now - float(window_sec)

        # prune old
        if MID_REJECT_EVENTS:
            i0 = 0
            for i, (ts, _k) in enumerate(MID_REJECT_EVENTS):
                if float(ts) >= cutoff:
                    i0 = i
                    break
            else:
                i0 = len(MID_REJECT_EVENTS)
            if i0 > 0:
                del MID_REJECT_EVENTS[:i0]

        counts = defaultdict(int)
        for ts, k in MID_REJECT_EVENTS:
            if float(ts) >= cutoff:
                counts[str(k)] += 1
        items = sorted(counts.items(), key=lambda kv: (-int(kv[1]), str(kv[0])))
        out = []
        for k, v in items[:max(1, int(topn or 3))]:
            out.append({"reason": str(k), "count": int(v)})
        return out
    except Exception:
        return []


# --- MID trigger reject digest (rolling window, for /health and [mid][status]) ---
# Institutional debug mode:
# - pretrig_no: reasons recorded when a pending is checked but price is NOT (yet) in-zone
# - trig_no_inzone: reasons recorded when price IS in-zone but EMIT is blocked by trigger filters
#
# NOTE: In normal flow we should only run heavy checks in-zone. This split helps prove it in logs
# and quickly answer "why no emit?" vs "still waiting for zone".

MID_PRETRIG_REJECT_EVENTS: list[tuple[float, str]] = []
MID_INZONE_REJECT_EVENTS: list[tuple[float, str]] = []
MID_TRIG_REJECT_MAX_EVENTS = 80000

def _mid_trig_reject_key(reason: str) -> str:
    try:
        r = (reason or "").strip().lower()
        if not r:
            return "unknown"
        token = r.split()[0].strip().strip(";:,.()[]{}")
        return token or "unknown"
    except Exception:
        return "unknown"

def _mid_trig_reject_add(reason: str, n: int = 1, *, bucket: str = "inzone") -> None:
    """Add a trigger reject reason to a rolling window bucket.
    bucket: 'pre' / 'pretrig' / 'all' -> pretrig_no
            'inzone' (default) -> trig_no_inzone
    """
    global MID_PRETRIG_REJECT_EVENTS, MID_INZONE_REJECT_EVENTS
    try:
        k = _mid_trig_reject_key(reason)
        if not k:
            return
        ts = time.time()
        cnt = max(1, int(n or 1))
        b = (bucket or "inzone").strip().lower()
        if b in ("pre", "pretrig", "all", "pretrig_no"):
            ev = MID_PRETRIG_REJECT_EVENTS
        else:
            ev = MID_INZONE_REJECT_EVENTS
        for _ in range(min(cnt, 20)):
            ev.append((ts, k))
        # cap memory per bucket
        if len(ev) > MID_TRIG_REJECT_MAX_EVENTS:
            del ev[:-MID_TRIG_REJECT_MAX_EVENTS]

        # Also aggregate counts within the current pending poll tick (for [mid][status]).
        try:
            global _MID_TRIG_REJECT_TICK_CUR
            cur = _MID_TRIG_REJECT_TICK_CUR
            if isinstance(cur, dict):
                add_n = min(cnt, 20)
                bk = "pre" if b in ("pre", "pretrig", "all", "pretrig_no") else "inzone"
                bucket_map = cur.get(bk)
                if isinstance(bucket_map, dict):
                    bucket_map[str(k)] = int(bucket_map.get(str(k), 0) or 0) + int(add_n)
        except Exception:
            pass
    except Exception:
        pass

def _mid_trig_reject_digest_top(topn: int = 5, window_sec: int | None = None, *, bucket: str = "inzone") -> list[dict]:
    """Return top trigger reject reasons from a given bucket within the rolling window."""
    try:
        if window_sec is None:
            try:
                window_sec = int(float(os.getenv("MID_TRIG_REJECT_WINDOW_SEC", "900") or 900))
            except Exception:
                window_sec = 900
        window_sec = max(30, min(int(window_sec), 24 * 3600))
        now = time.time()
        cutoff = now - float(window_sec)

        b = (bucket or "inzone").strip().lower()
        if b in ("pre", "pretrig", "all", "pretrig_no"):
            ev = MID_PRETRIG_REJECT_EVENTS
        else:
            ev = MID_INZONE_REJECT_EVENTS

        # prune old (in-place)
        if ev:
            i0 = 0
            for i, (ts, _k) in enumerate(ev):
                if float(ts) >= cutoff:
                    i0 = i
                    break
            else:
                i0 = len(ev)
            if i0 > 0:
                del ev[:i0]

        from collections import defaultdict
        counts = defaultdict(int)
        for ts, k in ev:
            if float(ts) >= cutoff:
                counts[str(k)] += 1
        items = sorted(counts.items(), key=lambda kv: (-int(kv[1]), str(kv[0])))
        out = []
        for k, v in items[:max(1, int(topn or 5))]:
            out.append({"reason": str(k), "count": int(v)})
        return out
    except Exception:
        return []


def _mid_trig_reject_digest_counts(window_sec: int | None = None, *, bucket: str = "inzone") -> dict[str, int]:
    """Return full counts of trigger reject reasons within the rolling window for a bucket.

    This is used by [mid][status] to print *all* reasons (optionally capped at format-time),
    instead of only top-N.
    """
    try:
        if window_sec is None:
            try:
                window_sec = int(float(os.getenv("MID_TRIG_REJECT_WINDOW_SEC", "900") or 900))
            except Exception:
                window_sec = 900
        window_sec = max(30, min(int(window_sec), 24 * 3600))
        now = time.time()
        cutoff = now - float(window_sec)

        b = (bucket or "inzone").strip().lower()
        if b in ("pre", "pretrig", "all", "pretrig_no"):
            ev = MID_PRETRIG_REJECT_EVENTS
        else:
            ev = MID_INZONE_REJECT_EVENTS

        # prune old (in-place)
        if ev:
            i0 = 0
            for i, (ts, _k) in enumerate(ev):
                if float(ts) >= cutoff:
                    i0 = i
                    break
            else:
                i0 = len(ev)
            if i0 > 0:
                del ev[:i0]

        from collections import defaultdict
        counts = defaultdict(int)
        for ts, k in ev:
            if float(ts) >= cutoff:
                counts[str(k)] += 1
        return {str(k): int(v) for k, v in counts.items() if int(v) > 0}
    except Exception:
        return {}


