def _mid_metrics_inc(name: str, n: int = 1) -> None:
    """Best-effort global metrics increment (never raises)."""
    global MID_SETUPS_FOUND_TOTAL, MID_PENDING_CREATED_TOTAL, MID_PENDING_TRIGGERED_TOTAL, MID_PENDING_EXPIRED_TOTAL
    try:
        k = str(name or "").strip().lower()
        if k == "setups_found":
            MID_SETUPS_FOUND_TOTAL += int(n)
        elif k == "pending_created":
            MID_PENDING_CREATED_TOTAL += int(n)
        elif k == "pending_triggered":
            MID_PENDING_TRIGGERED_TOTAL += int(n)
        elif k == "pending_expired":
            MID_PENDING_EXPIRED_TOTAL += int(n)
    except Exception:
        pass

def _mid_metrics_snapshot() -> dict:
    """Return current totals snapshot (safe)."""
    try:
        return {
            "last_tick_ts": float(MID_LAST_TICK_TS or 0.0),
            "setups_found": int(MID_SETUPS_FOUND_TOTAL),
            "pending_created": int(MID_PENDING_CREATED_TOTAL),
            "pending_triggered": int(MID_PENDING_TRIGGERED_TOTAL),
            "pending_expired": int(MID_PENDING_EXPIRED_TOTAL),
            "hard_blocks": int(_mid_hard_block_total()),
            "hardblock_top": str(MID_LAST_HARDBLOCK_TOP or "") or None,
            "hardblock_samples": MID_LAST_HARDBLOCK_SAMPLES if isinstance(MID_LAST_HARDBLOCK_SAMPLES, dict) else None,
            "last_summary": str(MID_LAST_SUMMARY) if MID_LAST_SUMMARY else None,
            "last_summary_ts": float(MID_LAST_SUMMARY_TS or 0.0),
        }
    except Exception:
        return {
            "last_tick_ts": 0.0,
            "setups_found": 0,
            "pending_created": 0,
            "pending_triggered": 0,
            "pending_expired": 0,
            "hard_blocks": 0,
            "hardblock_top": None,
            "hardblock_samples": None,
            "last_summary": None,
            "last_summary_ts": 0.0,
        }

def _mid_set_last_summary(summary: str) -> None:
    global MID_LAST_SUMMARY, MID_LAST_SUMMARY_TS
    MID_LAST_SUMMARY = summary
    MID_LAST_SUMMARY_TS = time.time()

async def mid_summary_heartbeat_loop() -> None:
    """Periodically re-log the last MID 'tick done' summary for visibility in log streams."""
    try:
        every = int(os.getenv("MID_SUMMARY_EVERY_SEC", "0") or "0")
    except Exception:
        every = 0
    if every <= 0:
        return
    logger.info("[mid][summary] heartbeat enabled every=%ss", every)
    while True:
        await asyncio.sleep(every)
        if MID_LAST_SUMMARY:
            age = time.time() - float(MID_LAST_SUMMARY_TS or time.time())
            logger.info("[mid][summary] %s (age=%.0fs)", MID_LAST_SUMMARY, age)



# --- MID hard-block counter (for honest [mid][summary] metrics) ---
# Counts cases where evaluate_on_exchange_mid_v2() rejected a candidate via _mid_block_reason(...).
_MID_HARD_BLOCK_TOTAL = 0

def _mid_inc_hard_block(n: int = 1) -> None:
    global _MID_HARD_BLOCK_TOTAL
    try:
        _MID_HARD_BLOCK_TOTAL += int(n)
    except Exception:
        pass

def _mid_hard_block_total() -> int:
    try:
        return int(_MID_HARD_BLOCK_TOTAL)
    except Exception:
        return 0

# --- MID hard-block breakdown (per-tick) ---
# We keep counts of *which* _mid_block_reason(...) caused a hard block.
# Reset each MID tick by setting _MID_HARD_BLOCK_TICK_TOKEN to a new value.
_MID_HARD_BLOCK_TICK_TOKEN = None  # type: ignore
_MID_HARD_BLOCK_BY_KEY = defaultdict(int)  # key -> count
_MID_HARD_BLOCK_SAMPLES = defaultdict(list)  # key -> [sample strings]

def _mid_hardblock_key(reason: str) -> str:
    """Normalize a raw block reason into a compact bucket key."""
    try:
        r = (reason or "").strip()
        if not r:
            return "unknown"
        head = r.split()[0]  # first token
        # common forms: 'late_entry_atr=1.23', 'anti_bounce_short ...', 'rsi_short=..', 'below_ema20_5m ...'
        key = head.split("=", 1)[0].strip()
        if key.startswith("anti_bounce_"):
            return "anti_bounce"
        if key.startswith("rsi_"):
            return "rsi"
        if key in ("below_ema20_5m", "above_ema20_5m"):
            return "ema20_5m"
        if key.startswith("near_recent_"):
            return "near_recent_extreme"
        if key.startswith("mid_"):
            return "mid_error"
        return key
    except Exception:
        return "unknown"



def _mid_zone_touch_alert_enabled() -> bool:
    try:
        return (os.getenv("MID_ZONE_TOUCH_ALERT_ENABLED", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        return True


def _mid_zone_touch_emit_enabled() -> bool:
    """Allow a first-touch pending to become a real entry signal.

    This upgrades the existing zone-touch alert path so strong first-touch reclaim /
    order-block retest setups can emit from the blue-arrow area instead of waiting
    for a later trigger after the impulse already started.
    """
    try:
        return (os.getenv("MID_ZONE_TOUCH_EMIT_ENABLED", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        return True


def _mid_zone_touch_emit_min_conf() -> int:
    """Confidence threshold for real first-touch emits.

    Defaults to a softer origin-style threshold so MID can behave more like a
    real discretionary trader: enter from the zone while the idea is still fresh,
    not only after the impulse candle already expanded.
    """
    try:
        base = int(float(os.getenv("MID_SMART_SETUP_EMIT_CONF", "90") or 90))
    except Exception:
        base = 90
    try:
        softer_default = int(float(os.getenv("MID_ZONE_TOUCH_EMIT_DEFAULT_CONF", str(min(base, 80))) or min(base, 80)))
    except Exception:
        softer_default = min(base, 80)
    try:
        origin_default = int(float(os.getenv("MID_SMART_SETUP_ORIGIN_CONF", str(softer_default)) or softer_default))
    except Exception:
        origin_default = softer_default
    try:
        fresh_default = int(float(os.getenv("MID_ZONE_TOUCH_EMIT_MIN_CONF_FRESH", str(min(origin_default, 78))) or min(origin_default, 78)))
    except Exception:
        fresh_default = min(origin_default, 78)
    try:
        raw = os.getenv("MID_ZONE_TOUCH_EMIT_MIN_CONF")
        if raw is None or str(raw).strip() == "":
            return max(0, int(min(fresh_default, softer_default, origin_default)))
        return max(0, int(float(raw)))
    except Exception:
        return max(0, int(min(fresh_default, softer_default, origin_default)))


def _mid_zone_touch_emit_context_ok(ta: dict | None, it: dict | None = None, *, now_ts: float | None = None) -> bool:
    """Whether a first zone touch is contextually strong enough for a live emit.

    Strong context examples:
      - very fresh BO/RT pending
      - order-block retest at the touch
      - liquidity sweep in the direction of the idea
      - narrow trusted supply/demand zone reached while the breakout idea is still fresh
    """
    t = ta if isinstance(ta, dict) else {}
    rec = it if isinstance(it, dict) else {}
    try:
        if bool(rec.get("smart_origin_fast_ok") or rec.get("smart_breakout_fast_ok")):
            return True
    except Exception:
        pass
    try:
        if _mid_pending_is_fresh_bo_rt(rec, now_ts=now_ts):
            return True
    except Exception:
        pass
    try:
        if bool(t.get("ob_retest") or rec.get("ob_retest")):
            return True
    except Exception:
        pass
    try:
        if bool(t.get("sweep_long") or t.get("sweep_short") or rec.get("sweep_long") or rec.get("sweep_short")):
            return True
    except Exception:
        pass
    try:
        bo = str(t.get("bo_rt") or t.get("breakout_retest") or rec.get("bo_rt") or rec.get("breakout_retest") or "").strip().upper()
        if bo.startswith("BO↑ + RETEST") or bo.startswith("BO↓ + RETEST") or bo.startswith("BO↑+RT") or bo.startswith("BO↓+RT"):
            return True
    except Exception:
        pass
    try:
        zone_src = str(rec.get("entry_zone_src") or "").strip().lower()
    except Exception:
        zone_src = ""
    try:
        trusted_zone = zone_src.startswith("ob") or zone_src.startswith("fvg") or zone_src.startswith("ch1h") or zone_src.startswith("ch4h")
    except Exception:
        trusted_zone = False
    if trusted_zone:
        try:
            zone_width_atr = float(rec.get("zone_width_atr")) if rec.get("zone_width_atr") is not None else None
        except Exception:
            zone_width_atr = None
        try:
            max_zone_width_atr = float(os.getenv("MID_ZONE_TOUCH_EMIT_MAX_ZONE_WIDTH_ATR", "2.20") or 2.20)
        except Exception:
            max_zone_width_atr = 2.20
        try:
            bo_age_create = int(float(rec.get("breakout_first_age_bars_create"))) if rec.get("breakout_first_age_bars_create") is not None else None
        except Exception:
            bo_age_create = None
        try:
            max_bo_age = int(float(os.getenv("MID_ZONE_TOUCH_EMIT_MAX_BREAKOUT_AGE_BARS", "3") or 3))
        except Exception:
            max_bo_age = 3
        try:
            bo_move_create = float(rec.get("breakout_first_move_atr_create")) if rec.get("breakout_first_move_atr_create") is not None else None
        except Exception:
            bo_move_create = None
        try:
            max_bo_move = float(os.getenv("MID_ZONE_TOUCH_EMIT_MAX_BREAKOUT_MOVE_ATR", "0.90") or 0.90)
        except Exception:
            max_bo_move = 0.90
        narrow_ok = (zone_width_atr is None) or (max_zone_width_atr <= 0) or (float(zone_width_atr) <= float(max_zone_width_atr))
        fresh_ok = ((bo_age_create is not None) and (int(bo_age_create) <= int(max_bo_age))) or ((bo_move_create is not None) and (float(bo_move_create) <= float(max_bo_move)))
        if narrow_ok and fresh_ok:
            return True
    return False


def _mid_zone_execution_v2_enabled() -> bool:
    """Enable the zone-first execution layer.

    When enabled, a strong pending that returns into the prepared zone can emit on a
    minimal micro-confirmation instead of needing the old full trigger stack.
    """
    try:
        return (os.getenv("MID_ZONE_EXECUTION_V2", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        return True


def _mid_zone_first_min_confirmations() -> int:
    """How many simple micro-confirmations are enough inside the zone."""
    try:
        return max(1, int(float(os.getenv("MID_ZONE_FIRST_MIN_CONFIRMATIONS", "1") or 1)))
    except Exception:
        return 1


def _mid_zone_first_micro_passed(checks: dict | None) -> tuple[int, list[str]]:
    """Count simple micro-confirmations for zone-first execution."""
    try:
        ch = checks if isinstance(checks, dict) else {}
        keys = ("reclaim", "bos_5m", "sweep", "displacement")
        passed = []
        for key in keys:
            try:
                val = str(ch.get(key) or "").strip().lower()
            except Exception:
                val = ""
            if val.startswith("pass"):
                passed.append(str(key))
        return (len(passed), passed)
    except Exception:
        return (0, [])


def _mid_zone_first_ready(ta: dict | None, it: dict | None, checks: dict | None = None, *, now_ts: float | None = None) -> tuple[bool, int, list[str]]:
    """Return whether a zone-first emit override is allowed.

    This is intentionally stricter than a generic smart-trigger pass:
    - the setup must already be in a strong zone context
    - only real vetoes may still block it
    - a small micro-confirmation basket (reclaim / 5m BOS / sweep / displacement)
      is enough; the old all-or-nothing trigger stack is not required
    """
    try:
        if not _mid_zone_execution_v2_enabled():
            return (False, 0, [])
        t = ta if isinstance(ta, dict) else {}
        rec = it if isinstance(it, dict) else {}
        ch = checks if isinstance(checks, dict) else {}
        try:
            if str(ch.get("zone") or "").strip().lower().startswith("fail"):
                return (False, 0, [])
        except Exception:
            pass
        if not _mid_zone_touch_emit_context_ok(t, rec, now_ts=now_ts):
            return (False, 0, [])
        guard_reason = _mid_zone_touch_guard_reason(t, rec)
        if guard_reason:
            return (False, 0, [])
        micro_n, labels = _mid_zone_first_micro_passed(ch)
        fresh_bo_rt = False
        try:
            fresh_bo_rt = _mid_pending_is_fresh_bo_rt(rec, now_ts=now_ts)
        except Exception:
            fresh_bo_rt = False
        conf = 0
        for cand in (t.get("confidence"), rec.get("confidence"), rec.get("min_confidence"), t.get("score")):
            try:
                conf = max(conf, int(float(cand or 0)))
            except Exception:
                pass
        conf_need = _mid_zone_touch_emit_min_conf()
        try:
            if fresh_bo_rt and micro_n >= 2:
                conf_need = min(int(conf_need), int(float(os.getenv("MID_ZONE_FIRST_MIN_CONF_FRESH", "76") or 76)))
            elif ("reclaim" in labels) and ("bos_5m" in labels or "displacement" in labels):
                conf_need = min(int(conf_need), int(float(os.getenv("MID_ZONE_FIRST_MIN_CONF_RECLAIM", "78") or 78)))
        except Exception:
            pass
        if conf < int(conf_need):
            return (False, micro_n, labels)
        try:
            price_now = float(t.get("entry") or t.get("close") or 0.0)
        except Exception:
            price_now = 0.0
        try:
            _anchor_ref, anchor_too_far, _anchor_slip_atr = _mid_pending_entry_ref(rec, price=price_now, ta=t)
        except Exception:
            anchor_too_far = False
            _anchor_slip_atr = 0.0
        if anchor_too_far:
            try:
                anchor_soft_max = float(os.getenv("MID_ZONE_FIRST_MAX_SLIPPAGE_ATR_FRESH", "0.90") if fresh_bo_rt else os.getenv("MID_ZONE_FIRST_MAX_SLIPPAGE_ATR", "0.55"))
            except Exception:
                anchor_soft_max = 0.90 if fresh_bo_rt else 0.55
            if float(_anchor_slip_atr or 0.0) > float(anchor_soft_max):
                return (False, micro_n, labels)
        if micro_n < _mid_zone_first_min_confirmations():
            return (False, micro_n, labels)
        return (True, micro_n, labels)
    except Exception:
        return (False, 0, [])


def _mid_pending_is_fresh_bo_rt(it: dict | None, *, now_ts: float | None = None) -> bool:
    try:
        rec = it if isinstance(it, dict) else {}
        bo_txt = str(rec.get("bo_rt") or rec.get("breakout_retest") or "").strip().upper()
        if not bo_txt:
            return False
        if ("BO" not in bo_txt) and ("BREAKOUT" not in bo_txt) and ("RETEST" not in bo_txt):
            return False
        try:
            max_bars = int(float(os.getenv("MID_FRESH_BO_RT_MAX_BARS", "4") or 4))
        except Exception:
            max_bars = 4
        try:
            max_sec = float(os.getenv("MID_FRESH_BO_RT_MAX_SEC", "1800") or 1800)
        except Exception:
            max_sec = 1800.0
        try:
            age_bars = rec.get("breakout_first_age_bars_create")
            if age_bars is not None and int(float(age_bars)) <= max(0, max_bars):
                return True
        except Exception:
            pass
        try:
            age_sec = rec.get("breakout_first_age_sec_create")
            if age_sec is not None and float(age_sec) <= max(0.0, max_sec):
                return True
        except Exception:
            pass
        if now_ts is not None:
            try:
                first_ts = rec.get("breakout_first_ts")
                if first_ts is not None:
                    ts = float(first_ts)
                    if ts > 1e12:
                        ts /= 1000.0
                    if ts > 0 and (float(now_ts) - ts) <= max(0.0, max_sec):
                        return True
            except Exception:
                pass
        return False
    except Exception:
        return False


def _mid_retest_hold_bars() -> int:
    """How many 5m bars price must stay inside the zone before emit.

    0 disables the hold requirement.
    """
    try:
        return max(0, int(float(os.getenv("MID_RETEST_HOLD_BARS", "0") or 0)))
    except Exception:
        return 0


def _mid_retest_hold_seconds() -> float:
    """Return hold requirement in seconds.

    MID_RETEST_HOLD_SEC wins when set explicitly. Otherwise we translate bars into
    5m candle time so 1 bar = 300 seconds.
    """
    try:
        raw = os.getenv("MID_RETEST_HOLD_SEC")
        if raw is not None and str(raw).strip() != "":
            return max(0.0, float(raw))
    except Exception:
        pass
    try:
        bars = _mid_retest_hold_bars()
        if bars <= 0:
            return 0.0
        return float(bars) * 300.0
    except Exception:
        return 0.0


def _mid_pending_zone_hold_ready(it: dict | None, *, now_ts: float | None = None, in_zone_now: bool = False) -> tuple[bool, str]:
    """Return whether a pending setup has held its zone long enough for emit.

    This is a WAIT gate, not a fail gate. It should delay emit while the retest is
    still fresh instead of consuming pending fails.
    """
    try:
        need_sec = _mid_retest_hold_seconds()
        if need_sec <= 0:
            return (True, "")
        rec = it if isinstance(it, dict) else {}
        has_zone = False
        try:
            lo = rec.get("entry_low")
            hi = rec.get("entry_high")
            has_zone = (lo is not None) and (hi is not None) and (float(hi) > float(lo) > 0)
        except Exception:
            has_zone = False
        if not has_zone:
            return (True, "")
        if not bool(in_zone_now):
            return (True, "")
        since = rec.get("_in_zone_since_ts")
        if since is None:
            return (False, f"zone_hold=0s<{int(round(need_sec))}s")
        ts_now = float(now_ts if now_ts is not None else time.time())
        elapsed = max(0.0, ts_now - float(since))
        if elapsed + 1e-9 < float(need_sec):
            return (False, f"zone_hold={int(elapsed)}s<{int(round(need_sec))}s")
        return (True, "")
    except Exception:
        return (True, "")


def _mid_pending_entry_ref(it: dict | None, *, price: float | None = None, ta: dict | None = None) -> tuple[float, bool, float]:
    """Prefer the original pending anchor over the current market price.

    Returns (entry_ref, too_far_from_anchor, slippage_atr).
    too_far_from_anchor means the current market has drifted too far from the
    stored pending entry idea and the setup should be skipped/expired instead of
    being repriced from the worse market price.
    """
    rec = it if isinstance(it, dict) else {}
    ta = ta or {}
    try:
        zone_mid = rec.get("pending_zone_mid")
        if zone_mid is None:
            lo = rec.get("entry_low")
            hi = rec.get("entry_high")
            if lo is not None and hi is not None:
                try:
                    zone_mid = (float(lo) + float(hi)) / 2.0
                except Exception:
                    zone_mid = None
        anchor = None
        for cand in (
            rec.get("pending_entry_anchor"),
            rec.get("pending_entry_ref"),
            zone_mid,
            rec.get("entry"),
            ta.get("entry"),
            price,
        ):
            try:
                fv = float(cand or 0.0)
                if fv > 0:
                    anchor = fv
                    break
            except Exception:
                pass
        if not anchor or anchor <= 0:
            return (0.0, False, 0.0)

        current = None
        for cand in (price, ta.get("entry"), ta.get("close"), anchor):
            try:
                fv = float(cand or 0.0)
                if fv > 0:
                    current = fv
                    break
            except Exception:
                pass
        if not current or current <= 0:
            return (float(anchor), False, 0.0)

        atr_use = None
        for cand in (ta.get("atr30"), ta.get("atr_abs"), rec.get("atr_at_create")):
            try:
                fv = float(cand or 0.0)
                if fv > 0:
                    atr_use = fv
                    break
            except Exception:
                pass
        if not atr_use or atr_use <= 0:
            atr_use = max(abs(float(anchor)) * 0.001, 1e-9)

        in_zone = False
        try:
            lo = rec.get("entry_low")
            hi = rec.get("entry_high")
            if lo is not None and hi is not None:
                lo_f = float(lo)
                hi_f = float(hi)
                if hi_f >= lo_f > 0:
                    in_zone = bool(lo_f <= float(current) <= hi_f)
        except Exception:
            in_zone = False

        try:
            slip_atr = abs(float(current) - float(anchor)) / float(atr_use)
        except Exception:
            slip_atr = 0.0

        try:
            max_slip = float(rec.get("pending_max_slippage_atr") or 0.0)
        except Exception:
            max_slip = 0.0
        if max_slip <= 0:
            try:
                env_name = "MID_PENDING_ANCHOR_MAX_SLIPPAGE_ATR_FRESH_BO_RT" if _mid_pending_is_fresh_bo_rt(rec) else "MID_PENDING_ANCHOR_MAX_SLIPPAGE_ATR"
                default_v = "0.55" if env_name.endswith("FRESH_BO_RT") else "0.35"
                max_slip = float(os.getenv(env_name, default_v) or default_v)
            except Exception:
                max_slip = 0.55 if _mid_pending_is_fresh_bo_rt(rec) else 0.35

        too_far = bool((not in_zone) and max_slip > 0 and slip_atr > max_slip)
        return (float(anchor), bool(too_far), float(slip_atr))
    except Exception:
        try:
            fallback = float((it or {}).get("entry") or 0.0)
        except Exception:
            fallback = 0.0
        return (float(fallback), False, 0.0)


def _mid_macd_hist_display4(val: float | None) -> str:
    """Return MACD hist string exactly like the TA block uses (+/- with 4 decimals)."""
    try:
        fv = float(val)
        if not math.isfinite(fv):
            return ""
        return f"{fv:+.4f}"
    except Exception:
        return ""


def _mid_macd_hist_emit_block_reason(direction: str, macd_hist: float | None) -> str:
    """Hard-block emit when MACD hist is on the wrong side or too weak.

    The comparison intentionally uses the same 4-decimal representation shown in the
    TA block, so values displayed as -0.0000 / +0.0000 remain neutral. A minimum
    absolute threshold can be configured with MID_TRIGGER_MIN_MACD_H (fallback:
    TA_MIN_MACD_H).
    """
    try:
        side = str(direction or "").strip().upper()
        if side not in ("LONG", "SHORT"):
            return ""
        disp = _mid_macd_hist_display4(macd_hist)
        if not disp:
            return ""
        try:
            disp_val = float(disp)
        except Exception:
            return ""
        try:
            thr_raw = os.getenv("MID_TRIGGER_MIN_MACD_H")
            if thr_raw is None or str(thr_raw).strip() == "":
                thr_raw = os.getenv("TA_MIN_MACD_H", "0")
            thr = max(0.0, float(thr_raw or 0.0))
        except Exception:
            thr = 0.0
        thr_disp = f"{thr:.4f}"
        if side == "LONG" and disp_val < thr:
            if thr > 0.0:
                return f"macd_hist={disp} [need >= +{thr_disp}]"
            return f"macd_hist={disp} [need > 0]"
        if side == "SHORT" and disp_val > (-thr):
            if thr > 0.0:
                return f"macd_hist={disp} [need <= -{thr_disp}]"
            return f"macd_hist={disp} [need < 0]"
        return ""
    except Exception:
        return ""


def _mid_directional_contradiction_reason(*sources: dict | None) -> str:
    """Infer a directional contradiction from one or more TA/pending payloads.

    Trigger-time paths occasionally carry the contradiction inputs split across
    multiple objects: the fresh TA can have the pattern while the pending record
    still holds the BO/RT label. This helper merges the available context so a
    wrong-way breakout (for example LONG + BO↓ + Retest) remains a hard block.

    It also understands optional raw BO/RT fields (breakout_retest_raw/bo_rt_raw)
    so the formatter can hide opposite-direction labels without weakening the
    trigger-time veto.
    """
    try:
        side = ""
        bo = ""
        pat = ""
        for src in sources:
            if not isinstance(src, dict):
                continue
            raw = str(src.get("block_reason") or "").strip()
            head = raw.split()[0].split("=", 1)[0].strip().lower() if raw else ""
            if head == "directional_contradiction":
                return raw or "directional_contradiction"
            if not side:
                for key in ("direction", "dir", "side", "dir4", "dir1"):
                    try:
                        v = str(src.get(key) or "").strip().upper()
                    except Exception:
                        v = ""
                    if v in ("LONG", "SHORT"):
                        side = v
                        break
            if not bo:
                try:
                    bo = str(
                        src.get("breakout_retest_raw")
                        or src.get("bo_rt_raw")
                        or src.get("breakout_retest")
                        or src.get("bo_rt")
                        or ""
                    ).strip()
                except Exception:
                    bo = ""
            if not pat:
                try:
                    pat = str(src.get("pattern") or "").strip()
                except Exception:
                    pat = ""

        if side not in ("LONG", "SHORT"):
            return ""

        try:
            pat_norm = " ".join(re.sub(r"[_-]+", " ", pat).split()).casefold()
        except Exception:
            pat_norm = ""

        try:
            bo_norm = str(bo or "").strip().upper().replace(" ", "")
        except Exception:
            bo_norm = ""

        if side == "LONG":
            if bo_norm.startswith("BO↓"):
                return f"directional_contradiction breakout={bo}"
            if pat_norm in {"bearish engulfing", "bear engulf", "shooting star", "evening star"}:
                return f"directional_contradiction pattern={pat or pat_norm}"
        elif side == "SHORT":
            if bo_norm.startswith("BO↑"):
                return f"directional_contradiction breakout={bo}"
            if pat_norm in {"bullish engulfing", "bull engulf", "hammer", "morning star"}:
                return f"directional_contradiction pattern={pat or pat_norm}"
        return ""
    except Exception:
        return ""

def _mid_zone_touch_guard_reason(ta: dict | None, it: dict | None = None) -> str:
    """Hard veto reasons for early zone-touch alerts.

    Zone-touch emits should behave like a real trader entering from a prepared
    zone: keep only truly dangerous contradictions as hard vetoes, while softer
    late/vwap/rsi imperfections stay informational and are handled later by score,
    RR and smart-exit logic.
    """
    try:
        t = ta if isinstance(ta, dict) else {}
        raw = str(t.get("block_reason") or "").strip()
        head = raw.split()[0].split("=", 1)[0].strip().lower() if raw else ""
        if head in (
            "directional_contradiction",
            "regime_block",
            "adx_30m",
            "adx_1h",
        ):
            return raw or head

        side = ""
        for key in ("direction", "dir", "side", "dir4", "dir1"):
            try:
                v = str(t.get(key) or "").strip().upper()
            except Exception:
                v = ""
            if v in ("LONG", "SHORT"):
                side = v
                break

        _dir_reason = _mid_directional_contradiction_reason(t, it)
        if _dir_reason:
            return _dir_reason

        try:
            rsi_5m = float(t.get("rsi"))
        except Exception:
            rsi_5m = float("nan")
        if rsi_5m == rsi_5m and side in ("LONG", "SHORT"):
            rsi_long_max = MID_ULTRA_RSI_LONG_MAX if MID_ULTRA_SAFE else MID_RSI_LONG_MAX
            rsi_long_min = MID_ULTRA_RSI_LONG_MIN if MID_ULTRA_SAFE else MID_RSI_LONG_MIN
            rsi_short_min = MID_ULTRA_RSI_SHORT_MIN if MID_ULTRA_SAFE else MID_RSI_SHORT_MIN
            rsi_short_max = MID_ULTRA_RSI_SHORT_MAX if MID_ULTRA_SAFE else MID_RSI_SHORT_MAX
            try:
                rsi_buf = float(os.getenv("MID_ZONE_TOUCH_HARD_RSI_BUFFER", "6") or 6)
            except Exception:
                rsi_buf = 6.0
            if side == "LONG":
                if rsi_5m >= (float(rsi_long_max) + float(rsi_buf)):
                    return f"rsi_long_extreme={rsi_5m:.1f} >= {(float(rsi_long_max) + float(rsi_buf)):g}"
                if rsi_5m < (float(rsi_long_min) - float(rsi_buf)):
                    return f"rsi_long_extreme={rsi_5m:.1f} < {(float(rsi_long_min) - float(rsi_buf)):g}"
            else:
                if rsi_5m <= (float(rsi_short_min) - float(rsi_buf)):
                    return f"rsi_short_extreme={rsi_5m:.1f} <= {(float(rsi_short_min) - float(rsi_buf)):g}"
                if rsi_5m >= (float(rsi_short_max) + float(rsi_buf)):
                    return f"rsi_short_extreme={rsi_5m:.1f} >= {(float(rsi_short_max) + float(rsi_buf)):g}"

        _macd_reason = _mid_macd_hist_emit_block_reason(side, t.get("macd_hist"))
        if _macd_reason:
            return _macd_reason

        if bool(t.get("trap_ok", True)) is False:
            return str(t.get("trap_reason") or "trap_block")
        return ""
    except Exception:
        return ""



def _mid_bo_label_is_short(label: str | None) -> bool:
    try:
        s = str(label or "").strip().upper().replace(" ", "")
        return bool(s) and s.startswith("BO↓")
    except Exception:
        return False


def _mid_futures_short_exec_zone_ok(zone_src: str | None) -> bool:
    try:
        zs = str(zone_src or "").strip().lower()
        return zs.startswith("ob30") or zs.startswith("fvg30:bear")
    except Exception:
        return False


def _mid_body_atr(body_abs: float | None, atr_abs: float | None) -> float:
    try:
        b = abs(float(body_abs or 0.0))
        a = abs(float(atr_abs or 0.0))
        if a <= 0:
            return 0.0
        return b / a
    except Exception:
        return 0.0


def _mid_futures_short_anti_bounce_relief_ok(*,
                                              market: str,
                                              direction: str,
                                              in_zone_now: bool,
                                              zone_src: str | None,
                                              bo_rt_label: str | None,
                                              vol_x: float | None) -> bool:
    """Allow borderline anti-bounce on strong futures SHORT retests inside a real sell zone."""
    try:
        if (market or "").upper().strip() != "FUTURES":
            return False
        if (direction or "").upper().strip() != "SHORT":
            return False
        if not bool(in_zone_now):
            return False
        if not _mid_futures_short_exec_zone_ok(zone_src):
            return False
        if not _mid_bo_label_is_short(bo_rt_label):
            return False
        try:
            min_vol = float(os.getenv("MID_V42_FUT_SHORT_ANTI_BOUNCE_RELIEF_MIN_VOL_X", "0.25") or 0.25)
        except Exception:
            min_vol = 0.25
        return float(vol_x or 0.0) >= float(min_vol)
    except Exception:
        return False


def _mid_futures_short_strong_confirm_ok(*,
                                         bo_rt_label: str | None,
                                         breakout_fresh_ok: bool,
                                         micro_trap_ok: bool,
                                         macd_hist: float | None,
                                         body_atr: float | None) -> bool:
    """Return True only for genuinely strong bearish confirmation."""
    try:
        bo_down = _mid_bo_label_is_short(bo_rt_label)
        try:
            body_need = float(os.getenv("MID_V42_FUT_SHORT_STRONG_BODY_ATR", "0.04") or 0.04)
        except Exception:
            body_need = 0.04
        body_ok = float(body_atr or 0.0) >= float(body_need)
        disp = _mid_macd_hist_display4(macd_hist)
        macd_bear = bool(disp) and disp.startswith("-") and disp != "-0.0000"
        if bo_down and breakout_fresh_ok:
            return True
        if bo_down and macd_bear:
            return True
        if micro_trap_ok and macd_bear:
            return True
        if bo_down and body_ok and micro_trap_ok:
            return True
        return False
    except Exception:
        return False


def _mid_futures_short_weak_emit_reason(*,
                                        market: str,
                                        direction: str,
                                        risk_flags=None,
                                        vol_x: float | None,
                                        body_atr: float | None,
                                        bo_rt_label: str | None,
                                        breakout_fresh_ok: bool,
                                        micro_trap_ok: bool,
                                        macd_hist: float | None) -> str:
    """Block weak futures SHORT emits with zero-body + low-volume and no real bearish confirmation."""
    try:
        if (market or "").upper().strip() != "FUTURES":
            return ""
        if (direction or "").upper().strip() != "SHORT":
            return ""
        flags = {str(x).strip().lower() for x in _mid_gate_listify(risk_flags) if str(x).strip()}
        try:
            weak_min_vol = float(os.getenv("MID_V42_FUT_SHORT_WEAK_MIN_VOL_X", "0.20") or 0.20)
        except Exception:
            weak_min_vol = 0.20
        try:
            zero_body_max = float(os.getenv("MID_V42_FUT_SHORT_ZERO_BODY_ATR_MAX", "0.02") or 0.02)
        except Exception:
            zero_body_max = 0.02
        vol_v = float(vol_x or 0.0)
        body_v = float(body_atr or 0.0)
        vol_low_now = ("vol_low" in flags) or (vol_v < float(weak_min_vol))
        zero_body_now = body_v <= float(zero_body_max)
        if not (vol_low_now and zero_body_now):
            return ""
        if _mid_futures_short_strong_confirm_ok(
            bo_rt_label=bo_rt_label,
            breakout_fresh_ok=bool(breakout_fresh_ok),
            micro_trap_ok=bool(micro_trap_ok),
            macd_hist=macd_hist,
            body_atr=body_v,
        ):
            return ""
        return f"fut_short_weak_emit:vol={vol_v:.2f}|body_atr={body_v:.2f}|confirm=0"
    except Exception:
        return ""


def _mid_final_emit_apply_reason(reason: str) -> str:
    try:
        r = str(reason or "").strip().lower()
    except Exception:
        r = ""
    if not r:
        return "blocked"
    if r.startswith("late_from_anchor"):
        return "late_entry"
    if "directional_contradiction" in r:
        return "directional_contradiction"
    if r.startswith("macd_hist=") or "macd_hist" in r:
        return "macd_hist"
    if r.startswith("anti_bounce_short") or r.startswith("anti_bounce_long"):
        return "anti_bounce"
    if r.startswith("fut_short_weak_emit"):
        return "vol_low"
    if r.startswith("instant_regime_block"):
        return "regime_block"
    return "blocked"


def _mid_final_emit_gate_reason(*,
                                sig=None,
                                ta: dict | None = None,
                                it: dict | None = None,
                                risk_flags=None,
                                vol_x: float | None = None,
                                body_atr: float | None = None,
                                bo_rt_label: str | None = None,
                                breakout_fresh_ok: bool = False,
                                micro_trap_ok: bool | None = None,
                                macd_hist: float | None = None,
                                anti_bounce_reason: str | None = None,
                                gate_meta: dict | None = None,
                                zone_src: str | None = None,
                                in_zone_now: bool = True,
                                route: str | None = None) -> str:
    """Unified final veto before any real emit of weak FUTURES SHORT.

    This closes the remaining bypasses where a signal can pass scan/pending gates
    but still be obviously wrong-way at the final moment of emission.
    """
    try:
        enabled = str(os.getenv("MID_V43_FINAL_EMIT_VETO", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        enabled = True
    if not enabled:
        return ""
    try:
        market_u = str((getattr(sig, "market", None) if sig is not None else "") or (ta or {}).get("market") or (it or {}).get("market") or "").upper().strip()
        direction_u = str((getattr(sig, "direction", None) if sig is not None else "") or (ta or {}).get("direction") or (it or {}).get("direction") or "").upper().strip()
    except Exception:
        market_u, direction_u = "", ""
    try:
        entry_now = _safe_float((ta or {}).get("entry"), None)
        if entry_now is None:
            entry_now = _safe_float((ta or {}).get("close"), None)
        if entry_now is None and sig is not None:
            entry_now = _safe_float(getattr(sig, "entry", None), None)
    except Exception:
        entry_now = None
    try:
        anchor_ref, anchor_far, anchor_slip_atr = _mid_pending_entry_ref(it, price=entry_now, ta=ta)
    except Exception:
        anchor_ref, anchor_far, anchor_slip_atr = (0.0, False, 0.0)
    try:
        fresh_anchor = bool(breakout_fresh_ok or _mid_pending_is_fresh_bo_rt(it))
    except Exception:
        fresh_anchor = bool(breakout_fresh_ok)
    try:
        hard_anchor_max = float(os.getenv("MID_FINAL_EMIT_MAX_ANCHOR_SLIP_ATR_FRESH", "0.75") if fresh_anchor else os.getenv("MID_FINAL_EMIT_MAX_ANCHOR_SLIP_ATR", "0.45"))
    except Exception:
        hard_anchor_max = 0.75 if fresh_anchor else 0.45
    try:
        if bool(in_zone_now):
            hard_anchor_max += float(os.getenv("MID_FINAL_EMIT_IN_ZONE_SLIP_PAD", "0.10") or 0.10)
    except Exception:
        pass
    if anchor_far and float(anchor_slip_atr or 0.0) > float(hard_anchor_max):
        return f"late_from_anchor:{float(anchor_slip_atr):.2f}>{float(hard_anchor_max):.2f}"

    smc_direct_route = _mid_is_direct_smc_route(route=route, sig=sig, ta=ta, rec=it, meta=gate_meta)

    # Directional contradiction must veto ALL real emits, not only FUTURES SHORT.
    # Trigger-time context can be split across fresh TA, pending record and gate_meta,
    # so merge all available sources before the short-only branch below.
    _dir_reason = _mid_directional_contradiction_reason(ta, it, gate_meta)
    if _dir_reason:
        return str(_dir_reason)

    if smc_direct_route:
        return ""

    if market_u != "FUTURES" or direction_u != "SHORT":
        return ""

    try:
        macd_v = macd_hist if macd_hist is not None else _safe_float((ta or {}).get("macd_hist"), None)
        if macd_v is None:
            macd_v = _safe_float((it or {}).get("macd_hist"), None)
    except Exception:
        macd_v = None
    _macd_reason = _mid_macd_hist_emit_block_reason(direction_u, macd_v)
    if _macd_reason:
        return str(_macd_reason)

    try:
        vol_v = vol_x if vol_x is not None else (ta or {}).get("rel_vol")
        if vol_v is None:
            vol_v = (ta or {}).get("vol_x")
        if vol_v is None:
            vol_v = (gate_meta or {}).get("vol_x")
        vol_v = float(vol_v or 0.0)
    except Exception:
        vol_v = 0.0

    try:
        body_v = body_atr if body_atr is not None else _mid_body_atr(float((ta or {}).get("last_body") or 0.0), float((ta or {}).get("atr30") or (ta or {}).get("atr_abs") or 0.0))
        if not body_v:
            body_v = float((gate_meta or {}).get("current_body_atr") or (gate_meta or {}).get("origin_body_atr") or 0.0)
    except Exception:
        body_v = 0.0

    try:
        bo_s = str(bo_rt_label or (it or {}).get("bo_rt") or (it or {}).get("breakout_retest") or "").strip()
    except Exception:
        bo_s = ""

    try:
        risk_flags_use = risk_flags if risk_flags is not None else (it or {}).get("risk_flags")
    except Exception:
        risk_flags_use = risk_flags

    try:
        micro_ok = bool(micro_trap_ok if micro_trap_ok is not None else bool((ta or {}).get("trap_ok", False)))
    except Exception:
        micro_ok = False

    try:
        breakout_ok = bool(breakout_fresh_ok or bool((it or {}).get("smart_breakout_fast_ok") or _mid_pending_is_fresh_bo_rt(it)))
    except Exception:
        breakout_ok = bool(breakout_fresh_ok)

    _weak_reason = _mid_futures_short_weak_emit_reason(
        market=market_u,
        direction=direction_u,
        risk_flags=risk_flags_use,
        vol_x=vol_v,
        body_atr=body_v,
        bo_rt_label=bo_s,
        breakout_fresh_ok=bool(breakout_ok),
        micro_trap_ok=bool(micro_ok),
        macd_hist=macd_v,
    )
    if _weak_reason:
        return str(_weak_reason)

    try:
        anti_reason = str(anti_bounce_reason or "").strip()
    except Exception:
        anti_reason = ""
    if not anti_reason:
        try:
            if isinstance(gate_meta, dict):
                for _x in (gate_meta.get("ignored_checks") or []):
                    _xs = str(_x or "").strip()
                    if "anti_bounce_short" in _xs or "anti_bounce_long" in _xs:
                        anti_reason = _xs.split(":", 1)[-1].strip() if ":" in _xs else _xs
                        break
        except Exception:
            anti_reason = anti_reason or ""
    if anti_reason:
        try:
            relief = bool((gate_meta or {}).get("fut_short_anti_bounce_relief"))
        except Exception:
            relief = False
        if not relief:
            try:
                relief = _mid_futures_short_anti_bounce_relief_ok(
                    market=market_u,
                    direction=direction_u,
                    in_zone_now=bool(in_zone_now),
                    zone_src=str(zone_src or (gate_meta or {}).get("zone_src") or (it or {}).get("entry_zone_src") or ""),
                    bo_rt_label=bo_s,
                    vol_x=vol_v,
                )
            except Exception:
                relief = False
        if not relief:
            return str(anti_reason)
    return ""
    

def _mid_trigger_selected_hardblock_reason(reason: str, it: dict | None = None) -> tuple[str | None, str | None]:
    """Selectively enforce hard-blocks that must be respected at actual entry / emit.

    Trader-style trigger logic keeps only the truly dangerous blockers as hard vetoes.
    Late-entry / anti-bounce / VWAP distance remain advisory unless they become extreme.
    This lets strong setups enter from the prepared zone instead of waiting until the
    move is already extended.

    Returns (log_reason, apply_reason) or (None, None) when the raw reason should
    remain ignored by trigger-time logic.
    """
    try:
        raw = str(reason or "").strip()
        if not raw:
            return (None, None)
        head = raw.split()[0].split("=", 1)[0].strip().lower()
        fresh_bo_rt = _mid_pending_is_fresh_bo_rt(it)
        try:
            trader_mode = (os.getenv("MID_TRIGGER_TRADER_MODE", "0") or "0").strip().lower() in ("1", "true", "yes", "on")
        except Exception:
            trader_mode = False
        if head in ("rsi_long", "rsi_short"):
            if trader_mode:
                m = re.search(r"([<>]=?)\s*([0-9.]+)", raw)
                if m:
                    try:
                        bound = float(m.group(2))
                        hard_pad = float(os.getenv("MID_TRIGGER_HARD_RSI_PAD", "6") or 6)
                        valm = re.search(r"=([0-9.]+)", raw)
                        val = float(valm.group(1)) if valm else None
                        if val is not None:
                            if (">" in m.group(1) and val < (bound + hard_pad)) or ("<" in m.group(1) and val > (bound - hard_pad)):
                                return (None, None)
                    except Exception:
                        pass
            return (head, head)
        if head == "macd_hist":
            return ("macd_hist", "macd_hist")
        if head in ("adx_30m", "adx_1h"):
            return (head, "regime_block")
        if head == "regime_block":
            return ("regime_block", "regime_block")
        if head == "vol_x":
            if trader_mode:
                return (None, None)
            return ("vol_low", "vol_low")
        if head == "directional_contradiction":
            return ("directional_contradiction", "directional_contradiction")
        if head in ("near_recent_low", "near_recent_high"):
            if trader_mode and fresh_bo_rt:
                return (None, None)
            return ("near_recent_extreme", "near_recent_extreme")
        if head in ("vwap_dist_atr", "vwap_bias", "wrong_vwap_side"):
            if trader_mode:
                m = re.search(r"vwap_dist_atr=([0-9.]+)\s*[<>]\s*([0-9.]+)", raw)
                if m:
                    try:
                        dist = float(m.group(1))
                        limit = max(1e-9, float(m.group(2)))
                        hard_mult = float(os.getenv("MID_TRIGGER_HARD_VWAP_DIST_MULT", "1.40") or 1.40)
                        if dist <= (limit * hard_mult):
                            return (None, None)
                    except Exception:
                        return (None, None)
                else:
                    return (None, None)
            return ("vwap_dist", "vwap_dist")
        if head == "late_entry_atr":
            if trader_mode:
                m = re.search(r"late_entry_atr=([0-9.]+)\s*>\s*([0-9.]+)", raw)
                if m:
                    try:
                        move = float(m.group(1))
                        limit = max(1e-9, float(m.group(2)))
                        hard_mult = float(os.getenv("MID_TRIGGER_HARD_LATE_ENTRY_MULT", "1.35") or 1.35)
                        if fresh_bo_rt:
                            hard_mult = max(hard_mult, float(os.getenv("MID_TRIGGER_HARD_LATE_ENTRY_MULT_FRESH", "1.60") or 1.60))
                        if move <= (limit * hard_mult):
                            return (None, None)
                    except Exception:
                        return (None, None)
                else:
                    return (None, None)
            return ("late_entry", "late_entry")
        if head in ("anti_bounce_short", "anti_bounce_long"):
            try:
                relax_fresh = (os.getenv("MID_TRIGGER_RELAX_ANTI_BOUNCE_FRESH_BO_RT", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
            except Exception:
                relax_fresh = True
            if trader_mode:
                m = re.search(r"=([0-9.]+)\s*>\s*([0-9.]+)", raw)
                if m:
                    try:
                        dist = float(m.group(1))
                        limit = max(1e-9, float(m.group(2)))
                        hard_mult = float(os.getenv("MID_TRIGGER_HARD_ANTI_BOUNCE_MULT", "1.25") or 1.25)
                        if (fresh_bo_rt and relax_fresh) or dist <= (limit * hard_mult):
                            return (None, None)
                    except Exception:
                        if fresh_bo_rt and relax_fresh:
                            return (None, None)
                elif fresh_bo_rt and relax_fresh:
                    return (None, None)
            else:
                if fresh_bo_rt and relax_fresh:
                    return (None, None)
            return ("anti_bounce", "anti_bounce")
        return (None, None)
    except Exception:
        return (None, None)

def _mid_hardblock_reset_tick() -> None:
    global _MID_HARD_BLOCK_TICK_TOKEN, _MID_HARD_BLOCK_BY_KEY, _MID_HARD_BLOCK_SAMPLES
    try:
        _MID_HARD_BLOCK_TICK_TOKEN = str(uuid.uuid4())
        _MID_HARD_BLOCK_BY_KEY = defaultdict(int)
        _MID_HARD_BLOCK_SAMPLES = defaultdict(list)
    except Exception:
        _MID_HARD_BLOCK_TICK_TOKEN = "1"
        _MID_HARD_BLOCK_BY_KEY = defaultdict(int)
        _MID_HARD_BLOCK_SAMPLES = defaultdict(list)

def _mid_hardblock_track(reason: str, symbol: str | None = None) -> None:
    """Track per-tick hard-block buckets (safe to call from anywhere)."""
    try:
        if not _MID_HARD_BLOCK_TICK_TOKEN:
            return
        k = _mid_hardblock_key(str(reason))
        _MID_HARD_BLOCK_BY_KEY[k] += 1
        # keep few samples for log context
        try:
            maxs = int(os.getenv("MID_HARDBLOCK_SAMPLES", "2") or "2")
        except Exception:
            maxs = 2
        if maxs > 0:
            arr = _MID_HARD_BLOCK_SAMPLES[k]
            if len(arr) < maxs:
                if symbol:
                    arr.append(f"{symbol}:{reason}")
                else:
                    arr.append(str(reason))
    except Exception:
        pass

def _mid_hardblock_dump(max_keys: int = 6) -> str:
    """Return compact breakdown string like: late_entry_atr=40, vwap_dist_atr=25, anti_bounce=18"""
    try:
        items = sorted([(k, int(v)) for k, v in _MID_HARD_BLOCK_BY_KEY.items()], key=lambda x: (-x[1], x[0]))
        items = items[:max(1, int(max_keys))]
        return ", ".join([f"{k}={v}" for k, v in items])
    except Exception:
        return ""


def _mid_soft_blocks_enabled() -> bool:
    try:
        return (os.getenv("MID_SOFT_BLOCKS_ENABLED", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        return True


def _mid_soft_block_penalty_for_reason(reason: str):
    """Return (bucket, penalty) when a former hard-block should become a score penalty.

    None means the reason must remain a hard block. We keep truly bad entries blocked
    (deep late entries / deep anti-bounce / extreme-near-level entries), while borderline
    cases become score penalties so strong pending setups can still survive scan.
    """
    try:
        if not _mid_soft_blocks_enabled():
            return None
        r = str(reason or "").strip()
        if not r:
            return None

        def _pen(name: str, default: float) -> float:
            try:
                return float(os.getenv(name, str(default)) or default)
            except Exception:
                return float(default)

        if r.startswith("bb_bounce_zone="):
            return ("bb_bounce_zone_penalty", -abs(_pen("MID_PENALTY_BB_BOUNCE_ZONE", 8.0)))

        if r.startswith("vwap_side_short"):
            return ("vwap_side_short_penalty", -abs(_pen("MID_PENALTY_VWAP_SIDE_SHORT", 6.0)))

        if r.startswith("late_entry_atr="):
            m = re.search(r"late_entry_atr=([0-9.]+)\s*>\s*([0-9.]+)", r)
            if not m:
                return None
            move = float(m.group(1))
            limit = max(1e-9, float(m.group(2)))
            hard_mult = _pen("MID_HARD_LATE_ENTRY_MULT", 1.50)
            if move > (limit * hard_mult):
                return None
            return ("late_entry_penalty", -abs(_pen("MID_PENALTY_LATE_ENTRY_ATR", 10.0)))

        if r.startswith("anti_bounce_short"):
            m = re.search(r"dist_low_atr=([0-9.]+)\s*>\s*([0-9.]+)", r)
            if not m:
                return None
            dist = float(m.group(1))
            limit = max(1e-9, float(m.group(2)))
            hard_mult = _pen("MID_HARD_ANTI_BOUNCE_MULT", 1.35)
            if dist > (limit * hard_mult):
                return None
            return ("anti_bounce_penalty", -abs(_pen("MID_PENALTY_ANTI_BOUNCE_ATR", 9.0)))

        if r.startswith("anti_bounce_long"):
            m = re.search(r"dist_high_atr=([0-9.]+)\s*>\s*([0-9.]+)", r)
            if not m:
                return None
            dist = float(m.group(1))
            limit = max(1e-9, float(m.group(2)))
            hard_mult = _pen("MID_HARD_ANTI_BOUNCE_MULT", 1.35)
            if dist > (limit * hard_mult):
                return None
            return ("anti_bounce_penalty", -abs(_pen("MID_PENALTY_ANTI_BOUNCE_ATR", 9.0)))

        if r.startswith("near_recent_low"):
            m = re.search(r"dist_atr=([0-9.]+)\s*<\s*([0-9.]+)", r)
            if not m:
                return None
            dist = float(m.group(1))
            thr = max(1e-9, float(m.group(2)))
            hard_frac = _pen("MID_HARD_NEAR_EXTREME_FRAC", 0.70)
            if dist < (thr * hard_frac):
                return None
            return ("near_recent_low_penalty", -abs(_pen("MID_PENALTY_NEAR_RECENT_LOW", 6.0)))

        if r.startswith("near_recent_high"):
            m = re.search(r"dist_atr=([0-9.]+)\s*<\s*([0-9.]+)", r)
            if not m:
                return None
            dist = float(m.group(1))
            thr = max(1e-9, float(m.group(2)))
            hard_frac = _pen("MID_HARD_NEAR_EXTREME_FRAC", 0.70)
            if dist < (thr * hard_frac):
                return None
            return ("near_recent_high_penalty", -abs(_pen("MID_PENALTY_NEAR_RECENT_HIGH", 6.0)))
    except Exception:
        return None
    return None

# --- MID trap digest sink (aggregates "MID blocked (trap)" into a periodic digest) ---

# Trap log dedup (avoid spamming the same message every second)
_MID_TRAP_LAST_LOG: Dict[str, float] = {}

# Per-tick log suppression (avoid repeating [mid][block]/[mid][trap] many times for same symbol)
_MID_TICK_CTX = contextvars.ContextVar('MID_TICK_CTX', default=None)


_MID_ADAPT_CTX = contextvars.ContextVar('MID_ADAPT_CTX', default=None)

# Evaluation phase marker for MID (used to split MACRO trap at SCAN vs MICRO trap at TRIGGER).
#
# IMPORTANT: This must exist as a ContextVar. Without it, code falls back to phase="scan"
# everywhere (because NameError is swallowed), which makes trigger-time checks incorrectly
# run the strict macro trap and drastically reduces emits.
_MID_EVAL_PHASE = contextvars.ContextVar('MID_EVAL_PHASE', default='scan')

def _mid_adapt_reset_tick() -> None:
    """Reset adaptive regime stats for the current MID tick."""
    try:
        _MID_ADAPT_CTX.set({'n': 0, 'sum_atrp': 0.0, 'sum_t': 0.0, 'seen': set()})
    except Exception:
        pass

def _mid_adapt_track(atrp: float, t: float, symbol: str | None = None) -> None:
    """Track per-symbol ATR% + normalized regime parameter (t in [0..1]).
    If symbol is provided, counts each symbol only once per tick (even if evaluated on many venues).
    """
    try:
        ctx = _MID_ADAPT_CTX.get()
        if not isinstance(ctx, dict):
            return
        sym = (str(symbol or '').strip().upper()) if symbol is not None else ''
        if sym:
            seen = ctx.get('seen')
            if not isinstance(seen, set):
                seen = set()
                ctx['seen'] = seen
            if sym in seen:
                return
            seen.add(sym)
        ctx['n'] = int(ctx.get('n') or 0) + 1
        ctx['sum_atrp'] = float(ctx.get('sum_atrp') or 0.0) + float(atrp or 0.0)
        ctx['sum_t'] = float(ctx.get('sum_t') or 0.0) + float(t or 0.0)
    except Exception:
        return


def _mid_adapt_regime_from_t(t: float) -> str:
    try:
        tt = float(t)
    except Exception:
        tt = 0.5
    if tt <= 0.33:
        return "LOW"
    if tt >= 0.66:
        return "HIGH"
    return "MID"

def _mid_adapt_snapshot() -> Optional[Tuple[str, float, float, int]]:
    """Return (regime, avg_atrp, avg_t, n) for current tick, or None."""
    try:
        ctx = _MID_ADAPT_CTX.get()
        if not isinstance(ctx, dict):
            return None
        n = int(ctx.get('n') or 0)
        if n <= 0:
            return None
        avg_atrp = float(ctx.get('sum_atrp') or 0.0) / float(n)
        avg_t = float(ctx.get('sum_t') or 0.0) / float(n)
        regime = _mid_adapt_regime_from_t(avg_t)
        return (regime, float(avg_atrp), float(avg_t), n)
    except Exception:
        return None


def _mid_trap_log_cooldown_sec() -> float:
    """Cooldown (seconds) for MID log de-duplication.

    Priority:
      1) MID_LOG_DEDUP_SEC (new, applies to ALL MID log types: trap/block/emit)
      2) MID_TRAP_LOG_COOLDOWN_SEC (legacy, kept for backward compatibility)
    """
    try:
        v = (os.getenv("MID_LOG_DEDUP_SEC") or "").strip()
        if v:
            return float(v)
        return float(os.getenv("MID_TRAP_LOG_COOLDOWN_SEC", "10") or 10)
    except Exception:
        return 10.0



def _mid_trap_should_log(key: str) -> bool:
    try:
        now = time.time()
        cd = max(0.0, float(_mid_trap_log_cooldown_sec()))
        if cd <= 0:
            return True
        last = _MID_TRAP_LAST_LOG.get(key, 0.0)
        if now - last < cd:
            return False
        _MID_TRAP_LAST_LOG[key] = now
        # light purge
        if len(_MID_TRAP_LAST_LOG) > 2000:
            cutoff = now - max(cd, 30.0)
            for k, ts in list(_MID_TRAP_LAST_LOG.items())[:500]:
                if ts < cutoff:
                    _MID_TRAP_LAST_LOG.pop(k, None)
        return True
    except Exception:
        return True
# Bot can register a sink callback that receives structured trap events.
_MID_TRAP_SINK = None  # type: ignore
def set_mid_trap_sink(cb):
    """Register a callable that receives trap events: cb(event: dict)."""
    global _MID_TRAP_SINK
    _MID_TRAP_SINK = cb

def _emit_mid_trap_event(event: dict) -> None:
    try:
        cb = _MID_TRAP_SINK
        if cb:
            cb(event)
    except Exception:
        pass

def _mid_trap_reason_key(reason: str) -> str:
    try:
        r = (reason or "").strip()
        if not r:
            return "unknown"
        return r.split()[0].strip()
    except Exception:
        return "unknown"

# ------------------ Stablecoin pair blocking (scanner + autotrade) ------------------
# Blocks stable-vs-stable pairs like USDCUSDT / DAIUSDT / USD1USDT, etc.
# Configure:
#   BLOCK_STABLECOIN_PAIRS=1 (default)
#   STABLECOINS=USDT,USDC,DAI,BUSD,TUSD,FDUSD,USDP,PYUSD,FRAX,EURC,USD1
#   BLOCKED_SYMBOLS=USDCUSDT,BUSDUSDT,DAIUSDT,USD1USDT  (optional additional hard blocks)

def _env_csv_set(name: str, default_csv: str) -> set[str]:
    raw = (os.getenv(name) or "").strip()
    if not raw:
        raw = default_csv
    return {p.strip().upper() for p in raw.split(",") if p and p.strip()}

_BLOCK_STABLECOIN_PAIRS = (os.getenv("BLOCK_STABLECOIN_PAIRS", "1").strip().lower() not in ("0","false","no","off"))

_STABLECOINS = _env_csv_set(
    "STABLECOINS",
    "USDT,USDC,DAI,BUSD,TUSD,FDUSD,USDP,PYUSD,FRAX,EURC,USD1"
)

_BLOCKED_SYMBOLS = _env_csv_set(
    "BLOCKED_SYMBOLS",
    ""
)

# Sort by length to match e.g. USD1 before USD
_STABLECOINS_SORTED = sorted(_STABLECOINS, key=len, reverse=True)

def _normalize_symbol(symbol: str) -> str:
    s = (symbol or "").upper().strip()
    s = s.replace("-", "").replace("_", "").replace("/", "")
    return s

def _split_base_quote(symbol: str) -> tuple[str, str]:
    """Split a concatenated symbol into (base, quote) when quote matches a known stablecoin."""
    s = _normalize_symbol(symbol)
    for q in _STABLECOINS_SORTED:
        if s.endswith(q) and len(s) > len(q):
            return (s[:-len(q)], q)
    return (s, "")

def is_blocked_symbol(symbol: str) -> bool:
    s = _normalize_symbol(symbol)
    if s in _BLOCKED_SYMBOLS:
        return True
    if not _BLOCK_STABLECOIN_PAIRS:
        return False
    base, quote = _split_base_quote(s)
    if quote and base in _STABLECOINS:
        return True
    return False



# ------------------ Auto-trade exchange API helpers ------------------

class ExchangeAPIError(RuntimeError):
    """Raised when an exchange API call fails (network / auth / rate limit / etc.)."""


def _extract_signal_id(sig: object) -> int:
    """Extract a stable, non-null signal id from a signal object."""
    try:
        v = getattr(sig, "signal_id", None)
        if v is None:
            v = getattr(sig, "id", None)
        v = int(v)
        return v if v > 0 else 0
    except Exception:
        return 0


def _should_deactivate_key(err_text: str) -> bool:
    """Return True only for credential/permission/IP-whitelist failures."""
    t = (err_text or "").lower()
    needles = (
        "invalid api-key",
        "api-key invalid",
        "invalid api key",
        "invalid key",
        "invalid signature",
        "signature for this request is not valid",
        "signature mismatch",
        "permission denied",
        "not authorized",
        "no permission",
        "apikey permission",
        "trade permission",
        "ip",
        "whitelist",
    )
    return any(n in t for n in needles)


