def _be_with_fee_buffer(entry_price: float, *, direction: str) -> float:
    """Return BE price adjusted by fee buffer."""
    try:
        ep = float(entry_price or 0.0)
        if ep <= 0:
            return 0.0
        buf = max(0.0, float(_BE_FEE_BUFFER_PCT)) / 100.0
        d = (direction or "").upper().strip()
        if d == "SHORT":
            return ep * (1.0 - buf)
        return ep * (1.0 + buf)
    except Exception:
        return float(entry_price or 0.0)

def _smartcap_floor_step(x: float, step: float) -> float:
    try:
        x = float(x)
        step = float(step)
        if step <= 0:
            return max(0.0, x)
        return max(0.0, math.floor(x / step) * step)
    except Exception:
        return 0.0

def _smartcap_multiplier(winrate: float | None) -> float:
    try:
        if winrate is None:
            return 1.0
        wr = float(winrate)
    except Exception:
        return 1.0
    if wr < 40.0:
        return 0.6
    if wr < 50.0:
        return 0.8
    if wr < 60.0:
        return 1.0
    if wr < 70.0:
        return 1.1
    return 1.25

def _calc_effective_futures_cap(*, balance_usdt: float, ui_cap_usdt: float, winrate: float | None) -> float:
    """Compute effective futures cap (USDT margin limit) using balance + winrate.

    - base = balance * _SMARTCAP_BASE_PCT
    - multiply by winrate bucket
    - rounded DOWN to _SMARTCAP_STEP_USDT
    - capped by ui_cap (if >0)
    - hard-capped by balance * _SMARTCAP_HARD_MAX_PCT (rounded down)
    """
    bal = max(0.0, float(balance_usdt or 0.0))
    ui = max(0.0, float(ui_cap_usdt or 0.0))
    base = bal * _SMARTCAP_BASE_PCT
    eff = base * _smartcap_multiplier(winrate)
    eff = _smartcap_floor_step(eff, _SMARTCAP_STEP_USDT)
    hard = _smartcap_floor_step(bal * _SMARTCAP_HARD_MAX_PCT, _SMARTCAP_STEP_USDT)
    if hard > 0:
        eff = min(eff, hard)
    if ui > 0:
        eff = min(eff, ui)
    return float(max(0.0, eff))



_BINANCE_TIME_OFFSET_MS = 0
_BINANCE_TIME_SYNC_MONO = 0.0
_BINANCE_TIME_SYNC_LOCK = None
_BINANCE_SIGNED_REQ_LOCK = None
_BINANCE_SIGNED_NEXT_TS = 0.0
_BINANCE_SIGNED_RATE_LIMIT_UNTIL = 0.0


def _binance_recv_window_ms() -> int:
    try:
        v = int(float(os.getenv("BINANCE_RECV_WINDOW_MS", "10000") or 10000))
    except Exception:
        v = 10000
    return max(5000, min(v, 60000))


def _binance_time_sync_ttl_sec() -> float:
    try:
        v = float(os.getenv("BINANCE_TIME_SYNC_TTL_SEC", "60") or 60)
    except Exception:
        v = 60.0
    return max(5.0, min(v, 300.0))


def _binance_signed_min_interval_sec() -> float:
    try:
        v = float(os.getenv("BINANCE_SIGNED_MIN_INTERVAL_MS", "250") or 250)
    except Exception:
        v = 250.0
    return max(0.0, min(v, 5000.0)) / 1000.0


def _binance_rate_limit_cooldown_sec() -> float:
    try:
        v = float(os.getenv("BINANCE_RATE_LIMIT_COOLDOWN_SEC", "120") or 120)
    except Exception:
        v = 120.0
    return max(5.0, min(v, 900.0))


def _binance_request_timeout_sec() -> float:
    try:
        v = float(os.getenv("BINANCE_HTTP_TIMEOUT_SEC", "15") or 15)
    except Exception:
        v = 15.0
    return max(5.0, min(v, 60.0))


def _binance_request_max_attempts() -> int:
    try:
        v = int(float(os.getenv("BINANCE_SIGNED_MAX_ATTEMPTS", "3") or 3))
    except Exception:
        v = 3
    return max(2, min(v, 6))


def _binance_request_retry_sleep_sec(attempt: int) -> float:
    try:
        base = float(os.getenv("BINANCE_SIGNED_RETRY_BASE_SEC", "0.8") or 0.8)
    except Exception:
        base = 0.8
    try:
        cap = float(os.getenv("BINANCE_SIGNED_RETRY_MAX_SEC", "4") or 4)
    except Exception:
        cap = 4.0
    step = max(0, int(attempt or 0))
    delay = max(0.0, float(base)) * (2 ** step)
    return max(0.0, min(delay, max(0.5, float(cap))))


def _binance_is_transient_request_error(exc: Exception | BaseException | None) -> bool:
    if exc is None:
        return False
    if isinstance(exc, (asyncio.TimeoutError, TimeoutError, aiohttp.ClientError, OSError, ConnectionResetError)):
        return True
    return _binance_is_transient_error_message(exc)


def _binance_is_transient_error_message(err) -> bool:
    s = str(err or "")
    sl = s.lower()
    needles = (
        "timeout",
        "timed out",
        "serverdisconnectederror",
        "clientconnectorerror",
        "clientoserror",
        "connectionreseterror",
        "connection reset",
        "temporarily unavailable",
        "temporary failure",
        "cannot connect to host",
        "name or service not known",
        "network is unreachable",
    )
    return any(n in sl for n in needles)


def _binance_is_rate_limit_error_message(err) -> bool:
    s = str(err or "")
    sl = s.lower()
    return (
        ("http 418" in sl)
        or ("http 429" in sl)
        or ("-1003" in sl)
        or ("too many requests" in sl)
        or ("rate limit" in sl)
        or ("way too much request weight" in sl)
        or ("cooldown active" in sl)
    )


def _binance_is_timestamp_error_message(err) -> bool:
    s = str(err or "")
    sl = s.lower()
    return ("-1021" in sl) or (("timestamp" in sl) and ("recvwindow" in sl))


def _binance_normalize_recv_window(params: dict) -> None:
    want = _binance_recv_window_ms()
    try:
        cur = int(str(params.get("recvWindow") or "0"))
    except Exception:
        cur = 0
    if cur < want:
        params["recvWindow"] = str(want)


async def _binance_note_rate_limit(err) -> None:
    global _BINANCE_SIGNED_RATE_LIMIT_UNTIL
    if not _binance_is_rate_limit_error_message(err):
        return
    until = time.monotonic() + _binance_rate_limit_cooldown_sec()
    if until > float(_BINANCE_SIGNED_RATE_LIMIT_UNTIL or 0.0):
        _BINANCE_SIGNED_RATE_LIMIT_UNTIL = until


async def _binance_wait_request_slot() -> None:
    global _BINANCE_SIGNED_REQ_LOCK, _BINANCE_SIGNED_NEXT_TS
    if _BINANCE_SIGNED_REQ_LOCK is None:
        _BINANCE_SIGNED_REQ_LOCK = asyncio.Lock()

    while True:
        wait_sec = 0.0
        async with _BINANCE_SIGNED_REQ_LOCK:
            now = time.monotonic()
            cool_until = float(_BINANCE_SIGNED_RATE_LIMIT_UNTIL or 0.0)
            if cool_until > now:
                wait_sec = cool_until - now
            else:
                wait_sec = float(_BINANCE_SIGNED_NEXT_TS or 0.0) - now
                if wait_sec <= 0:
                    _BINANCE_SIGNED_NEXT_TS = time.monotonic() + _binance_signed_min_interval_sec()
                    return
        await asyncio.sleep(wait_sec)


async def _binance_sync_server_time(
    session: aiohttp.ClientSession,
    *,
    base_url: str,
    force: bool = False,
) -> None:
    global _BINANCE_TIME_OFFSET_MS, _BINANCE_TIME_SYNC_MONO, _BINANCE_TIME_SYNC_LOCK
    if _BINANCE_TIME_SYNC_LOCK is None:
        _BINANCE_TIME_SYNC_LOCK = asyncio.Lock()
    now_mono = time.monotonic()
    if (not force) and _BINANCE_TIME_SYNC_MONO and ((now_mono - float(_BINANCE_TIME_SYNC_MONO or 0.0)) <= _binance_time_sync_ttl_sec()):
        return
    async with _BINANCE_TIME_SYNC_LOCK:
        now_mono = time.monotonic()
        if (not force) and _BINANCE_TIME_SYNC_MONO and ((now_mono - float(_BINANCE_TIME_SYNC_MONO or 0.0)) <= _binance_time_sync_ttl_sec()):
            return
        time_path = "/fapi/v1/time" if "fapi" in str(base_url or "") else "/api/v3/time"
        try:
            async with session.get(f"{base_url}{time_path}") as r:
                data = await r.json(content_type=None)
                if r.status != 200:
                    err = ExchangeAPIError(f"Binance time sync HTTP {r.status}: {data}")
                    await _binance_note_rate_limit(err)
                    raise err
                server_ms = int((data or {}).get("serverTime") or 0)
                if server_ms <= 0:
                    raise ExchangeAPIError(f"Binance time sync invalid payload: {data}")
        except ExchangeAPIError:
            raise
        except Exception as e:
            raise ExchangeAPIError(f"Binance time sync error: {e}")
        local_ms = int(time.time() * 1000)
        _BINANCE_TIME_OFFSET_MS = int(server_ms - local_ms)
        _BINANCE_TIME_SYNC_MONO = time.monotonic()


async def _binance_signed_request(
    session: aiohttp.ClientSession,
    *,
    base_url: str,
    path: str,
    method: str,
    api_key: str,
    api_secret: str,
    params: dict | None = None,
) -> dict:
    """Binance signed request helper with time-sync, timestamp retry and transient network retry."""
    params = dict(params or {})
    _binance_normalize_recv_window(params)
    headers = {"X-MBX-APIKEY": api_key}
    max_attempts = _binance_request_max_attempts()
    transient_codes = {"-1001", "-1007"}
    transient_http_statuses = {408, 500, 502, 503, 504}

    for attempt in range(max_attempts):
        await _binance_wait_request_slot()
        try:
            await _binance_sync_server_time(session, base_url=base_url, force=(attempt > 0))
        except ExchangeAPIError as e:
            if _binance_is_rate_limit_error_message(e):
                raise
            # Non-fatal: if time sync endpoint hiccups, try the request with the last known offset.
            pass

        params["timestamp"] = str(int(time.time() * 1000 + int(_BINANCE_TIME_OFFSET_MS or 0)))
        query = urllib.parse.urlencode(params, doseq=True)
        sig = hmac.new(api_secret.encode("utf-8"), query.encode("utf-8"), hashlib.sha256).hexdigest()
        url = f"{base_url}{path}?{query}&signature={sig}"

        try:
            async with session.request(method.upper(), url, headers=headers) as r:
                data = await r.json(content_type=None)
        except ExchangeAPIError:
            raise
        except Exception as e:
            if _binance_is_transient_request_error(e) and (attempt + 1) < max_attempts:
                delay = _binance_request_retry_sleep_sec(attempt)
                _log_rate_limited(
                    f"binance_retry:{method.upper()}:{path}",
                    f"[binance] transient request error {type(e).__name__} on {method.upper()} {path}; retry {attempt + 1}/{max_attempts} in {delay:.1f}s",
                    every_s=30,
                    level="warning",
                )
                await asyncio.sleep(delay)
                continue
            raise ExchangeAPIError(f"Binance API error: {type(e).__name__}: {e}")

        if r.status != 200:
            err = ExchangeAPIError(f"Binance API HTTP {r.status}: {data}")
            await _binance_note_rate_limit(err)
            if (attempt == 0) and _binance_is_timestamp_error_message(err):
                await _binance_sync_server_time(session, base_url=base_url, force=True)
                continue
            if (r.status in transient_http_statuses) and (attempt + 1) < max_attempts:
                delay = _binance_request_retry_sleep_sec(attempt)
                _log_rate_limited(
                    f"binance_retry_http:{method.upper()}:{path}:{r.status}",
                    f"[binance] transient HTTP {r.status} on {method.upper()} {path}; retry {attempt + 1}/{max_attempts} in {delay:.1f}s",
                    every_s=30,
                    level="warning",
                )
                await asyncio.sleep(delay)
                continue
            raise err

        if isinstance(data, dict):
            raw_code = data.get("code")
            if raw_code not in (None, 0, "0"):
                err = ExchangeAPIError(f"Binance API code {raw_code}: {data.get('msg') or data}")
                await _binance_note_rate_limit(err)
                if (attempt == 0) and ((str(raw_code) == "-1021") or _binance_is_timestamp_error_message(err)):
                    await _binance_sync_server_time(session, base_url=base_url, force=True)
                    continue
                if (str(raw_code) in transient_codes) and (attempt + 1) < max_attempts:
                    delay = _binance_request_retry_sleep_sec(attempt)
                    _log_rate_limited(
                        f"binance_retry_code:{method.upper()}:{path}:{raw_code}",
                        f"[binance] transient API code {raw_code} on {method.upper()} {path}; retry {attempt + 1}/{max_attempts} in {delay:.1f}s",
                        every_s=30,
                        level="warning",
                    )
                    await asyncio.sleep(delay)
                    continue
                raise err

        return data if isinstance(data, dict) else {"data": data}

    raise ExchangeAPIError(f"Binance API request failed after retry: {path}")


async def _bybit_signed_request(
    session: aiohttp.ClientSession,
    *,
    base_url: str,
    path: str,
    method: str,
    api_key: str,
    api_secret: str,
    params: dict | None = None,
) -> dict:
    """Bybit V5 signing helper (HMAC SHA256). We use GET for validation."""
    params = dict(params or {})
    ts = str(int(dt.datetime.now(dt.timezone.utc).timestamp() * 1000))
    recv = "5000"
    query = urllib.parse.urlencode(params, doseq=True)
    pre = ts + api_key + recv + query
    sig = hmac.new(api_secret.encode("utf-8"), pre.encode("utf-8"), hashlib.sha256).hexdigest()
    headers = {
        "X-BAPI-API-KEY": api_key,
        "X-BAPI-SIGN": sig,
        "X-BAPI-TIMESTAMP": ts,
        "X-BAPI-RECV-WINDOW": recv,
    }
    url = f"{base_url}{path}"
    if query:
        url += f"?{query}"
    try:
        async with session.request(method.upper(), url, headers=headers) as r:
            data = await r.json(content_type=None)
            if r.status != 200:
                raise ExchangeAPIError(f"Bybit API HTTP {r.status}: {data}")
            if isinstance(data, dict) and int(data.get("retCode", 0) or 0) != 0:
                raise ExchangeAPIError(f"Bybit API retCode {data.get('retCode')}: {data.get('retMsg')}")
            return data if isinstance(data, dict) else {"data": data}
    except ExchangeAPIError:
        raise
    except Exception as e:
        raise ExchangeAPIError(f"Bybit API error: {e}")


async def _bybit_v5_request(
    session: aiohttp.ClientSession,
    *,
    method: str,
    path: str,
    api_key: str,
    api_secret: str,
    params: dict | None = None,
    json_body: dict | None = None,
    base_url: str = "https://api.bybit.com",
) -> dict:
    """Bybit V5 request helper for GET/POST with proper signing.

    Signature: HMAC_SHA256(secret, timestamp + apiKey + recvWindow + payload)
      - payload is queryString for GET
      - payload is JSON string for POST
    """
    params = dict(params or {})
    ts = str(int(dt.datetime.now(dt.timezone.utc).timestamp() * 1000))
    recv = "5000"
    method_u = method.upper()
    query = urllib.parse.urlencode(params, doseq=True)
    body_str = ""
    if json_body is not None:
        body_str = json.dumps(json_body, separators=(",", ":"), ensure_ascii=False)
    payload = query if method_u == "GET" else body_str
    pre = ts + api_key + recv + payload
    sig = hmac.new(api_secret.encode("utf-8"), pre.encode("utf-8"), hashlib.sha256).hexdigest()
    headers = {
        "X-BAPI-API-KEY": api_key,
        "X-BAPI-SIGN": sig,
        "X-BAPI-TIMESTAMP": ts,
        "X-BAPI-RECV-WINDOW": recv,
        "Content-Type": "application/json",
    }
    url = f"{base_url}{path}"
    if query and method_u == "GET":
        url += f"?{query}"
    try:
        async with session.request(method_u, url, headers=headers, data=(body_str if method_u != "GET" else None)) as r:
            data = await r.json(content_type=None)
            if r.status != 200:
                raise ExchangeAPIError(f"Bybit API HTTP {r.status}: {data}")
            if isinstance(data, dict) and int(data.get("retCode", 0) or 0) != 0:
                raise ExchangeAPIError(f"Bybit API retCode {data.get('retCode')}: {data.get('retMsg')}")
            return data if isinstance(data, dict) else {"data": data}
    except ExchangeAPIError:
        raise
    except Exception as e:
        raise ExchangeAPIError(f"Bybit API error: {e}")



# ------------------ OKX / MEXC / Gate.io signed request helpers (SPOT auto-trade) ------------------

def _okx_inst(symbol: str) -> str:
    # OKX uses BASE-QUOTE
    s = symbol.upper()
    if s.endswith("USDT"):
        return f"{s[:-4]}-USDT"
    return s

def _okx_swap_inst(symbol: str) -> str:
    inst = _okx_inst(symbol)
    return inst if inst.endswith("-SWAP") else (inst + "-SWAP")

def _gate_pair(symbol: str) -> str:
    s = symbol.upper()
    if s.endswith("USDT"):
        return f"{s[:-4]}_USDT"
    return s

async def _okx_signed_request(
    session: aiohttp.ClientSession,
    *,
    base_url: str,
    path: str,
    method: str,
    api_key: str,
    api_secret: str,
    passphrase: str,
    params: dict | None = None,
    json_body: dict | None = None,
) -> dict:
    ts = dt.datetime.now(dt.timezone.utc).isoformat(timespec="milliseconds").replace("+00:00", "Z")
    method_u = method.upper()
    query = ""
    if params:
        query = urllib.parse.urlencode(params, doseq=True)
    body_str = ""
    if json_body is not None:
        body_str = json.dumps(json_body, separators=(",", ":"), ensure_ascii=False)
    req_path = path + (("?" + query) if (query and method_u == "GET") else "")
    prehash = ts + method_u + req_path + (body_str if method_u != "GET" else "")
    digest = hmac.new(api_secret.encode("utf-8"), prehash.encode("utf-8"), hashlib.sha256).digest()
    sign = base64.b64encode(digest).decode("utf-8")
    headers = {
        "OK-ACCESS-KEY": api_key,
        "OK-ACCESS-SIGN": sign,
        "OK-ACCESS-TIMESTAMP": ts,
        "OK-ACCESS-PASSPHRASE": passphrase,
        "Content-Type": "application/json",
    }
    url = base_url + req_path if method_u == "GET" else (base_url + path + (("?" + query) if query else ""))
    async with session.request(method_u, url, headers=headers, data=(body_str if method_u != "GET" else None)) as r:
        data = await r.json(content_type=None)
        if r.status != 200:
            raise ExchangeAPIError(f"OKX API HTTP {r.status}: {data}")
        # OKX returns {"code":"0",...} on success
        if isinstance(data, dict) and str(data.get("code")) not in ("0", "200", "OK", ""):
            raise ExchangeAPIError(f"OKX API code {data.get('code')}: {data.get('msg')}")
        return data if isinstance(data, dict) else {"data": data}

async def _mexc_signed_request(
    session: aiohttp.ClientSession,
    *,
    base_url: str,
    path: str,
    method: str,
    api_key: str,
    api_secret: str,
    params: dict | None = None,
) -> dict:
    """Signed MEXC Spot request.

    MEXC accepts signed POST/PUT/DELETE params either in the query string
    (with form content type) or in the request body. The current API examples
    use form-encoded bodies for POST order placement, and MEXC validates the
    request content type for these methods.
    """
    params = dict(params or {})
    params.setdefault("timestamp", str(int(dt.datetime.now(dt.timezone.utc).timestamp() * 1000)))
    params.setdefault("recvWindow", "5000")

    method_u = str(method or "GET").upper()
    payload = urllib.parse.urlencode(params, doseq=True)
    sig = hmac.new(api_secret.encode("utf-8"), payload.encode("utf-8"), hashlib.sha256).hexdigest()

    url = f"{base_url}{path}"
    headers = {"X-MEXC-APIKEY": api_key}
    req_kwargs: dict = {}

    if method_u == "GET":
        url = f"{url}?{payload}&signature={sig}"
    else:
        body = f"{payload}&signature={sig}"
        headers["Content-Type"] = "application/x-www-form-urlencoded"
        req_kwargs["data"] = body

    async with session.request(method_u, url, headers=headers, **req_kwargs) as r:
        try:
            data = await r.json(content_type=None)
        except Exception:
            data = await r.text()
        if r.status != 200:
            raise ExchangeAPIError(f"MEXC API HTTP {r.status}: {data}")
        return data if isinstance(data, dict) else {"data": data}

async def _gateio_signed_request(
    session: aiohttp.ClientSession,
    *,
    base_url: str,
    path: str,
    method: str,
    api_key: str,
    api_secret: str,
    params: dict | None = None,
    json_body: dict | None = None,
) -> dict:
    # Gate.io v4 signing: https://www.gate.io/docs/developers/apiv4/en/#authentication
    method_u = method.upper()
    query = urllib.parse.urlencode(params or {}, doseq=True)
    body_str = ""
    if json_body is not None:
        body_str = json.dumps(json_body, separators=(",", ":"), ensure_ascii=False)
    ts = str(int(dt.datetime.now(dt.timezone.utc).timestamp()))
    hashed_payload = hashlib.sha512(body_str.encode("utf-8")).hexdigest()
    sign_str = "\n".join([method_u, path, query, hashed_payload, ts])
    sig = hmac.new(api_secret.encode("utf-8"), sign_str.encode("utf-8"), hashlib.sha512).hexdigest()
    headers = {"KEY": api_key, "SIGN": sig, "Timestamp": ts, "Content-Type": "application/json"}
    url = f"{base_url}{path}"
    if query:
        url += "?" + query
    async with session.request(method_u, url, headers=headers, data=(body_str if json_body is not None else None)) as r:
        data = await r.json(content_type=None)
        if r.status >= 300:
            raise ExchangeAPIError(f"Gate.io API HTTP {r.status}: {data}")
        return data if isinstance(data, dict) else {"data": data}

