async def _okx_available_usdt(api_key: str, api_secret: str, passphrase: str, *, market_type: str = "spot") -> float:
    timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=timeout) as s:
        data = await _okx_signed_request(
            s,
            base_url="https://www.okx.com",
            path="/api/v5/account/balance",
            method="GET",
            api_key=api_key,
            api_secret=api_secret,
            passphrase=passphrase,
            params={"ccy": "USDT"},
        )
        dl = (data.get("data") or [])
        if not (isinstance(dl, list) and dl):
            return 0.0
        d0 = dl[0] if isinstance(dl[0], dict) else {}
        details = (d0.get("details") or [])
        coin = details[0] if isinstance(details, list) and details and isinstance(details[0], dict) else {}
        keys = ("availBal", "availEq", "eqUsd", "eq", "cashBal") if str(market_type or "spot").lower() == "futures" else ("availBal", "cashBal", "availEq", "eq", "eqUsd")
        for src in (coin, d0):
            if not isinstance(src, dict):
                continue
            for k in keys:
                v = src.get(k)
                if v not in (None, ""):
                    try:
                        return float(v or 0.0)
                    except Exception:
                        pass
        return 0.0

def _mexc_contract_symbol(symbol: str) -> str:
    s = (symbol or "").upper().strip()
    # MEXC contracts usually use BASE_USDT format
    if s.endswith("USDT") and "_" not in s:
        return f"{s[:-4]}_USDT"
    return s.replace("-", "_")

async def _mexc_futures_price(symbol: str) -> float:
    # MEXC Contract (Perpetual) public ticker
    # Endpoint is best-effort and parsed defensively.
    sym = _mexc_contract_symbol(symbol)
    data = await _http_json("GET", "https://contract.mexc.com/api/v1/contract/ticker", params={"symbol": sym}, timeout_s=8)
    # Typical shapes:
    # { "success": true, "code": 0, "data": { "lastPrice": "..." } }
    # or { "data": { "last_price": "..." } } or list variants.
    d = data.get("data") if isinstance(data, dict) else None
    if isinstance(d, dict):
        for k in ("lastPrice", "last_price", "last", "last_price24h", "lastPrice24h"):
            if k in d and d.get(k) is not None:
                return float(d.get(k) or 0.0)
    if isinstance(d, list) and d and isinstance(d[0], dict):
        for k in ("lastPrice", "last_price", "last"):
            if d[0].get(k) is not None:
                return float(d[0].get(k) or 0.0)
    # Fallback: some responses may put it at top-level
    if isinstance(data, dict):
        for k in ("lastPrice", "last_price", "last"):
            if data.get(k) is not None:
                return float(data.get(k) or 0.0)
    return 0.0

def _gateio_futures_contract(symbol: str) -> str:
    s = (symbol or "").upper().strip()
    # Gate futures USDT contracts use BASE_USDT
    if s.endswith("USDT") and "_" not in s:
        return f"{s[:-4]}_USDT"
    return s.replace("-", "_")

async def _gateio_futures_price(symbol: str) -> float:
    contract = _gateio_futures_contract(symbol)
    data = await _http_json("GET", "https://api.gateio.ws/api/v4/futures/usdt/tickers", params={"contract": contract}, timeout_s=8)
    # Response is list[dict] usually
    if isinstance(data, list) and data and isinstance(data[0], dict):
        for k in ("last", "last_price", "mark_price", "mark"):
            if data[0].get(k) is not None:
                return float(data[0].get(k) or 0.0)
    # Sometimes dict wrapper
    if isinstance(data, dict):
        d = data.get("data")
        if isinstance(d, list) and d and isinstance(d[0], dict):
            if d[0].get("last") is not None:
                return float(d[0].get("last") or 0.0)
    return 0.0

async def validate_autotrade_keys(
    *,
    exchange: str,
    market_type: str,
    api_key: str,
    api_secret: str,
    passphrase: str | None = None,
) -> dict:
    """Validate keys for READ + TRADE permissions (best-effort, no real orders).

    Returns:
      {"ok": bool, "read_ok": bool, "trade_ok": bool, "error": str|None}
    """
    ex = (exchange or "binance").lower().strip()
    mt = (market_type or "spot").lower().strip()
    if ex not in ("binance", "bybit", "okx", "mexc", "gateio"):
        return {"ok": False, "read_ok": False, "trade_ok": False, "error": "unsupported_exchange"}
    if mt not in ("spot", "futures"):
        mt = "spot"

    # Gate.io and MEXC are supported only for SPOT auto-trade in this codebase.
    # Avoid any futures/contract validation calls for them.
    if mt == "futures" and ex in ("mexc", "gateio"):
        return {"ok": False, "read_ok": False, "trade_ok": False, "error": "unsupported_market_for_exchange"}

    api_key = (api_key or "").strip()
    api_secret = (api_secret or "").strip()
    if not api_key or not api_secret:
        return {"ok": False, "read_ok": False, "trade_ok": False, "error": "missing_keys"}

    try:
        timeout = aiohttp.ClientTimeout(total=8)
        async with aiohttp.ClientSession(timeout=timeout) as s:
            # ---------------- Binance ----------------
            if ex == "binance":
                if mt == "spot":
                    acc = await _binance_signed_request(
                        s,
                        base_url="https://api.binance.com",
                        path="/api/v3/account",
                        method="GET",
                        api_key=api_key,
                        api_secret=api_secret,
                        params={"recvWindow": "5000"},
                    )
                    perms = acc.get("permissions")
                    perms_set: set[str] = set()
                    if isinstance(perms, (list, tuple)):
                        perms_set = {str(x).upper() for x in perms}
                    elif isinstance(perms, str):
                        perms_set = {p.strip().upper() for p in perms.split(",") if p.strip()}

                    if perms_set:
                        trade_ok = ("SPOT" in perms_set) or ("MARGIN" in perms_set) or ("TRADE" in perms_set)
                    else:
                        can_trade = acc.get("canTrade")
                        trade_ok = True if (can_trade is None) else bool(can_trade)

                    if not trade_ok:
                        return {"ok": True, "read_ok": True, "trade_ok": False, "error": "trade_permission_missing"}
                    return {"ok": True, "read_ok": True, "trade_ok": True, "error": None}

                # futures
                acc = await _binance_signed_request(
                    s,
                    base_url="https://fapi.binance.com",
                    path="/fapi/v2/account",
                    method="GET",
                    api_key=api_key,
                    api_secret=api_secret,
                    params={"recvWindow": "5000"},
                )
                can_trade = acc.get("canTrade")
                if can_trade is not None and not bool(can_trade):
                    return {"ok": True, "read_ok": True, "trade_ok": False, "error": "trade_permission_missing"}
                return {"ok": True, "read_ok": True, "trade_ok": True, "error": None}

            # ---------------- Bybit ----------------
            if ex == "bybit":
                data = await _bybit_signed_request(
                    s,
                    base_url="https://api.bybit.com",
                    path="/v5/user/query-api",
                    method="GET",
                    api_key=api_key,
                    api_secret=api_secret,
                    params={},
                )
                res = data.get("result") or {}
                if isinstance(res, dict):
                    ro = res.get("readOnly")
                    if ro is not None and int(ro) == 1:
                        return {"ok": True, "read_ok": True, "trade_ok": False, "error": "trade_permission_missing"}
                    perm = res.get("permissions") or res.get("permission")
                    if isinstance(perm, dict):
                        trade_flag = perm.get("Trade") or perm.get("trade") or perm.get("SpotTrade") or perm.get("ContractTrade")
                        if trade_flag is not None and not bool(trade_flag):
                            return {"ok": True, "read_ok": True, "trade_ok": False, "error": "trade_permission_missing"}
                return {"ok": True, "read_ok": True, "trade_ok": True, "error": None}

            # ---------------- OKX ----------------
            if ex == "okx":
                if not passphrase:
                    return {"ok": False, "read_ok": False, "trade_ok": False, "error": "missing_passphrase"}
                await _okx_signed_request(
                    s,
                    base_url="https://www.okx.com",
                    path="/api/v5/account/balance",
                    method="GET",
                    api_key=api_key,
                    api_secret=api_secret,
                    passphrase=passphrase,
                    params={"ccy": "USDT"},
                )
                return {"ok": True, "read_ok": True, "trade_ok": True, "error": None}

            # ---------------- MEXC ----------------
            if ex == "mexc":
                await _mexc_signed_request(
                    s,
                    base_url="https://api.mexc.com",
                    path="/api/v3/account",
                    method="GET",
                    api_key=api_key,
                    api_secret=api_secret,
                    params={},
                )
                return {"ok": True, "read_ok": True, "trade_ok": True, "error": None}

            # ---------------- Gate.io ----------------
            if ex == "gateio":
                await _gateio_signed_request(
                    s,
                    base_url="https://api.gateio.ws",
                    path="/api/v4/spot/accounts",
                    method="GET",
                    api_key=api_key,
                    api_secret=api_secret,
                    params={},
                )
                return {"ok": True, "read_ok": True, "trade_ok": True, "error": None}

        return {"ok": False, "read_ok": False, "trade_ok": False, "error": "unsupported_exchange"}

    except ExchangeAPIError as e:
        return {"ok": False, "read_ok": False, "trade_ok": False, "error": str(e)}


def _autotrade_fernet() -> Fernet:
    try:
        k = get_autotrade_master_key()
    except Exception as e:
        raise RuntimeError(f"AUTOTRADE_MASTER_KEY invalid: {e}") from e
    return Fernet(k.encode("utf-8"))


def _decrypt_token(token: str | None) -> str:
    if not token:
        return ""
    f = _autotrade_fernet()
    return f.decrypt(token.encode("utf-8")).decode("utf-8")


async def _http_json(method: str, url: str, *, params: dict | None = None, json_body: dict | None = None, headers: dict | None = None, timeout_s: int = 10) -> dict:
    timeout = aiohttp.ClientTimeout(total=timeout_s)
    async with aiohttp.ClientSession(timeout=timeout) as s:
        async with s.request(method.upper(), url, params=params, json=json_body, headers=headers) as r:
            data = await r.json(content_type=None)
            if r.status != 200:
                raise ExchangeAPIError(f"HTTP {r.status} {url}: {data}")
            return data if isinstance(data, dict) else {"data": data}


def _decimal_value(value: float | int | str | Decimal, default: str = "0") -> Decimal:
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError):
        return Decimal(default)


def _decimal_step(step: float | int | str | Decimal) -> Decimal | None:
    d = _decimal_value(step)
    if d <= 0:
        return None
    return d.copy_abs()


def _decimal_to_api_str(value: float | int | str | Decimal) -> str:
    d = _decimal_value(value)
    s = format(d, "f")
    if "." in s:
        s = s.rstrip("0").rstrip(".")
    return s or "0"


def _round_down_decimal(value: float | int | str | Decimal, step: float | int | str | Decimal) -> Decimal:
    d_val = _decimal_value(value)
    d_step = _decimal_step(step)
    if d_step is None:
        return d_val
    if d_val <= 0:
        return Decimal("0")
    units = (d_val / d_step).to_integral_value(rounding=ROUND_DOWN)
    return (units * d_step).quantize(d_step, rounding=ROUND_DOWN)


def _round_step(qty: float, step: float) -> float:
    """Round quantity down to the nearest step using decimal-safe arithmetic."""
    return float(_round_down_decimal(qty, step))


def _round_tick(price: float, tick: float) -> float:
    """Round price down to the nearest tick using decimal-safe arithmetic."""
    return float(_round_down_decimal(price, tick))


_BINANCE_INFO_CACHE: dict[str, dict] = {}


async def _binance_exchange_info(*, futures: bool) -> dict:
    key = "futures" if futures else "spot"
    if key in _BINANCE_INFO_CACHE and _BINANCE_INFO_CACHE[key].get("_ts", 0) > time.time() - 3600:
        return _BINANCE_INFO_CACHE[key]
    url = "https://fapi.binance.com/fapi/v1/exchangeInfo" if futures else "https://api.binance.com/api/v3/exchangeInfo"
    data = await _http_json("GET", url, timeout_s=10)
    data["_ts"] = time.time()
    _BINANCE_INFO_CACHE[key] = data
    return data


def _binance_symbol_filters(info: dict, symbol: str) -> tuple[float, float, float, float]:
    """Return (qty_step, min_qty, tick_size, min_notional) for symbol. Best-effort."""
    sym = symbol.upper()
    for s in info.get("symbols", []) or []:
        if str(s.get("symbol")).upper() == sym:
            step = 0.0
            min_qty = 0.0
            tick = 0.0
            min_notional = 0.0
            for f in s.get("filters", []) or []:
                if f.get("filterType") == "LOT_SIZE":
                    step = float(f.get("stepSize") or 0.0)
                    min_qty = float(f.get("minQty") or 0.0)
                elif f.get("filterType") == "PRICE_FILTER":
                    tick = float(f.get("tickSize") or 0.0)
                elif f.get("filterType") in ("MIN_NOTIONAL", "NOTIONAL"):
                    # spot often uses MIN_NOTIONAL; some endpoints expose NOTIONAL
                    mn = f.get("minNotional")
                    if mn is None:
                        mn = f.get("notional")
                    try:
                        min_notional = float(mn or 0.0)
                    except Exception:
                        pass
            return step, min_qty, tick, min_notional
    return 0.0, 0.0, 0.0, 0.0


async def _binance_price(symbol: str, *, futures: bool) -> float:
    sym = symbol.upper()
    url = "https://fapi.binance.com/fapi/v1/ticker/price" if futures else "https://api.binance.com/api/v3/ticker/price"
    data = await _http_json("GET", url, params={"symbol": sym}, timeout_s=8)
    return float(data.get("price") or 0.0)



# ------------------ Generic order sizing helpers ------------------

_RL_LOG_TS: dict[str, float] = {}

def _log_rate_limited(key: str, message: str, *, every_s: int = 60, level: str = "info") -> None:
    """Log at most once per `every_s` seconds per key."""
    try:
        now = time.time()
        last = _RL_LOG_TS.get(key, 0.0)
        if now - last < float(every_s):
            return
        _RL_LOG_TS[key] = now
        if level == "debug":
            logger.debug(message)
        elif level == "warning":
            logger.warning(message)
        elif level == "error":
            logger.error(message)
        else:
            logger.info(message)
    except Exception:
        # Logging must never break trading loop
        pass


_OKX_FILTER_CACHE: dict[str, dict] = {}
async def _okx_instrument_filters(*, inst_type: str, symbol: str) -> tuple[float, float, float]:
    """Return (qty_step, min_qty, tick) for OKX instruments (best-effort)."""
    key = f"{inst_type}:{symbol.upper()}"
    cached = _OKX_FILTER_CACHE.get(key)
    if cached and cached.get("_ts", 0) > time.time() - 3600:
        return float(cached.get("qty_step") or 0.0), float(cached.get("min_qty") or 0.0), float(cached.get("tick") or 0.0)

    inst = _okx_swap_inst(symbol) if str(inst_type or "SPOT").upper() == "SWAP" else _okx_inst(symbol)
    url = "https://www.okx.com/api/v5/public/instruments"
    data = await _http_json("GET", url, params={"instType": inst_type, "instId": inst}, timeout_s=10)
    lst = ((data.get("data") or []) if isinstance(data, dict) else [])
    qty_step = 0.0
    min_qty = 0.0
    tick = 0.0
    if lst and isinstance(lst, list) and isinstance(lst[0], dict):
        it = lst[0]
        # OKX uses lotSz / minSz / tickSz strings
        try:
            qty_step = float(it.get("lotSz") or 0.0)
        except Exception:
            qty_step = 0.0
        try:
            min_qty = float(it.get("minSz") or 0.0)
        except Exception:
            min_qty = 0.0
        try:
            tick = float(it.get("tickSz") or 0.0)
        except Exception:
            tick = 0.0

    _OKX_FILTER_CACHE[key] = {"_ts": time.time(), "qty_step": qty_step, "min_qty": min_qty, "tick": tick}
    return qty_step, min_qty, tick


_MEXC_FILTER_CACHE: dict[str, dict] = {}
async def _mexc_symbol_filters(symbol: str) -> tuple[float, float, float, float]:
    """Return (qty_step, min_qty, tick_size, min_notional) for MEXC spot symbol (best-effort)."""
    sym = symbol.upper()
    cached = _MEXC_FILTER_CACHE.get(sym)
    if cached and cached.get("_ts", 0) > time.time() - 3600:
        return float(cached.get("qty_step") or 0.0), float(cached.get("min_qty") or 0.0), float(cached.get("tick") or 0.0), float(cached.get("min_notional") or 0.0)

    url = "https://api.mexc.com/api/v3/exchangeInfo"
    data = await _http_json("GET", url, params={"symbol": sym}, timeout_s=10)
    step = 0.0
    min_qty = 0.0
    tick = 0.0
    min_notional = 0.0
    for s in data.get("symbols", []) or []:
        if str(s.get("symbol") or "").upper() != sym:
            continue
        for f in s.get("filters", []) or []:
            ft = f.get("filterType")
            if ft == "LOT_SIZE":
                try:
                    step = float(f.get("stepSize") or 0.0)
                except Exception:
                    step = 0.0
                try:
                    min_qty = float(f.get("minQty") or 0.0)
                except Exception:
                    min_qty = 0.0
            elif ft == "PRICE_FILTER":
                try:
                    tick = float(f.get("tickSize") or 0.0)
                except Exception:
                    tick = 0.0
            elif ft in ("MIN_NOTIONAL", "NOTIONAL"):
                mn = f.get("minNotional")
                if mn is None:
                    mn = f.get("notional")
                try:
                    min_notional = float(mn or 0.0)
                except Exception:
                    min_notional = 0.0
        break

    _MEXC_FILTER_CACHE[sym] = {"_ts": time.time(), "qty_step": step, "min_qty": min_qty, "tick": tick, "min_notional": min_notional}
    return step, min_qty, tick, min_notional


_GATE_FILTER_CACHE: dict[str, dict] = {}
async def _gate_symbol_filters(symbol: str) -> tuple[float, float, float, float]:
    """Return (qty_step, min_qty, tick, min_notional) for Gate.io spot symbol (best-effort)."""
    pair = _gate_pair(symbol)
    cached = _GATE_FILTER_CACHE.get(pair)
    if cached and cached.get("_ts", 0) > time.time() - 3600:
        return float(cached.get("qty_step") or 0.0), float(cached.get("min_qty") or 0.0), float(cached.get("tick") or 0.0), float(cached.get("min_notional") or 0.0)

    url = "https://api.gateio.ws/api/v4/spot/currency_pairs"
    data = await _http_json("GET", url, params={"currency_pair": pair}, timeout_s=10)
    # Gate returns either a dict (single) or list
    it = None
    if isinstance(data, dict):
        it = data
    elif isinstance(data, list) and data and isinstance(data[0], dict):
        it = data[0]

    qty_step = 0.0
    min_qty = 0.0
    tick = 0.0
    min_notional = 0.0
    if isinstance(it, dict):
        # amount_precision defines qty step = 10^-precision
        try:
            prec = int(it.get("amount_precision") or 0)
            if prec > 0:
                qty_step = 10 ** (-prec)
        except Exception:
            qty_step = 0.0
        try:
            min_qty = float(it.get("min_base_amount") or 0.0)
        except Exception:
            min_qty = 0.0
        try:
            min_notional = float(it.get("min_quote_amount") or 0.0)
        except Exception:
            min_notional = 0.0
        try:
            # tick size isn't always provided; leave 0 if absent
            tick = float(it.get("price_precision") or 0.0)
        except Exception:
            tick = 0.0

    _GATE_FILTER_CACHE[pair] = {"_ts": time.time(), "qty_step": qty_step, "min_qty": min_qty, "tick": tick, "min_notional": min_notional}
    return qty_step, min_qty, tick, min_notional


async def _normalize_close_qty(*, ex: str, mt: str, symbol: str, qty: float, px: float, is_reduce_close: bool = False) -> float:
    """Best-effort close qty normalization.

    For real reduce-only / position-closing orders we only round by exchange step and do
    not reject due to min_qty / min_notional floors. Otherwise tiny live futures positions
    can stay open on the exchange while the bot marks them closed locally.
    """
    q = max(0.0, float(qty))
    if q <= 0 or float(px or 0.0) <= 0:
        return 0.0

    min_usdt_floor = 15.0 if mt == "spot" else 10.0
    qty_step = 0.0
    min_qty = 0.0
    min_notional_ex = 0.0

    try:
        if ex == "binance":
            info = await _binance_exchange_info(futures=(mt == "futures"))
            qty_step, min_qty, _tick, mn = _binance_symbol_filters(info, symbol)
            min_notional_ex = float(mn or 0.0)
        elif ex == "bybit":
            qty_step, min_qty, _tick = await _bybit_instrument_filters(category=("linear" if mt == "futures" else "spot"), symbol=symbol)
        elif ex == "okx":
            # OKX uses instrument metadata; most bots here use spot only
            qty_step, min_qty, _tick = await _okx_instrument_filters(inst_type=("SWAP" if mt == "futures" else "SPOT"), symbol=symbol)
        elif ex == "mexc":
            qty_step, min_qty, _tick, mn = await _mexc_symbol_filters(symbol)
            min_notional_ex = float(mn or 0.0)
        else:
            qty_step, min_qty, _tick, mn = await _gate_symbol_filters(symbol)
            min_notional_ex = float(mn or 0.0)
    except Exception as e:
        _log_rate_limited(f"norm_filters:{ex}:{mt}:{symbol}", f"[SMART] filters fetch failed {ex}/{mt} {symbol}: {e}", every_s=300, level="debug")

    if qty_step and qty_step > 0:
        q = _round_step(q, qty_step)

    if is_reduce_close:
        return float(max(0.0, q))

    if min_qty and min_qty > 0 and q < min_qty:
        return 0.0

    min_notional = max(float(min_usdt_floor), float(min_notional_ex or 0.0))
    if min_notional > 0 and (q * float(px)) < min_notional:
        return 0.0

    return float(q)


# ------------------ Bybit trading helpers (V5, unified API) ------------------

async def _bybit_price(symbol: str, *, category: str) -> float:
    sym = str(symbol or "").upper().replace("/", "").replace("-", "").replace(":", "").strip()
    cat = str(category or "spot").lower().strip() or "spot"
    if not sym:
        return 0.0

    def _extract_price(data) -> float:
        if not isinstance(data, dict):
            return 0.0
        try:
            ret_code = int(data.get("retCode", 0) or 0)
        except Exception:
            ret_code = 0
        if ret_code != 0:
            return 0.0
        lst = (data.get("result") or {}).get("list") or []
        if lst and isinstance(lst, list) and isinstance(lst[0], dict):
            item = lst[0]
            for key in ("lastPrice", "last_price", "indexPrice", "markPrice"):
                try:
                    px = float(item.get(key) or 0.0)
                    if px > 0:
                        return px
                except Exception:
                    continue
            try:
                bid = float(item.get("bid1Price") or 0.0)
                ask = float(item.get("ask1Price") or 0.0)
                if bid > 0 and ask > 0:
                    return (bid + ask) / 2.0
                if bid > 0:
                    return bid
                if ask > 0:
                    return ask
            except Exception:
                pass
        return 0.0

    for attempt in range(3):
        try:
            data = await _http_json(
                "GET",
                "https://api.bybit.com/v5/market/tickers",
                params={"category": cat, "symbol": sym},
                timeout_s=10,
            )
            px = _extract_price(data)
            if px > 0:
                return float(px)
        except Exception:
            pass
        if attempt < 2:
            await asyncio.sleep(0.25 * (attempt + 1))
    return 0.0


_BYBIT_INFO_CACHE: dict[str, dict] = {}


async def _bybit_instrument_filters(*, category: str, symbol: str) -> tuple[float, float, float]:
    """Return (qty_step, min_qty, tick_size) for a Bybit V5 instrument."""
    key = f"{category}:{symbol.upper()}"
    cached = _BYBIT_INFO_CACHE.get(key)
    if cached and cached.get("_ts", 0) > time.time() - 3600:
        return float(cached.get("qty_step") or 0.0), float(cached.get("min_qty") or 0.0), float(cached.get("tick") or 0.0)

    data = await _http_json(
        "GET",
        "https://api.bybit.com/v5/market/instruments-info",
        params={"category": category, "symbol": symbol.upper()},
        timeout_s=10,
    )
    lst = ((data.get("result") or {}).get("list") or [])
    qty_step = 0.0
    min_qty = 0.0
    tick = 0.0
    if lst and isinstance(lst, list) and isinstance(lst[0], dict):
        it = lst[0]
        lot = it.get("lotSizeFilter") or {}
        pf = it.get("priceFilter") or {}
        try:
            if str(category or "").lower() == "spot":
                # Bybit spot instruments do not expose lotSizeFilter.qtyStep.
                # The quantity increment is provided via basePrecision.
                qty_step = float(lot.get("basePrecision") or 0.0)
            else:
                qty_step = float(lot.get("qtyStep") or 0.0)
        except Exception:
            qty_step = 0.0
        try:
            min_qty = float(lot.get("minOrderQty") or 0.0)
        except Exception:
            min_qty = 0.0
        try:
            tick = float(pf.get("tickSize") or 0.0)
        except Exception:
            tick = 0.0

    _BYBIT_INFO_CACHE[key] = {"_ts": time.time(), "qty_step": qty_step, "min_qty": min_qty, "tick": tick}
    return qty_step, min_qty, tick


async def _bybit_available_usdt(api_key: str, api_secret: str, *, market_type: str = "spot") -> float:
    timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=timeout) as s:
        data = await _bybit_v5_request(
            s,
            method="GET",
            path="/v5/account/wallet-balance",
            api_key=api_key,
            api_secret=api_secret,
            params={"accountType": "UNIFIED", "coin": "USDT"},
        )
        res = (data.get("result") or {})
        lst = res.get("list") or []
        if not lst:
            return 0.0

        row = lst[0] if isinstance(lst[0], dict) else {}
        coin = None
        cl = row.get("coin") if isinstance(row, dict) else None
        if isinstance(cl, list) and cl:
            for item in cl:
                if isinstance(item, dict) and str(item.get("coin") or "USDT").upper() == "USDT":
                    coin = item
                    break
            if coin is None and isinstance(cl[0], dict):
                coin = cl[0]

        def _first_positive(*values) -> float:
            for v in values:
                if v in (None, ""):
                    continue
                try:
                    f = float(v or 0.0)
                except Exception:
                    continue
                if f > 0:
                    return f
            return 0.0

        if str(market_type or "spot").lower() == "futures":
            if isinstance(row, dict):
                v = _first_positive(
                    row.get("totalAvailableBalance"),
                    row.get("totalWalletBalance"),
                    row.get("totalMarginBalance"),
                )
                if v > 0:
                    return v
            if isinstance(coin, dict):
                v = _first_positive(
                    coin.get("availableToWithdraw"),
                    coin.get("transferBalance"),
                    coin.get("walletBalance"),
                    coin.get("equity"),
                )
                if v > 0:
                    return v
            return 0.0

        if isinstance(coin, dict):
            v = _first_positive(
                coin.get("walletBalance"),
                coin.get("equity"),
                coin.get("availableToWithdraw"),
                coin.get("transferBalance"),
            )
            if v > 0:
                return v
        if isinstance(row, dict):
            v = _first_positive(
                row.get("totalWalletBalance"),
                row.get("totalAvailableBalance"),
                row.get("totalEquity"),
            )
            if v > 0:
                return v
        return 0.0

async def _bybit_order_create(
    *,
    api_key: str,
    api_secret: str,
    category: str,
    symbol: str,
    side: str,
    order_type: str,
    qty: float,
    price: float | None = None,
    reduce_only: bool | None = None,
    trigger_price: float | None = None,
    close_on_trigger: bool | None = None,
    market_unit: str | None = None,
) -> dict:
    body: dict[str, Any] = {
        "category": category,
        "symbol": symbol.upper(),
        "side": "Buy" if side.upper() in ("BUY", "LONG") else "Sell",
        "orderType": order_type,
        "qty": _decimal_to_api_str(qty),
        "timeInForce": "GTC",
    }
    if price is not None:
        body["price"] = _decimal_to_api_str(price)
    if reduce_only is not None:
        body["reduceOnly"] = bool(reduce_only)
    if trigger_price is not None:
        body["triggerPrice"] = _decimal_to_api_str(trigger_price)
    if close_on_trigger is not None:
        body["closeOnTrigger"] = bool(close_on_trigger)
    if str(category or "").lower() == "spot" and str(order_type or "").lower() == "market" and market_unit:
        body["marketUnit"] = str(market_unit)
    timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=timeout) as s:
        return await _bybit_v5_request(
            s,
            method="POST",
            path="/v5/order/create",
            api_key=api_key,
            api_secret=api_secret,
            json_body=body,
        )


