_BINANCE_FUTURES_MODE_CACHE: dict[str, tuple[float, bool]] = {}


def _binance_futures_position_side_from_direction(*, direction: str | None = None, side: str | None = None) -> str:
    raw = str(direction or side or "").upper().strip()
    return "SHORT" if raw in ("SHORT", "SELL") else "LONG"


def _binance_futures_close_position_side_from_order_side(side: str | None) -> str:
    return "LONG" if str(side or "").upper().strip() == "SELL" else "SHORT"


def _binance_is_position_row(d: dict | None, symbol: str) -> bool:
    if not isinstance(d, dict):
        return False
    if str(d.get("symbol") or "").upper() != str(symbol or "").upper():
        return False
    return any(k in d for k in ("positionAmt", "positionSide", "entryPrice", "unRealizedProfit", "notional"))


async def _binance_futures_position_context(
    *,
    api_key: str,
    api_secret: str,
    symbol: str,
    session: aiohttp.ClientSession | None = None,
) -> dict:
    timeout = aiohttp.ClientTimeout(total=_binance_request_timeout_sec())
    rows: list[dict] = []
    payload_valid = False
    if session is None:
        async with aiohttp.ClientSession(timeout=timeout) as s:
            data = await _binance_signed_request(
                s,
                base_url="https://fapi.binance.com",
                path="/fapi/v2/positionRisk",
                method="GET",
                api_key=api_key,
                api_secret=api_secret,
                params={"symbol": symbol.upper(), "recvWindow": "5000"},
            )
    else:
        data = await _binance_signed_request(
            session,
            base_url="https://fapi.binance.com",
            path="/fapi/v2/positionRisk",
            method="GET",
            api_key=api_key,
            api_secret=api_secret,
            params={"symbol": symbol.upper(), "recvWindow": "5000"},
        )
    if isinstance(data, list):
        payload_valid = True
        rows = [d for d in data if _binance_is_position_row(d, symbol)]
    elif isinstance(data, dict):
        payload = data.get("data")
        if isinstance(payload, list):
            payload_valid = True
            rows = [d for d in payload if _binance_is_position_row(d, symbol)]
        elif isinstance(payload, dict):
            payload_valid = True
            if _binance_is_position_row(payload, symbol):
                rows = [payload]
        elif _binance_is_position_row(data, symbol):
            payload_valid = True
            rows = [data]
    hedge_mode = any(str((d or {}).get("positionSide") or "").upper() in ("LONG", "SHORT") for d in rows)
    if _SMART_BINANCE_DEBUG:
        try:
            logger.info(
                "[BINANCE_POS_CTX] sym=%s hedge=%s valid=%s rows=%s",
                symbol.upper(),
                bool(hedge_mode),
                bool(payload_valid),
                json.dumps(_binance_debug_compact_pos_rows(rows), ensure_ascii=False),
            )
            if not payload_valid:
                logger.warning(
                    "[BINANCE_POS_CTX_INVALID] sym=%s payload=%s",
                    symbol.upper(),
                    json.dumps(data, ensure_ascii=False, default=str)[:1200],
                )
        except Exception:
            pass
    return {"rows": rows, "hedge_mode": hedge_mode, "payload_valid": payload_valid}


async def _binance_futures_is_hedge_mode(*, api_key: str, api_secret: str, symbol: str | None = None) -> bool:
    cache_key = hashlib.sha1(f"{api_key}|{(symbol or '*').upper()}".encode("utf-8")).hexdigest()
    now_ts = time.time()
    cached = _BINANCE_FUTURES_MODE_CACHE.get(cache_key)
    if cached and (now_ts - float(cached[0] or 0.0) <= 30.0):
        return bool(cached[1])

    hedge_mode: bool | None = None
    if symbol:
        try:
            ctx = await _binance_futures_position_context(api_key=api_key, api_secret=api_secret, symbol=symbol)
            rows = ctx.get("rows") or []
            if rows:
                hedge_mode = bool(ctx.get("hedge_mode"))
        except Exception:
            hedge_mode = None

    if hedge_mode is None:
        timeout = aiohttp.ClientTimeout(total=10)
        async with aiohttp.ClientSession(timeout=timeout) as s:
            data = await _binance_signed_request(
                s,
                base_url="https://fapi.binance.com",
                path="/fapi/v1/positionSide/dual",
                method="GET",
                api_key=api_key,
                api_secret=api_secret,
                params={"recvWindow": "5000"},
            )
        raw = None
        if isinstance(data, dict):
            raw = data.get("dualSidePosition")
        hedge_mode = str(raw).strip().lower() in ("true", "1", "yes", "on") if raw is not None else False

    _BINANCE_FUTURES_MODE_CACHE[cache_key] = (now_ts, bool(hedge_mode))
    return bool(hedge_mode)


