async def autotrade_execute(user_id: int, sig: "Signal") -> dict:
    """Execute real trading orders for a signal for a single user.

    Returns dict:
      {"ok": bool, "skipped": bool, "api_error": str|None}
    """
    uid = int(user_id)
    market = (getattr(sig, "market", "") or "").upper()
    if market not in ("SPOT", "FUTURES"):
        return {"ok": False, "skipped": True, "api_error": None, "skip_reason": "bad_market", "details": {"market": market}}

    def _skip(reason: str, **details) -> dict:
        return {"ok": False, "skipped": True, "api_error": None, "skip_reason": reason, "details": details or {}}

    def _fail(api_error: str, **details) -> dict:
        return {"ok": False, "skipped": False, "api_error": api_error, "details": details or {}}


    # Hard block: stable-vs-stable pairs (fail-safe)
    sym = (getattr(sig, "symbol", "") or "").upper().strip()
    if is_blocked_symbol(sym):
        logger.warning("[autotrade] blocked stable pair skip: %s", sym)
        return _skip("blocked_symbol", symbol=sym)

    try:
        risk_note_u = str(getattr(sig, "risk_note", "") or "").upper()
    except Exception:
        risk_note_u = ""
    if ("ZONE_TOUCH_ALERT=1" in risk_note_u) or ("NO_AUTOTRADE=1" in risk_note_u):
        return _skip("zone_touch_alert", symbol=sym)

    st = await db_store.get_autotrade_settings(uid)
    mt = "spot" if market == "SPOT" else "futures"


    # Extract TA extras (ATR 5m) from confirmations JSON for smarter manager (trailing, near-TP2).
    def _sig_ta_float(name: str) -> float:
        try:
            raw = getattr(sig, "confirmations", "") or ""
            if not raw:
                return 0.0
            data = json.loads(raw) if isinstance(raw, str) else raw
            if isinstance(data, dict):
                # Some deployments store {"ta": {...}}; others store TA dict directly.
                ta = data.get("ta") if isinstance(data.get("ta"), dict) else data
                v = ta.get(name, 0.0) if isinstance(ta, dict) else 0.0
                return float(v or 0.0)
        except Exception:
            return 0.0
        return 0.0

    atr5_sig = _sig_ta_float("atr5")
    atr5_pct_sig = _sig_ta_float("atr5_pct")
    atr_pct_sig = _sig_ta_float("atr_pct")
    fut_lock_conn = None
    fut_lock_key = None

    def _safe_floor_div_positions(cap_usdt: float, margin_usdt: float) -> int:
        try:
            cap_v = float(cap_usdt or 0.0)
            margin_v = float(margin_usdt or 0.0)
            if cap_v <= 0 or margin_v <= 0:
                return 0
            return max(0, int(math.floor((cap_v + 1e-9) / margin_v)))
        except Exception:
            return 0

    async def _guard_futures_capacity(*, cap_limit_usdt: float, exchange_name: str, free_usdt: float | None = None):
        """Serialize futures cap checks across replicas and enforce both USDT cap and max positions."""
        lock_conn = await db_store.get_pool().acquire(timeout=30.0)
        lock_key = None
        try:
            lock_key = await db_store.acquire_autotrade_cap_lock(lock_conn, user_id=uid, market_type="futures")
            used_locked = await db_store.get_autotrade_used_usdt(uid, "futures", conn=lock_conn)
            active_locked = await db_store.get_autotrade_open_positions_count(uid, "futures", conn=lock_conn)
            eff_locked = float(cap_limit_usdt or 0.0)
            max_pos_locked = _safe_floor_div_positions(eff_locked, need_usdt)

            if max_pos_locked > 0 and active_locked >= max_pos_locked:
                await db_store.release_autotrade_cap_lock(lock_conn, lock_key)
                await db_store.get_pool().release(lock_conn)
                return _skip(
                    "futures_cap_positions_reached",
                    active_positions=int(active_locked),
                    max_positions=int(max_pos_locked),
                    used_usdt=float(used_locked),
                    need_usdt=float(need_usdt),
                    cap_usdt=float(eff_locked),
                    free_usdt=(float(free_usdt) if free_usdt is not None else None),
                    exchange=exchange_name,
                    market=market,
                )

            if eff_locked > 0 and used_locked + need_usdt > eff_locked:
                await db_store.release_autotrade_cap_lock(lock_conn, lock_key)
                await db_store.get_pool().release(lock_conn)
                return _skip(
                    "futures_cap_reached",
                    active_positions=int(active_locked),
                    max_positions=int(max_pos_locked),
                    used_usdt=float(used_locked),
                    need_usdt=float(need_usdt),
                    cap_usdt=float(eff_locked),
                    free_usdt=(float(free_usdt) if free_usdt is not None else None),
                    exchange=exchange_name,
                    market=market,
                )

            return lock_conn, lock_key, eff_locked, used_locked, active_locked, max_pos_locked
        except Exception:
            try:
                if lock_key is not None:
                    await db_store.release_autotrade_cap_lock(lock_conn, lock_key)
            finally:
                await db_store.get_pool().release(lock_conn)
            raise
    # --- Admin gate (like SIGNAL): global per-user Auto-trade allow/deny + expiry ---
    # This is independent from per-market toggles in autotrade_settings.
    # If disabled/expired/blocked -> skip silently.
    try:
        acc = await db_store.get_autotrade_access(uid)
        if bool(acc.get("is_blocked")):
            return _skip("access_blocked")
        if not bool(acc.get("autotrade_enabled")):
            return _skip("access_disabled")
        if bool(acc.get("autotrade_stop_after_close")):
            return _skip("stop_after_close")
        exp = acc.get("autotrade_expires_at")
        if exp is not None:
            import datetime as _dt
            now = _dt.datetime.now(_dt.timezone.utc)
            try:
                if exp.tzinfo is None:
                    exp = exp.replace(tzinfo=_dt.timezone.utc)
                if exp <= now:
                    return _skip("access_expired")
            except Exception:
                return _skip("access_expiry_check_failed")
    except Exception:
        # best-effort: if access columns not ready, default to allow
        pass

    enabled = bool(st.get("spot_enabled")) if mt == "spot" else bool(st.get("futures_enabled"))
    if not enabled:
        return _skip("market_disabled", market=market)

    
    exchange = str(st.get("spot_exchange" if mt == "spot" else "futures_exchange") or "binance").lower().strip()

    # SPOT: choose exchange using the user's priority, but do not hard-fail when
    # confirmations/available_exchanges are empty or incomplete. Some signals arrive
    # with only source_exchange/binance in confirmations even though the pair exists
    # on Bybit/OKX/MEXC/Gate and the user expects the first eligible exchange from
    # their priority list to be used.
    if mt == "spot":
        allowed = ["binance", "bybit", "okx", "mexc", "gateio"]

        def _norm_spot_venues(raw: str) -> set[str]:
            out: set[str] = set()
            for part in re.split(r"[+ ,;/|•·]+", str(raw or "").strip()):
                p = part.strip().lower()
                if not p:
                    continue
                if p in ("binance", "bnb"):
                    out.add("binance")
                elif p in ("bybit", "byb"):
                    out.add("bybit")
                elif p in ("okx",):
                    out.add("okx")
                elif p in ("mexc",):
                    out.add("mexc")
                elif p in ("gateio", "gate", "gate.io", "gateio.ws"):
                    out.add("gateio")
            return out

        conf_raw = str((getattr(sig, "available_exchanges", "") or getattr(sig, "confirmations", "") or "")).strip()
        conf_set: set[str] = _norm_spot_venues(conf_raw)
        src_ex = str(getattr(sig, "source_exchange", "") or "").strip().lower()
        if src_ex in allowed:
            conf_set.add(src_ex)

        # Priority list from DB (comma-separated)
        pr_csv = str(st.get("spot_exchange_priority") or "binance,bybit,okx,mexc,gateio")
        pr = [x.strip().lower() for x in pr_csv.split(",") if x.strip()]
        pr2: list[str] = []
        for x in pr:
            if x in allowed and x not in pr2:
                pr2.append(x)
        for x in allowed:
            if x not in pr2:
                pr2.append(x)

        async def _get_spot_keys_row(ex: str):
            row = await db_store.get_autotrade_keys_row(user_id=uid, exchange=ex, market_type="spot")
            if not row or not bool(row.get("is_active")):
                return None
            if not (row.get("api_key_enc") and row.get("api_secret_enc")):
                return None
            if ex == "okx" and not row.get("passphrase_enc"):
                return None
            return row

        async def _spot_symbol_exists(ex: str, sym: str) -> bool:
            ex = (ex or "").lower().strip()
            sym = (sym or "").upper().replace("/", "")
            try:
                if ex == "binance":
                    info = await _binance_exchange_info(futures=False)
                    for s in (info.get("symbols", []) or []):
                        if str(s.get("symbol") or "").upper() == sym:
                            stt = str(s.get("status") or "").upper()
                            return (stt in ("TRADING", "1")) or (stt == "")
                    return False
                if ex == "bybit":
                    data = await _http_json(
                        "GET",
                        "https://api.bybit.com/v5/market/instruments-info",
                        params={"category": "spot", "symbol": sym},
                        timeout_s=10,
                    )
                    lst = ((data.get("result") or {}).get("list") or [])
                    if lst:
                        return True
                    # Some spot symbols are still queryable via ticker even when
                    # instruments-info is temporarily empty / rate-limited.
                    try:
                        px = await _bybit_price(sym, category="spot")
                        return bool(px and px > 0)
                    except Exception:
                        return False
                if ex == "okx":
                    try:
                        await _okx_instrument_filters(inst_type="SPOT", symbol=sym)
                        return True
                    except Exception:
                        try:
                            return bool(await _okx_public_price(sym))
                        except Exception:
                            return False
                if ex == "mexc":
                    data = await _http_json("GET", "https://api.mexc.com/api/v3/exchangeInfo", params={"symbol": sym}, timeout_s=10)
                    lst = (data.get("symbols") or [])
                    if any(str(x.get("symbol") or "").upper() == sym for x in lst):
                        return True
                    try:
                        return bool(await _mexc_public_price(sym))
                    except Exception:
                        return False
                if ex == "gateio":
                    pair = _gate_pair(sym)
                    data = await _http_json("GET", "https://api.gateio.ws/api/v4/spot/currency_pairs", params={"id": pair}, timeout_s=10)
                    if isinstance(data, list) and any(str(x.get("id") or "").upper() == pair.upper() for x in data):
                        return True
                    if isinstance(data, dict) and str(data.get("id") or "").upper() == pair.upper():
                        return True
                    try:
                        return bool(await _gateio_public_price(sym))
                    except Exception:
                        return False
            except Exception:
                return False
            return False

        chosen = None
        chosen_reason = ""

        # 1) Best case: first exchange from user priority that is both confirmed and usable.
        if conf_set:
            for ex in pr2:
                if ex not in conf_set:
                    continue
                row = await _get_spot_keys_row(ex)
                if not row:
                    continue
                if not (await _spot_symbol_exists(ex, sym)):
                    continue
                chosen = ex
                chosen_reason = "confirmed+priority"
                break

        # 2) Fallback: confirmations are often incomplete. Use first user-priority
        # exchange with valid keys where the symbol actually exists.
        if not chosen:
            for ex in pr2:
                row = await _get_spot_keys_row(ex)
                if not row:
                    continue
                if not (await _spot_symbol_exists(ex, sym)):
                    continue
                chosen = ex
                chosen_reason = "priority_fallback"
                break

        if not chosen:
            return {
                "ok": False,
                "skipped": True,
                "skip_reason": "no_exchange_available",
                "details": {
                    "confirmations_raw": conf_raw,
                    "confirmations": sorted(conf_set),
                    "priority": pr2,
                    "symbol": sym,
                },
                "api_error": None,
            }

        exchange = chosen
        try:
            logger.info(
                "[autotrade][route][spot] uid=%s sym=%s chosen=%s reason=%s conf_raw=%s conf=%s priority=%s",
                uid, sym, exchange, chosen_reason, conf_raw or "-", ",".join(sorted(conf_set)) or "-", ",".join(pr2),
            )
        except Exception:
            pass

    # FUTURES: choose exchange based on where the futures contract actually exists
    # (BINANCE/BYBIT/OKX). If the signal provides a list of executable futures venues
    # in available_exchanges/confirmations, we enforce it. Otherwise we allow the
    # user-selected exchange as a best-effort fallback.
    if mt == "futures":
        fut_allowed = ["binance", "bybit", "okx"]

        # Parse venues like "BINANCE+OKX" -> {"binance","okx"}
        conf_raw = str((getattr(sig, "available_exchanges", "") or getattr(sig, "confirmations", "") or "")).strip()
        conf_set: set[str] = set()
        for part in re.split(r"[+ ,;/|•·]+", conf_raw.strip()):
            p = part.strip().lower()
            if not p:
                continue
            if p in ("binance", "bnb"):
                conf_set.add("binance")
            elif p in ("bybit", "byb"):
                conf_set.add("bybit")
            elif p in ("okx",):
                conf_set.add("okx")

        # Helper: does user have active futures keys for exchange?
        async def _has_fut_keys(ex: str) -> bool:
            try:
                row = await db_store.get_autotrade_keys_row(user_id=uid, exchange=ex, market_type="futures")
                if not row or not bool(row.get("is_active")):
                    return False
                if not (row.get("api_key_enc") and row.get("api_secret_enc")):
                    return False
                if ex == "okx" and not row.get("passphrase_enc"):
                    return False
                return True
            except Exception:
                return False

        # Normalize invalid selection
        if exchange not in fut_allowed:
            exchange = "binance"

        # Choose futures exchange by priority:
        # - user must have active futures keys
        # - futures contract must exist on that exchange (prevents 'Symbol Is Invalid')
        # - if signal provides confirmations/available_exchanges, enforce that subset
        async def _fut_contract_exists(ex: str, sym: str) -> bool:
            ex = (ex or "").lower()
            sym = (sym or "").upper().replace("/", "")
            try:
                if ex == "binance":
                    info = await _binance_exchange_info(futures=True)
                    for s in (info.get("symbols", []) or []):
                        if str(s.get("symbol") or "").upper() == sym:
                            stt = str(s.get("status") or "").upper()
                            return (stt in ("TRADING", "1")) or (stt == "")
                    return False
                if ex == "bybit":
                    data = await _http_json(
                        "GET",
                        "https://api.bybit.com/v5/market/instruments-info",
                        params={"category": "linear", "symbol": sym},
                        timeout_s=10,
                    )
                    lst = ((data.get("result") or {}).get("list") or [])
                    return bool(lst)
                if ex == "okx":
                    inst = _okx_swap_inst(sym)
                    data = await _http_json(
                        "GET",
                        "https://www.okx.com/api/v5/public/instruments",
                        params={"instType": "SWAP", "instId": inst},
                        timeout_s=10,
                    )
                    lst = ((data.get("data") or []) if isinstance(data, dict) else [])
                    return bool(lst)
            except Exception:
                return False
            return False

        candidates = [exchange] + [x for x in fut_allowed if x != exchange]
        if conf_set:
            candidates = [x for x in candidates if x in conf_set]

        chosen = None
        for ex in candidates:
            if not (await _has_fut_keys(ex)):
                continue
            # Use the normalized signal symbol captured above. Using `symbol` here can
            # raise UnboundLocalError because `symbol` is assigned later in this function.
            if not (await _fut_contract_exists(ex, sym)):
                continue
            chosen = ex
            break
        if not chosen:
            return _skip("no_exchange_available", market=market)
        exchange = chosen

    # amounts
    spot_amt = float(st.get("spot_amount_per_trade") or 0.0)
    fut_margin = float(st.get("futures_margin_per_trade") or 0.0)
    fut_cap = float(st.get("futures_cap") or 0.0)
    fut_lev = int(st.get("futures_leverage") or 1)

    need_usdt = spot_amt if mt == "spot" else fut_margin
    # MID positions are typically noisier; optionally reduce allocation via SMART_MID_ALLOC_MULT
    try:
        if _is_mid_signal(sig):
            mult = float(os.getenv("SMART_MID_ALLOC_MULT", "1.0") or 1.0)
            if mult > 0:
                need_usdt *= mult
    except Exception:
        pass

    # Hard minimums (validated in bot UI and DB, but re-checked here for safety)
    if mt == "spot" and 0 < need_usdt < 15:
        return _skip("amount_below_minimum", minimum=15, requested=float(need_usdt), market=market)
    if mt == "futures" and 0 < need_usdt < 10:
        return _skip("amount_below_minimum", minimum=10, requested=float(need_usdt), market=market)
    if need_usdt <= 0:
        return _skip("amount_not_set", requested=float(need_usdt), market=market)

    async def _spot_free_usdt_for_exchange(ex_name: str) -> float:
        row_keys = await db_store.get_autotrade_keys_row(user_id=uid, exchange=ex_name, market_type="spot")
        if not row_keys or not bool(row_keys.get("is_active")):
            return 0.0
        try:
            k = _decrypt_token(row_keys.get("api_key_enc"))
            s = _decrypt_token(row_keys.get("api_secret_enc"))
            if ex_name == "binance":
                return float(await _binance_spot_free_usdt(k, s))
            if ex_name == "bybit":
                return float(await _bybit_available_usdt(k, s, market_type="spot"))
            if ex_name == "okx":
                p = _decrypt_token(row_keys.get("passphrase_enc")) if row_keys.get("passphrase_enc") else ""
                if not p:
                    return 0.0
                return float(await _okx_available_usdt(k, s, p, market_type="spot"))
            if ex_name == "mexc":
                return float(await _mexc_spot_free_usdt(k, s))
            if ex_name == "gateio":
                return float(await _gateio_spot_free_usdt(k, s))
        except Exception:
            return 0.0
        return 0.0

    async def _futures_free_usdt_for_exchange(ex_name: str) -> float:
        row_keys = await db_store.get_autotrade_keys_row(user_id=uid, exchange=ex_name, market_type="futures")
        if not row_keys or not bool(row_keys.get("is_active")):
            return 0.0
        try:
            k = _decrypt_token(row_keys.get("api_key_enc"))
            s = _decrypt_token(row_keys.get("api_secret_enc"))
            if ex_name == "binance":
                return float(await _binance_futures_available_margin(k, s))
            if ex_name == "bybit":
                return float(await _bybit_available_usdt(k, s, market_type="futures"))
            if ex_name == "okx":
                p = _decrypt_token(row_keys.get("passphrase_enc")) if row_keys.get("passphrase_enc") else ""
                if not p:
                    return 0.0
                return float(await _okx_available_usdt(k, s, p, market_type="futures"))
        except Exception:
            return 0.0
        return 0.0

    if mt == "spot":
        spot_candidates = [x for x in (pr2 if 'pr2' in locals() else [exchange]) if x in ("binance", "bybit", "okx", "mexc", "gateio")]
        if conf_set:
            tmp = [x for x in spot_candidates if x in conf_set]
            if tmp:
                spot_candidates = tmp
        if exchange in spot_candidates:
            spot_candidates = [exchange] + [x for x in spot_candidates if x != exchange]
        best_ex = None
        best_free = -1.0
        for ex_name in spot_candidates:
            free = await _spot_free_usdt_for_exchange(ex_name)
            if free >= need_usdt:
                best_ex = ex_name
                break
            if free > best_free:
                best_free = free
                best_ex = ex_name
        if best_ex and best_ex != exchange:
            try:
                logger.info("[autotrade][route][spot][balance] uid=%s sym=%s reroute=%s->%s need=%.8f best_free=%.8f", uid, sym, exchange, best_ex, float(need_usdt), float(best_free))
            except Exception:
                pass
            exchange = best_ex

    if mt == "futures":
        fut_candidates = [x for x in ([exchange] + [x for x in ("binance", "bybit", "okx") if x != exchange]) if x in ("binance", "bybit", "okx")]
        if conf_set:
            tmp = [x for x in fut_candidates if x in conf_set]
            if tmp:
                fut_candidates = tmp
        best_ex = None
        best_free = -1.0
        for ex_name in fut_candidates:
            free = await _futures_free_usdt_for_exchange(ex_name)
            if free >= need_usdt:
                best_ex = ex_name
                break
            if free > best_free:
                best_free = free
                best_ex = ex_name
        if best_ex and best_ex != exchange:
            try:
                logger.info("[autotrade][route][futures][balance] uid=%s sym=%s reroute=%s->%s need=%.8f best_free=%.8f", uid, sym, exchange, best_ex, float(need_usdt), float(best_free))
            except Exception:
                pass
            exchange = best_ex

    # fetch keys
    row = await db_store.get_autotrade_keys_row(user_id=uid, exchange=exchange, market_type=mt)
    if not row or not bool(row.get("is_active")):
        return _skip("keys_inactive", exchange=exchange, market=market)
    try:
        api_key = _decrypt_token(row.get("api_key_enc"))
        api_secret = _decrypt_token(row.get("api_secret_enc"))
    except Exception as e:
        try:
            if mt == "futures" and fut_lock_conn is not None and fut_lock_key is not None:
                await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
                await db_store.get_pool().release(fut_lock_conn)
                fut_lock_conn = None
                fut_lock_key = None
        except Exception:
            pass
        await db_store.mark_autotrade_key_error(
            user_id=uid,
            exchange=exchange,
            market_type=mt,
            error=f"decrypt_error: {e}",
            deactivate=True,
        )
        return {"ok": False, "skipped": True, "api_error": f"decrypt_error"}

    symbol = str(getattr(sig, "symbol", "") or "").upper().replace("/", "")
    if not symbol:
        return _skip("missing_symbol")

    direction = str(getattr(sig, "direction", "LONG") or "LONG").upper()
    entry = float(getattr(sig, "entry", 0.0) or 0.0)
    sl = float(getattr(sig, "sl", 0.0) or 0.0)
    tp1 = float(getattr(sig, "tp1", 0.0) or 0.0)
    tp2 = float(getattr(sig, "tp2", 0.0) or 0.0)

    try:
        if exchange == "bybit":
            category = "spot" if mt == "spot" else "linear"
            # Futures cap is user-defined (by margin). Spot cap is implicit (wallet balance).
            free = await _bybit_available_usdt(api_key, api_secret, market_type=mt)
            if free < need_usdt:
                return _skip("insufficient_balance", free_usdt=float(free), need_usdt=float(need_usdt), exchange=exchange, market=market)

            cap_decreased = False
            prev_eff_val = None
            winrate = None
            eff_cap = float(fut_cap or 0.0)

            if mt == "futures":
                # Smart effective cap uses CURRENT available balance + winrate.
                try:
                    w = await db_store.get_autotrade_winrate(uid, market_type="futures", limit=20)
                    if int(w.get("n") or 0) >= 5:
                        winrate = float(w.get("winrate") or 0.0)
                except Exception:
                    winrate = None

                eff_cap = _calc_effective_futures_cap(balance_usdt=float(free), ui_cap_usdt=float(fut_cap), winrate=winrate)

                prev_eff = _LAST_EFFECTIVE_FUT_CAP.get(uid)
                _LAST_EFFECTIVE_FUT_CAP[uid] = float(eff_cap)
                if prev_eff is not None:
                    prev_eff_val = float(prev_eff)
                    if float(eff_cap) + 1e-9 < float(prev_eff):
                        dec = float(prev_eff) - float(eff_cap)
                        now_ts = time.time()
                        last_ts = float(_LAST_EFFECTIVE_FUT_CAP_NOTIFY_AT.get(uid) or 0.0)
                        if dec >= _SMARTCAP_DECREASE_MIN_USDT and (now_ts - last_ts) >= _SMARTCAP_COOLDOWN_SEC:
                            cap_decreased = True
                            _LAST_EFFECTIVE_FUT_CAP_NOTIFY_AT[uid] = now_ts

                cap_guard = await _guard_futures_capacity(
                    cap_limit_usdt=float(eff_cap),
                    exchange_name=exchange,
                    free_usdt=float(free),
                )
                if isinstance(cap_guard, dict):
                    cap_guard.update({
                        "cap_ui": float(fut_cap),
                        "cap_effective": float(eff_cap),
                        "cap_decreased": cap_decreased,
                        "cap_prev_effective": prev_eff_val,
                        "winrate": (float(winrate) if winrate is not None else None),
                    })
                    return cap_guard
                fut_lock_conn, fut_lock_key, _eff_cap_locked, _used_locked, _active_locked, _max_pos_locked = cap_guard

            direction_local = direction
            if mt == "spot":
                # Spot: only long/buy is supported.
                side = "BUY"
            else:
                side = "BUY" if direction_local == "LONG" else "SELL"
            close_side = "SELL" if side == "BUY" else "BUY"

            px = await _bybit_price(symbol, category=category)
            if px <= 0:
                return _skip(
                    "market_price_unavailable",
                    exchange=exchange,
                    market=market,
                    symbol=symbol,
                    price_source="bybit_public_ticker",
                )

            # Entry-range guard: allow market entry only when current price stays close enough
            # to the signal entry. This reduces missed fills from overly strict exact-entry logic,
            # while still preventing very late market chases.
            try:
                entry_range_pct = float(os.getenv("AUTOTRADE_ENTRY_RANGE_PCT", "0.0050") or 0.0050)
            except Exception:
                entry_range_pct = 0.0050
            try:
                if float(entry or 0.0) > 0 and float(entry_range_pct) > 0:
                    entry_ref = float(entry)
                    entry_diff_pct = abs(float(px) - entry_ref) / entry_ref
                    if entry_diff_pct > float(entry_range_pct):
                        return _skip(
                            "outside_entry_range",
                            entry_price=float(entry_ref),
                            market_price=float(px),
                            diff_pct=float(entry_diff_pct),
                            allowed_pct=float(entry_range_pct),
                            exchange=exchange,
                            market=market,
                        )
            except Exception:
                pass

            qty_step, min_qty, tick = await _bybit_instrument_filters(category=category, symbol=symbol)

            # Spot qty in base; Futures qty in contracts (approx via notional/price)
            if mt == "spot":
                qty = max(0.0, need_usdt / px)
            else:
                qty = max(0.0, (need_usdt * float(fut_lev)) / px)
            if qty_step > 0:
                qty = _round_step(qty, qty_step)
            if min_qty > 0 and qty < min_qty:
                raise ExchangeAPIError(f"Bybit qty<minQty after rounding: {qty} < {min_qty}")

            entry_order_qty = qty
            entry_market_unit = None
            base_before = 0.0
            if mt == "spot":
                # Bybit SPOT market BUY interprets qty as quote value by default.
                # Send the user-configured USDT amount explicitly to avoid wrong units
                # and decimal-length rejections (retCode 170148).
                entry_order_qty = max(0.0, float(need_usdt))
                entry_market_unit = "quoteCoin"
                try:
                    base_before = float(await _spot_base_balance(ex="bybit", api_key=api_key, api_secret=api_secret, passphrase=None, symbol=symbol))
                except Exception:
                    base_before = 0.0

            entry_res = await _bybit_order_create(
                api_key=api_key,
                api_secret=api_secret,
                category=category,
                symbol=symbol,
                side=side,
                order_type="Market",
                qty=entry_order_qty,
                reduce_only=False if mt == "futures" else None,
                market_unit=entry_market_unit,
            )
            order_id = ((entry_res.get("result") or {}).get("orderId") or (entry_res.get("result") or {}).get("orderId"))

            if mt == "spot":
                exec_qty = 0.0
                try:
                    if order_id:
                        entry_status = await _bybit_order_status(
                            api_key=api_key,
                            api_secret=api_secret,
                            category=category,
                            symbol=symbol,
                            order_id=str(order_id),
                        )
                        lst = ((entry_status.get("result") or {}).get("list") or [])
                        od = lst[0] if (lst and isinstance(lst[0], dict)) else {}
                        exec_qty = float(od.get("cumExecQty") or 0.0)
                except Exception:
                    exec_qty = 0.0
                if exec_qty <= 0:
                    try:
                        base_after = float(await _spot_base_balance(ex="bybit", api_key=api_key, api_secret=api_secret, passphrase=None, symbol=symbol))
                        exec_qty = max(0.0, base_after - float(base_before or 0.0))
                    except Exception:
                        exec_qty = 0.0
                if exec_qty <= 0:
                    exec_qty = float(qty)
                if qty_step > 0:
                    exec_qty = _round_step(exec_qty, qty_step)
                if min_qty > 0 and exec_qty < min_qty:
                    raise ExchangeAPIError(f"Bybit SPOT entry executedQty<minQty after rounding: {exec_qty} < {min_qty}")
                qty = float(exec_qty)

            has_tp2 = tp2 > 0 and abs(tp2 - tp1) > 1e-12
            qty1 = _round_step(qty * (0.5 if has_tp2 else 1.0), qty_step)
            qty2 = _round_step(qty - qty1, qty_step) if has_tp2 else 0.0
            if has_tp2 and min_qty > 0 and qty2 < min_qty:
                has_tp2 = False
                qty1 = qty
                qty2 = 0.0

            # --- VIRTUAL mode: do not place SL/TP orders on exchange ---
            if _VIRTUAL_SLTP_ALL:
                entry_p = float(entry or 0.0)
                ref = {
                "signal_timeframe": getattr(sig, "timeframe", None),
                "signal_kind": ("MID" if _is_mid_signal(sig) else "MAIN"),
                    "virtual": True,
                    "exchange": "bybit",
                    "signal_timeframe": getattr(sig, "timeframe", None),
                    "signal_kind": ("MID" if _is_mid_signal(sig) else "MAIN"),
                    "market_type": mt,
                    "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                    "direction": direction,
                    "side": side,
                    "close_side": ("SELL" if str(side).upper() == "BUY" else "BUY"),
                    "entry_price": entry_p,
                    "qty": float(qty),
                    "tp1": float(tp1 or 0.0),
                    "tp2": float(tp2 or 0.0),
                    "sl": float(sl or 0.0),
                    "tp1_hit": False,
                    "be_moved": False,
                    "be_price": 0.0,
                }
                sig_id = _extract_signal_id(sig)
                if sig_id <= 0:
                    raise ExchangeAPIError("missing signal_id")
                await db_store.create_autotrade_position(
                    user_id=uid,
                    signal_id=sig_id,
                    exchange="bybit",
                    market_type=mt,
                    symbol=symbol,
                    side=side,
                    allocated_usdt=need_usdt,
                    api_order_ref=json.dumps(ref),
                )
                return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}


            # Place SL first; if SL fails, immediately close to avoid unprotected exposure.
            try:
                sl_res = await _bybit_order_create(
                    api_key=api_key,
                    api_secret=api_secret,
                    category=category,
                    symbol=symbol,
                    side=close_side,
                    order_type="Market",
                    qty=qty,
                    reduce_only=(True if mt == "futures" else None),
                    trigger_price=_round_tick(sl, tick),
                    close_on_trigger=(True if mt == "futures" else None),
                )
            except Exception:
                try:
                    await _bybit_order_create(
                        api_key=api_key,
                        api_secret=api_secret,
                        category=category,
                        symbol=symbol,
                        side=close_side,
                        order_type="Market",
                        qty=qty,
                        reduce_only=(True if mt == "futures" else None),
                    )
                except Exception:
                    pass
                raise

            # TP(s) as limit reduce-only for futures; spot normal sell. If TP1 fails, close to avoid half-configured strategy.
            try:
                tp1_res = await _bybit_order_create(
                    api_key=api_key,
                    api_secret=api_secret,
                    category=category,
                    symbol=symbol,
                    side=close_side,
                    order_type="Limit",
                    qty=qty1,
                    price=_round_tick(tp1, tick),
                    reduce_only=(True if mt == "futures" else None),
                )
            except Exception:
                try:
                    await _bybit_cancel_order(api_key=api_key, api_secret=api_secret, category=category, symbol=symbol, order_id=str((sl_res.get("result") or {}).get("orderId") or ""))
                except Exception:
                    pass
                try:
                    await _bybit_order_create(
                        api_key=api_key,
                        api_secret=api_secret,
                        category=category,
                        symbol=symbol,
                        side=close_side,
                        order_type="Market",
                        qty=qty,
                        reduce_only=(True if mt == "futures" else None),
                    )
                except Exception:
                    pass
                raise

            tp2_res = None
            if has_tp2 and qty2 > 0:
                try:
                    tp2_res = await _bybit_order_create(
                        api_key=api_key,
                        api_secret=api_secret,
                        category=category,
                        symbol=symbol,
                        side=close_side,
                        order_type="Limit",
                        qty=qty2,
                        price=_round_tick(tp2, tick),
                        reduce_only=(True if mt == "futures" else None),
                    )
                except Exception:
                    tp2_res = None

            def _rid(x: dict | None) -> str | None:
                if not isinstance(x, dict):
                    return None
                return str((x.get("result") or {}).get("orderId") or "") or None

            ref = {
                "exchange": "bybit",
                "market_type": mt,
                "category": category,
                "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                "side": side,
                "close_side": close_side,
                "entry_order_id": str(order_id) if order_id else None,
                "sl_order_id": _rid(sl_res),
                "tp1_order_id": _rid(tp1_res),
                "tp2_order_id": _rid(tp2_res),
                "entry_price": float(entry or 0.0),
                "be_price": float(entry or 0.0),
                "be_moved": False,
                "qty": qty,
                "tp1": tp1,
                "tp2": tp2,
                "sl": sl,
            }

            sig_id = _extract_signal_id(sig)
            if sig_id <= 0:
                raise ExchangeAPIError("missing signal_id")
            await db_store.create_autotrade_position(
                user_id=uid,
                signal_id=sig_id,
                exchange="bybit",
                market_type=mt,
                symbol=symbol,
                side=side,
                allocated_usdt=need_usdt,
                api_order_ref=json.dumps(ref),
            )
            return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange,
                    **({"cap_ui": float(fut_cap), "cap_effective": float(eff_cap), "cap_decreased": bool(cap_decreased), "cap_prev_effective": prev_eff_val, "winrate": (float(winrate) if winrate is not None else None)} if mt == "futures" else {})
                    }

        
        # -------- OKX / MEXC / Gate.io --------
        if exchange in ("okx", "mexc", "gateio"):
            symbol = _normalize_symbol(getattr(sig, "symbol", "") or "")
            if not symbol:
                raise ExchangeAPIError("missing symbol")

            if mt == "spot":
                if exchange == "okx":
                    passphrase = _decrypt_token(row.get("passphrase_enc"))
                    free = await _okx_available_usdt(api_key, api_secret, passphrase, market_type="spot")
                elif exchange == "mexc":
                    free = await _mexc_spot_free_usdt(api_key, api_secret)
                else:
                    free = await _gateio_spot_free_usdt(api_key, api_secret)
                if free < need_usdt:
                    return _skip("insufficient_balance", free_usdt=float(free), need_usdt=float(need_usdt), exchange=exchange, market=market)

                if exchange == "okx":
                    px = await _okx_public_price(symbol)
                elif exchange == "mexc":
                    px = await _mexc_public_price(symbol)
                else:
                    px = await _gateio_public_price(symbol)

                if not px or px <= 0:
                    raise ExchangeAPIError("price_unavailable")

                est_qty = (need_usdt / float(px)) if need_usdt > 0 else 0.0
                if est_qty <= 0:
                    raise ExchangeAPIError("qty_estimate_zero")

                qty_step = 0.0
                min_qty = 0.0
                try:
                    if exchange == "okx":
                        qty_step, min_qty, _tick = await _okx_instrument_filters(inst_type="SPOT", symbol=symbol)
                    elif exchange == "mexc":
                        qty_step, min_qty, _tick, _mn = await _mexc_symbol_filters(symbol)
                    else:
                        qty_step, min_qty, _tick, _mn = await _gate_symbol_filters(symbol)
                except Exception:
                    qty_step = 0.0
                    min_qty = 0.0

                if direction == "SHORT":
                    return _skip("spot_short_not_supported", exchange=exchange, market=market)

                balance_passphrase = passphrase if exchange == "okx" else None
                base_before = 0.0
                try:
                    base_before = float(await _spot_base_balance(ex=exchange, api_key=api_key, api_secret=api_secret, passphrase=balance_passphrase, symbol=symbol))
                except Exception:
                    base_before = 0.0

                if exchange == "okx":
                    entry_order = await _okx_spot_market_buy(api_key=api_key, api_secret=api_secret, passphrase=passphrase, symbol=symbol, quote_usdt=need_usdt)
                elif exchange == "mexc":
                    entry_order = await _mexc_spot_market_buy(api_key=api_key, api_secret=api_secret, symbol=symbol, quote_usdt=need_usdt)
                else:
                    entry_order = await _gateio_spot_market_buy(api_key=api_key, api_secret=api_secret, symbol=symbol, quote_usdt=need_usdt)

                managed_qty = float(est_qty)
                try:
                    base_after = float(await _spot_base_balance(ex=exchange, api_key=api_key, api_secret=api_secret, passphrase=balance_passphrase, symbol=symbol))
                    delta_qty = max(0.0, base_after - float(base_before or 0.0))
                    if delta_qty > 0:
                        managed_qty = float(delta_qty)
                except Exception:
                    managed_qty = float(est_qty)
                if managed_qty <= 0:
                    managed_qty = float(est_qty)
                if qty_step > 0:
                    managed_qty = _round_step(managed_qty, qty_step)
                if min_qty > 0 and managed_qty < min_qty:
                    fallback_qty = _round_step(est_qty, qty_step) if qty_step > 0 else float(est_qty)
                    if fallback_qty >= min_qty:
                        managed_qty = float(fallback_qty)

                ref = {
                    "exchange": exchange,
                    "market_type": "spot",
                    "symbol": symbol,
                    "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                    "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                    "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                    "side": "BUY",
                    "close_side": "SELL",
                    "virtual": True,
                    "entry_price": float(px),
                    "be_price": float(px),
                    "be_moved": False,
                    "tp1_hit": False,
                    "qty": float(managed_qty),
                    "tp1": float(tp1 or 0.0),
                    "tp2": float(tp2 or 0.0),
                    "sl": float(sl or 0.0),
                }

                sig_id = _extract_signal_id(sig)
                if sig_id <= 0:
                    raise ExchangeAPIError("missing signal_id")
                await db_store.create_autotrade_position(
                    user_id=uid,
                    signal_id=sig_id,
                    exchange=exchange,
                    market_type="spot",
                    symbol=symbol,
                    side="BUY",
                    allocated_usdt=need_usdt,
                    api_order_ref=json.dumps(ref),
                )
                return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}

            if exchange != "okx":
                return _skip("unsupported_market_type_for_exchange", exchange=exchange, market=market)

            passphrase = _decrypt_token(row.get("passphrase_enc"))
            free = await _okx_available_usdt(api_key, api_secret, passphrase, market_type="futures")
            eff_cap = float(st.get("effective_futures_cap") or 0.0)
            if eff_cap <= 0:
                eff_cap = float(fut_cap or 0.0)
            cap_guard = await _guard_futures_capacity(
                cap_limit_usdt=float(eff_cap),
                exchange_name=exchange,
                free_usdt=float(free),
            )
            if isinstance(cap_guard, dict):
                return cap_guard
            fut_lock_conn, fut_lock_key, _eff_cap_locked, _used_locked, _active_locked, _max_pos_locked = cap_guard

            if free < need_usdt:
                await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
                await db_store.get_pool().release(fut_lock_conn)
                fut_lock_conn = None
                fut_lock_key = None
                return _skip("insufficient_balance", free_usdt=float(free), need_usdt=float(need_usdt), exchange=exchange, market=market)

            await _okx_futures_set_leverage(api_key=api_key, api_secret=api_secret, passphrase=passphrase, symbol=symbol, leverage=fut_lev)

            px = await _okx_public_price(symbol, market_type="futures")
            if px <= 0:
                raise ExchangeAPIError("OKX futures price=0")

            raw_qty = (need_usdt * float(fut_lev)) / px
            step, min_qty, _tick = await _okx_instrument_filters(inst_type="SWAP", symbol=symbol)
            qty = _round_step(raw_qty, step) if step > 0 else raw_qty
            if min_qty > 0 and qty < min_qty:
                qty = min_qty

            side = "BUY" if direction == "LONG" else "SELL"
            entry_res = await _okx_futures_market_open(
                api_key=api_key,
                api_secret=api_secret,
                passphrase=passphrase,
                symbol=symbol,
                side=side,
                qty=qty,
            )

            entry_p = float(entry or 0.0)
            ref = {
                "virtual": True,
                "exchange": "okx",
                "market_type": "futures",
                "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                "direction": direction,
                "side": side.upper(),
                "close_side": ("SELL" if side.upper() == "BUY" else "BUY"),
                "entry_order_id": ((entry_res.get("data") or [{}])[0].get("ordId") if isinstance(entry_res.get("data"), list) and entry_res.get("data") else None),
                "entry_price": entry_p,
                "qty": float(qty),
                "tp1": float(tp1 or 0.0),
                "tp2": float(tp2 or 0.0),
                "sl": float(sl or 0.0),
                "tp1_hit": False,
                "be_moved": False,
                "be_price": 0.0,
            }
            sig_id = _extract_signal_id(sig)
            if sig_id <= 0:
                raise ExchangeAPIError("missing signal_id")
            try:
                await db_store.create_autotrade_position(
                    user_id=uid,
                    signal_id=sig_id,
                    exchange="okx",
                    market_type="futures",
                    symbol=symbol,
                    side=side,
                    allocated_usdt=need_usdt,
                    api_order_ref=json.dumps(ref),
                )
            finally:
                await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
                await db_store.get_pool().release(fut_lock_conn)
                fut_lock_conn = None
                fut_lock_key = None
            return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}

        # Safety guard: never fall through into Binance execution for other exchanges
        if exchange != "binance":
            return _skip("unsupported_exchange", exchange=exchange, market=market)

# -------- Binance --------
        if mt == "spot":
            free = await _binance_spot_free_usdt(api_key, api_secret)
            if free < need_usdt:
                return _skip("insufficient_balance", free_usdt=float(free), need_usdt=float(need_usdt), exchange=exchange, market=market)

            info = await _binance_exchange_info(futures=False)
            qty_step, min_qty, tick, min_notional = _binance_symbol_filters(info, symbol)

            # Entry: market buy by quote amount (USDT)
            entry_res = await _binance_spot_market_buy_quote(
                api_key=api_key,
                api_secret=api_secret,
                symbol=symbol,
                quote_usdt=need_usdt,
            )

            exec_qty = float(entry_res.get("executedQty") or 0.0)
            if exec_qty <= 0:
                # fallback: attempt to infer from fills
                q = 0.0
                for f in entry_res.get("fills", []) or []:
                    q += float(f.get("qty") or 0.0)
                exec_qty = q
            if exec_qty <= 0:
                raise ExchangeAPIError(f"Binance SPOT entry executedQty=0: {entry_res}")

            # Split for TP1/TP2 (respect LOT_SIZE)
            has_tp2 = tp2 > 0 and abs(tp2 - tp1) > 1e-12
            # Partial close % is configurable via env (TP1_PARTIAL_CLOSE_PCT_SPOT)
            p = max(0.0, min(100.0, float(_tp1_partial_close_pct('SPOT'))))
            a = p / 100.0
            qty1 = exec_qty * (a if has_tp2 else 1.0)
            qty2 = (exec_qty - qty1) if has_tp2 else 0.0
            qty1 = _round_step(qty1, qty_step)
            qty2 = _round_step(qty2, qty_step)
            exec_qty = _round_step(exec_qty, qty_step)
            if exec_qty < min_qty:
                raise ExchangeAPIError(f"Binance SPOT qty<minQty after rounding: {exec_qty} < {min_qty}")
            if has_tp2 and qty2 < min_qty:
                # If the second leg becomes too small, do a single TP.
                has_tp2 = False
                qty1 = exec_qty
                qty2 = 0.0

            # --- VIRTUAL mode: do not place SL/TP orders on exchange ---
            if _VIRTUAL_SLTP_ALL:
                # Use actual executed qty from entry as the managed base qty.
                entry_p = float(entry or 0.0)
                ref = {
                    "virtual": True,
                    "exchange": "binance",
                    "market_type": "spot",
                    "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                    "direction": direction,
                    "side": "BUY",
                    "close_side": "SELL",
                    "entry_price": entry_p,
                    "qty": float(exec_qty),
                    "tp1": float(tp1 or 0.0),
                    "tp2": float(tp2 or 0.0),
                    "sl": float(sl or 0.0),
                    "tp1_hit": False,
                    "be_moved": False,
                    "be_price": 0.0,
                }
                sig_id = _extract_signal_id(sig)
                if sig_id <= 0:
                    raise ExchangeAPIError("missing signal_id")
                await db_store.create_autotrade_position(
                    user_id=uid,
                    signal_id=sig_id,
                    exchange="binance",
                    market_type="spot",
                    symbol=symbol,
                    side="BUY",
                    allocated_usdt=need_usdt,
                    api_order_ref=json.dumps(ref),
                )
                return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}


            # Place SL first; if SL fails, immediately close (sell) to avoid an unprotected position.
            try:
                sl_res = await _binance_spot_stop_loss_limit_sell(
                    api_key=api_key,
                    api_secret=api_secret,
                    symbol=symbol,
                    qty=exec_qty,
                    stop_price=_round_tick(sl, tick),
                )
            except Exception as e:
                # Emergency close
                try:
                    await _binance_spot_market_sell_base(api_key=api_key, api_secret=api_secret, symbol=symbol, qty=exec_qty)
                except Exception:
                    pass
                raise

            # Place TP(s). If TP1 fails, close to avoid keeping a half-configured strategy.
            try:
                tp1_res = await _binance_spot_limit_sell(api_key=api_key, api_secret=api_secret, symbol=symbol, qty=qty1, price=_round_tick(tp1, tick))
            except Exception:
                try:
                    await _binance_cancel_order(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(sl_res.get("orderId") or 0), futures=False)
                except Exception:
                    pass
                try:
                    await _binance_spot_market_sell_base(api_key=api_key, api_secret=api_secret, symbol=symbol, qty=exec_qty)
                except Exception:
                    pass
                raise
            tp2_res = None
            if has_tp2 and qty2 > 0:
                tp2_res = await _binance_spot_limit_sell(api_key=api_key, api_secret=api_secret, symbol=symbol, qty=qty2, price=_round_tick(tp2, tick))

            ref = {
                "exchange": "binance",
                "market_type": "spot",
                "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                "side": "BUY",
                "entry_order_id": entry_res.get("orderId"),
                "sl_order_id": sl_res.get("orderId"),
                "tp1_order_id": tp1_res.get("orderId"),
                "tp2_order_id": (tp2_res.get("orderId") if isinstance(tp2_res, dict) else None),
                "entry_price": float(entry or 0.0),
                "be_price": float(entry or 0.0),
                "be_moved": False,
                "qty": exec_qty,
                "tp1": tp1,
                "tp2": tp2,
                "sl": sl,
            }

            sig_id = _extract_signal_id(sig)
            if sig_id <= 0:
                raise ExchangeAPIError("missing signal_id")
            await db_store.create_autotrade_position(
                user_id=uid,
                signal_id=sig_id,
                exchange="binance",
                market_type="spot",
                symbol=symbol,
                side="BUY",
                allocated_usdt=need_usdt,
                api_order_ref=json.dumps(ref),
            )
            return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}

        # futures
        avail = await _binance_futures_available_margin(api_key, api_secret)
        eff_cap = float(st.get("effective_futures_cap") or 0.0)
        if eff_cap <= 0:
            eff_cap = float(fut_cap or 0.0)
        cap_guard = await _guard_futures_capacity(
            cap_limit_usdt=float(eff_cap),
            exchange_name=exchange,
            free_usdt=float(avail),
        )
        if isinstance(cap_guard, dict):
            return cap_guard
        fut_lock_conn, fut_lock_key, _eff_cap_locked, _used_locked, _active_locked, _max_pos_locked = cap_guard

        if avail < need_usdt:
            await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
            await db_store.get_pool().release(fut_lock_conn)
            fut_lock_conn = None
            fut_lock_key = None
            return _skip("insufficient_balance", free_usdt=float(avail), need_usdt=float(need_usdt), exchange=exchange, market=market)

        if avail < need_usdt:
            return _skip("insufficient_balance", free_usdt=float(avail), need_usdt=float(need_usdt), exchange=exchange, market=market)

        await _binance_futures_set_leverage(api_key=api_key, api_secret=api_secret, symbol=symbol, leverage=fut_lev)

        # compute qty from margin*leverage/price
        px = await _binance_price(symbol, futures=True)
        if px <= 0:
            raise ExchangeAPIError("Binance futures price=0")
        raw_qty = (need_usdt * float(fut_lev)) / px
        info = await _binance_exchange_info(futures=True)
        step, min_qty, tick, _mn = _binance_symbol_filters(info, symbol)
        qty = _round_step(raw_qty, step) if step > 0 else raw_qty
        if min_qty > 0 and qty < min_qty:
            qty = min_qty

        side = "BUY" if direction == "LONG" else "SELL"
        close_side = "SELL" if side == "BUY" else "BUY"
        hedge_mode = await _binance_futures_is_hedge_mode(api_key=api_key, api_secret=api_secret, symbol=symbol)
        position_side = _binance_futures_position_side_from_direction(direction=direction, side=side)
        entry_res = await _binance_futures_market_open(
            api_key=api_key,
            api_secret=api_secret,
            symbol=symbol,
            side=side,
            qty=qty,
            position_side=position_side,
            hedge_mode=hedge_mode,
        )

        entry_order_id = 0
        try:
            entry_order_id = int(entry_res.get("orderId") or 0)
        except Exception:
            entry_order_id = 0
        entry_status_res = {}
        if entry_order_id > 0:
            try:
                entry_status_res = await _binance_order_status(
                    api_key=api_key,
                    api_secret=api_secret,
                    symbol=symbol,
                    order_id=entry_order_id,
                    futures=True,
                )
            except Exception as e:
                entry_status_res = {"orderId": entry_order_id, "_error": str(e)}
        if _SMART_BINANCE_DEBUG:
            try:
                logger.info(
                    "[BINANCE_ENTRY_DEBUG] uid=%s ex=binance market=futures sym=%s side=%s pos_side=%s hedge=%s qty=%s entry_res=%s order_status=%s",
                    uid,
                    symbol,
                    side,
                    position_side,
                    bool(hedge_mode),
                    float(qty),
                    json.dumps(_binance_debug_compact_order(entry_res), ensure_ascii=False),
                    json.dumps(_binance_debug_compact_order(entry_status_res), ensure_ascii=False),
                )
            except Exception:
                pass

        # --- VIRTUAL mode: do not place SL/TP orders on exchange ---
        if _VIRTUAL_SLTP_ALL:
            entry_p = float(entry or 0.0)
            ref = {
                "virtual": True,
                "exchange": "binance",
                "market_type": "futures",
                "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
                "direction": direction,
                "side": side.upper(),
                "close_side": ("SELL" if side.upper() == "BUY" else "BUY"),
                "position_side": position_side,
                "hedge_mode": bool(hedge_mode),
                "entry_price": entry_p,
                "qty": float(qty),
                "tp1": float(tp1 or 0.0),
                "tp2": float(tp2 or 0.0),
                "sl": float(sl or 0.0),
                "tp1_hit": False,
                "be_moved": False,
                "be_price": 0.0,
                "entry_order_id": int(entry_order_id or 0),
                "entry_client_order_id": str(entry_res.get("clientOrderId") or ""),
                "entry_order_status": str((entry_status_res or entry_res).get("status") or entry_res.get("status") or ""),
                "entry_executed_qty": float((entry_status_res or entry_res).get("executedQty") or entry_res.get("executedQty") or 0.0),
                "entry_avg_price": float((entry_status_res or entry_res).get("avgPrice") or entry_res.get("avgPrice") or 0.0),
            }
            sig_id = _extract_signal_id(sig)
            if sig_id <= 0:
                raise ExchangeAPIError("missing signal_id")
            try:
                await db_store.create_autotrade_position(
                    user_id=uid,
                    signal_id=sig_id,
                    exchange="binance",
                    market_type="futures",
                    symbol=symbol,
                    side=side,
                    allocated_usdt=need_usdt,
                    api_order_ref=json.dumps(ref),
                )
            finally:
                await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
                await db_store.get_pool().release(fut_lock_conn)
                fut_lock_conn = None
                fut_lock_key = None
            return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}


        # Place SL first; if SL fails, immediately close position to avoid unprotected exposure.
        try:
            sl_res = await _binance_futures_stop_market_close_all(
                api_key=api_key,
                api_secret=api_secret,
                symbol=symbol,
                side=close_side,
                stop_price=_round_tick(sl, tick),
                position_side=position_side,
                hedge_mode=hedge_mode,
            )
        except Exception:
            try:
                await _binance_futures_reduce_market(
                    api_key=api_key,
                    api_secret=api_secret,
                    symbol=symbol,
                    side=close_side,
                    qty=qty,
                    position_side=position_side,
                    hedge_mode=hedge_mode,
                )
            except Exception:
                pass
            raise

        # TP reduce-only limits (respect LOT_SIZE)
        has_tp2 = tp2 > 0 and abs(tp2 - tp1) > 1e-12
        qty1 = _round_step(qty * (0.5 if has_tp2 else 1.0), step)
        qty2 = _round_step(qty - qty1, step) if has_tp2 else 0.0
        if min_qty > 0 and qty1 < min_qty:
            # Not enough size for strategy
            raise ExchangeAPIError(f"Binance FUTURES qty<minQty after rounding: {qty1} < {min_qty}")
        if has_tp2 and min_qty > 0 and qty2 < min_qty:
            has_tp2 = False
            qty1 = qty
            qty2 = 0.0
        try:
            tp1_res = await _binance_futures_reduce_limit(
                api_key=api_key,
                api_secret=api_secret,
                symbol=symbol,
                side=close_side,
                qty=qty1,
                price=_round_tick(tp1, tick),
                position_side=position_side,
                hedge_mode=hedge_mode,
            )
        except Exception:
            # Cancel SL and close to avoid half-configured strategy
            try:
                await _binance_cancel_order(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(sl_res.get("orderId") or 0), futures=True)
            except Exception:
                pass
            try:
                await _binance_futures_reduce_market(
                    api_key=api_key,
                    api_secret=api_secret,
                    symbol=symbol,
                    side=close_side,
                    qty=qty,
                    position_side=position_side,
                    hedge_mode=hedge_mode,
                )
            except Exception:
                pass
            raise
        tp2_res = None
        if has_tp2 and qty2 > 0:
            try:
                tp2_res = await _binance_futures_reduce_limit(
                    api_key=api_key,
                    api_secret=api_secret,
                    symbol=symbol,
                    side=close_side,
                    qty=qty2,
                    price=_round_tick(tp2, tick),
                    position_side=position_side,
                    hedge_mode=hedge_mode,
                )
            except Exception:
                tp2_res = None

        ref = {
            "exchange": "binance",
            "market_type": "futures",
            "symbol": symbol,
                "atr_pct": float(atr_pct_sig) if mt == "futures" else 0.0,
                "atr5": float(atr5_sig) if mt == "futures" else 0.0,
                "atr5_pct": float(atr5_pct_sig) if mt == "futures" else 0.0,
            "side": side,
            "close_side": close_side,
            "position_side": position_side,
            "hedge_mode": bool(hedge_mode),
            "entry_order_id": entry_res.get("orderId"),
            "sl_order_id": sl_res.get("orderId"),
            "tp1_order_id": tp1_res.get("orderId"),
            "tp2_order_id": (tp2_res.get("orderId") if isinstance(tp2_res, dict) else None),
            "entry_price": float(entry or 0.0),
            "be_price": float(entry or 0.0),
            "be_moved": False,
            "qty": qty,
            "tp1": tp1,
            "tp2": tp2,
            "sl": sl,
        }

        sig_id = _extract_signal_id(sig)
        if sig_id <= 0:
            raise ExchangeAPIError("missing signal_id")
        try:
            await db_store.create_autotrade_position(
                user_id=uid,
                signal_id=sig_id,
                exchange="binance",
                market_type="futures",
                symbol=symbol,
                side=side,
                allocated_usdt=need_usdt,
                api_order_ref=json.dumps(ref),
            )
        finally:
            await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
            await db_store.get_pool().release(fut_lock_conn)
            fut_lock_conn = None
            fut_lock_key = None
        return {"ok": True, "skipped": False, "api_error": None, "exchange": exchange}

    except ExchangeAPIError as e:
        try:
            if mt == "futures" and fut_lock_conn is not None and fut_lock_key is not None:
                await db_store.release_autotrade_cap_lock(fut_lock_conn, fut_lock_key)
                await db_store.get_pool().release(fut_lock_conn)
                fut_lock_conn = None
                fut_lock_key = None
        except Exception:
            pass
        err = str(e)
        await db_store.mark_autotrade_key_error(
            user_id=uid,
            exchange=exchange,
            market_type=mt,
            error=err,
            deactivate=_should_deactivate_key(err),
        )
        return _fail(err, exchange=exchange, market=market, market_type=mt)
    except Exception as e:
        err = f"{type(e).__name__}: {e}"
        await db_store.mark_autotrade_key_error(
            user_id=uid,
            exchange=exchange,
            market_type=mt,
            error=err,
            deactivate=_should_deactivate_key(err),
        )
        return {"ok": False, "skipped": False, "api_error": err, "details": {"exchange": exchange, "market": market, "market_type": mt}}


# ------------------ Auto-trade soft reconcile (manual close sync) ------------------
# If a user closes a position manually on the exchange, SL/TP orders may never be FILLED,
# and the DB row in autotrade_positions can stay OPEN forever. We periodically reconcile
# OPEN rows against real balances/positions and close them best-effort.
_LAST_RECONCILE_TS: dict[int, float] = {}
_SMART_TICK_TS: dict[int, float] = {}  # pos_id -> last log ts
_RECONCILE_COOLDOWN_SEC = max(10, int(os.getenv("AUTOTRADE_RECONCILE_SEC", "60") or "60"))
_DUST_PCT = float(os.getenv("AUTOTRADE_DUST_PCT", "0.01") or "0.01")   # 1% of original qty
_DUST_MIN = float(os.getenv("AUTOTRADE_DUST_MIN", "1e-8") or "1e-8")
_SMART_BINANCE_DEBUG = _env_bool("SMART_BINANCE_DEBUG", False)
_SMART_BINANCE_DEBUG_MAX_ROWS = max(1, int(os.getenv("SMART_BINANCE_DEBUG_MAX_ROWS", "5") or "5"))
_SMART_RECONCILE_GRACE_SEC = max(0.0, float(os.getenv("AUTOTRADE_RECONCILE_GRACE_SEC", "90") or "90"))
_SMART_RECONCILE_ZERO_HITS = max(1, int(os.getenv("AUTOTRADE_RECONCILE_ZERO_HITS", "3") or "3"))
_SMART_MANAGER_DEBUG_LOGS = _env_bool("SMART_MANAGER_DEBUG_LOGS", False)

def _binance_debug_compact_order(order: dict | None) -> dict:
    if not isinstance(order, dict):
        return {}
    out = {}
    for k in (
        "symbol", "orderId", "clientOrderId", "status", "side", "positionSide",
        "type", "origQty", "executedQty", "cumQty", "cumBase", "avgPrice",
        "price", "stopPrice", "reduceOnly", "closePosition", "workingType",
        "updateTime", "time", "code", "msg", "_error",
    ):
        if k in order and order.get(k) not in (None, ""):
            out[k] = order.get(k)
    return out

def _binance_debug_compact_pos_rows(rows: list[dict] | None) -> list[dict]:
    out: list[dict] = []
    for d in list(rows or [])[:_SMART_BINANCE_DEBUG_MAX_ROWS]:
        if not isinstance(d, dict):
            continue
        item = {}
        for k in (
            "symbol", "positionSide", "positionAmt", "entryPrice", "breakEvenPrice",
            "markPrice", "unRealizedProfit", "liquidationPrice", "leverage", "marginType",
            "isolatedMargin", "notional", "updateTime",
        ):
            if k in d and d.get(k) not in (None, ""):
                item[k] = d.get(k)
        out.append(item)
    return out

def _base_asset(symbol: str) -> str:
    s = (symbol or "").upper().strip()
    for q in ("USDT","USDC","BUSD","USD"):
        if s.endswith(q) and len(s) > len(q):
            return s[:-len(q)]
    return s

async def _spot_base_balance(*, ex: str, api_key: str, api_secret: str, passphrase: str | None, symbol: str) -> float:
    base = _base_asset(symbol)
    timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=timeout) as s:
        ex = (ex or "").lower().strip()
        if ex == "binance":
            data = await _binance_signed_request(
                s, base_url="https://api.binance.com", path="/api/v3/account", method="GET",
                api_key=api_key, api_secret=api_secret, params={"recvWindow":"5000"},
            )
            bals = data.get("balances") or []
            if isinstance(bals, list):
                for b in bals:
                    if isinstance(b, dict) and str(b.get("asset") or "").upper() == base:
                        free = float(b.get("free") or 0.0)
                        locked = float(b.get("locked") or 0.0)
                        return float(free + locked)
            return 0.0

        if ex == "bybit":
            # V5 unified wallet-balance; best-effort.
            data = await _bybit_v5_request(
                s, method="GET", path="/v5/account/wallet-balance",
                api_key=api_key, api_secret=api_secret,
                params={"accountType":"UNIFIED", "coin": base},
            )
            res = (data.get("result") or {})
            lst = res.get("list") or []
            if isinstance(lst, list) and lst:
                cl = (lst[0].get("coin") or [])
                if isinstance(cl, list) and cl:
                    coin = cl[0]
                    if isinstance(coin, dict):
                        free = float(coin.get("availableToWithdraw") or coin.get("walletBalance") or 0.0)
                        # no separate "locked" field exposed consistently; walletBalance is OK for our dust check
                        return float(free)
            return 0.0

        if ex == "okx":
            data = await _okx_signed_request(
                s, base_url="https://www.okx.com", path="/api/v5/account/balance", method="GET",
                api_key=api_key, api_secret=api_secret, passphrase=(passphrase or ""),
                params={"ccy": base},
            )
            dl = (data.get("data") or [])
            if isinstance(dl, list) and dl:
                details = (dl[0].get("details") or [])
                if isinstance(details, list) and details:
                    d0 = details[0]
                    if isinstance(d0, dict):
                        cash = float(d0.get("cashBal") or 0.0)
                        frozen = float(d0.get("frozenBal") or 0.0)
                        return float(cash + frozen)
            return 0.0

        if ex == "mexc":
            data = await _mexc_signed_request(
                s, base_url="https://api.mexc.com", path="/api/v3/account", method="GET",
                api_key=api_key, api_secret=api_secret, params={},
            )
            bals = data.get("balances") or []
            if isinstance(bals, list):
                for b in bals:
                    if isinstance(b, dict) and str(b.get("asset") or "").upper() == base:
                        free = float(b.get("free") or 0.0)
                        locked = float(b.get("locked") or 0.0)
                        return float(free + locked)
            return 0.0

        if ex == "gateio":
            data = await _gateio_signed_request(
                s, base_url="https://api.gateio.ws", path="/api/v4/spot/accounts", method="GET",
                api_key=api_key, api_secret=api_secret, params={},
            )
            if isinstance(data, list):
                for a in data:
                    if isinstance(a, dict) and str(a.get("currency") or "").upper() == base:
                        avail = float(a.get("available") or 0.0)
                        locked = float(a.get("locked") or 0.0)
                        return float(avail + locked)
            return 0.0

    return 0.0

async def _futures_position_size(*, ex: str, api_key: str, api_secret: str, symbol: str, category: str = "linear", passphrase: str | None = None, position_side: str | None = None) -> float:
    timeout = aiohttp.ClientTimeout(total=_binance_request_timeout_sec())
    async with aiohttp.ClientSession(timeout=timeout) as s:
        ex = (ex or "").lower().strip()
        if ex == "binance":
            ctx = await _binance_futures_position_context(api_key=api_key, api_secret=api_secret, symbol=symbol, session=s)
            if not bool(ctx.get("payload_valid", True)):
                raise ExchangeAPIError(f"Binance positionRisk invalid payload for {symbol}")
            rows = list(ctx.get("rows") or [])
            want_side = str(position_side or "").upper().strip()
            selected_amt = 0.0
            selected_side = ""
            selected_reason = "no_rows"

            if want_side:
                for d in rows:
                    if str((d or {}).get("positionSide") or "").upper() == want_side:
                        selected_amt = float(d.get("positionAmt") or 0.0)
                        selected_side = want_side
                        selected_reason = "exact_side"
                        break

            if selected_reason == "no_rows" and rows:
                nonzero_rows = []
                for d in rows:
                    try:
                        amt = float(d.get("positionAmt") or 0.0)
                    except Exception:
                        amt = 0.0
                    if abs(amt) > 0.0:
                        nonzero_rows.append(d)
                if len(nonzero_rows) == 1:
                    selected_amt = float(nonzero_rows[0].get("positionAmt") or 0.0)
                    selected_side = str((nonzero_rows[0] or {}).get("positionSide") or "").upper()
                    selected_reason = "single_nonzero"
                else:
                    for pref in ("BOTH", "LONG", "SHORT"):
                        for d in rows:
                            if str((d or {}).get("positionSide") or "").upper() == pref:
                                selected_amt = float(d.get("positionAmt") or 0.0)
                                selected_side = pref
                                selected_reason = f"pref_{pref.lower()}"
                                break
                        if selected_reason != "no_rows":
                            break
                    if selected_reason == "no_rows":
                        selected_amt = float(rows[0].get("positionAmt") or 0.0)
                        selected_side = str((rows[0] or {}).get("positionSide") or "").upper()
                        selected_reason = "first_row"

            if _SMART_BINANCE_DEBUG:
                try:
                    logger.info(
                        "[BINANCE_POS_SIZE] sym=%s want_side=%s hedge=%s reason=%s selected_side=%s size=%s rows=%s",
                        symbol.upper(),
                        want_side,
                        bool(ctx.get("hedge_mode")),
                        selected_reason,
                        selected_side,
                        float(selected_amt or 0.0),
                        json.dumps(_binance_debug_compact_pos_rows(rows), ensure_ascii=False),
                    )
                except Exception:
                    pass
            return float(selected_amt or 0.0)

        if ex == "bybit":
            data = await _bybit_v5_request(
                s, method="GET", path="/v5/position/list",
                api_key=api_key, api_secret=api_secret,
                params={"category": category, "symbol": symbol},
            )
            res = data.get("result") or {}
            lst = res.get("list") or []
            if isinstance(lst, list) and lst:
                d0 = lst[0]
                if isinstance(d0, dict):
                    return float(d0.get("size") or 0.0)
            return 0.0

        if ex == "okx":
            inst = _okx_swap_inst(symbol)
            data = await _okx_signed_request(
                s,
                base_url="https://www.okx.com",
                path="/api/v5/account/positions",
                method="GET",
                api_key=api_key,
                api_secret=api_secret,
                passphrase=(passphrase or ""),
                params={"instId": inst},
            )
            lst = (data.get("data") or [])
            if isinstance(lst, list):
                for d in lst:
                    if isinstance(d, dict) and str(d.get("instId") or "").upper() == inst.upper():
                        try:
                            return abs(float(d.get("pos") or 0.0))
                        except Exception:
                            return 0.0
            return 0.0
    return 0.0

async def autotrade_manager_loop(*, notify_api_error, notify_smart_event=None, backend_instance=None) -> None:
    """Background loop to manage SL/TP/BE for real orders.

    notify_api_error(user_id:int, exchange:str, market_type:str, text:str) will be called only on API errors.
    notify_smart_event(user_id:int, text:str) may be called for SL/TP decisions.
    """

    import socket as _socket
    _wid_base = os.getenv("AUTOTRADE_MANAGER_ID") or os.getenv("RAILWAY_REPLICA_ID") or os.getenv("HOSTNAME") or _socket.gethostname()
    manager_worker_id = f"{_wid_base}:{os.getpid()}"
    manager_batch = int(os.getenv("AUTOTRADE_MANAGER_BATCH", "300") or 300)
    manager_lease_sec = int(os.getenv("AUTOTRADE_MANAGER_LEASE_SEC", "120") or 120)
    manager_sleep_sec = max(0.5, _parse_seconds_env("AUTOTRADE_MANAGER_SLEEP_SEC", 2.0))

    # autotrade_manager_loop is a module-level coroutine, not a Backend method.
    # Use an explicit Backend instance for shared price/diagnostic helpers so SMART_TICK
    # never crashes with NameError: name 'self' is not defined.
    price_backend = backend_instance
    if price_backend is None:
        global _AUTOTRADE_MANAGER_BACKEND_SINGLETON
        try:
            price_backend = _AUTOTRADE_MANAGER_BACKEND_SINGLETON
        except NameError:
            _AUTOTRADE_MANAGER_BACKEND_SINGLETON = None
            price_backend = None
        if price_backend is None:
            price_backend = Backend()
            _AUTOTRADE_MANAGER_BACKEND_SINGLETON = price_backend

    def _as_float(x, default: float = 0.0) -> float:
        try:
            if x is None:
                return float(default)
            return float(str(x))
        except Exception:
            return float(default)

    def _binance_avg_price(order: dict) -> float:
        if not isinstance(order, dict):
            return 0.0
        ap = _as_float(order.get("avgPrice"), 0.0)
        if ap > 0:
            return ap
        exec_qty = _as_float(order.get("executedQty"), 0.0)
        cqq = _as_float(order.get("cummulativeQuoteQty"), 0.0)
        return (cqq / exec_qty) if exec_qty > 0 else 0.0

    def _bybit_avg_price(resp: dict) -> float:
        # resp is full response from _bybit_order_status
        try:
            lst = ((resp.get("result") or {}).get("list") or [])
            o = lst[0] if (lst and isinstance(lst[0], dict)) else {}
        except Exception:
            o = {}
        ap = _as_float(o.get("avgPrice"), 0.0)
        if ap > 0:
            return ap
        qty = _as_float(o.get("cumExecQty"), 0.0)
        val = _as_float(o.get("cumExecValue"), 0.0)
        return (val / qty) if qty > 0 else 0.0

    def _calc_autotrade_pnl_from_orders(*, ref: dict, entry_order: dict, exit_order: dict, exchange: str, market_type: str, allocated_usdt: float) -> tuple[float | None, float | None]:
        """Compute net PnL using entry/exit average fills + modeled fees.

        Improvements vs legacy:
        - uses executed qty from the *exit* order when available
        - subtracts modeled fees (FEE_RATE_SPOT/FEE_RATE_FUTURES) for entry+exit notionals
        - adds any previously accumulated realized pnl from partial closes (e.g., TP1) stored in ref

        Still an approximation (we do not fetch per-fill commissions/funding to keep API usage light).
        """
        try:
            side = str(ref.get("side") or "BUY").upper()
            qty_ref = _as_float(ref.get("qty"), 0.0)
            if qty_ref <= 0:
                return None, None

            # Extract executed qty from the exit order if possible (more accurate for partial closes)
            def _binance_exec_qty(order: dict) -> float:
                if not isinstance(order, dict):
                    return 0.0
                return _as_float(order.get("executedQty"), 0.0)

            def _bybit_exec_qty(resp: dict) -> float:
                try:
                    lst = ((resp.get("result") or {}).get("list") or [])
                    o = lst[0] if (lst and isinstance(lst[0], dict)) else {}
                except Exception:
                    o = {}
                return _as_float(o.get("cumExecQty"), 0.0)

            if exchange == "binance":
                entry_p = _binance_avg_price(entry_order)
                exit_p = _binance_avg_price(exit_order)
                qty_exit = _binance_exec_qty(exit_order)
            else:
                entry_p = _bybit_avg_price(entry_order)
                exit_p = _bybit_avg_price(exit_order)
                qty_exit = _bybit_exec_qty(exit_order)

            if entry_p <= 0 or exit_p <= 0:
                return None, None

            qty_used = qty_exit if qty_exit > 0 else qty_ref
            qty_used = max(0.0, min(float(qty_used), float(qty_ref) if qty_ref > 0 else float(qty_used)))
            if qty_used <= 0:
                return None, None

            # BUY = long, SELL = short (for futures); for spot we assume BUY then SELL
            if side == "BUY":
                pnl_gross = (exit_p - entry_p) * qty_used
            else:
                pnl_gross = (entry_p - exit_p) * qty_used

            # Modeled fees (keep light: no per-fill fees API calls)
            fr = float(FEE_RATE_SPOT if str(market_type).lower() == "spot" else FEE_RATE_FUTURES)
            fees_est = fr * ((entry_p * qty_used) + (exit_p * qty_used))

            # Add previously realized pnl/fees from earlier partial closes (e.g. TP1)
            realized_pnl = _as_float(ref.get("realized_pnl_usdt"), 0.0)
            realized_fee = _as_float(ref.get("realized_fee_usdt"), 0.0)

            pnl_net = float(pnl_gross) - float(fees_est) + float(realized_pnl) - float(realized_fee)

            alloc = float(allocated_usdt or 0.0)
            roi = (pnl_net / alloc * 100.0) if alloc > 0 else None
            return float(pnl_net), (float(roi) if roi is not None else None)
        except Exception:
            return None, None

    def _estimate_autotrade_pnl_snapshot(*, ref: dict, exit_price: float, market_type: str, allocated_usdt: float, qty_hint: float | None = None) -> tuple[float | None, float | None]:
        """Best-effort net PnL snapshot for smart-manager closes.

        Uses the current decision price as the exit and includes any realized PnL/fees
        already accumulated from earlier partial closes (for example TP1 partial).
        This keeps auto-trade stats useful even when we do not have an exchange order
        payload for the closing leg yet.
        """
        try:
            exit_p = _as_float(exit_price, 0.0)
            if exit_p <= 0:
                return None, None

            entry_p = _as_float(ref.get("entry_price"), _as_float(ref.get("entry"), 0.0))
            if entry_p <= 0:
                return None, None

            qty_ref = _as_float(ref.get("qty"), 0.0)
            if qty_ref <= 0 and qty_hint is not None:
                qty_ref = _as_float(qty_hint, 0.0)
            if qty_ref <= 0:
                return None, None

            side = str(ref.get("side") or "BUY").upper().strip()
            if side in ("SHORT", "SELL"):
                pnl_gross = (entry_p - exit_p) * qty_ref
            else:
                pnl_gross = (exit_p - entry_p) * qty_ref

            fee_rate = float(FEE_RATE_SPOT if str(market_type).lower() == "spot" else FEE_RATE_FUTURES)
            fees_est = fee_rate * ((entry_p * qty_ref) + (exit_p * qty_ref))

            realized_pnl = _as_float(ref.get("realized_pnl_usdt"), 0.0)
            realized_fee = _as_float(ref.get("realized_fee_usdt"), 0.0)

            pnl_net = float(pnl_gross) - float(fees_est) + float(realized_pnl) - float(realized_fee)
            alloc = float(allocated_usdt or 0.0)
            roi = (pnl_net / alloc * 100.0) if alloc > 0 else None
            return float(pnl_net), (float(roi) if roi is not None else None)
        except Exception:
            return None, None

    # One-time fast self-heal (at startup): populate meta.ref from api_order_ref for all OPEN positions.
    async def _meta_selfheal_once() -> None:
        try:
            rows0 = await db_store.list_open_autotrade_positions(limit=500)
        except Exception:
            return
        for rr in rows0 or []:
            try:
                ref0 = json.loads(rr.get("api_order_ref") or "{}")
            except Exception:
                continue

            meta0 = {}
            try:
                mr = rr.get("meta")
                if isinstance(mr, str):
                    meta0 = json.loads(mr or "{}") or {}
                elif isinstance(mr, dict):
                    meta0 = dict(mr)
            except Exception:
                meta0 = {}

            try:
                if meta0.get("ref"):
                    continue
                src_ref = ""
                for k in (
                    "ref",
                    "order_ref",
                    "client_order_ref",
                    "clientOrderId",
                    "client_order_id",
                    "orderLinkId",
                    "order_link_id",
                ):
                    v = ref0.get(k)
                    if v is not None and str(v).strip():
                        src_ref = str(v).strip()
                        break
                if src_ref:
                    # merge-patch only (keep any existing meta fields)
                    await db_store.update_autotrade_position_meta(row_id=int(rr.get("id") or 0), meta={"ref": src_ref}, replace=False)
            except Exception:
                pass

    try:
        await _meta_selfheal_once()
    except Exception:
        pass

    # Best-effort; never crash.
    while True:
        try:
            rows = await db_store.claim_open_autotrade_positions(owner=manager_worker_id, limit=manager_batch, lease_sec=manager_lease_sec)
            for r in rows:
                rid = int((r or {}).get('id') or 0)
                # Refresh lease so other replicas won't steal it mid-processing.
                try:
                    if rid > 0:
                        await db_store.touch_autotrade_position_lock(row_id=rid, owner=manager_worker_id, lease_sec=manager_lease_sec)
                except Exception:
                    pass

                try:
                    ref = json.loads(r.get("api_order_ref") or "{}")
                    tf = str(ref.get("signal_timeframe") or "")
                    kind = str(ref.get("signal_kind") or "")
                    is_mid = (kind.upper() == "MID") or _is_mid_tf(tf)
                except Exception:
                    continue

                # --- Meta (persistent per-position extra state) ---
                meta = {}
                try:
                    meta_raw = r.get("meta")
                    if isinstance(meta_raw, str):
                        meta = json.loads(meta_raw or "{}") or {}
                    elif isinstance(meta_raw, dict):
                        meta = dict(meta_raw)
                    else:
                        meta = {}
                except Exception:
                    meta = {}

                # --- Self-heal: if meta.ref is empty, copy from api_order_ref (slow migration without manual scripts) ---
                try:
                    if not (meta.get("ref") or ""):
                        src_ref = ""
                        for k in ("ref", "order_ref", "client_order_ref", "clientOrderId", "client_order_id", "orderLinkId", "order_link_id"):
                            v = ref.get(k)
                            if v is not None and str(v).strip():
                                src_ref = str(v).strip()
                                break
                        if src_ref:
                            meta["ref"] = src_ref
                            try:
                                await db_store.update_autotrade_position_meta(row_id=int(r.get("id") or 0), meta=meta, replace=False)
                            except Exception:
                                pass
                except Exception:
                    pass

                # Keep in-memory copy (used later in this loop)
                r["meta"] = meta

                async def _sync_pos_meta(extra: dict | None = None) -> None:
                    patch = {
                        "tp1_hit": bool(ref.get("tp1_hit") or meta.get("tp1_hit")),
                        "be_moved": bool(ref.get("be_moved") or meta.get("be_moved")),
                        "be_price": float(ref.get("be_price") or meta.get("be_price") or 0.0),
                        "tp1_partial": bool(ref.get("tp1_partial") or meta.get("tp1_partial")),
                        "be_pending": bool(ref.get("be_pending") or meta.get("be_pending")),
                        "direction": str(ref.get("direction") or meta.get("direction") or ""),
                        "entry_price": float(ref.get("entry_price") or meta.get("entry_price") or 0.0),
                        "tp1": float(ref.get("tp1") or meta.get("tp1") or 0.0),
                        "tp2": float(ref.get("tp2") or meta.get("tp2") or 0.0),
                        "sl": float(ref.get("sl") or meta.get("sl") or 0.0),
                        "qty": float(ref.get("qty") or meta.get("qty") or 0.0),
                    }
                    existing_reason = patch.get("closed_reason") or meta.get("closed_reason") or ref.get("closed_reason")
                    if existing_reason:
                        patch["closed_reason"] = _normalize_autotrade_close_reason(existing_reason)
                    if extra:
                        patch.update(extra)
                    if patch.get("closed_reason"):
                        patch["closed_reason"] = _normalize_autotrade_close_reason(patch.get("closed_reason"))
                    try:
                        await db_store.update_autotrade_position_meta(row_id=int(r.get("id") or 0), meta=patch, replace=False)
                        try:
                            meta.update(patch)
                            r["meta"] = meta
                        except Exception as e:
                            _smart_log_exception("smart_close_log", e)
                    except Exception:
                        pass

                try:
                    await _sync_pos_meta()
                except Exception:
                    pass

                ex = str(ref.get("exchange") or r.get("exchange") or "").lower()
                if ex not in ("binance", "bybit", "okx", "mexc", "gateio"):
                    continue

                uid = int(r.get("user_id"))
                mt = str(ref.get("market_type") or r.get("market_type") or "").lower()
                futures = (mt == "futures")

                # Heartbeat log for manager loop (kept enabled; rate-limited).
                try:
                    pos_id_tick = int(r.get("id") or 0)
                except Exception:
                    pos_id_tick = 0
                now_tick = time.time()
                last_tick = _SMART_TICK_TS.get(pos_id_tick, 0.0) if pos_id_tick else 0.0
                smart_tick_due = bool((not pos_id_tick) or (now_tick - last_tick >= 60.0))
                if smart_tick_due and pos_id_tick:
                    _SMART_TICK_TS[pos_id_tick] = now_tick
                sym_tick = str(ref.get("symbol") or r.get("symbol") or "")
                side_tick = str(ref.get("side") or r.get("side") or "")
                symbol = str(ref.get("symbol") or r.get("symbol") or "").upper()

                # Load keys
                row = await db_store.get_autotrade_keys_row(user_id=uid, exchange=ex, market_type=mt)
                if not row or not bool(row.get("is_active")):
                    continue
                try:
                    api_key = _decrypt_token(row.get("api_key_enc"))
                    api_secret = _decrypt_token(row.get("api_secret_enc"))
                except Exception:
                    continue

                # passphrase may be needed by OKX spot/futures helpers; keep it initialized
                # for all exchanges so reconcile never crashes on non-OKX futures paths.
                passphrase = ""
                if ex == "okx":
                    try:
                        passphrase = _decrypt_token(row.get("passphrase_enc")) if row.get("passphrase_enc") else ""
                    except Exception:
                        passphrase = ""

                # --- Soft reconcile: detect manual close and close stale OPEN rows ---
                # If user closed manually on exchange, SL/TP may never be FILLED -> DB can remain OPEN forever.
                # We periodically verify that the position/holding still exists on the exchange.
                try:
                    pos_id = int(r.get("id") or 0)
                except Exception:
                    pos_id = 0
                now_ts = time.time()
                last_ts = _LAST_RECONCILE_TS.get(pos_id, 0.0)
                opened_at = r.get("opened_at")
                open_age_sec = 999999.0
                try:
                    if hasattr(opened_at, "timestamp"):
                        open_age_sec = max(0.0, time.time() - float(opened_at.timestamp()))
                    elif opened_at:
                        open_age_sec = max(
                            0.0,
                            time.time() - dt.datetime.fromisoformat(str(opened_at).replace("Z", "+00:00")).timestamp(),
                        )
                except Exception:
                    open_age_sec = 999999.0

                try:
                    zero_hits = int(meta.get("reconcile_zero_hits") or 0)
                except Exception:
                    zero_hits = 0

                if pos_id and open_age_sec >= _SMART_RECONCILE_GRACE_SEC and (now_ts - last_ts) >= _RECONCILE_COOLDOWN_SEC:
                    _LAST_RECONCILE_TS[pos_id] = now_ts
                    try:
                        # Determine if position is still open on exchange
                        is_closed = False
                        if mt == "spot":
                            bal = await _spot_base_balance(ex=ex, api_key=api_key, api_secret=api_secret,
                                                           passphrase=(passphrase or None), symbol=symbol)
                            ref_qty = _as_float(ref.get("qty"), 0.0)
                            eps = max(_DUST_MIN, abs(ref_qty) * _DUST_PCT)
                            if bal <= eps:
                                is_closed = True
                        else:
                            # futures (Binance/Bybit/OKX in this codebase)
                            pos_side_dbg = (str(ref.get("position_side") or _binance_futures_position_side_from_direction(direction=ref.get("direction"), side=ref.get("side"))) if ex == "binance" else None)
                            size = await _futures_position_size(
                                ex=ex,
                                api_key=api_key,
                                api_secret=api_secret,
                                symbol=symbol,
                                category=str(ref.get("category") or "linear"),
                                passphrase=(passphrase or None),
                                position_side=pos_side_dbg,
                            )
                            size_f = abs(float(size or 0.0))
                            if _SMART_MANAGER_DEBUG_LOGS:
                                logger.info(
                                    "[SMART_RECONCILE] uid=%s ex=%s market=%s sym=%s size=%s pos_side=%s hedge=%s age=%.1fs zero_hits=%s",
                                    uid,
                                    ex,
                                    mt,
                                    symbol,
                                    size_f,
                                    str(pos_side_dbg or ""),
                                    bool(ref.get("hedge_mode")),
                                    open_age_sec,
                                    zero_hits,
                                )
                            if size_f <= _DUST_MIN:
                                zero_hits += 1
                                extra_meta = {
                                    "reconcile_zero_hits": zero_hits,
                                    "last_seen_size": size_f,
                                    "last_reconcile_age_sec": round(open_age_sec, 1),
                                    "last_reconcile_pos_side": str(pos_side_dbg or ""),
                                    "last_reconcile_hedge_mode": bool(ref.get("hedge_mode")),
                                }
                                if ex == "binance" and _SMART_BINANCE_DEBUG and _SMART_MANAGER_DEBUG_LOGS:
                                    entry_oid_dbg = 0
                                    try:
                                        entry_oid_dbg = int(ref.get("entry_order_id") or 0)
                                    except Exception:
                                        entry_oid_dbg = 0
                                    order_dbg = {}
                                    if entry_oid_dbg > 0:
                                        try:
                                            order_dbg = await _binance_order_status(
                                                api_key=api_key,
                                                api_secret=api_secret,
                                                symbol=symbol,
                                                order_id=entry_oid_dbg,
                                                futures=True,
                                            )
                                        except Exception as e:
                                            order_dbg = {"orderId": entry_oid_dbg, "_error": str(e)}
                                    pos_rows_dbg = []
                                    try:
                                        ctx_dbg = await _binance_futures_position_context(api_key=api_key, api_secret=api_secret, symbol=symbol)
                                        pos_rows_dbg = _binance_debug_compact_pos_rows(ctx_dbg.get("rows") or [])
                                    except Exception as e:
                                        pos_rows_dbg = [{"_error": str(e)}]
                                    extra_meta.update({
                                        "last_reconcile_entry_order": _binance_debug_compact_order(order_dbg),
                                        "last_reconcile_position_rows": pos_rows_dbg,
                                    })
                                    try:
                                        logger.info(
                                            "[SMART_RECONCILE_DEBUG] uid=%s ex=%s market=%s sym=%s order=%s rows=%s",
                                            uid,
                                            ex,
                                            mt,
                                            symbol,
                                            json.dumps(_binance_debug_compact_order(order_dbg), ensure_ascii=False),
                                            json.dumps(pos_rows_dbg, ensure_ascii=False),
                                        )
                                    except Exception:
                                        pass
                                await _sync_pos_meta(extra_meta)
                                is_closed = zero_hits >= _SMART_RECONCILE_ZERO_HITS
                            else:
                                if zero_hits:
                                    await _sync_pos_meta({
                                        "reconcile_zero_hits": 0,
                                        "last_seen_size": size_f,
                                        "last_reconcile_age_sec": round(open_age_sec, 1),
                                        "last_reconcile_pos_side": str(pos_side_dbg or ""),
                                        "last_reconcile_hedge_mode": bool(ref.get("hedge_mode")),
                                    })

                        if is_closed:
                            # Best-effort: cancel any known child orders to avoid stray fills after manual close.
                            # (Some exchanges allow reduce-only orders to remain; spot leftovers are especially risky.)
                            try:
                                if ex in ("binance", "bybit"):
                                    cat2 = str(ref.get("category") or ("linear" if mt == "futures" else "spot"))
                                    for oid in [ref.get("tp1_order_id"), ref.get("tp2_order_id"), ref.get("sl_order_id")]:
                                        if not oid:
                                            continue
                                        try:
                                            if ex == "binance":
                                                await _binance_cancel_order(
                                                    api_key=api_key,
                                                    api_secret=api_secret,
                                                    symbol=symbol,
                                                    order_id=int(oid),
                                                    futures=(mt == "futures"),
                                                )
                                            else:
                                                await _bybit_cancel_order(
                                                    api_key=api_key,
                                                    api_secret=api_secret,
                                                    category=cat2,
                                                    symbol=symbol,
                                                    order_id=str(oid),
                                                )
                                        except Exception:
                                            pass
                            except Exception:
                                pass

                            # Persist a reason so UI/debug can distinguish manual closes from TP/SL.
                            try:
                                if pos_id:
                                    await db_store.update_autotrade_position_meta(
                                        row_id=int(pos_id),
                                        meta={"closed_reason": "MANUAL_CLOSE", "closed_by_user": True},
                                        replace=False,
                                    )
                            except Exception:
                                pass

                            # Best-effort PnL: use current price at detection time.
                            entry = _as_float(ref.get("entry"), _as_float(r.get("entry"), 0.0))
                            qty = _as_float(ref.get("qty"), 0.0)
                            side = str(ref.get("side") or r.get("side") or "").upper()
                            allocated_usdt = _as_float(r.get("allocated_usdt"), 0.0)
                            px = 0.0
                            try:
                                direction_hint = str(ref.get("direction") or ("LONG" if side not in ("SELL", "SHORT") else "SHORT")).upper()
                                sig = Signal(
                                    symbol=symbol,
                                    market=("SPOT" if mt == "spot" else "FUTURES"),
                                    direction=direction_hint,
                                    timeframe="5m",
                                    entry=float(entry or 0.0),
                                    source_exchange=str(ex or "").upper(),
                                )
                                px, _px_src = await price_backend._get_price_with_source(sig)
                                px = float(px or 0.0)
                            except Exception:
                                px = 0.0
                            pnl_usdt = None
                            roi_percent = None
                            try:
                                if entry and qty and px:
                                    if mt == "futures":
                                        # futures: BUY=LONG, SELL=SHORT
                                        if side in ("SELL", "SHORT"):
                                            pnl = (entry - px) * qty
                                        else:
                                            pnl = (px - entry) * qty
                                    else:
                                        # spot: only long
                                        pnl = (px - entry) * qty
                                    pnl_usdt = float(pnl)
                                    if allocated_usdt > 0:
                                        roi_percent = float(pnl_usdt) / float(allocated_usdt) * 100.0
                            except Exception:
                                pnl_usdt = None
                                roi_percent = None

                            await db_store.close_autotrade_position(
                                user_id=uid,
                                signal_id=r.get("signal_id"),
                                exchange=ex,
                                market_type=mt,
                                status="CLOSED",
                                pnl_usdt=pnl_usdt,
                                roi_percent=roi_percent,
                                row_id=int(r.get("id") or 0),
                            )
                            # respect stop_after_close flag
                            try:
                                acc2 = await db_store.get_autotrade_access(uid)
                                if bool(acc2.get("autotrade_stop_after_close")):
                                    if await db_store.count_open_autotrade_positions(uid) <= 0:
                                        await db_store.finalize_autotrade_disable(uid)
                            except Exception:
                                pass
                            continue
                    except Exception as e:
                        # Never crash the manager loop because of reconcile.
                        is_binance_rl = (ex == "binance" and _binance_is_rate_limit_error_message(e))
                        is_binance_transient = (ex == "binance" and _binance_is_transient_error_message(e))
                        try:
                            await _sync_pos_meta({
                                "last_reconcile_error": str(e)[:500],
                                "last_reconcile_error_at": dt.datetime.now(dt.timezone.utc).isoformat(),
                                "last_reconcile_rate_limited": bool(is_binance_rl),
                                "last_reconcile_transient": bool(is_binance_transient),
                            })
                        except Exception as e:
                            _smart_log_exception("smart_close_ref_persist", e)
                        if is_binance_rl:
                            logger.info("Soft reconcile skipped for pos_id=%s due to Binance rate limit: %s", pos_id, e)
                        elif is_binance_transient:
                            _log_rate_limited(
                                f"smart_reconcile_transient:{ex}:{symbol}",
                                f"Soft reconcile transient Binance error for pos_id={pos_id} sym={symbol}: {e}",
                                every_s=max(30, int(_RECONCILE_COOLDOWN_SEC)),
                                level="warning",
                            )
                        else:
                            logger.exception("Soft reconcile error for pos_id=%s", pos_id)
                tp1_id = ref.get("tp1_order_id")
                tp2_id = ref.get("tp2_order_id")
                sl_id = ref.get("sl_order_id")
                be_moved = bool(ref.get("be_moved"))
                side_str = 'LONG' if str(ref.get('side','BUY')).upper() in ('BUY','LONG') else 'SHORT'
                if mt == 'spot' and side_str != 'LONG':
                    # Spot manager supports LONG only (no short spot).
                    # Futures SHORT must continue to the virtual management branch below.
                    await _sync_pos_meta({"closed_reason": "EXECUTION_ERROR", "error_detail": "unsupported_side"})
                    await db_store.close_autotrade_position(user_id=uid, signal_id=r.get('signal_id'), exchange=ex, market_type=mt, status='ERROR', row_id=int(r.get('id') or 0))
                    continue
                be_price = float(ref.get("be_price") or 0.0)
                close_side = str(ref.get("close_side") or ("SELL" if str(ref.get("side")) == "BUY" else "BUY")).upper()

                
                # -------- Virtual management (ALL exchanges / SPOT+FUTURES) --------
                # If ref["virtual"] is True, we manage by watching price and sending MARKET closes.
                if bool(ref.get("virtual")) or _SMART_PRO_CONTROL_REAL:

                    # If this position was opened with exchange TP/SL orders (virtual==False) but PRO-control is enabled,
                    # cancel child orders once to avoid double-execution and then manage it with the same PRO rules as virtual mode.
                    if (not bool(ref.get("virtual"))) and _SMART_PRO_CONTROL_REAL and (not bool(ref.get("pro_real_init"))):
                        try:
                            if ex == "binance":
                                for oid in [ref.get("tp1_order_id"), ref.get("tp2_order_id"), ref.get("sl_order_id")]:
                                    try:
                                        if oid:
                                            await _binance_cancel_order(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(oid), futures=(mt=="futures"))
                                    except Exception:
                                        pass
                            elif ex == "bybit":
                                cat = ("linear" if mt == "futures" else "spot")
                                for oid in [ref.get("tp1_order_id"), ref.get("tp2_order_id"), ref.get("sl_order_id")]:
                                    try:
                                        if oid:
                                            await _bybit_cancel_order(api_key=api_key, api_secret=api_secret, category=cat, symbol=symbol, order_id=str(oid))
                                    except Exception:
                                        pass
                        except Exception as e:
                            _smart_log_exception("smart_close_meta_sync", e)
                        # Clear stored child order ids so legacy branch won't touch them.
                        ref["tp1_order_id"] = None
                        ref["tp2_order_id"] = None
                        ref["sl_order_id"] = None
                        ref["be_moved"] = False
                        ref["pro_real_init"] = True
                        dirty = True
                    price_diag = "-"
                    sig = None
                    try:
                        # --- price (decision) ---
                        # Shared oracle for ALL exchanges / SPOT+FUTURES.
                        # Uses venue WS first when available, then other configured WS sources,
                        # and only falls back to REST/public when all WS sources miss.
                        direction_hint = str(ref.get("direction") or ("LONG" if str(ref.get("side")).upper() in ("BUY", "LONG") else "SHORT")).upper()
                        sig = Signal(
                            symbol=symbol,
                            market=("SPOT" if mt == "spot" else "FUTURES"),
                            direction=direction_hint,
                            timeframe="5m",
                            entry=float(ref.get("entry_price") or 0.0),
                            source_exchange=str(ex or "").upper(),
                        )
                        px, px_src = await price_backend._get_price_with_source(sig)
                        if float(px or 0.0) > 0:
                            if ref.get("px_decision_src") != str(px_src):
                                ref["px_decision_src"] = str(px_src)
                                dirty = True
                        else:
                            px = 0.0
                    except PriceUnavailableError as e:
                        px = 0.0
                        px_src = "-"
                        price_diag = f"{SMART_PRICE_DIAG_PATCH_ID} " + str(e)[:760]
                        if smart_tick_due and sig is not None:
                            try:
                                price_diag = await price_backend._smart_price_unavailable_diag(sig)
                            except Exception as diag_e:
                                price_diag = f"{SMART_PRICE_DIAG_PATCH_ID} diag_err:{type(diag_e).__name__}:{str(diag_e)[:180]}"
                    except Exception as e:
                        px = 0.0
                        px_src = "-"
                        price_diag = f"{SMART_PRICE_DIAG_PATCH_ID} unexpected:{type(e).__name__}:{str(e)[:260]}"
                        if smart_tick_due and sig is not None:
                            try:
                                price_diag = await price_backend._smart_price_unavailable_diag(sig)
                            except Exception:
                                pass

                    if not px or px <= 0:
                        if smart_tick_due:
                            try:
                                logger.info(
                                    "SMART_TICK uid=%s market=%s ex=%s sym=%s side=%s virtual=%s px=NA entry=%.10f tp1=%.10f tp2=%.10f sl=%.10f be=%.10f qty=%.10f state=%s mode=%s reason=%s px_src=%s diag=%s",
                                    uid,
                                    mt,
                                    ex,
                                    sym_tick,
                                    side_tick,
                                    bool(ref.get("virtual")),
                                    float(ref.get("entry_price") or 0.0),
                                    float(ref.get("tp1") or 0.0),
                                    float(ref.get("tp2") or 0.0),
                                    float(ref.get("sl") or 0.0),
                                    float(ref.get("be_price") or meta.get("be_price") or 0.0),
                                    float(ref.get("qty") or meta.get("qty") or 0.0),
                                    str(ref.get("sm_state") or "INIT").upper(),
                                    str(ref.get("tp1_mode") or "-").upper(),
                                    "PRICE_UNAVAILABLE",
                                    str(px_src or "-"),
                                    str(price_diag or "-")[:1200],
                                )
                            except Exception:
                                pass
                        continue

                    entry_p = float(ref.get("entry_price") or 0.0)
                    qty = float(ref.get("qty") or 0.0)
                    tp1 = float(ref.get("tp1") or 0.0)
                    tp2 = float(ref.get("tp2") or 0.0)
                    sl = float(ref.get("sl") or 0.0)
                    tp1_hit = bool(ref.get("tp1_hit"))
                    be_moved = bool(ref.get("be_moved"))
                    direction = str(ref.get("direction") or ("LONG" if str(ref.get("side")).upper() in ("BUY","LONG") else "SHORT")).upper()
                    # If BE is active, be_price is stored; otherwise computed at TP1.
                    be_price = float(ref.get("be_price") or 0.0)

                    def _smart_close_snapshot(exit_price: float | None = None, qty_override: float | None = None) -> tuple[float | None, float | None]:
                        px_used = float(exit_price if exit_price is not None else px)
                        qty_used = float(qty_override if qty_override is not None else qty)
                        return _estimate_autotrade_pnl_snapshot(
                            ref=ref,
                            exit_price=px_used,
                            market_type=mt,
                            allocated_usdt=float(r.get("allocated_usdt") or 0.0),
                            qty_hint=qty_used,
                        )

                    async def _mark_local_full_close(close_reason: str, *, close_price_value: float | None = None, close_price_source: str | None = None, close_note: str | None = None, tp1_hit: bool | None = None, be_moved_value: bool | None = None) -> None:
                        reason_norm = _normalize_autotrade_close_reason(close_reason or "SYNC_CLOSE")
                        try:
                            close_px_keep = float(close_price_value) if close_price_value is not None else float(px)
                        except Exception:
                            close_px_keep = float(px)
                        close_px_src = str(close_price_source or ("market" if reason_norm not in ("TP2", "FULL_TP1", "FULL_TP1_NO_TP2", "BE", "SL") else "signal"))
                        try:
                            logger.info(
                                "SMART_CLOSE uid=%s market=%s ex=%s sym=%s side=%s virtual=%s px=%.10f entry=%.10f tp1=%.10f tp2=%.10f sl=%.10f be=%.10f qty=%.10f reason=%s close_px=%.10f close_px_src=%s note=%s px_src=%s",
                                uid,
                                mt,
                                ex,
                                symbol,
                                str(ref.get("side") or side_tick or ""),
                                bool(ref.get("virtual")),
                                float(px),
                                float(entry_p),
                                float(tp1),
                                float(tp2),
                                float(sl),
                                float(be_price),
                                float(qty),
                                reason_norm,
                                float(close_px_keep),
                                close_px_src,
                                str(close_note or ""),
                                str(px_src or "-"),
                            )
                        except Exception as e:
                            _smart_log_exception("smart_notify_send", e)
                        ref["qty"] = 0.0
                        ref["closed_reason"] = reason_norm
                        if close_px_keep > 0:
                            ref["closed_price"] = float(close_px_keep)
                            ref["closed_price_source"] = close_px_src
                        if close_note:
                            ref["closed_note"] = str(close_note)
                        if tp1_hit is not None:
                            ref["tp1_hit"] = bool(tp1_hit)
                        if be_moved_value is not None:
                            ref["be_moved"] = bool(be_moved_value)
                        try:
                            await db_store.update_autotrade_order_ref(
                                row_id=int(r.get("id") or 0),
                                api_order_ref=json.dumps(ref),
                            )
                        except Exception:
                            pass
                        patch = {
                            "closed_reason": reason_norm,
                            "qty": 0.0,
                        }
                        if close_px_keep > 0:
                            patch["closed_price"] = float(close_px_keep)
                            patch["closed_price_source"] = close_px_src
                        if close_note:
                            patch["closed_note"] = str(close_note)
                        if tp1_hit is not None:
                            patch["tp1_hit"] = bool(tp1_hit)
                        if be_moved_value is not None:
                            patch["be_moved"] = bool(be_moved_value)
                        be_px_keep = float(ref.get("be_price") or meta.get("be_price") or 0.0)
                        if be_px_keep > 0:
                            patch["be_price"] = be_px_keep
                        try:
                            await _sync_pos_meta(patch)
                        except Exception:
                            pass

                    if qty <= 0:
                        existing_reason = _normalize_autotrade_close_reason(ref.get("closed_reason") or meta.get("closed_reason") or "SYNC_CLOSE")
                        await _sync_pos_meta({"closed_reason": existing_reason, "tp1_hit": bool(ref.get("tp1_hit") or meta.get("tp1_hit")), "be_moved": bool(ref.get("be_moved") or meta.get("be_moved")), "be_price": float(ref.get("be_price") or meta.get("be_price") or 0.0)})
                        pnl_usdt, roi_percent = _smart_close_snapshot()

                        await db_store.close_autotrade_position(
                            user_id=uid,
                            signal_id=r.get("signal_id"),
                            exchange=ex,
                            market_type=mt,
                            status="CLOSED",
                            pnl_usdt=pnl_usdt,
                            roi_percent=roi_percent,
                            row_id=int(r.get("id") or 0),
                        )
                        continue

                    async def _close_market(q: float) -> bool:
                        nonlocal last_close_explain, last_close_norm_qty
                        requested_qty = max(0.0, float(q))
                        last_close_explain = ""
                        last_close_norm_qty = 0.0
                        if requested_qty <= 0:
                            last_close_explain = "requested qty is zero"
                            return False

                        tracked_qty = max(0.0, float(qty))
                        full_close_requested = (tracked_qty <= 0.0) or (requested_qty >= max(tracked_qty * 0.995, tracked_qty - 1e-12))
                        raw_qty = float(requested_qty)
                        actual_qty = 0.0
                        category_close = str(ref.get("category") or ("linear" if mt == "futures" else "spot"))

                        try:
                            if full_close_requested:
                                if mt == "spot":
                                    actual_qty = float(await _spot_base_balance(ex=ex, api_key=api_key, api_secret=api_secret, passphrase=passphrase, symbol=symbol))
                                elif ex in ("binance", "bybit", "okx"):
                                    actual_qty = abs(float(await _futures_position_size(
                                        ex=ex,
                                        api_key=api_key,
                                        api_secret=api_secret,
                                        symbol=symbol,
                                        category=category_close,
                                        passphrase=passphrase,
                                        position_side=(str(ref.get("position_side") or _binance_futures_position_side_from_direction(direction=direction, side=ref.get("side"))) if ex == "binance" else None),
                                    )))
                        except Exception as e:
                            _log_rate_limited(
                                f"smart_actual_qty_err:{uid}:{ex}:{mt}:{symbol}",
                                f"[SMART] actual size fetch failed {ex}/{mt} {symbol}: {e}",
                                every_s=120,
                                level="debug",
                            )
                            actual_qty = 0.0

                        if actual_qty > 0:
                            raw_qty = float(actual_qty)

                        # For real reduce-only close orders do not reject by minNotional/minQty.
                        q2 = await _normalize_close_qty(ex=ex, mt=mt, symbol=symbol, qty=raw_qty, px=px, is_reduce_close=True)
                        last_close_norm_qty = float(q2 or 0.0)

                        if ex == "bybit" and mt == "spot":
                            qty_step_dbg = 0.0
                            try:
                                qty_step_dbg, _min_qty_dbg, _tick_dbg = await _bybit_instrument_filters(category="spot", symbol=symbol)
                            except Exception:
                                qty_step_dbg = 0.0
                            logger.info(
                                "[SMART] bybit spot close qty symbol=%s category=spot tracked_qty=%s requested_qty=%s actual_qty=%s qty_step=%s normalized_qty=%s",
                                symbol,
                                tracked_qty,
                                requested_qty,
                                actual_qty,
                                qty_step_dbg,
                                q2,
                            )

                        if q2 <= 0:
                            last_close_explain = _sm_reason_qty_zero(requested_qty, actual_qty)
                            _log_rate_limited(
                                f"smart_skip_small:{uid}:{ex}:{mt}:{symbol}",
                                f"[SMART] skip close: normalized qty is zero {ex}/{mt} {symbol} px={px} requested={requested_qty} actual={actual_qty}",
                                every_s=120,
                                level=("info" if mt == "spot" else "debug"),
                            )
                            return False
                        # Spot short is not supported in this bot; virtual logic assumes LONG for spot.
                        if mt == "spot":
                            if ex == "binance":
                                await _binance_spot_market_sell_base(api_key=api_key, api_secret=api_secret, symbol=symbol, qty=q2)
                            elif ex == "bybit":
                                await _bybit_order_create(
                                    api_key=api_key,
                                    api_secret=api_secret,
                                    category="spot",
                                    symbol=symbol,
                                    side="Sell",
                                    order_type="Market",
                                    qty=q2,
                                    market_unit="baseCoin",
                                )
                                logger.info("[SMART] bybit spot market close sent symbol=%s qty=%s", symbol, q2)
                            elif ex == "okx":
                                await _okx_spot_market_sell(api_key=api_key, api_secret=api_secret, passphrase=passphrase or "", symbol=symbol, base_qty=q2)
                            elif ex == "mexc":
                                await _mexc_spot_market_sell(api_key=api_key, api_secret=api_secret, symbol=symbol, base_qty=q2)
                            else:
                                await _gateio_spot_market_sell(api_key=api_key, api_secret=api_secret, symbol=symbol, base_qty=q2)
                            last_close_explain = _sm_reason_market_close_sent(q2)
                            return True

                        # Futures
                        close_side = "SELL" if direction == "LONG" else "BUY"
                        if ex == "binance":
                            await _binance_futures_reduce_market(
                                api_key=api_key,
                                api_secret=api_secret,
                                symbol=symbol,
                                side=close_side,
                                qty=q2,
                                position_side=str(ref.get("position_side") or _binance_futures_position_side_from_direction(direction=direction, side=ref.get("side"))),
                                hedge_mode=(bool(ref.get("hedge_mode")) if ref.get("hedge_mode") is not None else None),
                            )
                        elif ex == "bybit":
                            await _bybit_order_create(
                                api_key=api_key,
                                api_secret=api_secret,
                                category=category_close,
                                symbol=symbol,
                                side=("Sell" if close_side == "SELL" else "Buy"),
                                order_type="Market",
                                qty=q2,
                                reduce_only=True,
                            )
                        elif ex == "okx":
                            await _okx_futures_reduce_market(
                                api_key=api_key,
                                api_secret=api_secret,
                                passphrase=passphrase or "",
                                symbol=symbol,
                                side=("sell" if close_side == "SELL" else "buy"),
                                qty=q2,
                            )
                        else:
                            # Other futures exchanges aren't supported in this bot; close silently
                            raise ExchangeAPIError("unsupported futures exchange in virtual mode")
                        last_close_explain = _sm_reason_market_close_sent(q2)
                        return True

                    def _hit_sl() -> bool:
                        if sl <= 0:
                            return False
                        return (px <= sl) if direction == "LONG" else (px >= sl)

                    def _hit_tp(level: float) -> bool:
                        if level <= 0:
                            return False
                        return (px >= level) if direction == "LONG" else (px <= level)

                    def _hit_be() -> bool:
                        if be_price <= 0:
                            return False
                        return (px <= be_price) if direction == "LONG" else (px >= be_price)

                    def _smart_tick_reason() -> str:
                        try:
                            closed_reason = _normalize_autotrade_close_reason(
                                ref.get("closed_reason") or meta.get("closed_reason") or ""
                            )
                            if closed_reason:
                                return f"CLOSED_{closed_reason}"
                            if qty <= 0:
                                return "QTY_ZERO_SYNC_CLOSE"
                            if tp2 > 0 and _hit_tp(tp2):
                                return "TP2_REACHED_PENDING_CLOSE"
                            if tp1 > 0 and (not tp1_hit) and _hit_tp(tp1):
                                return "TP1_REACHED_PENDING_DECISION"
                            if bool(ref.get("tp1_partial")) and bool(ref.get("be_pending")) and (not be_moved):
                                ok_confirm = (px >= entry_p) if direction == "LONG" else (px <= entry_p)
                                return "WAIT_BE_ARM_CONFIRM" if ok_confirm else "WAIT_BE_ARM_PRICE_CONFIRM"
                            if be_moved and _hit_be():
                                return "BE_REACHED_PENDING_CLOSE"
                            if _hit_sl():
                                return "SL_REACHED_PENDING_CLOSE"
                            if tp1_hit and str(ref.get("tp1_mode") or "").upper() == "HOLD_TO_TP2":
                                return "HOLD_TO_TP2"
                            if bool(ref.get("tp1_partial")) and be_moved:
                                return "WAIT_TP2_OR_BE"
                            if tp1_hit:
                                return "WAIT_MANAGED_EXIT"
                            if armed_sl:
                                return "MONITOR_TP_SL"
                            return "MONITOR_HARD_SL"
                        except Exception:
                            return "MONITOR"

                    if smart_tick_due:
                        try:
                            logger.info(
                                "SMART_TICK uid=%s market=%s ex=%s sym=%s side=%s virtual=%s px=%.10f entry=%.10f tp1=%.10f tp2=%.10f sl=%.10f be=%.10f qty=%.10f state=%s mode=%s reason=%s px_src=%s",
                                uid,
                                mt,
                                ex,
                                sym_tick,
                                side_tick,
                                bool(ref.get("virtual")),
                                float(px),
                                float(entry_p),
                                float(tp1),
                                float(tp2),
                                float(sl),
                                float(be_price),
                                float(qty),
                                str(ref.get("sm_state") or "INIT").upper(),
                                str(ref.get("tp1_mode") or "-").upper(),
                                _smart_tick_reason(),
                                str(px_src or "-"),
                            )
                        except Exception:
                            pass

                    # --- SMART virtual manager (no immediate SL/TP; momentum-aware TP; delayed BE; reversal exit) ---
                    now_ts = time.time()

                    # Tunables (env)
                    ARM_SL_AFTER_PCT = float(os.getenv("SMART_ARM_SL_AFTER_PCT", "0.22") or 0.22)          # legacy compatibility knob; structural SL below arms immediately when SL exists
                    HARD_SL_PCT      = float(os.getenv("SMART_HARD_SL_PCT", "2.80") or 2.80)               # emergency stop while SL is not armed

                    # TP1 -> TP2 probability decision
                    TP2_PROB_STRONG  = float(os.getenv("SMART_TP2_PROB_STRONG", "0.72") or 0.72)           # hold to TP2 if prob >= strong
                    TP2_PROB_MED     = float(os.getenv("SMART_TP2_PROB_MED", "0.45") or 0.45)              # partial at TP1 if prob >= med
                    TP1_PARTIAL_PCT  = float(os.getenv("SMART_TP1_PARTIAL_PCT", "0.50") or 0.50)           # partial close size at TP1 (weak/medium)
                    TP1_PARTIAL_MIN_PCT = _env_float_mid("SMART_TP1_PARTIAL_MIN_PCT", 0.25, is_mid)
                    TP1_PARTIAL_MAX_PCT = _env_float_mid("SMART_TP1_PARTIAL_MAX_PCT", max(0.55, TP1_PARTIAL_PCT), is_mid)
                    FORCE_FULL_TP1_NO_TP2 = (os.getenv("SMART_FORCE_FULL_TP1_IF_NO_TP2", "1").strip().lower() not in ("0","false","no","off"))

                    # Momentum / structure
                    MOM_WINDOW_SEC   = float(os.getenv("SMART_MOMENTUM_WINDOW_SEC", "30") or 30)           # anchor update window
                    EARLY_EXIT_NEG_PCT= _env_float_mid("SMART_EARLY_EXIT_MOM_NEG_PCT", 0.16, is_mid)    # adverse move threshold vs anchor
                    EARLY_EXIT_CONSEC= _env_int_mid("SMART_EARLY_EXIT_CONSEC_NEG", 2, is_mid)       # consecutive adverse hits
                    EARLY_EXIT_MIN_GAIN= _env_float_mid("SMART_EARLY_EXIT_MIN_GAIN_PCT", 0.12, is_mid)  # only early-exit if already in profit

                    # Weakness exit BEFORE TP1 (protect early profit when move fades)
                    WEAKNESS_EXIT_ENABLED = (os.getenv("SMART_WEAKNESS_EXIT_ENABLED", "1").strip().lower() not in ("0","false","no","off"))
                    WEAKNESS_MIN_GAIN = _env_float_mid("SMART_WEAKNESS_MIN_GAIN_PCT", 0.45, is_mid)
                    WEAKNESS_MIN_GIVEBACK = _env_float_mid("SMART_WEAKNESS_MIN_GIVEBACK_PCT", 0.28, is_mid)
                    WEAKNESS_GIVEBACK_FRAC = _env_float_mid("SMART_WEAKNESS_GIVEBACK_FRACTION", 0.45, is_mid)
                    WEAKNESS_MIN_TP1_PROGRESS = _env_float_mid("SMART_WEAKNESS_MIN_TP1_PROGRESS", 0.15, is_mid)
                    WEAKNESS_TP1_PROGRESS_MAX = _env_float_mid("SMART_WEAKNESS_TP1_PROGRESS_MAX", 0.82, is_mid)
                    WEAKNESS_NEG_HITS = _env_int_mid("SMART_WEAKNESS_NEG_HITS", 1, is_mid)
                    WEAKNESS_MIN_RETAIN_PCT = _env_float_mid("SMART_WEAKNESS_MIN_RETAIN_PCT", 0.05, is_mid)

                    # Post-entry invalidation BEFORE SL (allows early exit in a small loss / tiny profit)
                    INVALIDATION_EXIT_ENABLED = (os.getenv("SMART_INVALIDATION_EXIT_ENABLED", "1" if is_mid else "0").strip().lower() not in ("0","false","no","off"))
                    INVALIDATION_MIN_BARS = _env_int_mid("SMART_INVALIDATION_MIN_5M_BARS", 1, is_mid)
                    INVALIDATION_MAX_BARS = _env_int_mid("SMART_INVALIDATION_MAX_5M_BARS", 6, is_mid)
                    INVALIDATION_SCORE_CLOSE = _env_int_mid("SMART_INVALIDATION_SCORE_CLOSE", 3, is_mid)
                    INVALIDATION_SCORE_LOSS = _env_int_mid("SMART_INVALIDATION_SCORE_LOSS", 2, is_mid)
                    INVALIDATION_NEG_HITS = _env_int_mid("SMART_INVALIDATION_NEG_HITS", max(2, EARLY_EXIT_CONSEC), is_mid)
                    INVALIDATION_MIN_LOSS_PCT = _env_float_mid("SMART_INVALIDATION_MIN_LOSS_PCT", 0.10, is_mid)
                    INVALIDATION_MAX_LOSS_PCT = _env_float_mid("SMART_INVALIDATION_MAX_LOSS_PCT", 0.55, is_mid)
                    INVALIDATION_SL_FRAC_CAP = _env_float_mid("SMART_INVALIDATION_SL_FRAC_CAP", 0.30, is_mid)
                    INVALIDATION_SCORE_OVERRIDE = _env_int_mid("SMART_INVALIDATION_SCORE_OVERRIDE", 4, is_mid)
                    INVALIDATION_CACHE_SEC = _env_float_mid("SMART_INVALIDATION_CACHE_SEC", 20.0, is_mid)
                    INVALIDATION_RECLAIM_BUFFER_PCT = _env_float_mid("SMART_INVALIDATION_RECLAIM_BUFFER_PCT", 0.05, is_mid)
                    INVALIDATION_RECLAIM_MIN_GAIN_PCT = _env_float_mid("SMART_INVALIDATION_RECLAIM_MIN_GAIN_PCT", 0.10, is_mid)

                    # Dynamic BE
                    BE_DELAY_SEC     = _env_float_mid("SMART_BE_DELAY_SEC", 25.0, is_mid)                  # delay before arming BE after partial TP1
                    BE_MIN_PCT       = _env_float_mid("SMART_BE_MIN_PCT", 0.06, is_mid)
                    BE_MAX_PCT       = float(os.getenv("SMART_BE_MAX_PCT", "0.45") or 0.45)
                    BE_VOL_MULT      = float(os.getenv("SMART_BE_VOL_MULT", "0.35") or 0.35)
                    BE_ARM_PCT_TO_TP2= float(os.getenv("SMART_BE_ARM_PCT_TO_TP2", "0.15") or 0.15)         # arm BE only after this progress to TP2

                    # Peak -> reversal
                    PEAK_MIN_GAIN_PCT= float(os.getenv("SMART_PEAK_MIN_GAIN_PCT", "0.42") or 0.42)
                    REV_EXIT_PCT     = float(os.getenv("SMART_REVERSAL_EXIT_PCT", "0.32") or 0.32)
                    PROFIT_LOCK_ENABLED = (os.getenv("SMART_PROFIT_LOCK_ENABLED", "1").strip().lower() not in ("0","false","no","off"))
                    PROFIT_LOCK_MIN_PCT = _env_float_mid("SMART_PROFIT_LOCK_MIN_PCT", 0.18, is_mid)
                    PROFIT_LOCK_MAX_PCT = _env_float_mid("SMART_PROFIT_LOCK_MAX_PCT", 0.55, is_mid)

                    # TP2 runner: if TP2 is hit with strong impulse, do not close immediately;
                    # keep the position alive for a small extra push and exit either near the local peak
                    # on reversal, or immediately if price falls back to TP2.
                    TP2_RUN_ENABLED = (os.getenv("SMART_TP2_RUN_ENABLED", "1").strip().lower() not in ("0","false","no","off"))
                    TP2_RUN_MIN_MOM_PCT = _env_float_mid("SMART_TP2_RUN_MIN_MOM_PCT", 0.18, is_mid)
                    TP2_RUN_MIN_PROB = _env_float_mid("SMART_TP2_RUN_MIN_PROB", 0.72, is_mid)
                    TP2_RUN_MIN_PEAK_EXT_PCT = _env_float_mid("SMART_TP2_RUN_MIN_PEAK_EXT_PCT", 0.22, is_mid)
                    TP2_RUN_PEAK_GIVEBACK_PCT = _env_float_mid("SMART_TP2_RUN_PEAK_GIVEBACK_PCT", 0.24, is_mid)
                    TP2_RUN_MIN_HOLD_SEC = _env_float_mid("SMART_TP2_RUN_MIN_HOLD_SEC", 1.0, is_mid)

                    # Persistent state in ref (typed overlay to reduce fragile dict access).
                    sm_pos = SmartPositionState.from_ref(
                        ref,
                        direction=direction,
                        entry_price=entry_p,
                        current_price=px,
                        now_ts=now_ts,
                    )
                    state = sm_pos.sm_state
                    armed_sl = sm_pos.armed_sl
                    tp1_seen = sm_pos.tp1_seen
                    tp1_partial = sm_pos.tp1_partial
                    tp1_ts = sm_pos.tp1_ts
                    be_pending = sm_pos.be_pending
                    last_px = sm_pos.last_px
                    last_px_ts = sm_pos.last_px_ts
                    best_px = sm_pos.best_px
                    hard_sl = sm_pos.hard_sl
                    tp2_runner_active = sm_pos.tp2_runner_active
                    tp2_runner_peak_px = sm_pos.tp2_runner_peak_px
                    tp2_runner_floor_px = float(sm_pos.tp2_runner_floor_px or tp2 or 0.0)
                    tp2_runner_armed_ts = sm_pos.tp2_runner_armed_ts

                    dirty = False
                    last_close_explain = ""
                    last_close_norm_qty = 0.0

                    def _fmt_sm_price(v: float) -> str:
                        try:
                            return f"{float(v):.10f}".rstrip("0").rstrip(".")
                        except Exception:
                            return str(v)

                    async def _notify_smart_once(kind: str, text_msg: str, *, cooldown_sec: float = 30.0) -> None:
                        nonlocal dirty
                        if not callable(notify_smart_event):
                            return
                        now_notice = float(time.time())
                        key = f"sm_notify_{kind}_ts"
                        try:
                            last_notice = float(ref.get(key) or 0.0)
                        except Exception:
                            last_notice = 0.0
                        if cooldown_sec > 0 and (now_notice - last_notice) < float(cooldown_sec):
                            return
                        ref[key] = float(now_notice)
                        dirty = True
                        try:
                            await notify_smart_event(uid, text_msg)
                        except Exception:
                            pass

                    def _sm_side_text() -> str:
                        return _tr(uid, "sm_side_short") if direction == "SHORT" else _tr(uid, "sm_side_long")

                    def _sm_decision_text(decision: str) -> str:
                        key = {
                            "CLOSED": "sm_decision_closed",
                            "NOT CLOSED": "sm_decision_not_closed",
                            "PARTIAL CLOSED": "sm_decision_partial_closed",
                        }.get(str(decision or "").upper(), "sm_decision_not_closed")
                        return _tr(uid, key)

                    def _sm_level_text(level_label: str) -> str:
                        key = {
                            "SL": "lbl_sl",
                            "TP1": "lbl_tp1",
                            "TP2": "lbl_tp2",
                            "HARD SL": "lbl_hard_sl",
                            "PEAK": "lbl_peak",
                            "TRAIL": "lbl_trail",
                        }.get(str(level_label or "").upper())
                        return _tr(uid, key) if key else str(level_label)

                    def _sm_mode_text(mode: str) -> str:
                        key = {
                            "HOLD_TO_TP2": "sm_mode_hold_to_tp2",
                            "PARTIAL_TP1": "sm_mode_partial_tp1",
                            "FULL_TP1": "sm_mode_full_tp1",
                            "FULL_TP1_NO_TP2": "sm_mode_full_tp1_no_tp2",
                        }.get(str(mode or "").upper())
                        return _tr(uid, key) if key else str(mode)

                    def _sm_reason_market_close_sent(qty_sent: float) -> str:
                        return _trf(uid, "sm_reason_market_close_sent", qty=_fmt_sm_price(qty_sent))

                    def _sm_reason_qty_zero(requested_qty: float, actual_qty: float) -> str:
                        return _trf(uid, "sm_reason_qty_zero", requested=_fmt_sm_price(requested_qty), actual=_fmt_sm_price(actual_qty))

                    def _sm_reason_close_returned_false() -> str:
                        return _tr(uid, "sm_reason_close_returned_false")

                    def _sm_reason_execution_error(detail: str = "") -> str:
                        detail_clean = str(detail or "").strip()
                        if not detail_clean:
                            detail_clean = _sm_reason_close_returned_false()
                        return _trf(uid, "sm_reason_execution_error", detail=detail_clean)

                    def _sm_reason_weakness_exit(*, best_gain_pct: float, giveback_pct: float, giveback_frac: float, progress_to_tp1: float, neg_hits: int) -> str:
                        return _trf(
                            uid,
                            "sm_reason_weakness_exit",
                            best_gain=f"{best_gain_pct:.2f}",
                            giveback=f"{giveback_pct:.2f}",
                            giveback_frac=f"{giveback_frac * 100.0:.0f}",
                            progress=f"{progress_to_tp1:.2f}",
                            neg_hits=int(neg_hits),
                        )

                    def _sm_reason_early_exit(*, neg_hits: int, need_hits: int, gain_now_pct: float, min_gain_pct: float, adverse_pct: float, adverse_need_pct: float) -> str:
                        return _trf(
                            uid,
                            "sm_reason_early_exit",
                            neg_hits=int(neg_hits),
                            need_hits=int(need_hits),
                            gain_now=f"{gain_now_pct:.2f}",
                            min_gain=f"{min_gain_pct:.2f}",
                            adverse=f"{adverse_pct:.2f}",
                            adverse_need=f"{adverse_need_pct:.2f}",
                        )

                    def _sm_reason_reversal_exit(*, gain_pct: float, retrace_pct: float, gain_need: float, retrace_need: float) -> str:
                        return _trf(
                            uid,
                            "sm_reason_reversal_exit",
                            gain=f"{gain_pct:.2f}",
                            retrace=f"{retrace_pct:.2f}",
                            gain_need=f"{gain_need:.2f}",
                            retrace_need=f"{retrace_need:.2f}",
                        )

                    def _sm_invalidation_component_text(name: str) -> str:
                        key = {
                            "bos_against": "sm_inv_bos_against",
                            "reclaim_loss": "sm_inv_reclaim_loss",
                            "vwap_loss": "sm_inv_vwap_loss",
                            "ema20_loss": "sm_inv_ema20_loss",
                            "trend_loss": "sm_inv_trend_loss",
                            "slow_drift": "sm_inv_slow_drift",
                        }.get(str(name or "").strip().lower())
                        return _tr(uid, key) if key else str(name or "")

                    def _sm_reason_invalidation_exit(*, score: int, loss_now_pct: float, max_loss_pct: float, full_sl_loss_pct: float, bars_since_entry: int, components: str) -> str:
                        comp_tokens = [str(x).strip() for x in str(components or "").split(",") if str(x).strip()]
                        comp_text = ", ".join(_sm_invalidation_component_text(x) for x in comp_tokens) or "-"
                        return _trf(
                            uid,
                            "sm_reason_invalidation_exit",
                            score=int(score),
                            loss=f"{loss_now_pct:.2f}",
                            max_loss=f"{max_loss_pct:.2f}",
                            full_sl=f"{full_sl_loss_pct:.2f}",
                            age_bars=int(bars_since_entry),
                            components=comp_text,
                        )

                    def _sm_reason_trail_exit(*, trail_price: float, current_price: float, confirm_sec: float) -> str:
                        return _trf(
                            uid,
                            "sm_reason_trail_exit",
                            trail_price=_fmt_sm_price(trail_price),
                            current_price=_fmt_sm_price(current_price),
                            confirm_sec=f"{confirm_sec:.1f}",
                        )

                    def _sm_join_reason(*parts: str) -> str:
                        out = [str(x).strip() for x in parts if str(x or "").strip()]
                        return "; ".join(out)

                    def _clamp01(v: float) -> float:
                        return clamp01(v)

                    def _smart_dynamic_partial_pct(*, prob_tp2: float, prog_to_tp2: float, mom_fav_pct: float, dist_pct: float, giveback_frac: float) -> float:
                        return SmartDecisionEngine.compute_dynamic_partial_pct(
                            prob_tp2=prob_tp2,
                            prog_to_tp2=prog_to_tp2,
                            mom_fav_pct=mom_fav_pct,
                            dist_pct=dist_pct,
                            giveback_frac=giveback_frac,
                            tp1_partial_pct=TP1_PARTIAL_PCT,
                            tp1_partial_min_pct=TP1_PARTIAL_MIN_PCT,
                            tp1_partial_max_pct=TP1_PARTIAL_MAX_PCT,
                        )

                    async def _notify_smart_decision(trigger: str, decision: str, *, level_label: str, level_price: float, reason: str, cooldown_sec: float = 30.0, decision_price: float | None = None) -> None:
                        try:
                            px_decision_val = float(decision_price) if decision_price is not None else float(px)
                        except Exception:
                            px_decision_val = float(px)
                        txt = _trf(
                            uid,
                            "sm_msg_decision",
                            title=_tr(uid, "sm_title"),
                            symbol=symbol,
                            market=_market_label(uid, mt),
                            side=_sm_side_text(),
                            trigger=trigger,
                            decision=_sm_decision_text(decision),
                            px_decision=_fmt_sm_price(px_decision_val),
                            level_label=_sm_level_text(level_label),
                            level_price=_fmt_sm_price(level_price),
                            reason=reason,
                            source=str(px_src or "-"),
                        )
                        await _notify_smart_once(f"{trigger}:{decision}", txt, cooldown_sec=cooldown_sec)


                    # Initialize hard emergency SL once (while SL is not armed).
                    if hard_sl <= 0 and entry_p > 0:
                        if direction == "LONG":
                            hard_sl = entry_p * (1.0 - (max(0.2, HARD_SL_PCT) / 100.0))
                        else:
                            hard_sl = entry_p * (1.0 + (max(0.2, HARD_SL_PCT) / 100.0))
                        ref["hard_sl"] = float(hard_sl)
                        dirty = True

                    # Update best price (peak) in favorable direction
                    if direction == "LONG":
                        if px > best_px:
                            best_px = px
                            ref["best_px"] = float(best_px)
                            dirty = True
                    else:
                        if px < best_px:
                            best_px = px
                            ref["best_px"] = float(best_px)
                            dirty = True

                    # --- OPTIONAL trailing stop after TP1 (uses ATR(5m) if available) ---
                    TRAIL_AFTER_TP1 = (os.getenv("SMART_TRAIL_AFTER_TP1", "0").strip().lower() not in ("0","false","no","off"))
                    TRAIL_ATR_MULT  = float(os.getenv("SMART_TRAIL_ATR_MULT", "1.30") or 1.30)
                    TRAIL_CONFIRM_SEC = float(os.getenv("SMART_TRAIL_CONFIRM_SEC", "2") or 2)
                    # Prefer ATR(5m) from signal; fallback to ATR% (30m) stored on ref (if present)
                    atr5_ref = float(ref.get("atr5") or 0.0)
                    if atr5_ref <= 0 and entry_p > 0:
                        try:
                            atrp = float(ref.get("atr_pct") or 0.0)
                            atr5_ref = (atrp / 100.0) * entry_p if atrp > 0 else 0.0
                        except Exception:
                            atr5_ref = 0.0

                    if TRAIL_AFTER_TP1 and atr5_ref > 0 and bool(ref.get("tp1_seen")):
                        # activate only after TP1 decision (partial or hold); protect profits on pullback
                        if direction == "LONG":
                            trail_px = float(best_px) - (max(0.5, TRAIL_ATR_MULT) * float(atr5_ref))
                        else:
                            trail_px = float(best_px) + (max(0.5, TRAIL_ATR_MULT) * float(atr5_ref))
                        if trail_px > 0:
                            ref["trail_px"] = float(trail_px)
                            # track how long price stayed beyond trail
                            t_first = float(ref.get("trail_first_ts") or 0.0)
                            hit_trail = (px <= trail_px) if direction == "LONG" else (px >= trail_px)
                            if hit_trail:
                                if t_first <= 0:
                                    ref["trail_first_ts"] = float(now_ts)
                                    dirty = True
                                elif (now_ts - t_first) >= TRAIL_CONFIRM_SEC:
                                    # close remaining qty (market reduce-only)
                                    trail_closed = False
                                    try:
                                        trail_closed = await _close_market(qty)
                                    except Exception as e:
                                        _log_rate_limited(f"smart_trail_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] trail close failed {ex}/{mt} {symbol}: {e}", every_s=30, level="error")
                                    if trail_closed:
                                        await _notify_smart_decision(
                                            "TP2",
                                            "CLOSED",
                                            level_label="TRAIL",
                                            level_price=trail_px if trail_px > 0 else px,
                                            reason=_sm_join_reason(
                                                _sm_reason_trail_exit(
                                                    trail_price=float(trail_px or 0.0),
                                                    current_price=float(px),
                                                    confirm_sec=float(TRAIL_CONFIRM_SEC),
                                                ),
                                                last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty),
                                            ),
                                            cooldown_sec=5.0,
                                        )
                                        await _mark_local_full_close("TRAIL_EXIT", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                                        pnl_usdt, roi_percent = _smart_close_snapshot()

                                        await db_store.close_autotrade_position(
                                            user_id=uid,
                                            signal_id=r.get("signal_id"),
                                            exchange=ex,
                                            market_type=mt,
                                            status="CLOSED",
                                            pnl_usdt=pnl_usdt,
                                            roi_percent=roi_percent,
                                            row_id=int(r.get("id") or 0),
                                        )
                                        continue
                                    await _notify_smart_decision(
                                        "TP2",
                                        "NOT CLOSED",
                                        level_label="TRAIL",
                                        level_price=trail_px if trail_px > 0 else px,
                                        reason=_sm_reason_execution_error(),
                                        cooldown_sec=15.0,
                                    )
                                    ref["sm_state"] = "TRAIL_EXIT"
                                    dirty = True
                            else:
                                if t_first != 0.0:
                                    ref["trail_first_ts"] = 0.0
                                    dirty = True

                    # Update momentum anchor price every MOM_WINDOW_SEC
                    if (now_ts - last_px_ts) >= max(5.0, MOM_WINDOW_SEC):
                        ref["last_px"] = float(px)
                        ref["last_px_ts"] = float(now_ts)
                        last_px = float(px)
                        last_px_ts = float(now_ts)
                        dirty = True

                    # Structural SL arms as soon as an explicit SL exists. False breaches are handled
                    # by the structural confirmation logic below, which is safer than delaying the arm.
                    if SmartDecisionEngine.should_arm_sl(sl_price=sl, armed_sl=armed_sl):
                        armed_sl = True
                        ref["armed_sl"] = True
                        ref["sm_state"] = "PROTECT"
                        dirty = True
                    # Reversal exit (close near the top/bottom when retrace starts)
                    if entry_p > 0 and best_px > 0:
                        reversal_exit = SmartExitEngine.evaluate_reversal_exit(
                            direction=direction,
                            entry_price=entry_p,
                            current_price=px,
                            best_price=best_px,
                            peak_min_gain_pct=PEAK_MIN_GAIN_PCT,
                            reversal_exit_pct=REV_EXIT_PCT,
                            tp1_mode=str(ref.get("tp1_mode") or ""),
                            tp1_partial=bool(ref.get("tp1_partial")),
                            tp2_probability=float(ref.get("tp2_prob") or 0.0),
                            tp1_seen=tp1_seen,
                        )
                        if reversal_exit.should_close:
                            close_ok = False
                            try:
                                close_ok = await _close_market(qty)
                            except Exception as e:
                                _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] close_market failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                            if close_ok:
                                await _notify_smart_decision(
                                    "TP2",
                                    "CLOSED",
                                    level_label="PEAK",
                                    level_price=best_px if best_px > 0 else px,
                                    reason=_sm_join_reason(
                                        _sm_reason_reversal_exit(
                                            gain_pct=float(reversal_exit.gain_pct),
                                            retrace_pct=float(reversal_exit.retrace_pct),
                                            gain_need=float(reversal_exit.gain_threshold),
                                            retrace_need=float(reversal_exit.retrace_threshold),
                                        ),
                                        last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty),
                                    ),
                                    cooldown_sec=5.0,
                                )
                                await _mark_local_full_close("REVERSAL_EXIT", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                                pnl_usdt, roi_percent = _smart_close_snapshot()

                                await db_store.close_autotrade_position(
                                    user_id=uid,
                                    signal_id=r.get("signal_id"),
                                    exchange=ex,
                                    market_type=mt,
                                    status="CLOSED",
                                    pnl_usdt=pnl_usdt,
                                    roi_percent=roi_percent,
                                    row_id=int(r.get("id") or 0),
                                )
                                continue
                            else:
                                await _notify_smart_decision(
                                    "TP2",
                                    "NOT CLOSED",
                                    level_label="PEAK",
                                    level_price=best_px if best_px > 0 else px,
                                    reason=_sm_reason_execution_error(),
                                    cooldown_sec=15.0,
                                )

                    # Effective SL: before arming -> HARD SL only; after arming -> original SL (fallback to HARD if missing)

                    # --- Early-exit (structure break): consecutive adverse momentum hits while in profit ---
                    neg_count = int(ref.get("neg_count") or 0)
                    # adverse move vs anchor
                    adv_pct = 0.0
                    if last_px > 0:
                        if direction == "LONG":
                            adv_pct = max(0.0, (1.0 - (px / last_px)) * 100.0)
                        else:
                            adv_pct = max(0.0, (px / last_px - 1.0) * 100.0)

                    if adv_pct >= max(0.0, EARLY_EXIT_NEG_PCT):
                        neg_count += 1
                    else:
                        neg_count = 0

                    ref["neg_count"] = int(neg_count)
                    dirty = True

                    # only exit early if already in profit (protect wins)
                    gain_now_pct = 0.0
                    if entry_p > 0:
                        if direction == "LONG":
                            gain_now_pct = (px / entry_p - 1.0) * 100.0
                        else:
                            gain_now_pct = (1.0 - (px / entry_p)) * 100.0

                    # --- Weakness exit BEFORE TP1: protect early profit if the move fades before target ---
                    weakness_eval = SmartExitEngine.evaluate_weakness_exit(
                        direction=direction,
                        entry_price=entry_p,
                        current_price=px,
                        best_price=best_px,
                        tp1_price=tp1,
                        tp1_seen=tp1_seen,
                        neg_count=neg_count,
                        weakness_enabled=WEAKNESS_EXIT_ENABLED,
                        weakness_min_gain_pct=WEAKNESS_MIN_GAIN,
                        weakness_min_giveback_pct=WEAKNESS_MIN_GIVEBACK,
                        weakness_giveback_fraction=WEAKNESS_GIVEBACK_FRAC,
                        weakness_min_tp1_progress=WEAKNESS_MIN_TP1_PROGRESS,
                        weakness_tp1_progress_max=WEAKNESS_TP1_PROGRESS_MAX,
                        weakness_neg_hits=WEAKNESS_NEG_HITS,
                        weakness_min_retain_pct=WEAKNESS_MIN_RETAIN_PCT,
                    )
                    best_gain_pct = float(weakness_eval.best_gain_pct)
                    giveback_pct = float(weakness_eval.giveback_pct)
                    giveback_frac = float(weakness_eval.giveback_frac)
                    progress_to_tp1 = float(weakness_eval.progress_to_tp1)

                    if weakness_eval.should_close:
                        weakness_close_error = ""
                        weakness_reason = _sm_reason_weakness_exit(
                            best_gain_pct=float(best_gain_pct),
                            giveback_pct=float(giveback_pct),
                            giveback_frac=float(giveback_frac),
                            progress_to_tp1=float(progress_to_tp1),
                            neg_hits=int(neg_count),
                        )
                        close_ok = False
                        try:
                            close_ok = await _close_market(qty)
                        except Exception as e:
                            weakness_close_error = str(e)
                            _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] weakness-exit close failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                        if close_ok:
                            await _notify_smart_decision("WEAKNESS", "CLOSED", level_label="TP1", level_price=tp1, reason=weakness_reason, cooldown_sec=5.0)
                            await _mark_local_full_close("WEAKNESS_EXIT", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                            pnl_usdt, roi_percent = _smart_close_snapshot()

                            await db_store.close_autotrade_position(
                                user_id=uid,
                                signal_id=r.get("signal_id"),
                                exchange=ex,
                                market_type=mt,
                                status="CLOSED",
                                pnl_usdt=pnl_usdt,
                                roi_percent=roi_percent,
                                row_id=int(r.get("id") or 0),
                            )
                            continue
                        else:
                            fail_reason = _sm_reason_execution_error(weakness_close_error or last_close_explain or _sm_reason_close_returned_false())
                            await _notify_smart_decision("WEAKNESS", "NOT CLOSED", level_label="TP1", level_price=tp1, reason=fail_reason, cooldown_sec=15.0)

                    invalidation_eval = None
                    if INVALIDATION_EXIT_ENABLED and is_mid and mt == "futures" and entry_p > 0 and (not tp1_seen):
                        try:
                            inv_fetch_max_bars = max(1, int(INVALIDATION_MAX_BARS or 1))
                        except Exception:
                            inv_fetch_max_bars = 6
                        if float(open_age_sec or 0.0) <= float((inv_fetch_max_bars + 2) * 300):
                            inv_refresh = (now_ts - float(ref.get("inv_eval_ts") or 0.0)) >= max(5.0, float(INVALIDATION_CACHE_SEC or 20.0))
                            bos_against = bool(ref.get("inv_bos_against"))
                            reclaim_loss = bool(ref.get("inv_reclaim_loss"))
                            vwap_loss = bool(ref.get("inv_vwap_loss"))
                            ema20_loss = bool(ref.get("inv_ema20_loss"))
                            trend_loss = bool(ref.get("inv_trend_loss"))
                            if inv_refresh:
                                try:
                                    df5_inv = await price_backend.load_candles(symbol, "5m", mt, limit=48)
                                    df5_inv = _mid_norm_ohlcv(df5_inv)
                                except Exception:
                                    df5_inv = None
                                if df5_inv is not None and not getattr(df5_inv, "empty", True) and len(df5_inv) >= 8:
                                    try:
                                        df5_closed = df5_inv.copy()
                                        try:
                                            if len(df5_closed) >= 3 and "open_time_ms" in df5_closed.columns:
                                                last_ot_ms = float(df5_closed.iloc[-1].get("open_time_ms", float("nan")))
                                                if np.isfinite(last_ot_ms) and last_ot_ms > 0 and (last_ot_ms / 1000.0) > (now_ts - 240.0):
                                                    df5_closed = df5_closed.iloc[:-1]
                                        except Exception:
                                            pass
                                        if len(df5_closed) >= 8:
                                            op5 = df5_closed["open"].astype(float)
                                            hi5 = df5_closed["high"].astype(float)
                                            lo5 = df5_closed["low"].astype(float)
                                            cl5 = df5_closed["close"].astype(float)
                                            close_last_5m = float(cl5.iloc[-1])
                                            ema20_5m = float(cl5.ewm(span=20, adjust=False).mean().iloc[-1]) if len(cl5) >= 5 else float("nan")
                                            vwap_5m = calc_vwap(df5_closed.tail(24))

                                            bos_against = False
                                            try:
                                                lb = 20
                                                k = max(2, int(MID_BOS_RECENT_BARS))
                                                if len(lo5) >= lb + k + 1:
                                                    prev_low = float(lo5.iloc[-(lb + k + 1):-(k)].min())
                                                    prev_high = float(hi5.iloc[-(lb + k + 1):-(k)].max())
                                                    for j in range(-k, 0):
                                                        _low = float(lo5.iloc[j])
                                                        _high = float(hi5.iloc[j])
                                                        _close = float(cl5.iloc[j])
                                                        if direction == "LONG" and (_low < prev_low) and (_close < prev_low):
                                                            bos_against = True
                                                        if direction == "SHORT" and (_high > prev_high) and (_close > prev_high):
                                                            bos_against = True
                                            except Exception:
                                                bos_against = False

                                            two_red_5m = bool(len(cl5) >= 2 and float(cl5.iloc[-1]) < float(op5.iloc[-1]) and float(cl5.iloc[-2]) < float(op5.iloc[-2]))
                                            two_green_5m = bool(len(cl5) >= 2 and float(cl5.iloc[-1]) > float(op5.iloc[-1]) and float(cl5.iloc[-2]) > float(op5.iloc[-2]))
                                            lower_highs_5m = False
                                            higher_lows_5m = False
                                            try:
                                                tol = max(0.0, float(MID_HL_TOL_PCT))
                                                nlh = max(3, int(MID_LOWER_HIGHS_LOOKBACK))
                                                if len(hi5) >= nlh:
                                                    hh = [float(x) for x in hi5.iloc[-nlh:].tolist()]
                                                    lower_highs_5m = all(hh[i] <= hh[i - 1] * (1.0 + tol) for i in range(1, len(hh)))
                                                nhl = max(3, int(MID_HIGHER_LOWS_LOOKBACK))
                                                if len(lo5) >= nhl:
                                                    ll = [float(x) for x in lo5.iloc[-nhl:].tolist()]
                                                    higher_lows_5m = all(ll[i] >= ll[i - 1] * (1.0 - tol) for i in range(1, len(ll)))
                                            except Exception:
                                                lower_highs_5m = False
                                                higher_lows_5m = False

                                            if direction == "LONG":
                                                vwap_loss = bool((vwap_5m is not None) and close_last_5m < float(vwap_5m))
                                                ema20_loss = bool((ema20_5m == ema20_5m) and close_last_5m < float(ema20_5m))
                                                trend_loss = bool(two_red_5m or lower_highs_5m)
                                                best_gain_live = max(0.0, (best_px / entry_p - 1.0) * 100.0) if best_px > 0 else 0.0
                                                reclaim_loss = bool(best_gain_live >= float(INVALIDATION_RECLAIM_MIN_GAIN_PCT) and close_last_5m <= entry_p * (1.0 - float(INVALIDATION_RECLAIM_BUFFER_PCT) / 100.0))
                                            else:
                                                vwap_loss = bool((vwap_5m is not None) and close_last_5m > float(vwap_5m))
                                                ema20_loss = bool((ema20_5m == ema20_5m) and close_last_5m > float(ema20_5m))
                                                trend_loss = bool(two_green_5m or higher_lows_5m)
                                                best_gain_live = max(0.0, (1.0 - (best_px / entry_p)) * 100.0) if best_px > 0 else 0.0
                                                reclaim_loss = bool(best_gain_live >= float(INVALIDATION_RECLAIM_MIN_GAIN_PCT) and close_last_5m >= entry_p * (1.0 + float(INVALIDATION_RECLAIM_BUFFER_PCT) / 100.0))

                                            ref["inv_eval_ts"] = float(now_ts)
                                            ref["inv_bos_against"] = bool(bos_against)
                                            ref["inv_reclaim_loss"] = bool(reclaim_loss)
                                            ref["inv_vwap_loss"] = bool(vwap_loss)
                                            ref["inv_ema20_loss"] = bool(ema20_loss)
                                            ref["inv_trend_loss"] = bool(trend_loss)
                                            dirty = True
                                    except Exception as e:
                                        _smart_log_exception("mid_presl_invalidation_flags", e)

                            invalidation_eval = SmartExitEngine.evaluate_invalidation_exit(
                                direction=direction,
                                entry_price=entry_p,
                                current_price=px,
                                best_price=best_px,
                                tp1_price=tp1,
                                sl_price=sl,
                                tp1_seen=tp1_seen,
                                open_age_sec=open_age_sec,
                                neg_count=neg_count,
                                bos_against=bool(ref.get("inv_bos_against")),
                                reclaim_loss=bool(ref.get("inv_reclaim_loss")),
                                vwap_loss=bool(ref.get("inv_vwap_loss")),
                                ema20_loss=bool(ref.get("inv_ema20_loss")),
                                trend_loss=bool(ref.get("inv_trend_loss")),
                                invalidation_enabled=INVALIDATION_EXIT_ENABLED,
                                invalidation_min_bars=INVALIDATION_MIN_BARS,
                                invalidation_max_bars=INVALIDATION_MAX_BARS,
                                invalidation_score_close=INVALIDATION_SCORE_CLOSE,
                                invalidation_score_on_loss=INVALIDATION_SCORE_LOSS,
                                invalidation_neg_hits=INVALIDATION_NEG_HITS,
                                invalidation_min_loss_pct=INVALIDATION_MIN_LOSS_PCT,
                                invalidation_max_loss_pct=INVALIDATION_MAX_LOSS_PCT,
                                invalidation_sl_frac_cap=INVALIDATION_SL_FRAC_CAP,
                                invalidation_score_override=INVALIDATION_SCORE_OVERRIDE,
                            )
                            if invalidation_eval.should_close:
                                invalidation_close_error = ""
                                invalidation_reason = _sm_reason_invalidation_exit(
                                    score=int(invalidation_eval.score),
                                    loss_now_pct=float(invalidation_eval.loss_now_pct),
                                    max_loss_pct=float(invalidation_eval.max_early_loss_pct),
                                    full_sl_loss_pct=float(invalidation_eval.full_sl_loss_pct),
                                    bars_since_entry=int(invalidation_eval.bars_since_entry),
                                    components=str(invalidation_eval.components or ""),
                                )
                                close_ok = False
                                try:
                                    close_ok = await _close_market(qty)
                                except Exception as e:
                                    invalidation_close_error = str(e)
                                    _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] invalidation-exit close failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                                if close_ok:
                                    await _notify_smart_decision(
                                        "INVALIDATION",
                                        "CLOSED",
                                        level_label="SL",
                                        level_price=sl if sl > 0 else px,
                                        reason=_sm_join_reason(invalidation_reason, last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty)),
                                        cooldown_sec=5.0,
                                    )
                                    await _mark_local_full_close("INVALIDATION_EXIT", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                                    pnl_usdt, roi_percent = _smart_close_snapshot()

                                    await db_store.close_autotrade_position(
                                        user_id=uid,
                                        signal_id=r.get("signal_id"),
                                        exchange=ex,
                                        market_type=mt,
                                        status="CLOSED",
                                        pnl_usdt=pnl_usdt,
                                        roi_percent=roi_percent,
                                        row_id=int(r.get("id") or 0),
                                    )
                                    continue
                                else:
                                    fail_reason = _sm_reason_execution_error(invalidation_close_error or last_close_explain or _sm_reason_close_returned_false())
                                    await _notify_smart_decision("INVALIDATION", "NOT CLOSED", level_label="SL", level_price=sl if sl > 0 else px, reason=fail_reason, cooldown_sec=15.0)

                    if neg_count >= max(1, int(EARLY_EXIT_CONSEC)) and gain_now_pct >= float(EARLY_EXIT_MIN_GAIN):
                        close_ok = False
                        early_exit_error = ""
                        early_exit_reason = _sm_reason_early_exit(
                            neg_hits=int(neg_count),
                            need_hits=int(EARLY_EXIT_CONSEC),
                            gain_now_pct=float(gain_now_pct),
                            min_gain_pct=float(EARLY_EXIT_MIN_GAIN),
                            adverse_pct=float(adv_pct),
                            adverse_need_pct=float(EARLY_EXIT_NEG_PCT),
                        )
                        try:
                            close_ok = await _close_market(qty)
                        except Exception as e:
                            early_exit_error = str(e)
                            _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] early-exit close failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                        if close_ok:
                            await _notify_smart_decision("TP1", "CLOSED", level_label="TP1", level_price=tp1 if tp1 > 0 else px, reason=_sm_join_reason(early_exit_reason, last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty)), cooldown_sec=5.0)
                            await _mark_local_full_close("EARLY_EXIT", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                            pnl_usdt, roi_percent = _smart_close_snapshot()

                            await db_store.close_autotrade_position(
                                user_id=uid,
                                signal_id=r.get("signal_id"),
                                exchange=ex,
                                market_type=mt,
                                status="CLOSED",
                                pnl_usdt=pnl_usdt,
                                roi_percent=roi_percent,
                                row_id=int(r.get("id") or 0),
                            )
                            continue
                        else:
                            fail_reason = _sm_reason_execution_error(early_exit_error or last_close_explain or _sm_reason_close_returned_false())
                            await _notify_smart_decision("TP1", "NOT CLOSED", level_label="TP1", level_price=tp1 if tp1 > 0 else px, reason=fail_reason, cooldown_sec=15.0)
                    # --- SMART STRUCTURAL SL ---
                    # Goals:
                    # 1) If structure SL is broken -> close (decisive)
                    # 2) Avoid one-tick / one-wick false SL (confirmation)
                    # 3) If price quickly reclaims above SL (noise sweep) -> do NOT close
                    # 4) Keep HARD SL as emergency fallback
                    SL_CONFIRM_LAST = int(os.getenv("SMART_SL_CONFIRM_LAST", "3") or 3)
                    SL_CONFIRM_HITS = int(os.getenv("SMART_SL_CONFIRM_HITS", "2") or 2)
                    SL_CONFIRM_SEC  = float(os.getenv("SMART_SL_CONFIRM_SEC", "3") or 3)
                    SL_DEEP_PCT     = float(os.getenv("SMART_SL_DEEP_PCT", "0.15") or 0.15)

                    # Noise-sweep protection: allow quick reclaim above SL within grace window
                    SL_GRACE_SEC    = float(os.getenv("SMART_SL_GRACE_SEC", "6") or 6)
                    SL_GRACE_BASE   = float(os.getenv("SMART_SL_GRACE_BASE", "0") or 0)
                    SL_GRACE_ATR_K  = float(os.getenv("SMART_SL_GRACE_ATR_K", "0") or 0)
                    SL_USE_5M_CLOSE = (os.getenv("SMART_SL_USE_5M_CLOSE", "0").strip().lower() not in ("0","false","no","off"))
                    # Adaptive grace: grace = max(SMART_SL_GRACE_SEC, SMART_SL_GRACE_BASE + SMART_SL_GRACE_ATR_K * ATR%)
                    try:
                        atrp = float(ref.get("atr_pct") or ref.get("atr_pct_30m") or 0.0)
                    except Exception:
                        atrp = 0.0
                    try:
                        SL_GRACE_SEC = max(float(SL_GRACE_SEC), float(SL_GRACE_BASE) + float(SL_GRACE_ATR_K) * max(0.0, float(atrp)))
                    except Exception:
                        pass
                    SL_RECLAIM_PCT  = float(os.getenv("SMART_SL_RECLAIM_PCT", "0.04") or 0.04)  # reclaim buffer around SL
                    SL_BOUNCE_PCT   = float(os.getenv("SMART_SL_BOUNCE_PCT", "0.10") or 0.10)    # bounce from breach extreme

                    # SPOT virtual positions need a faster and more deterministic SL path.
                    # Default behavior below makes SPOT close on the first confirmed breach,
                    # while FUTURES keep the existing anti-wick / anti-noise protections.
                    if mt == "spot":
                        SL_CONFIRM_HITS = int(os.getenv("SMART_SPOT_SL_CONFIRM_HITS", "1") or 1)
                        SL_CONFIRM_SEC  = float(os.getenv("SMART_SPOT_SL_CONFIRM_SEC", "0") or 0)
                        SL_DEEP_PCT     = float(os.getenv("SMART_SPOT_SL_DEEP_PCT", "0.0") or 0.0)
                        SL_GRACE_SEC    = float(os.getenv("SMART_SPOT_SL_GRACE_SEC", "0") or 0)
                        SL_RECLAIM_PCT  = float(os.getenv("SMART_SPOT_SL_RECLAIM_PCT", "0.0") or 0.0)
                        SL_BOUNCE_PCT   = float(os.getenv("SMART_SPOT_SL_BOUNCE_PCT", "0.0") or 0.0)
                        SL_USE_5M_CLOSE = (os.getenv("SMART_SPOT_SL_USE_5M_CLOSE", "0").strip().lower() not in ("0","false","no","off"))

                    sl_struct = float(sl or 0.0)
                    sl_hard   = float(hard_sl or 0.0)

                    # Emergency HARD SL always active
                    def _hit_hard() -> bool:
                        if sl_hard <= 0:
                            return False
                        return (px <= sl_hard) if direction == "LONG" else (px >= sl_hard)

                    # Structural SL hit (raw)
                    def _hit_struct() -> bool:
                        if sl_struct <= 0:
                            return False
                        return (px <= sl_struct) if direction == "LONG" else (px >= sl_struct)

                    def _reclaimed() -> bool:
                        if sl_struct <= 0:
                            return False
                        # Price back inside with a tiny buffer to avoid flicker around SL
                        if direction == "LONG":
                            return px >= sl_struct * (1.0 + SL_RECLAIM_PCT / 100.0)
                        else:
                            return px <= sl_struct * (1.0 - SL_RECLAIM_PCT / 100.0)

                    def _deep_breach() -> bool:
                        if sl_struct <= 0 or entry_p <= 0:
                            return False
                        if direction == "LONG":
                            d = (sl_struct - px)
                        else:
                            d = (px - sl_struct)
                        if d <= 0:
                            return False
                        return (d / entry_p) * 100.0 >= SL_DEEP_PCT

                    # Update breach tracking state and structural decision via typed core helper.
                    sl_hits = int(ref.get("sl_hits") or 0)
                    sl_first_ts = float(ref.get("sl_first_ts") or 0.0)
                    sl_extreme = float(ref.get("sl_extreme") or 0.0)  # lowest px for LONG breach, highest for SHORT breach

                    def _allow_struct_close() -> bool:
                        if not SL_USE_5M_CLOSE or sl_first_ts <= 0:
                            return True
                        try:
                            next5m = (math.floor(float(sl_first_ts) / 300.0) + 1.0) * 300.0
                        except Exception:
                            return True
                        # wait for the next 5m boundary (proxy for a candle close confirmation)
                        return float(now_ts) >= float(next5m)

                    sl_eval = SmartExitEngine.evaluate_structural_sl(
                        direction=direction,
                        entry_price=entry_p,
                        current_price=px,
                        sl_price=sl_struct,
                        hard_sl_price=sl_hard,
                        now_ts=now_ts,
                        sl_hits=sl_hits,
                        sl_first_ts=sl_first_ts,
                        sl_extreme=sl_extreme,
                        sl_confirm_hits=SL_CONFIRM_HITS,
                        sl_confirm_sec=SL_CONFIRM_SEC,
                        sl_deep_pct=SL_DEEP_PCT,
                        sl_grace_sec=SL_GRACE_SEC,
                        sl_reclaim_pct=SL_RECLAIM_PCT,
                        sl_bounce_pct=SL_BOUNCE_PCT,
                        allow_struct_close=_allow_struct_close(),
                    )
                    crossed = bool(sl_eval.crossed)
                    sl_close = bool(sl_eval.should_close)
                    sl_hits = int(sl_eval.sl_hits)
                    sl_first_ts = float(sl_eval.sl_first_ts)
                    sl_extreme = float(sl_eval.sl_extreme)
                    if (ref.get("sl_hits") or 0) != sl_hits or float(ref.get("sl_first_ts") or 0.0) != sl_first_ts or float(ref.get("sl_extreme") or 0.0) != sl_extreme:
                        ref["sl_hits"] = int(sl_hits)
                        ref["sl_first_ts"] = float(sl_first_ts)
                        ref["sl_extreme"] = float(sl_extreme)
                        dirty = True
                    age = float(sl_eval.age_sec)

                    if mt == "spot" and crossed:
                        _log_rate_limited(
                            f"smart_spot_sl_diag:{uid}:{ex}:{symbol}",
                            f"[SMART_SPOT_SL] uid={uid} ex={ex} sym={symbol} side={direction} virtual={bool(ref.get('virtual'))} "
                            f"px_decision={px:.10f} px_src={str(px_src or '-')} "
                            f"sl={sl_struct:.10f} crossed={crossed} sl_close={sl_close} "
                            f"hits={sl_hits} age={((now_ts - sl_first_ts) if sl_first_ts > 0 else 0.0):.2f}s "
                            f"deep={bool(sl_eval.deep_breach)} hard={bool(sl_eval.hard_hit)}",
                            every_s=5,
                            level="info",
                        )

                    if crossed and not sl_close:
                        age = (now_ts - sl_first_ts) if sl_first_ts > 0 else 0.0
                        sl_wait_reasons: list[str] = []
                        if sl_hits < SL_CONFIRM_HITS:
                            sl_wait_reasons.append(_trf(uid, "sm_reason_wait_confirm_hits", hits=sl_hits, need=SL_CONFIRM_HITS))
                        if age < max(0.0, float(SL_CONFIRM_SEC)):
                            sl_wait_reasons.append(_trf(uid, "sm_reason_wait_confirm_time", age=f"{age:.1f}", need=f"{float(SL_CONFIRM_SEC):.1f}"))
                        if SL_GRACE_SEC > 0 and age < float(SL_GRACE_SEC):
                            sl_wait_reasons.append(_trf(uid, "sm_reason_wait_grace", age=f"{age:.1f}", need=f"{float(SL_GRACE_SEC):.1f}"))
                        if SL_USE_5M_CLOSE and not _allow_struct_close():
                            sl_wait_reasons.append(_tr(uid, "sm_reason_wait_5m_close"))
                        if not sl_wait_reasons:
                            sl_wait_reasons.append(_tr(uid, "sm_reason_wait_generic"))
                        await _notify_smart_decision(
                            "SL",
                            "NOT CLOSED",
                            level_label="SL",
                            level_price=sl_struct,
                            reason="; ".join(sl_wait_reasons),
                            cooldown_sec=15.0,
                        )

                    # --- SL (smart structural) ---
                    if sl_close:

                        close_ok = False
                        sl_close_error = ""
                        try:
                            close_ok = await _close_market(qty)
                        except Exception as e:
                            sl_close_error = str(e)
                            _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] close_market failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")

                        _log_rate_limited(
                            f"smart_spot_close_diag:{uid}:{ex}:{symbol}",
                            f"[SMART_CLOSE] uid={uid} ex={ex} sym={symbol} side={direction} virtual={bool(ref.get('virtual'))} "
                            f"px_decision={px:.10f} px_src={str(px_src or '-')} "
                            f"sl={sl_struct:.10f} crossed={crossed} sl_close={sl_close} "
                            f"close_ok={close_ok} close_err={sl_close_error or '-'}",
                            every_s=2,
                            level="info",
                        )
                        if close_ok:
                            sl_reason = _tr(uid, "sm_reason_hard_sl") if bool(sl_eval.hard_hit) else (_tr(uid, "sm_reason_deep_breach") if bool(sl_eval.deep_breach) else _tr(uid, "sm_reason_structure_break"))
                            await _notify_smart_decision("SL", "CLOSED", level_label="SL", level_price=sl_struct if sl_struct > 0 else sl_hard, reason=_sm_join_reason(sl_reason, last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty)), cooldown_sec=5.0)
                            await _mark_local_full_close("SL", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")), be_moved_value=bool(ref.get("be_moved") or meta.get("be_moved")))
                            pnl_usdt, roi_percent = _smart_close_snapshot()

                            await db_store.close_autotrade_position(
                                user_id=uid,
                                signal_id=r.get("signal_id"),
                                exchange=ex,
                                market_type=mt,
                                status="CLOSED",
                                pnl_usdt=pnl_usdt,
                                roi_percent=roi_percent,
                                row_id=int(r.get("id") or 0),
                            )
                            continue
                        else:
                            fail_reason = sl_close_error or last_close_explain or _sm_reason_close_returned_false()
                            await _notify_smart_decision("SL", "NOT CLOSED", level_label="SL", level_price=sl_struct if sl_struct > 0 else sl_hard, reason=fail_reason, cooldown_sec=15.0)

                    # --- TP2 runner management: after strong TP2 touch, hold above TP2 and exit by real 1m reversal / micro-structure break / sharp return to TP2 ---
                    if tp2 > 0 and tp2_runner_active:
                        runner_floor = float(tp2_runner_floor_px or tp2 or 0.0)
                        runner_peak = float(tp2_runner_peak_px or px)
                        if direction == "LONG":
                            if px > runner_peak:
                                runner_peak = float(px)
                                ref["tp2_runner_peak_px"] = float(runner_peak)
                                tp2_runner_peak_px = float(runner_peak)
                                dirty = True
                            peak_ext_pct = max(0.0, (runner_peak / max(1e-9, runner_floor) - 1.0) * 100.0) if runner_floor > 0 else 0.0
                            back_to_tp2 = runner_floor > 0 and px <= runner_floor
                        else:
                            if px < runner_peak:
                                runner_peak = float(px)
                                ref["tp2_runner_peak_px"] = float(runner_peak)
                                tp2_runner_peak_px = float(runner_peak)
                                dirty = True
                            peak_ext_pct = max(0.0, (1.0 - (runner_peak / max(1e-9, runner_floor))) * 100.0) if runner_floor > 0 else 0.0
                            back_to_tp2 = runner_floor > 0 and px >= runner_floor

                        runner_ready = (now_ts - float(tp2_runner_armed_ts or 0.0)) >= max(0.0, float(TP2_RUN_MIN_HOLD_SEC))
                        tp2_runner_reason = ""
                        tp2_runner_reason_user = ""
                        tp2_runner_close_px = float(px)

                        runner_eval = SmartExitEngine.evaluate_tp2_runner(
                            direction=direction,
                            current_price=px,
                            runner_floor_price=runner_floor,
                            runner_peak_price=runner_peak,
                            now_ts=now_ts,
                            armed_ts=tp2_runner_armed_ts,
                            min_hold_sec=TP2_RUN_MIN_HOLD_SEC,
                            min_peak_extension_pct=TP2_RUN_MIN_PEAK_EXT_PCT,
                            peak_giveback_pct=TP2_RUN_PEAK_GIVEBACK_PCT,
                        )

                        if runner_eval.back_to_tp2:
                            tp2_runner_reason = f"tp2_return peak_ext={peak_ext_pct:.2f}% peak={runner_peak:.4f} floor={runner_floor:.4f}"
                            tp2_runner_close_px = float(px)
                            tp2_runner_reason_user = _trf(
                                uid,
                                "sm_reason_tp2_runner_return_tp2",
                                close_price=_fmt_sm_price(tp2_runner_close_px),
                                tp2_price=_fmt_sm_price(tp2),
                                peak_price=_fmt_sm_price(runner_peak),
                            )
                        elif runner_eval.should_close:
                            tp2_runner_reason = f"tp2_peak_giveback peak_ext={runner_eval.peak_extension_pct:.2f}% giveback={runner_eval.giveback_from_peak_pct:.2f}% peak={runner_peak:.4f} floor={runner_floor:.4f}"
                            tp2_runner_close_px = float(px)
                            tp2_runner_reason_user = _trf(
                                uid,
                                "sm_reason_tp2_runner_first_opposite",
                                close_price=_fmt_sm_price(tp2_runner_close_px),
                                tp2_price=_fmt_sm_price(tp2),
                                peak_price=_fmt_sm_price(runner_peak),
                                pullback_pct=f"{runner_eval.giveback_from_peak_pct:.2f}",
                            )
                        elif runner_ready and price_backend is not None and hasattr(price_backend, "load_candles"):
                            try:
                                tp2_run_pullback_min_pct = max(0.01, float(os.getenv("SMART_TP2_RUN_1M_PULLBACK_MIN_PCT", "0.10") or 0.10))
                            except Exception:
                                tp2_run_pullback_min_pct = 0.10
                            try:
                                tp2_run_micro_lookback = max(4, int(os.getenv("SMART_TP2_RUN_1M_MICRO_LOOKBACK", "6") or 6))
                            except Exception:
                                tp2_run_micro_lookback = 6
                            try:
                                df1m_run = await price_backend.load_candles(symbol, "1m", mt, limit=max(20, tp2_run_micro_lookback + 6))
                            except Exception:
                                df1m_run = pd.DataFrame()
                            df1m_run = _mid_norm_ohlcv(df1m_run)
                            if df1m_run is not None and not getattr(df1m_run, "empty", True) and len(df1m_run) >= 4:
                                df1m_run = df1m_run.copy().reset_index(drop=True)
                                if "open_time_ms" in df1m_run.columns:
                                    try:
                                        close_ms = pd.to_numeric(df1m_run["open_time_ms"], errors="coerce").fillna(0).astype("int64") + 60000
                                        mask_closed = (close_ms <= int(now_ts * 1000)) & (close_ms > int(float(tp2_runner_armed_ts or 0.0) * 1000))
                                        df1m_closed = df1m_run.loc[mask_closed].copy().reset_index(drop=True)
                                    except Exception:
                                        df1m_closed = df1m_run.iloc[:-1].copy().reset_index(drop=True)
                                else:
                                    df1m_closed = df1m_run.iloc[:-1].copy().reset_index(drop=True)

                                if len(df1m_closed) >= 1:
                                    last_c = df1m_closed.iloc[-1]
                                    last_open = float(last_c.get("open") or 0.0)
                                    last_high = float(last_c.get("high") or 0.0)
                                    last_low = float(last_c.get("low") or 0.0)
                                    last_close = float(last_c.get("close") or 0.0)
                                    tp2_runner_close_px = float(last_close or px)
                                    if direction == "LONG":
                                        pullback_from_peak_pct = max(0.0, (1.0 - (tp2_runner_close_px / max(1e-9, runner_peak))) * 100.0) if runner_peak > 0 else 0.0
                                        first_opposite = (last_close < last_open) and (pullback_from_peak_pct >= tp2_run_pullback_min_pct)
                                        micro_break = False
                                        if len(df1m_closed) >= max(4, tp2_run_micro_lookback):
                                            recent = df1m_closed.tail(tp2_run_micro_lookback).reset_index(drop=True)
                                            highs = recent["high"].astype(float).tolist()
                                            lows = recent["low"].astype(float).tolist()
                                            lc = float(recent["close"].astype(float).iloc[-1])
                                            prev_hi = max(highs[:-2]) if len(highs) >= 3 else highs[-2]
                                            prev_lo = min(lows[:-2]) if len(lows) >= 3 else lows[-2]
                                            micro_break = (highs[-2] < prev_hi) and (lows[-2] < prev_lo) and (lc < lows[-2])
                                        if first_opposite:
                                            tp2_runner_reason = f"tp2_first_red_1m peak_ext={peak_ext_pct:.2f}% pullback={pullback_from_peak_pct:.2f}% peak={runner_peak:.4f} c1m={last_close:.4f}"
                                            tp2_runner_reason_user = _trf(
                                                uid,
                                                "sm_reason_tp2_runner_first_opposite",
                                                close_price=_fmt_sm_price(tp2_runner_close_px),
                                                tp2_price=_fmt_sm_price(tp2),
                                                peak_price=_fmt_sm_price(runner_peak),
                                                pullback_pct=f"{pullback_from_peak_pct:.2f}",
                                            )
                                        elif micro_break:
                                            tp2_runner_reason = f"tp2_micro_break_1m peak_ext={peak_ext_pct:.2f}% peak={runner_peak:.4f} c1m={last_close:.4f}"
                                            tp2_runner_reason_user = _trf(
                                                uid,
                                                "sm_reason_tp2_runner_micro_break",
                                                pattern="LH/LL break",
                                                close_price=_fmt_sm_price(tp2_runner_close_px),
                                                tp2_price=_fmt_sm_price(tp2),
                                                peak_price=_fmt_sm_price(runner_peak),
                                            )
                                    else:
                                        pullback_from_peak_pct = max(0.0, (tp2_runner_close_px / max(1e-9, runner_peak) - 1.0) * 100.0) if runner_peak > 0 else 0.0
                                        first_opposite = (last_close > last_open) and (pullback_from_peak_pct >= tp2_run_pullback_min_pct)
                                        micro_break = False
                                        if len(df1m_closed) >= max(4, tp2_run_micro_lookback):
                                            recent = df1m_closed.tail(tp2_run_micro_lookback).reset_index(drop=True)
                                            highs = recent["high"].astype(float).tolist()
                                            lows = recent["low"].astype(float).tolist()
                                            lc = float(recent["close"].astype(float).iloc[-1])
                                            prev_hi = min(highs[:-2]) if len(highs) >= 3 else highs[-2]
                                            prev_lo = max(lows[:-2]) if len(lows) >= 3 else lows[-2]
                                            micro_break = (highs[-2] > prev_hi) and (lows[-2] > prev_lo) and (lc > highs[-2])
                                        if first_opposite:
                                            tp2_runner_reason = f"tp2_first_green_1m peak_ext={peak_ext_pct:.2f}% pullback={pullback_from_peak_pct:.2f}% peak={runner_peak:.4f} c1m={last_close:.4f}"
                                            tp2_runner_reason_user = _trf(
                                                uid,
                                                "sm_reason_tp2_runner_first_opposite",
                                                close_price=_fmt_sm_price(tp2_runner_close_px),
                                                tp2_price=_fmt_sm_price(tp2),
                                                peak_price=_fmt_sm_price(runner_peak),
                                                pullback_pct=f"{pullback_from_peak_pct:.2f}",
                                            )
                                        elif micro_break:
                                            tp2_runner_reason = f"tp2_micro_break_1m peak_ext={peak_ext_pct:.2f}% peak={runner_peak:.4f} c1m={last_close:.4f}"
                                            tp2_runner_reason_user = _trf(
                                                uid,
                                                "sm_reason_tp2_runner_micro_break",
                                                pattern="HH/HL break",
                                                close_price=_fmt_sm_price(tp2_runner_close_px),
                                                tp2_price=_fmt_sm_price(tp2),
                                                peak_price=_fmt_sm_price(runner_peak),
                                            )

                        if tp2_runner_reason:
                            close_ok = False
                            tp2_runner_close_error = ""
                            try:
                                close_ok = await _close_market(qty)
                            except Exception as e:
                                tp2_runner_close_error = str(e)
                                _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] tp2-runner close failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                            if close_ok:
                                await _notify_smart_decision("TP2", "CLOSED", level_label="TP2", level_price=tp2, decision_price=tp2_runner_close_px, reason=_sm_join_reason(tp2_runner_reason_user or tp2_runner_reason, last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty)), cooldown_sec=5.0)
                                await _mark_local_full_close("TP2_RUNNER", close_price_value=tp2_runner_close_px, close_price_source="market", close_note=tp2_runner_reason, tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                                pnl_usdt, roi_percent = _smart_close_snapshot()

                                await db_store.close_autotrade_position(
                                    user_id=uid,
                                    signal_id=r.get("signal_id"),
                                    exchange=ex,
                                    market_type=mt,
                                    status="CLOSED",
                                    pnl_usdt=pnl_usdt,
                                    roi_percent=roi_percent,
                                    row_id=int(r.get("id") or 0),
                                )
                                continue
                            else:
                                fail_reason = tp2_runner_close_error or last_close_explain or _sm_reason_close_returned_false()
                                await _notify_smart_decision("TP2", "NOT CLOSED", level_label="TP2", level_price=tp2, reason=fail_reason, cooldown_sec=15.0)

                    # --- TP2: if reached, close 100%, unless strong impulse says to run above TP2 first ---
                    if tp2 > 0 and _hit_tp(tp2):
                        if not tp2_runner_active:
                            tp2_mom_fav_pct = 0.0
                            if last_px > 0:
                                if direction == "LONG":
                                    tp2_mom_fav_pct = max(0.0, (px / last_px - 1.0) * 100.0)
                                else:
                                    tp2_mom_fav_pct = max(0.0, (1.0 - (px / last_px)) * 100.0)
                            tp2_prob_now = _clamp01(float(ref.get("tp2_prob") or 0.0))
                            tp1_mode_now = str(ref.get("tp1_mode") or "").upper()
                            extend_tp2 = bool(
                                TP2_RUN_ENABLED and (
                                    tp1_mode_now == "HOLD_TO_TP2"
                                    or tp2_prob_now >= float(TP2_RUN_MIN_PROB)
                                    or tp2_mom_fav_pct >= float(TP2_RUN_MIN_MOM_PCT)
                                )
                            )
                            if extend_tp2:
                                ref["tp2_runner_active"] = True
                                ref["tp2_runner_floor_px"] = float(tp2)
                                ref["tp2_runner_peak_px"] = float(px)
                                ref["tp2_runner_armed_ts"] = float(now_ts)
                                ref["sm_state"] = "TP2_RUN"
                                tp2_runner_active = True
                                tp2_runner_floor_px = float(tp2)
                                tp2_runner_peak_px = float(px)
                                tp2_runner_armed_ts = float(now_ts)
                                dirty = True
                                await _notify_smart_decision(
                                    "TP2",
                                    "NOT CLOSED",
                                    level_label="TP2",
                                    level_price=tp2,
                                    reason=_trf(uid, "sm_reason_tp2_runner_started", mom=f"{tp2_mom_fav_pct:.2f}%", prob=f"{tp2_prob_now:.2f}"),
                                    cooldown_sec=10.0,
                                )
                            else:
                                close_ok = False
                                tp2_close_error = ""
                                try:
                                    close_ok = await _close_market(qty)
                                except Exception as e:
                                    tp2_close_error = str(e)
                                    _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] close_market failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                                if close_ok:
                                    await _notify_smart_decision("TP2", "CLOSED", level_label="TP2", level_price=tp2, reason=_sm_join_reason(_tr(uid, "sm_reason_tp2_reached"), last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty)), cooldown_sec=5.0)
                                    await _mark_local_full_close("TP2", tp1_hit=bool(ref.get("tp1_hit") or meta.get("tp1_hit")))
                                    pnl_usdt, roi_percent = _smart_close_snapshot()

                                    await db_store.close_autotrade_position(
                                        user_id=uid,
                                        signal_id=r.get("signal_id"),
                                        exchange=ex,
                                        market_type=mt,
                                        status="CLOSED",
                                        pnl_usdt=pnl_usdt,
                                        roi_percent=roi_percent,
                                        row_id=int(r.get("id") or 0),
                                    )
                                    continue
                                else:
                                    fail_reason = tp2_close_error or last_close_explain or _sm_reason_close_returned_false()
                                    await _notify_smart_decision("TP2", "NOT CLOSED", level_label="TP2", level_price=tp2, reason=fail_reason, cooldown_sec=15.0)

                    # --- TP1: probability engine (TP2 vs take profit now) ---
                    if (tp1 > 0) and (not tp1_seen) and _hit_tp(tp1):
                        tp1_decision = SmartDecisionEngine.finalize_tp1_decision(
                            base=SmartDecisionEngine.compute_tp2_probability(
                                entry_price=entry_p,
                                current_price=px,
                                best_price=best_px,
                                last_price=last_px,
                                tp2_price=tp2,
                                direction=direction,
                            ),
                            tp2_price=tp2,
                            force_full_if_no_tp2=FORCE_FULL_TP1_NO_TP2,
                            prob_strong=TP2_PROB_STRONG,
                            prob_med=TP2_PROB_MED,
                            tp1_partial_pct=TP1_PARTIAL_PCT,
                            tp1_partial_min_pct=TP1_PARTIAL_MIN_PCT,
                            tp1_partial_max_pct=TP1_PARTIAL_MAX_PCT,
                        )
                        mom_fav_pct = float(tp1_decision.momentum_favor_pct)
                        mom_adv_pct = float(tp1_decision.momentum_adverse_pct)
                        prob_tp2 = float(tp1_decision.probability)
                        prog = float(tp1_decision.progress_to_tp2)
                        dist = float(tp1_decision.distance_to_tp2_pct)
                        tp2_giveback_frac = float(tp1_decision.giveback_fraction)

                        ref["tp1_seen"] = True
                        tp1_seen = True
                        ref["tp2_prob"] = float(prob_tp2)
                        dirty = True

                        mode = str(tp1_decision.mode)
                        ref["tp1_mode"] = mode
                        dirty = True

                        if mode == "HOLD_TO_TP2":
                            # Strong conditions: skip TP1 close, aim for TP2 (close 100%)
                            ref["tp1_hit"] = True
                            dirty = True
                            try:
                                await _sync_pos_meta({"tp1_hit": True})
                            except Exception:
                                pass
                            await _notify_smart_decision("TP1", "NOT CLOSED", level_label="TP1", level_price=tp1, reason=_trf(uid, "sm_reason_hold_to_tp2", mode=_sm_mode_text(mode), prob_tp2=f"{prob_tp2:.2f}", progress=f"{float(prog):.2f}", mom_fav=f"{float(mom_fav_pct):.2f}%", mom_adv=f"{float(mom_adv_pct):.2f}%"), cooldown_sec=30.0)
                        elif mode == "PARTIAL_TP1":
                            partial_pct = float(tp1_decision.partial_pct or _smart_dynamic_partial_pct(
                                prob_tp2=float(prob_tp2),
                                prog_to_tp2=float(prog),
                                mom_fav_pct=float(mom_fav_pct),
                                dist_pct=float(dist),
                                giveback_frac=float(tp2_giveback_frac),
                            ))
                            q_close = max(0.0, qty * max(0.05, min(0.95, partial_pct)))
                            q_rem = max(0.0, qty - q_close)
                            if q_close > 0:
                                partial_ok = False
                                tp1_partial_error = ""
                                try:
                                    partial_ok = await _close_market(q_close)
                                except Exception as e:
                                    tp1_partial_error = str(e)
                                    _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] close market failed {ex}/{mt} {symbol}: {e}", every_s=60, level="info")
                                if partial_ok:
                                    await _notify_smart_decision("TP1", "PARTIAL CLOSED", level_label="TP1", level_price=tp1, reason=_trf(uid, "sm_reason_tp1_partial_closed", mode=_sm_mode_text(mode), closed_qty=_fmt_sm_price(q_close), remaining_qty=_fmt_sm_price(q_rem), detail=(last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or q_close))), cooldown_sec=5.0)
                                    ref["qty"] = float(q_rem)
                                    qty = float(q_rem)
                                    ref["tp1_hit"] = True
                                    ref["tp1_partial"] = True
                                    ref["tp1_ts"] = float(now_ts)
                                    ref["be_pending"] = True
                                    dirty = True
                                    try:
                                        await _sync_pos_meta({"tp1_hit": True, "tp1_partial": True, "be_pending": True})
                                    except Exception:
                                        pass
                                else:
                                    fail_reason = tp1_partial_error or last_close_explain or _sm_reason_close_returned_false()
                                    await _notify_smart_decision("TP1", "NOT CLOSED", level_label="TP1", level_price=tp1, reason=fail_reason, cooldown_sec=15.0)
                        else:
                            # FULL_TP1 / FULL_TP1_NO_TP2
                            close_ok = False
                            tp1_close_error = ""
                            try:
                                close_ok = await _close_market(qty)
                            except Exception as e:
                                tp1_close_error = str(e)
                                _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] close market failed {ex}/{mt} {symbol}: {e}", every_s=60, level="info")
                            if close_ok:
                                await _notify_smart_decision("TP1", "CLOSED", level_label="TP1", level_price=tp1, reason=_trf(uid, "sm_reason_tp1_full_close", mode=_sm_mode_text(mode), detail=(last_close_explain or _sm_reason_market_close_sent(last_close_norm_qty or qty))), cooldown_sec=5.0)
                                await _mark_local_full_close(str(mode), tp1_hit=True)
                                pnl_usdt, roi_percent = _smart_close_snapshot()

                                await db_store.close_autotrade_position(
                                    user_id=uid,
                                    signal_id=r.get("signal_id"),
                                    exchange=ex,
                                    market_type=mt,
                                    status="CLOSED",
                                    pnl_usdt=pnl_usdt,
                                    roi_percent=roi_percent,
                                    row_id=int(r.get("id") or 0),
                                )
                                continue
                            else:
                                fail_reason = tp1_close_error or last_close_explain or _sm_reason_close_returned_false()
                                await _notify_smart_decision("TP1", "NOT CLOSED", level_label="TP1", level_price=tp1, reason=fail_reason, cooldown_sec=15.0)
# --- Arm BE only AFTER partial TP1 and after a short delay + confirmation
                    if bool(ref.get("tp1_partial")) and bool(ref.get("be_pending")) and (not be_moved) and entry_p > 0:
                        if (now_ts - float(ref.get("tp1_ts") or 0.0)) >= max(0.0, BE_DELAY_SEC):
                            # Confirm: still not below entry (for long) / not above entry (for short)
                            ok_confirm = (px >= entry_p) if direction == "LONG" else (px <= entry_p)
                            if ok_confirm:
                                # Arm BE only if enough progress to TP2 (optional)
                                ok_prog = True
                                if tp2 > 0 and entry_p > 0 and tp2 != entry_p and BE_ARM_PCT_TO_TP2 > 0:
                                    if direction == "LONG":
                                        prog2 = (px - entry_p) / (tp2 - entry_p)
                                    else:
                                        prog2 = (entry_p - px) / (entry_p - tp2)
                                    ok_prog = float(prog2) >= float(BE_ARM_PCT_TO_TP2)

                                if ok_prog:
                                    # Dynamic BE buffer: min + vol_mult*vol, clamped
                                    vol_pct = 0.0
                                    if last_px > 0:
                                        vol_pct = abs(px / last_px - 1.0) * 100.0
                                    buf_pct = max(float(BE_MIN_PCT), min(float(BE_MAX_PCT), float(BE_MIN_PCT) + float(BE_VOL_MULT) * float(vol_pct)))

                                    tp2_prob_now = _clamp01(float(ref.get("tp2_prob") or 0.0))
                                    be_fee = float(_be_with_fee_buffer(entry_p, direction=direction) or 0.0)
                                    be_price = SmartDecisionEngine.compute_be_price(
                                        entry_price=entry_p,
                                        current_price=px,
                                        last_price=last_px,
                                        direction=direction,
                                        be_min_pct=BE_MIN_PCT,
                                        be_max_pct=BE_MAX_PCT,
                                        be_vol_mult=BE_VOL_MULT,
                                        be_fee_price=be_fee,
                                        profit_lock_enabled=PROFIT_LOCK_ENABLED,
                                        profit_lock_min_pct=PROFIT_LOCK_MIN_PCT,
                                        profit_lock_max_pct=PROFIT_LOCK_MAX_PCT,
                                        tp2_probability=tp2_prob_now,
                                    )

                                    ref["be_price"] = float(be_price)
                                    ref["be_moved"] = True
                                    ref["be_pending"] = False
                                    be_moved = True
                                    dirty = True
                                    try:
                                        await _sync_pos_meta({"be_moved": True, "be_price": float(be_price), "be_pending": False})
                                    except Exception:
                                        pass

                    # --- BE hit: close remaining ---
                    if bool(ref.get("be_moved")) and _hit_be():
                        close_ok = False
                        try:
                            close_ok = await _close_market(qty)
                        except Exception as e:
                            _log_rate_limited(f"smart_close_err:{uid}:{ex}:{mt}:{symbol}", f"[SMART] close_market failed {ex}/{mt} {symbol}: {e}", every_s=60, level="error")
                        if close_ok:
                            await _mark_local_full_close("BE", tp1_hit=True, be_moved_value=True)
                            pnl_usdt, roi_percent = _smart_close_snapshot()

                            await db_store.close_autotrade_position(
                                user_id=uid,
                                signal_id=r.get("signal_id"),
                                exchange=ex,
                                market_type=mt,
                                status="CLOSED",
                                pnl_usdt=pnl_usdt,
                                roi_percent=roi_percent,
                                row_id=int(r.get("id") or 0),
                            )
                            continue

                    # Persist updated ref if changed
                    if dirty:
                        try:
                            await db_store.update_autotrade_order_ref(row_id=int(r.get("id") or 0), api_order_ref=json.dumps(ref))
                        except Exception as e:
                            _smart_log_exception("smart_dirty_ref_persist", e)
                        try:
                            await _sync_pos_meta()
                        except Exception as e:
                            _smart_log_exception("smart_dirty_meta_sync", e)

                    continue
# If TP1 filled and BE not moved: cancel SL and place new SL at entry (BE)
                if tp1_id and (not be_moved) and be_price > 0:
                    if ex == "binance":
                        try:
                            o = await _binance_order_status(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(tp1_id), futures=futures)
                            tp1_filled = (str(o.get("status")) == "FILLED")
                        except ExchangeAPIError as e:
                            try:
                                await notify_api_error(uid, ex, mt, str(e)[:200])
                            except Exception:
                                pass
                            continue
                    else:
                        category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                        try:
                            o = await _bybit_order_status(api_key=api_key, api_secret=api_secret, category=category, symbol=symbol, order_id=str(tp1_id))
                            lst = ((o.get("result") or {}).get("list") or [])
                            st = (lst[0].get("orderStatus") if (lst and isinstance(lst[0], dict)) else None)
                            tp1_filled = (str(st) == "Filled")
                        except ExchangeAPIError as e:
                            try:
                                await notify_api_error(uid, ex, mt, str(e)[:200])
                            except Exception:
                                pass
                            continue
                    if tp1_filled:
                        try:
                            if sl_id:
                                if ex == "binance":
                                    await _binance_cancel_order(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(sl_id), futures=futures)
                                else:
                                    category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                                    await _bybit_cancel_order(api_key=api_key, api_secret=api_secret, category=category, symbol=symbol, order_id=str(sl_id))
                        except Exception:
                            pass

                        # Accumulate realized PnL on partial close (TP1) to improve final PnL accuracy.
                        # Keep this light: reuse TP1 status response ("o") and optionally fetch entry order once.
                        try:
                            if not bool(ref.get("tp1_realized_done")):
                                # Determine executed qty and avg price for TP1
                                if ex == "binance":
                                    tp1_qty_exec = _as_float(o.get("executedQty"), 0.0)
                                    tp1_avg = _binance_avg_price(o)
                                else:
                                    try:
                                        lst0 = ((o.get("result") or {}).get("list") or [])
                                        od0 = lst0[0] if (lst0 and isinstance(lst0[0], dict)) else {}
                                    except Exception:
                                        od0 = {}
                                    tp1_qty_exec = _as_float(od0.get("cumExecQty"), 0.0)
                                    tp1_avg = _bybit_avg_price(o)

                                # Get entry avg price (best-effort)
                                entry_avg = _as_float(ref.get("entry_avg_price"), 0.0)
                                if entry_avg <= 0:
                                    entry_id = ref.get("entry_order_id")
                                    if entry_id:
                                        if ex == "binance":
                                            eo = await _binance_order_status(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(entry_id), futures=futures)
                                            entry_avg = _binance_avg_price(eo)
                                        else:
                                            category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                                            eo = await _bybit_order_status(api_key=api_key, api_secret=api_secret, category=category, symbol=symbol, order_id=str(entry_id))
                                            entry_avg = _bybit_avg_price(eo)
                                if entry_avg <= 0:
                                    entry_avg = _as_float(ref.get("entry_price"), 0.0)

                                if tp1_qty_exec > 0 and tp1_avg > 0 and entry_avg > 0:
                                    side_local = str(ref.get("side") or "BUY").upper()
                                    if side_local == "BUY":
                                        pnl_gross = (tp1_avg - entry_avg) * tp1_qty_exec
                                    else:
                                        pnl_gross = (entry_avg - tp1_avg) * tp1_qty_exec

                                    fr_local = float(FEE_RATE_SPOT if str(mt).lower() == "spot" else FEE_RATE_FUTURES)
                                    fees_est = fr_local * ((entry_avg * tp1_qty_exec) + (tp1_avg * tp1_qty_exec))

                                    ref["realized_pnl_usdt"] = float(_as_float(ref.get("realized_pnl_usdt"), 0.0) + pnl_gross)
                                    ref["realized_fee_usdt"] = float(_as_float(ref.get("realized_fee_usdt"), 0.0) + fees_est)
                                    ref["realized_qty"] = float(_as_float(ref.get("realized_qty"), 0.0) + tp1_qty_exec)
                                    ref["entry_avg_price"] = float(entry_avg)
                                    ref["tp1_realized_done"] = True
                        except Exception:
                            # Best-effort only; do not block management.
                            pass

                        # Place new SL at BE
                        if ex == "binance":
                            if futures:
                                new_sl = await _binance_futures_stop_market_close_all(api_key=api_key, api_secret=api_secret, symbol=symbol, side=close_side, stop_price=be_price)
                            else:
                                qty = float(ref.get("qty") or 0.0)
                                new_sl = await _binance_spot_stop_loss_limit_sell(api_key=api_key, api_secret=api_secret, symbol=symbol, qty=qty, stop_price=be_price)
                        else:
                            category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                            qty = float(ref.get("qty") or 0.0)
                            new_sl = await _bybit_order_create(
                                api_key=api_key,
                                api_secret=api_secret,
                                category=category,
                                symbol=symbol,
                                side=close_side,
                                order_type="Market",
                                qty=qty,
                                trigger_price=be_price,
                                reduce_only=(True if mt == "futures" else None),
                                close_on_trigger=(True if mt == "futures" else None),
                            )

                        if ex == "binance":
                            ref["sl_order_id"] = new_sl.get("orderId")
                        else:
                            ref["sl_order_id"] = str(((new_sl.get("result") or {}).get("orderId") or "")) or None
                        ref["be_moved"] = True
                        await db_store.update_autotrade_order_ref(row_id=int(r.get("id")), api_order_ref=json.dumps(ref))

                # Close detection: SL filled OR (TP2 filled if exists else TP1 filled)
                # If SL FILLED -> closed
                if sl_id:
                    if ex == "binance":
                        try:
                            o_sl = await _binance_order_status(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(sl_id), futures=futures)
                            sl_filled = (str(o_sl.get("status")) == "FILLED")
                        except ExchangeAPIError as e:
                            try:
                                await notify_api_error(uid, ex, mt, str(e)[:200])
                            except Exception:
                                pass
                            continue
                    else:
                        category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                        try:
                            o_sl = await _bybit_order_status(api_key=api_key, api_secret=api_secret, category=category, symbol=symbol, order_id=str(sl_id))
                            lst = ((o_sl.get("result") or {}).get("list") or [])
                            stx = (lst[0].get("orderStatus") if (lst and isinstance(lst[0], dict)) else None)
                            sl_filled = (str(stx) == "Filled")
                        except ExchangeAPIError as e:
                            try:
                                await notify_api_error(uid, ex, mt, str(e)[:200])
                            except Exception:
                                pass
                            continue
                    if sl_filled:
                        pnl_usdt = None
                        roi_percent = None
                        try:
                            entry_id = ref.get("entry_order_id")
                            entry_order = None
                            if entry_id:
                                if ex == "binance":
                                    entry_order = await _binance_order_status(
                                        api_key=api_key,
                                        api_secret=api_secret,
                                        symbol=symbol,
                                        order_id=int(entry_id),
                                        futures=futures,
                                    )
                                else:
                                    category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                                    entry_order = await _bybit_order_status(
                                        api_key=api_key,
                                        api_secret=api_secret,
                                        category=category,
                                        symbol=symbol,
                                        order_id=str(entry_id),
                                    )
                            if entry_order:
                                pnl_usdt, roi_percent = _calc_autotrade_pnl_from_orders(
                                    ref=ref,
                                    entry_order=entry_order,
                                    exit_order=o_sl,
                                    exchange=ex,
                                    market_type=mt,
                                    allocated_usdt=float(r.get("allocated_usdt") or 0.0),
                                )
                        except Exception:
                            pnl_usdt = None
                            roi_percent = None
                        await _sync_pos_meta({"closed_reason": ("BE" if bool(ref.get("be_moved")) else "SL"), "tp1_hit": bool(ref.get("tp1_hit") or meta.get("tp1_hit")), "be_moved": bool(ref.get("be_moved") or meta.get("be_moved")), "be_price": float(ref.get("be_price") or meta.get("be_price") or 0.0)})
                        await db_store.close_autotrade_position(
                            user_id=uid,
                            signal_id=r.get("signal_id"),
                            exchange=ex,
                            market_type=mt,
                            status="CLOSED",
                            pnl_usdt=pnl_usdt,
                            roi_percent=roi_percent,
                            row_id=int(r.get("id") or 0),
                        )
                        try:
                            acc2 = await db_store.get_autotrade_access(uid)
                            if bool(acc2.get("autotrade_stop_after_close")):
                                if await db_store.count_open_autotrade_positions(uid) <= 0:
                                    await db_store.finalize_autotrade_disable(uid)
                        except Exception:
                            pass
                        continue

                target_id = tp2_id or tp1_id
                if target_id:
                    if ex == "binance":
                        try:
                            o_tp = await _binance_order_status(api_key=api_key, api_secret=api_secret, symbol=symbol, order_id=int(target_id), futures=futures)
                            tp_filled = (str(o_tp.get("status")) == "FILLED")
                        except ExchangeAPIError as e:
                            try:
                                await notify_api_error(uid, ex, mt, str(e)[:200])
                            except Exception:
                                pass
                            continue
                    else:
                        category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                        try:
                            o_tp = await _bybit_order_status(api_key=api_key, api_secret=api_secret, category=category, symbol=symbol, order_id=str(target_id))
                            lst = ((o_tp.get("result") or {}).get("list") or [])
                            stx = (lst[0].get("orderStatus") if (lst and isinstance(lst[0], dict)) else None)
                            tp_filled = (str(stx) == "Filled")
                        except ExchangeAPIError as e:
                            try:
                                await notify_api_error(uid, ex, mt, str(e)[:200])
                            except Exception:
                                pass
                            continue
                    if tp_filled:
                        pnl_usdt = None
                        roi_percent = None
                        try:
                            entry_id = ref.get("entry_order_id")
                            entry_order = None
                            if entry_id:
                                if ex == "binance":
                                    entry_order = await _binance_order_status(
                                        api_key=api_key,
                                        api_secret=api_secret,
                                        symbol=symbol,
                                        order_id=int(entry_id),
                                        futures=futures,
                                    )
                                else:
                                    category = str(ref.get("category") or ("spot" if mt == "spot" else "linear"))
                                    entry_order = await _bybit_order_status(
                                        api_key=api_key,
                                        api_secret=api_secret,
                                        category=category,
                                        symbol=symbol,
                                        order_id=str(entry_id),
                                    )
                            if entry_order:
                                pnl_usdt, roi_percent = _calc_autotrade_pnl_from_orders(
                                    ref=ref,
                                    entry_order=entry_order,
                                    exit_order=o_tp,
                                    exchange=ex,
                                    market_type=mt,
                                    allocated_usdt=float(r.get("allocated_usdt") or 0.0),
                                )
                        except Exception:
                            pnl_usdt = None
                            roi_percent = None
                        tp2_cfg = float(ref.get("tp2") or meta.get("tp2") or 0.0)
                        close_reason = "TP2" if bool(tp2_id) else ("FULL_TP1" if tp2_cfg > 0 else "FULL_TP1_NO_TP2")
                        await _sync_pos_meta({"closed_reason": close_reason, "tp1_hit": bool(ref.get("tp1_hit") or meta.get("tp1_hit") or (not bool(tp2_id)))})
                        await db_store.close_autotrade_position(
                            user_id=uid,
                            signal_id=r.get("signal_id"),
                            exchange=ex,
                            market_type=mt,
                            status="CLOSED",
                            pnl_usdt=pnl_usdt,
                            roi_percent=roi_percent,
                            row_id=int(r.get("id") or 0),
                        )
                        try:
                            acc2 = await db_store.get_autotrade_access(uid)
                            if bool(acc2.get("autotrade_stop_after_close")):
                                if await db_store.count_open_autotrade_positions(uid) <= 0:
                                    await db_store.finalize_autotrade_disable(uid)
                        except Exception:
                            pass

        except ExchangeAPIError as e:
            # global API issue; no user id here
            logger.warning("Auto-trade manager API error: %s", e)
        except Exception:
            logger.exception("Auto-trade manager loop error")

        await asyncio.sleep(manager_sleep_sec)


# --- i18n template safety guard (prevents leaking {placeholders} to users) ---
_UNFILLED_RE = re.compile(r'(?<!\{)\{[a-zA-Z0-9_]+\}(?!\})')

def _sanitize_template_text(uid: int, text: str, ctx: str = "") -> str:
    if not text:
        return text
    hits = _UNFILLED_RE.findall(text)
    if hits:
        logger.error("Unfilled i18n placeholders for uid=%s ctx=%s hits=%s text=%r", uid, ctx, sorted(set(hits)), text)
        text = _UNFILLED_RE.sub("", text)
        text = re.sub(r"[ \t]{2,}", " ", text)
        text = re.sub(r"\n{3,}", "\n\n", text).strip()
    return text

async def safe_send(bot, chat_id: int, text: str, *, ctx: str = "", **kwargs):
    text = _sanitize_template_text(chat_id, text, ctx=ctx)
    # Never recurse. Send via bot API.
    return await bot.send_message(chat_id, text, **kwargs)



# ------------------ ENV helpers ------------------
def _env_int(name: str, default: int) -> int:
    v = os.getenv(name, "").strip()
    if not v:
        return default
    try:
        return int(v)
    except Exception:
        return default

def _env_float(name: str, default: float) -> float:
    v = os.getenv(name, "").strip()
    if not v:
        return default
    try:
        return float(v)
    except Exception:
        return default


def _env_str(name: str, default: str) -> str:
    v = os.getenv(name, "").strip()
    return v if v else default
def _env_bool(name: str, default: bool = False) -> bool:
    v = os.getenv(name, "").strip().lower()
    if v == "":
        return default
    return v in ("1", "true", "yes", "y", "on")


# --- i18n helpers (loaded from i18n.json; no hardcoded auto-close texts) ---
I18N_FILE = Path(__file__).with_name("i18n.json")
LANG_FILE = Path("langs.json")

_I18N_CACHE: dict = {}
_I18N_MTIME: float = 0.0
_LANG_CACHE: dict[int, str] = {}
_LANG_CACHE_MTIME: float = 0.0

def _load_i18n() -> dict:
    global _I18N_CACHE, _I18N_MTIME
    try:
        if I18N_FILE.exists():
            mt = I18N_FILE.stat().st_mtime
            if _I18N_CACHE and mt == _I18N_MTIME:
                return _I18N_CACHE
            data = json.loads(I18N_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict) and "ru" in data and "en" in data:
                _I18N_CACHE = data
                _I18N_MTIME = mt
                return data
    except Exception:
        pass
    if not _I18N_CACHE:
        _I18N_CACHE = {"ru": {}, "en": {}}
    return _I18N_CACHE

def _load_langs_if_needed() -> None:
    global _LANG_CACHE, _LANG_CACHE_MTIME
    try:
        if not LANG_FILE.exists():
            _LANG_CACHE = {}
            _LANG_CACHE_MTIME = 0.0
            return
        mt = LANG_FILE.stat().st_mtime
        if mt == _LANG_CACHE_MTIME:
            return
        raw = json.loads(LANG_FILE.read_text(encoding="utf-8"))
        if isinstance(raw, dict):
            tmp: dict[int, str] = {}
            for k, v in raw.items():
                try:
                    uid = int(k)
                except Exception:
                    continue
                vv = (v or "").lower().strip()
                tmp[uid] = "en" if vv == "en" else "ru"
            _LANG_CACHE = tmp
            _LANG_CACHE_MTIME = mt
    except Exception:
        pass

def _get_lang(uid: int) -> str:
    _load_langs_if_needed()
    return _LANG_CACHE.get(int(uid), "ru")

def _tr(uid: int, key: str) -> str:
    lang = _get_lang(uid)
    i18n = _load_i18n()
    d = i18n.get(lang, {})
    if key in d:
        return d.get(key, key)
    return i18n.get("en", {}).get(key, key)

class _SafeDict(dict):
    def __missing__(self, key):
        return "{" + key + "}"

def _trf(uid: int, key: str, **kwargs) -> str:
    tmpl = _tr(uid, key)
    try:
        return str(tmpl).format_map(_SafeDict(**kwargs))
    except Exception:
        return str(tmpl)

def _market_label(uid: int, market: str) -> str:
    return _tr(uid, "lbl_spot") if str(market).upper() == "SPOT" else _tr(uid, "lbl_futures")
