# ------------------ backend-only metrics helpers ------------------

def calc_profit_pct(entry: float, tp: float, direction: str) -> float:
    """Estimated profit percent from entry to tp for LONG/SHORT."""
    try:
        entry = float(entry)
        tp = float(tp)
        if entry == 0:
            return 0.0
        side = str(direction or "LONG").upper().strip()
        if side == "SHORT":
            return (entry - tp) / entry * 100.0
        return (tp - entry) / entry * 100.0
    except Exception:
        return 0.0

def default_futures_leverage() -> str:
    v = os.getenv("FUTURES_LEVERAGE_DEFAULT", "5").strip()
    return v or "5"

def open_metrics(sig: "Signal") -> dict:
    """Return placeholders for OPEN templates, computed only here (backend-only)."""
    side = (getattr(sig, "direction", "") or "LONG").upper().strip()
    mkt = (getattr(sig, "market", "") or "FUTURES").upper().strip()
    # prefer TP2 for estimate; fallback to TP1
    tp = getattr(sig, "tp2", 0.0) or getattr(sig, "tp1", 0.0) or 0.0
    entry = getattr(sig, "entry", 0.0) or 0.0
    profit = calc_profit_pct(entry, tp, side)
    return {
        "side": side,
        "market": mkt,
        "profit": round(float(profit), 1),
        "lev": default_futures_leverage(),
        "rr": round(float(getattr(sig, "rr", 0.0) or 0.0), 1),
    }


MIN_SIGNAL_PROFIT_PCT = max(0.0, float(os.getenv("MIN_SIGNAL_PROFIT_PCT", "1.0") or 1.0))

def signal_expected_profit_pct(sig: "Signal") -> float:
    """Estimated signal profit % using TP2 if available, otherwise TP1."""
    try:
        side = (getattr(sig, "direction", "") or "LONG").upper().strip()
        entry = float(getattr(sig, "entry", 0.0) or 0.0)
        tp = float(getattr(sig, "tp2", 0.0) or getattr(sig, "tp1", 0.0) or 0.0)
        return float(calc_profit_pct(entry, tp, side))
    except Exception:
        return 0.0

def signal_min_profit_gate(sig: "Signal") -> tuple[bool, float, float]:
    """Return (ok, expected_profit_pct, min_required_pct)."""
    try:
        min_req = max(0.0, float(os.getenv("MIN_SIGNAL_PROFIT_PCT", str(MIN_SIGNAL_PROFIT_PCT)) or MIN_SIGNAL_PROFIT_PCT))
    except Exception:
        min_req = float(MIN_SIGNAL_PROFIT_PCT)
    profit = signal_expected_profit_pct(sig)
    return (float(profit) >= float(min_req), float(profit), float(min_req))



def signal_rr_gate(sig: "Signal") -> tuple[bool, float, float]:
    """Return (ok, rr_value, min_required_rr).

    In this deployment low-RR setups are allowed through, but we still calculate and
    expose RR for logging/UI. When MID_ALLOW_LOW_RR_SIGNALS=0 the old hard gate remains.
    """
    try:
        market = str(getattr(sig, "market", "FUTURES") or "FUTURES").upper().strip()
    except Exception:
        market = "FUTURES"
    try:
        if market == "SPOT":
            min_req = float(os.getenv("MID_MIN_RR_EMIT_SPOT", "1.20") or 1.20)
        else:
            min_req = float(os.getenv("MID_MIN_RR_EMIT_FUTURES", os.getenv("MID_MIN_RR_EMIT_FUT", "1.15")) or 1.15)
    except Exception:
        min_req = 1.20 if market == "SPOT" else 1.15

    try:
        rr = float(getattr(sig, "rr", 0.0) or 0.0)
        if rr <= 0:
            entry = float(getattr(sig, "entry", 0.0) or 0.0)
            sl = float(getattr(sig, "sl", 0.0) or 0.0)
            tp1 = float(getattr(sig, "tp1", 0.0) or 0.0)
            tp2 = float(getattr(sig, "tp2", 0.0) or 0.0)
            rr = _rr_from_levels(entry, sl, tp1, tp2)
    except Exception:
        rr = 0.0

    if _mid_allow_low_rr_signals():
        return (True, float(rr), float(min_req))
    return (float(rr) >= float(min_req), float(rr), float(min_req))


def _mid_instant_emit_market_thresholds(market: str) -> tuple[float, float]:
    """Return strict ATR%% and volume minimums for VIP instant emit.

    In early-entry mode we cap legacy-deployment thresholds to sane values so smart-setup
    can still emit near the start of the move instead of always falling back to pending.
    """
    m = (market or "SPOT").upper().strip()
    try:
        if m == "FUTURES":
            min_atr = float(os.getenv("MID_INSTANT_EMIT_MIN_ATR_PCT_FUTURES", os.getenv("MID_INSTANT_EMIT_MIN_ATR_PCT_FUT", "0.11")) or 0.11)
            min_vol = float(os.getenv("MID_INSTANT_EMIT_MIN_VOL_X_FUTURES", os.getenv("MID_INSTANT_EMIT_MIN_VOL_X_FUT", "0.28")) or 0.28)
        else:
            min_atr = float(os.getenv("MID_INSTANT_EMIT_MIN_ATR_PCT_SPOT", "0.18") or 0.18)
            min_vol = float(os.getenv("MID_INSTANT_EMIT_MIN_VOL_X_SPOT", "0.10") or 0.10)
    except Exception:
        if m == "FUTURES":
            min_atr, min_vol = 0.11, 0.28
        else:
            min_atr, min_vol = 0.18, 0.10
    try:
        if _MID_EARLY_ENTRY_GUARD and _mid_soft_blocks_enabled():
            if m == "FUTURES":
                min_atr = min(float(min_atr), float(os.getenv("MID_EARLY_ENTRY_INSTANT_ATR_CAP_FUTURES", os.getenv("MID_EARLY_ENTRY_INSTANT_ATR_CAP_FUT", "0.09")) or 0.09))
                min_vol = min(float(min_vol), float(os.getenv("MID_EARLY_ENTRY_INSTANT_VOL_CAP_FUTURES", os.getenv("MID_EARLY_ENTRY_INSTANT_VOL_CAP_FUT", "0.05")) or 0.05))
            else:
                min_atr = min(float(min_atr), float(os.getenv("MID_EARLY_ENTRY_INSTANT_ATR_CAP_SPOT", "0.15") or 0.15))
                min_vol = min(float(min_vol), float(os.getenv("MID_EARLY_ENTRY_INSTANT_VOL_CAP_SPOT", "0.03") or 0.03))
    except Exception:
        pass
    return (float(max(0.0, min_atr)), float(max(0.0, min_vol)))


def _mid_instant_profit_cap(market: str) -> float:
    """Return instant profit cap per market with backward-compatible fallback.

    Defaults:
      - SPOT: 1.0
      - FUTURES: 0.5
    Legacy MID_EARLY_ENTRY_INSTANT_PROFIT_CAP still works as a shared fallback when
    market-specific envs are not provided.
    """
    m = (market or "SPOT").upper().strip()
    base_default = 0.5 if m == "FUTURES" else 1.0
    common_raw = os.getenv("MID_EARLY_ENTRY_INSTANT_PROFIT_CAP")
    try:
        common = float(common_raw) if common_raw not in (None, "") else float(base_default)
    except Exception:
        common = float(base_default)
    try:
        if m == "FUTURES":
            value = float(
                os.getenv(
                    "MID_EARLY_ENTRY_INSTANT_PROFIT_CAP_FUTURES",
                    os.getenv("MID_EARLY_ENTRY_INSTANT_PROFIT_CAP_FUT", str(common)),
                )
                or common
            )
        else:
            value = float(os.getenv("MID_EARLY_ENTRY_INSTANT_PROFIT_CAP_SPOT", str(common)) or common)
    except Exception:
        value = common
    return float(max(0.0, value))


def _mid_instant_emit_near_extreme_ok(*, direction: str, entry: float, recent_low: float | None, recent_high: float | None,
                                      atr30: float | None, market: str = "SPOT") -> tuple[bool, str]:
    """Recent-extreme guard for VIP instant emit.

    Missing context should not hard-block instant emit by default. False negatives were
    common when recent high/low data was absent or ATR was temporarily unavailable.
    Set MID_INSTANT_EMIT_NEAR_EXTREME_REQUIRE_DATA=1 to restore fail-closed behavior.
    """
    try:
        require_data = str(os.getenv("MID_INSTANT_EMIT_NEAR_EXTREME_REQUIRE_DATA", "0") or "0").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        require_data = False
    try:
        atr = float(atr30 or 0.0)
        px = float(entry or 0.0)
        if atr <= 0 or px <= 0:
            return ((False, "near_extreme_no_atr") if require_data else (True, "near_extreme_skip_no_atr"))
        m = (market or "SPOT").upper().strip()
        if m == "FUTURES":
            thr = float(os.getenv("MID_INSTANT_EMIT_NEAR_EXTREME_ATR_FUTURES", os.getenv("MID_INSTANT_EMIT_NEAR_EXTREME_ATR_FUT", "0.45")) or 0.45)
        else:
            thr = float(os.getenv("MID_INSTANT_EMIT_NEAR_EXTREME_ATR_SPOT", "0.35") or 0.35)
        d = (direction or "").upper().strip()
        if d == "LONG":
            hi = float(recent_high or 0.0)
            if hi <= 0:
                return ((False, "near_extreme_no_high") if require_data else (True, "near_extreme_skip_no_high"))
            dist = (hi - px) / atr
            if dist < float(thr):
                return (False, f"near_recent_high dist_atr={dist:.2f} < {thr:g}")
            return (True, f"near_recent_high dist_atr={dist:.2f}")
        if d == "SHORT":
            lo = float(recent_low or 0.0)
            if lo <= 0:
                return ((False, "near_extreme_no_low") if require_data else (True, "near_extreme_skip_no_low"))
            dist = (px - lo) / atr
            if dist < float(thr):
                return (False, f"near_recent_low dist_atr={dist:.2f} < {thr:g}")
            return (True, f"near_recent_low dist_atr={dist:.2f}")
    except Exception as e:
        return ((False, f"near_extreme_error:{e}") if require_data else (True, f"near_extreme_skip_error:{type(e).__name__}"))
    return (True, "near_extreme_skip_bad_dir")


def _mid_smart_setup_trap_eval(*,
                                 market: str,
                                 direction: str,
                                 entry: float | None,
                                 atr30_abs: float | None,
                                 bb_pos: str | None = None,
                                 vwap_val: float | None = None,
                                 last_body: float | None = None,
                                 vol_x: float | None = None,
                                 vol_last: float | None = None,
                                 vol_avg: float | None = None,
                                 breakout_fresh_ok: bool = False,
                                 origin_fast_ok: bool = False,
                                 in_zone_now: bool = False,
                                 allow_no_zone_breakout: bool = False,
                                 confidence: float | None = None) -> tuple[bool, str, dict]:
    """Separate smart-setup trap for instant emit only.

    Design goal: reduce SL on impulsive smart_setup entries *without* noticeably
    reducing total signal count. When this trap fails, the caller should simply
    skip instant emit and keep the setup alive for pending / retest handling.
    """
    meta: dict[str, object] = {}
    try:
        enabled = str(os.getenv("MID_SMART_SETUP_TRAP_ENABLED", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        enabled = True
    meta["enabled"] = bool(enabled)
    if not enabled:
        meta["primary_reason"] = "smart_setup_trap_disabled"
        meta["all_reasons"] = "smart_setup_trap_disabled"
        return (True, "smart_setup_trap_disabled", meta)

    try:
        active = bool(breakout_fresh_ok) or bool(origin_fast_ok) or bool(allow_no_zone_breakout) or (not bool(in_zone_now))
    except Exception:
        active = True
    meta["active"] = bool(active)
    meta["breakout_fresh_ok"] = bool(breakout_fresh_ok)
    meta["origin_fast_ok"] = bool(origin_fast_ok)
    meta["in_zone_now"] = bool(in_zone_now)
    meta["allow_no_zone_breakout"] = bool(allow_no_zone_breakout)
    if not active:
        meta["primary_reason"] = "smart_setup_trap_inactive"
        meta["all_reasons"] = "smart_setup_trap_inactive"
        return (True, "smart_setup_trap_inactive", meta)

    try:
        only_breakout = str(os.getenv("MID_SMART_SETUP_TRAP_ONLY_BREAKOUT", "0") or "0").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        only_breakout = False
    if only_breakout and not bool(breakout_fresh_ok):
        meta["primary_reason"] = "smart_setup_trap_skip_non_breakout"
        meta["all_reasons"] = "smart_setup_trap_skip_non_breakout"
        return (True, "smart_setup_trap_skip_non_breakout", meta)

    try:
        mkt = (market or "SPOT").upper().strip()
    except Exception:
        mkt = "SPOT"
    try:
        diru = (direction or "").upper().strip()
    except Exception:
        diru = ""
    try:
        px = float(entry or 0.0)
    except Exception:
        px = 0.0
    try:
        atr = float(atr30_abs or 0.0)
    except Exception:
        atr = 0.0
    try:
        vwap = float(vwap_val or 0.0)
    except Exception:
        vwap = 0.0
    try:
        body_atr = (abs(float(last_body or 0.0)) / atr) if atr > 0 else 0.0
    except Exception:
        body_atr = 0.0
    try:
        conf_v = float(confidence or 0.0)
    except Exception:
        conf_v = 0.0
    try:
        vol_ratio = float(vol_x or 0.0)
    except Exception:
        vol_ratio = 0.0
    if not vol_ratio:
        try:
            _vl = float(vol_last or 0.0)
            _va = float(vol_avg or 0.0)
            if _va > 0:
                vol_ratio = _vl / _va
        except Exception:
            vol_ratio = 0.0

    bb = str(bb_pos or "").strip()
    vwap_dist_atr = (abs(px - vwap) / atr) if (px > 0 and vwap > 0 and atr > 0) else 0.0

    try:
        relax_at = float(os.getenv("MID_SMART_SETUP_TRAP_RELAX_CONF", "97") or 97)
    except Exception:
        relax_at = 97.0
    try:
        relax_mult = float(os.getenv("MID_SMART_SETUP_TRAP_RELAX_MULT", "1.08") or 1.08)
    except Exception:
        relax_mult = 1.08

    if mkt == "FUTURES":
        try:
            max_vwap_dist = float(os.getenv("MID_SMART_SETUP_TRAP_VWAP_DIST_ATR_MAX_FUT", "1.15") or 1.15)
        except Exception:
            max_vwap_dist = 1.15
    else:
        try:
            max_vwap_dist = float(os.getenv("MID_SMART_SETUP_TRAP_VWAP_DIST_ATR_MAX_SPOT", "1.00") or 1.00)
        except Exception:
            max_vwap_dist = 1.00
    if conf_v >= relax_at:
        max_vwap_dist *= max(1.0, float(relax_mult))

    try:
        bb_combo_vwap_min = float(os.getenv("MID_SMART_SETUP_TRAP_BB_COMBO_VWAP_MIN", "0.90") or 0.90)
    except Exception:
        bb_combo_vwap_min = 0.90
    try:
        impulse_body_min = float(os.getenv("MID_SMART_SETUP_TRAP_IMPULSE_BODY_ATR_MIN", "0.50") or 0.50)
    except Exception:
        impulse_body_min = 0.50
    try:
        impulse_vwap_min = float(os.getenv("MID_SMART_SETUP_TRAP_IMPULSE_VWAP_MIN", "0.85") or 0.85)
    except Exception:
        impulse_vwap_min = 0.85
    try:
        impulse_vol_min = float(os.getenv("MID_SMART_SETUP_TRAP_IMPULSE_VOL_X_MIN", "0.0") or 0.0)
    except Exception:
        impulse_vol_min = 0.0

    if diru == "LONG":
        bb_extreme = bb in ("↑high",)
        bb_soft = bb in ("mid→high",)
    elif diru == "SHORT":
        bb_extreme = bb in ("↓low",)
        bb_soft = bb in ("low→mid",)
    else:
        bb_extreme = False
        bb_soft = False

    meta.update({
        "market": mkt,
        "dir": diru,
        "bb_pos": bb or "-",
        "bb_extreme": bool(bb_extreme),
        "bb_soft": bool(bb_soft),
        "entry": float(px),
        "atr30_abs": float(atr),
        "vwap_val": float(vwap),
        "vwap_dist_atr": float(vwap_dist_atr),
        "max_vwap_dist_atr": float(max_vwap_dist),
        "body_atr": float(body_atr),
        "impulse_body_min": float(impulse_body_min),
        "impulse_vwap_min": float(impulse_vwap_min),
        "vol_x": float(vol_ratio),
        "impulse_vol_min": float(impulse_vol_min),
        "confidence": float(conf_v),
        "relax_conf": float(relax_at),
    })

    reasons: list[str] = []
    softened_reasons: list[str] = []
    try:
        soften_in_zone = str(os.getenv("MID_SMART_SETUP_TRAP_SOFTEN_IN_ZONE", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        soften_in_zone = True
    try:
        zone_vwap_hard_mult = float(os.getenv("MID_SMART_SETUP_TRAP_IN_ZONE_VWAP_HARD_MULT", "2.20") or 2.20)
    except Exception:
        zone_vwap_hard_mult = 2.20
    zone_soft_trap = bool(soften_in_zone and in_zone_now and (not allow_no_zone_breakout))
    zone_vwap_hard_limit = float(max_vwap_dist) * max(1.0, float(zone_vwap_hard_mult))
    meta["zone_soft_trap"] = bool(zone_soft_trap)
    meta["zone_vwap_hard_limit"] = float(zone_vwap_hard_limit)
    try:
        block_bb_extreme = str(os.getenv("MID_SMART_SETUP_TRAP_BLOCK_BB_EXTREME", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        block_bb_extreme = True
    if block_bb_extreme and bb_extreme:
        reasons.append(f"smart_setup_trap_bb_extreme:{bb or '-'}")

    try:
        block_vwap_stretch = str(os.getenv("MID_SMART_SETUP_TRAP_BLOCK_VWAP_STRETCH", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        block_vwap_stretch = True
    if block_vwap_stretch and vwap_dist_atr > float(max_vwap_dist):
        _reason = f"smart_setup_trap_vwap_ext:{vwap_dist_atr:.2f}>{max_vwap_dist:.2f}"
        if zone_soft_trap and vwap_dist_atr <= float(zone_vwap_hard_limit):
            softened_reasons.append(_reason)
        else:
            reasons.append(_reason)

    try:
        block_bb_combo = str(os.getenv("MID_SMART_SETUP_TRAP_BLOCK_BB_COMBO", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        block_bb_combo = True
    if block_bb_combo and bb_soft and vwap_dist_atr >= float(bb_combo_vwap_min):
        _reason = f"smart_setup_trap_bb_stretch:{bb or '-'}|vwap={vwap_dist_atr:.2f}"
        if zone_soft_trap and vwap_dist_atr <= float(zone_vwap_hard_limit):
            softened_reasons.append(_reason)
        else:
            reasons.append(_reason)

    try:
        block_impulse = str(os.getenv("MID_SMART_SETUP_TRAP_BLOCK_IMPULSE", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        block_impulse = True
    if block_impulse and body_atr >= float(impulse_body_min) and vwap_dist_atr >= float(impulse_vwap_min) and float(vol_ratio) >= float(impulse_vol_min):
        if bb_soft or bb_extreme or bool(breakout_fresh_ok):
            reasons.append(f"smart_setup_trap_impulse:body={body_atr:.2f}|vwap={vwap_dist_atr:.2f}|vol={vol_ratio:.2f}")

    if softened_reasons:
        meta["softened_reasons"] = list(softened_reasons)
        try:
            meta["softened_reasons_text"] = "|".join(str(x) for x in softened_reasons if str(x).strip())
        except Exception:
            meta["softened_reasons_text"] = ""

    if reasons:
        meta["fail_reasons"] = list(reasons)
        meta["primary_reason"] = str(reasons[0])
        meta["all_reasons"] = "|".join(reasons)
        try:
            _smart_setup_log(
                "trap_block",
                market=mkt,
                dir=diru,
                reason=str(reasons[0]),
                all_reasons=str(meta.get("all_reasons") or reasons[0]),
                bb=bb or "-",
                vwap_dist=f"{vwap_dist_atr:.2f}",
                body_atr=f"{body_atr:.2f}",
                conf=f"{conf_v:.1f}",
                in_zone=int(bool(in_zone_now)),
                breakout=int(bool(breakout_fresh_ok)),
            )
        except Exception:
            pass
        return (False, str(reasons[0]), meta)

    meta["fail_reasons"] = []
    if softened_reasons:
        try:
            meta["primary_reason"] = str(softened_reasons[0])
            meta["all_reasons"] = "|".join(list(softened_reasons))
        except Exception:
            meta["primary_reason"] = "pass"
            meta["all_reasons"] = "pass"
    else:
        meta["primary_reason"] = "pass"
        meta["all_reasons"] = "pass"
    return (True, "pass", meta)


def _mid_instant_emit_reason_priority(reason: str) -> tuple[int, str]:
    """Stable ordering for instant-emit blockers so the primary reason is actionable."""
    s = str(reason or "").strip()
    key = s.lower()
    priorities = [
        ("instant_zone_wait", 10),
        ("instant_zone_missing", 11),
        ("instant_conf_low", 20),
        ("instant_no_zone_conf", 21),
        ("instant_profit_low", 30),
        ("instant_atr_low", 40),
        ("instant_vol_low", 41),
        ("instant_regime_block", 50),
        ("smart_setup_trap_", 55),
        ("near_recent_", 60),
        ("near_extreme_", 61),
        ("micro_", 70),
        ("late_entry_", 80),
        ("anti_bounce_", 81),
        ("instant_no_zone_atr", 90),
        ("instant_no_zone_vol", 91),
        ("instant_risk_flags", 100),
    ]
    for prefix, score in priorities:
        if key.startswith(prefix):
            return (score, key)
    return (500, key)


def _mid_smc_confluence_snapshot(*,
                                direction: str,
                                ta: dict | None = None,
                                rec: dict | None = None,
                                bo_rt_label: str | None = None) -> dict:
    """Summarize SMC confluence so emit gates can prioritize real OB/FVG/BOS setups.

    The goal is no longer just "score influence". We collect enough evidence to allow
    dedicated emit routes for the classic SMC combinations the user asked for:
      - OB + FVG overlap priority emit
      - HTF OB + LTF FVG retest emit
      - BOS -> retest POI -> confirm emit
      - displacement / dual-FVG origin emit
      - liquidity sweep -> reclaim -> continuation emit
    """
    t = ta if isinstance(ta, dict) else {}
    r = rec if isinstance(rec, dict) else {}
    diru = str(direction or '').upper().strip()
    bo = str(bo_rt_label or t.get('bo_rt') or t.get('breakout_retest') or r.get('bo_rt') or r.get('breakout_retest') or '').upper().strip()
    ob_zone = str(t.get('ob_zone') or r.get('ob_zone') or '').strip()
    fvg_kind = str(t.get('fvg') or r.get('fvg') or '').upper().strip()
    fvg_active = bool(t.get('fvg_active') if t.get('fvg_active') is not None else r.get('fvg_active'))
    ob_retest = bool(t.get('ob_retest') if t.get('ob_retest') is not None else r.get('ob_retest'))
    sweep_long = bool(t.get('sweep_long') if t.get('sweep_long') is not None else r.get('sweep_long'))
    sweep_short = bool(t.get('sweep_short') if t.get('sweep_short') is not None else r.get('sweep_short'))
    sweep_ok = sweep_long if diru == 'LONG' else (sweep_short if diru == 'SHORT' else False)
    bos_up_5m = bool(t.get('bos_up_5m') if t.get('bos_up_5m') is not None else r.get('bos_up_5m'))
    bos_down_5m = bool(t.get('bos_down_5m') if t.get('bos_down_5m') is not None else r.get('bos_down_5m'))
    bos_ok = bos_up_5m if diru == 'LONG' else (bos_down_5m if diru == 'SHORT' else False)
    bo_ok = False
    if diru == 'LONG':
        bo_ok = bo.startswith('BO↑') or bo.startswith('BOUP') or bo.startswith('BO+')
        fvg_dir_ok = fvg_kind.startswith('BULL')
    elif diru == 'SHORT':
        bo_ok = bo.startswith('BO↓') or bo.startswith('BODN') or bo.startswith('BO-')
        fvg_dir_ok = fvg_kind.startswith('BEAR')
    else:
        fvg_dir_ok = False
    ob_ok = bool(ob_zone and ob_zone != '—')
    entry_kind = str(t.get('entry_kind') or r.get('entry_kind') or '').upper().strip()
    try:
        entry_confluence = int(float(t.get('entry_confluence') if t.get('entry_confluence') is not None else r.get('entry_confluence') or 0) or 0)
    except Exception:
        entry_confluence = 0
    try:
        disp_body_atr = float(t.get('disp_body_atr') if t.get('disp_body_atr') is not None else r.get('disp_body_atr') or 0.0)
    except Exception:
        disp_body_atr = 0.0
    try:
        disp_min = float(os.getenv('MID_SMC_DISPLACEMENT_MIN', os.getenv('MID_INST_DISP_MIN', '0.25')) or 0.25)
    except Exception:
        disp_min = 0.25
    overlap = bool('OB+FVG' in entry_kind)
    if not overlap and ob_ok and fvg_active and fvg_dir_ok:
        overlap = bool(ob_retest or entry_confluence >= 3)
    htf_ltf = bool((ob_ok and fvg_active and fvg_dir_ok) and (overlap or ob_retest or entry_confluence >= 2))
    confirm_ok = bool(bos_ok or bo_ok or ob_retest or disp_body_atr >= disp_min)
    breakout_retest_poi = bool((bo_ok or bos_ok) and (overlap or ob_retest or fvg_active or ob_ok) and confirm_ok)
    liquidity_reclaim = bool(sweep_ok and confirm_ok and (ob_retest or fvg_active or ob_ok))
    displacement_hint = bool((disp_body_atr >= disp_min) and (bo_ok or bos_ok) and (fvg_active or ob_ok))
    dual_fvg_hint = False
    stacked_fvg_hint = False
    try:
        mbp = t.get('mid_bonus_parts') if isinstance(t.get('mid_bonus_parts'), dict) else {}
        fvg_bonus = float(mbp.get('fvg', 0.0) or 0.0)
    except Exception:
        fvg_bonus = 0.0
    for _src in (t, r):
        try:
            if bool(_src.get('dual_fvg')) or bool(_src.get('dual_fvg_hint')):
                dual_fvg_hint = True
            if bool(_src.get('stacked_fvg')) or bool(_src.get('stacked_imbalance')) or bool(_src.get('stacked_fvg_hint')):
                stacked_fvg_hint = True
            _fc = _src.get('fvg_count')
            if _fc is not None and float(_fc) >= 2:
                dual_fvg_hint = True
        except Exception:
            pass
    if not dual_fvg_hint:
        dual_fvg_hint = bool(fvg_active and (bo_ok or bos_ok) and fvg_bonus >= 4.0)
    if not stacked_fvg_hint:
        stacked_fvg_hint = bool(dual_fvg_hint and fvg_bonus >= 5.0)
    priority = 0
    if overlap:
        priority += 4
    if htf_ltf:
        priority += 3
    if breakout_retest_poi:
        priority += 3
    if liquidity_reclaim:
        priority += 4
    if displacement_hint:
        priority += 3
    if dual_fvg_hint:
        priority += 2
    if stacked_fvg_hint:
        priority += 1
    if sweep_ok:
        priority += 1
    if entry_confluence >= 3:
        priority += 1
    choch_up = bool(t.get('choch_up_5m') if t.get('choch_up_5m') is not None else (t.get('choch_up') if t.get('choch_up') is not None else (r.get('choch_up_5m') if r.get('choch_up_5m') is not None else r.get('choch_up'))))
    choch_down = bool(t.get('choch_down_5m') if t.get('choch_down_5m') is not None else (t.get('choch_down') if t.get('choch_down') is not None else (r.get('choch_down_5m') if r.get('choch_down_5m') is not None else r.get('choch_down'))))
    mss_up = bool(t.get('mss_up_5m') if t.get('mss_up_5m') is not None else (t.get('mss_up') if t.get('mss_up') is not None else (r.get('mss_up_5m') if r.get('mss_up_5m') is not None else r.get('mss_up'))))
    mss_down = bool(t.get('mss_down_5m') if t.get('mss_down_5m') is not None else (t.get('mss_down') if t.get('mss_down') is not None else (r.get('mss_down_5m') if r.get('mss_down_5m') is not None else r.get('mss_down'))))
    mss_ok = (bos_ok or choch_up or mss_up) if diru == 'LONG' else (bos_ok or choch_down or mss_down if diru == 'SHORT' else False)
    smt_bull = bool(t.get('smt_bull') if t.get('smt_bull') is not None else (t.get('smt_long') if t.get('smt_long') is not None else (r.get('smt_bull') if r.get('smt_bull') is not None else r.get('smt_long'))))
    smt_bear = bool(t.get('smt_bear') if t.get('smt_bear') is not None else (t.get('smt_short') if t.get('smt_short') is not None else (r.get('smt_bear') if r.get('smt_bear') is not None else r.get('smt_short'))))
    smt_ok_raw = t.get('smt_ok') if t.get('smt_ok') is not None else r.get('smt_ok')
    smt_present = any((
        t.get('smt_ok') is not None,
        r.get('smt_ok') is not None,
        t.get('smt_bull') is not None,
        t.get('smt_bear') is not None,
        t.get('smt_long') is not None,
        t.get('smt_short') is not None,
        r.get('smt_bull') is not None,
        r.get('smt_bear') is not None,
        r.get('smt_long') is not None,
        r.get('smt_short') is not None,
    ))
    if smt_ok_raw is not None:
        smt_ok = bool(smt_ok_raw)
        smt_present = True
    else:
        smt_ok = smt_bull if diru == 'LONG' else (smt_bear if diru == 'SHORT' else False)
        smt_present = bool(smt_present or smt_ok)
    return {
        'bo_ok': bool(bo_ok),
        'bos_ok': bool(bos_ok),
        'confirm_ok': bool(confirm_ok),
        'ob_ok': bool(ob_ok),
        'fvg_ok': bool(fvg_active and fvg_dir_ok),
        'fvg_active': bool(fvg_active),
        'overlap': bool(overlap),
        'htf_ltf': bool(htf_ltf),
        'breakout_retest_poi': bool(breakout_retest_poi),
        'liquidity_reclaim': bool(liquidity_reclaim),
        'displacement_hint': bool(displacement_hint),
        'dual_fvg_hint': bool(dual_fvg_hint),
        'stacked_fvg_hint': bool(stacked_fvg_hint),
        'disp_body_atr': float(disp_body_atr),
        'disp_min': float(disp_min),
        'mss_ok': bool(mss_ok),
        'choch_ok': bool(mss_ok),
        'smt_ok': bool(smt_ok),
        'smt_present': bool(smt_present),
        'entry_kind': entry_kind or '—',
        'entry_confluence': int(entry_confluence),
        'priority': int(priority),
    }


def _mid_smc_emit_route_label(route: str | None) -> str:
    labels = {
        'smc_ob_fvg_overlap': 'OB+FVG priority emit',
        'smc_htf_ob_ltf_fvg': 'HTF OB + LTF FVG retest emit',
        'smc_bos_retest_confirm': 'BOS → FVG/OB retest → confirm',
        'smc_displacement_origin': 'displacement origin fast-path',
        'smc_dual_fvg_origin': 'dual/stacked FVG origin',
        'smc_liquidity_reclaim': 'liquidity sweep → reclaim → BOS continuation',
    }
    return labels.get(str(route or '').strip(), '')


def _mid_smc_emit_route_priority_label(route: str | None) -> str:
    labels = {
        'smc_liquidity_reclaim': 'priority #1',
        'smc_ob_fvg_overlap': 'priority #2',
        'smc_htf_ob_ltf_fvg': 'priority #3',
        'smc_bos_retest_confirm': 'priority #4',
        'smc_displacement_origin': 'priority #5',
        'smc_dual_fvg_origin': 'priority #6',
    }
    return labels.get(str(route or '').strip(), '')


def _mid_smc_route_requirement_profile(route: str | None, regime: str | None = None) -> dict:
    """Route-specific institutional confirmation profile.

    v3 adds stricter institutional confirmations:
      - MSS / CHOCH quality check on confirmation routes
      - optional SMT confluence when the feed provides it
      - reclaim hold inside the zone before emit
      - fake-BOS protection via minimum displacement body/ATR
    """
    route_s = str(route or "").strip()
    reg_u = str(regime or "").upper().strip()
    is_range_like = ("CHOPPY" in reg_u) or ("RANGE" in reg_u)
    prof = {
        "route": route_s,
        "require_reclaim": False,
        "require_bos": False,
        "require_sweep": False,
        "require_displacement": False,
        "require_retest": False,
        "require_mss": False,
        "prefer_smt": False,
        "require_reclaim_hold": False,
        "require_fake_bos_filter": False,
        "allow_direct_emit": True,
        "min_conf_direct": 0,
    }
    if route_s == "smc_liquidity_reclaim":
        prof.update({
            "require_reclaim": True,
            "require_bos": True,
            "require_sweep": True,
            "require_retest": True,
            "require_mss": True,
            "prefer_smt": True,
            "require_reclaim_hold": True,
            "require_fake_bos_filter": True,
            "min_conf_direct": 78,
        })
    elif route_s in ("smc_ob_fvg_overlap", "smc_htf_ob_ltf_fvg"):
        prof.update({
            "require_reclaim": True,
            "require_bos": True,
            "require_sweep": bool(is_range_like),
            "require_retest": True,
            "require_mss": True,
            "prefer_smt": True,
            "require_reclaim_hold": True,
            "require_fake_bos_filter": True,
            "min_conf_direct": 80 if is_range_like else 78,
        })
    elif route_s == "smc_bos_retest_confirm":
        prof.update({
            "require_reclaim": bool(is_range_like),
            "require_bos": True,
            "require_sweep": bool(is_range_like),
            "require_retest": True,
            "require_mss": True,
            "require_reclaim_hold": True,
            "require_fake_bos_filter": True,
            "min_conf_direct": 80 if is_range_like else 76,
        })
    elif route_s in ("smc_displacement_origin", "smc_dual_fvg_origin"):
        prof.update({
            "require_reclaim": True,
            "require_bos": True,
            "require_sweep": bool(is_range_like),
            "require_displacement": True,
            "require_fake_bos_filter": True,
            "allow_direct_emit": False,
            "min_conf_direct": 84 if is_range_like else 82,
        })
    return prof



def _mid_compose_setup_label(setup_source: str | None, smc_route: str | None = None, smc_label: str | None = None) -> str:
    base = _mid_setup_source_label(setup_source)
    extra = str(smc_label or _mid_smc_emit_route_label(smc_route) or '').strip()
    if base and extra:
        return f"{base} | {extra}"
    return base or extra


def _mid_is_direct_smc_route(*,
                             route: str | None = None,
                             sig=None,
                             ta: dict | None = None,
                             rec: dict | None = None,
                             meta: dict | None = None) -> bool:
    """Return True when the signal belongs to a strong SMC direct-emit route.

    This helper intentionally looks across explicit route arg, signal attrs, TA payload,
    pending record and gate meta so direct SMC emits never fall back into generic
    soft-block pre/final gates by accident.
    """
    direct_routes = {
        'smc_liquidity_reclaim',
        'smc_ob_fvg_overlap',
        'smc_htf_ob_ltf_fvg',
        'smc_bos_retest_confirm',
        'smc_displacement_origin',
        'smc_dual_fvg_origin',
    }

    def _cand(v):
        try:
            s = str(v or '').strip()
        except Exception:
            s = ''
        return s

    try:
        for src in (route,
                    getattr(sig, 'emit_route', ''),
                    getattr(sig, 'smc_setup_route', ''),
                    (ta or {}).get('emit_route'),
                    (ta or {}).get('smc_setup_route'),
                    (rec or {}).get('emit_route'),
                    (rec or {}).get('smc_setup_route'),
                    (meta or {}).get('route'),
                    (meta or {}).get('emit_route'),
                    (meta or {}).get('smc_setup_route')):
            s = _cand(src)
            if s in direct_routes:
                return True
    except Exception:
        pass
    return False


def _mid_pick_smc_emit_route(*,
                             direction: str,
                             smc_snapshot: dict | None = None,
                             origin_fast_ok: bool = False,
                             breakout_fast_ok: bool = False,
                             zone_valid: bool = False,
                             in_zone_now: bool = False,
                             liquidity_reclaim_ok: bool = False) -> dict:
    smc = dict(smc_snapshot or {})
    route = ''
    setup_source = ''
    priority = 0
    if bool(liquidity_reclaim_ok or smc.get('liquidity_reclaim')) and bool(zone_valid and in_zone_now):
        route = 'smc_liquidity_reclaim'
        setup_source = 'liquidity_reclaim'
        priority = 130
    elif bool(smc.get('overlap')) and bool(zone_valid and in_zone_now):
        route = 'smc_ob_fvg_overlap'
        setup_source = 'zone_retest'
        priority = 120
    elif bool(smc.get('htf_ltf')) and bool(zone_valid and in_zone_now):
        route = 'smc_htf_ob_ltf_fvg'
        setup_source = 'zone_retest'
        priority = 110
    elif bool(smc.get('breakout_retest_poi')) and bool(smc.get('confirm_ok')) and bool(zone_valid and in_zone_now):
        route = 'smc_bos_retest_confirm'
        setup_source = 'zone_retest'
        priority = 100
    elif bool(origin_fast_ok) and bool(smc.get('displacement_hint')):
        route = 'smc_displacement_origin'
        setup_source = 'origin'
        priority = 95
    elif bool(origin_fast_ok) and bool(smc.get('dual_fvg_hint') or smc.get('stacked_fvg_hint')):
        route = 'smc_dual_fvg_origin'
        setup_source = 'origin'
        priority = 92
    elif bool(origin_fast_ok):
        setup_source = 'origin'
        priority = 60
    elif bool(breakout_fast_ok):
        setup_source = 'breakout'
        priority = 55
    elif bool(zone_valid and in_zone_now):
        setup_source = 'zone_retest'
        priority = 50
    label = _mid_smc_emit_route_label(route)
    return {
        'route': str(route or ''),
        'route_label': str(label or ''),
        'setup_source': str(setup_source or ''),
        'setup_label': _mid_compose_setup_label(setup_source, route, label),
        'priority': int(priority),
    }


def _mid_smart_setup_origin_fastpath(*,
                                    market: str,
                                    direction: str,
                                    confidence: float,
                                    atr_pct: float | None,
                                    atr30_abs: float | None,
                                    vol_x: float | None,
                                    regime: str | None,
                                    bo_rt_label: str | None,
                                    breakout_age_bars: int | None,
                                    breakout_move_atr: float | None,
                                    dist_to_zone_atr: float | None,
                                    dist_to_zone_pct: float | None,
                                    last_body: float | None,
                                    origin_body: float | None = None,
                                    origin_vol_x: float | None = None,
                                    origin_body_src: str | None = None,
                                    origin_vol_src: str | None = None,
                                    sweep_long: bool = False,
                                    sweep_short: bool = False,
                                    risk_flags=None,
                                    smc_snapshot: dict | None = None) -> tuple[bool, str, dict]:
    """Allow smart-setup to emit from the origin / first reclaim before retest.

    This fast-path is intentionally earlier than breakout_fastpath. It targets the
    exact start of the move (liq sweep / first reclaim / first displacement), so it
    must tolerate being far from the later retest zone while still rejecting obvious
    contradictions or stale/overextended entries.
    """
    meta: dict[str, object] = {}
    try:
        enabled = str(os.getenv("MID_SMART_SETUP_ORIGIN_ENABLED", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        enabled = True
    if not enabled:
        return (False, "origin_fast_disabled", meta)

    diru = str(direction or "").upper().strip()
    bo = str(bo_rt_label or "").strip().upper()
    reg_u = str(regime or "").upper().strip()
    flags = {str(x).strip().lower() for x in _mid_gate_listify(risk_flags) if str(x).strip()}
    smc = dict(smc_snapshot or {})
    smc_priority = int(smc.get("priority") or 0)
    smc_overlap = bool(smc.get("overlap"))
    smc_htf_ltf = bool(smc.get("htf_ltf"))
    smc_breakout_poi = bool(smc.get("breakout_retest_poi"))
    smc_displacement = bool(smc.get("displacement_hint"))
    smc_dual_fvg = bool(smc.get("dual_fvg_hint"))

    try:
        base_conf_need = int(float(os.getenv("MID_SMART_SETUP_EMIT_CONF", "90") or 90))
    except Exception:
        base_conf_need = 90
    try:
        conf_need = int(float(os.getenv("MID_SMART_SETUP_ORIGIN_CONF", str(min(base_conf_need, 76))) or min(base_conf_need, 76)))
    except Exception:
        conf_need = min(base_conf_need, 76)
    conf_need = max(0, int(conf_need))

    min_atr, min_vol = _mid_instant_emit_market_thresholds(market)
    try:
        atr_mult = float(os.getenv("MID_SMART_SETUP_ORIGIN_ATR_MULT", "0.75") or 0.75)
    except Exception:
        atr_mult = 0.75
    try:
        vol_need = float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_VOL_X", "0") or 0)
    except Exception:
        vol_need = 0.0
    if vol_need <= 0:
        # Origin fast is allowed to fire at the *start* of a real move, before
        # volume/relative-volume fully expands on the current bar.
        vol_need = 0.0
    atr_need = max(0.0, float(min_atr) * max(0.0, float(atr_mult)))
    try:
        min_body_atr = float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_BODY_ATR", "0.08") or 0.08)
    except Exception:
        min_body_atr = 0.08
    try:
        max_age_bars = int(float(os.getenv("MID_SMART_SETUP_ORIGIN_MAX_AGE_BARS", "3") or 3))
    except Exception:
        max_age_bars = 3
    try:
        max_move_atr = float(os.getenv("MID_SMART_SETUP_ORIGIN_MAX_MOVE_ATR", "1.20") or 1.20)
    except Exception:
        max_move_atr = 1.20
    try:
        allowed_regimes = {str(x).strip().upper() for x in _mid_gate_listify(os.getenv("MID_SMART_SETUP_ORIGIN_ALLOWED_REGIMES", "")) if str(x).strip()}
    except Exception:
        allowed_regimes = set()

    if smc_priority >= 2:
        try:
            conf_need = min(int(conf_need), int(float(os.getenv("MID_SMC_ORIGIN_CONF", "74") or 74)))
        except Exception:
            conf_need = min(int(conf_need), 74)
        try:
            min_body_atr = min(float(min_body_atr), float(os.getenv("MID_SMC_ORIGIN_MIN_BODY_ATR", "0.05") or 0.05))
        except Exception:
            pass
        try:
            max_move_atr = max(float(max_move_atr), float(os.getenv("MID_SMC_ORIGIN_MAX_MOVE_ATR", "1.35") or 1.35))
        except Exception:
            pass
    if smc_overlap or smc_htf_ltf or smc_displacement or smc_dual_fvg:
        try:
            vol_need = min(float(vol_need), float(os.getenv("MID_SMC_ORIGIN_MIN_VOL_X", "0.0") or 0.0))
        except Exception:
            vol_need = 0.0

    hard_flags = {"scale_mismatch", "blocked", "structure_mismatch", "block:directional_contradiction"}
    active_hard_flags = sorted([x for x in flags if x in hard_flags])

    bo_ok = False
    if diru == "LONG":
        bo_ok = bo.startswith("BO↑") or bo.startswith("BOUP") or bo.startswith("BO+")
        sweep_ok = bool(sweep_long)
    elif diru == "SHORT":
        bo_ok = bo.startswith("BO↓") or bo.startswith("BODN") or bo.startswith("BO-")
        sweep_ok = bool(sweep_short)
    else:
        sweep_ok = False

    conf_v = float(confidence or 0.0)
    atr_v = float(atr_pct or 0.0)
    age_v = None if breakout_age_bars is None else int(breakout_age_bars)
    move_v = None if breakout_move_atr is None else float(breakout_move_atr)
    dist_atr_v = None if dist_to_zone_atr is None else float(dist_to_zone_atr)
    dist_pct_v = float(dist_to_zone_pct or 0.0)
    atr30_v = float(atr30_abs or 0.0)
    vol_v = 0.0
    body_v = 0.0
    body_src_eff = "origin_body"
    vol_src_eff = "origin_vol_x"
    try:
        for _src_name, _cand in ((str(origin_vol_src or "origin_vol_x") or "origin_vol_x", origin_vol_x),
                                 ("current_rel_vol", vol_x)):
            try:
                _fv = float(_cand or 0.0)
            except Exception:
                _fv = 0.0
            if _fv > float(vol_v or 0.0):
                vol_v = float(_fv)
                vol_src_eff = str(_src_name or "origin_vol_x")
    except Exception:
        try:
            vol_v = float(vol_x or 0.0)
        except Exception:
            vol_v = 0.0
        vol_src_eff = "current_rel_vol"
    try:
        for _src_name, _cand in ((str(origin_body_src or "origin_body") or "origin_body", origin_body),
                                 ("last_body", last_body)):
            try:
                _fv = abs(float(_cand or 0.0))
            except Exception:
                _fv = 0.0
            if _fv > float(body_v or 0.0):
                body_v = float(_fv)
                body_src_eff = str(_src_name or "origin_body")
    except Exception:
        try:
            body_v = abs(float(last_body or 0.0))
        except Exception:
            body_v = 0.0
        body_src_eff = "last_body"
    body_atr_v = (body_v / atr30_v) if atr30_v > 0 else 0.0

    try:
        body_need_eff = float(min_body_atr)
    except Exception:
        body_need_eff = 0.20
    try:
        vol_need_eff = float(vol_need)
    except Exception:
        vol_need_eff = 0.0
    try:
        age0_body_min = float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_BODY_ATR_AGE0", "0.04") or 0.04)
    except Exception:
        age0_body_min = 0.04
    try:
        age0_vol_min = float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_VOL_X_AGE0", "0.05") or 0.05)
    except Exception:
        age0_vol_min = 0.05
    try:
        age0_move_evidence = float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_MOVE_ATR_AGE0", "0.12") or 0.12)
    except Exception:
        age0_move_evidence = 0.12
    try:
        age0_live_vol_min = float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_VOL_X_AGE0_LIVE", "0.03") or 0.03)
    except Exception:
        age0_live_vol_min = 0.03
    age0_has_alt_impulse = False
    if bo_ok and age_v is not None and age_v <= 0:
        try:
            body_need_eff = min(body_need_eff, float(age0_body_min))
        except Exception:
            pass
        try:
            vol_need_eff = min(vol_need_eff, float(age0_vol_min))
        except Exception:
            pass
        try:
            age0_has_alt_impulse = bool(sweep_ok) or (move_v is not None and float(move_v) >= float(age0_move_evidence)) or (vol_v >= float(max(vol_need_eff, age0_vol_min)))
        except Exception:
            age0_has_alt_impulse = bool(sweep_ok)

    try:
        fresh_origin_bias = bool(bo_ok and age_v is not None and age_v <= 1)
    except Exception:
        fresh_origin_bias = False
    if fresh_origin_bias:
        try:
            conf_need = min(int(conf_need), int(float(os.getenv("MID_SMART_SETUP_ORIGIN_CONF_FRESH", "72") or 72)))
        except Exception:
            conf_need = min(int(conf_need), 72)
        try:
            body_need_eff = min(float(body_need_eff), float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_BODY_ATR_FRESH", "0.05") or 0.05))
        except Exception:
            pass
        try:
            vol_need_eff = min(float(vol_need_eff), float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_VOL_X_FRESH", "0.00") or 0.00))
        except Exception:
            pass
        try:
            max_move_atr = max(float(max_move_atr), float(os.getenv("MID_SMART_SETUP_ORIGIN_MAX_MOVE_ATR_FRESH", "1.30") or 1.30))
        except Exception:
            pass
    meta.update({
        "enabled": bool(enabled),
        "fresh_origin_bias": bool(fresh_origin_bias),
        "bo_rt": bo,
        "bo_ok": bool(bo_ok),
        "sweep_ok": bool(sweep_ok),
        "regime": reg_u,
        "allowed_regimes": sorted(allowed_regimes),
        "conf": int(round(conf_v)),
        "conf_need": int(conf_need),
        "atr_pct": float(atr_v),
        "atr_need": float(atr_need),
        "vol_x": float(vol_v),
        "vol_need": float(vol_need_eff),
        "body_atr": float(body_atr_v),
        "body_source": str(body_src_eff or (origin_body_src or ("origin_body" if origin_body is not None else "last_body"))),
        "vol_source": str(vol_src_eff or (origin_vol_src or ("origin_vol_x" if origin_vol_x is not None else "rel_vol"))),
        "body_need_atr": float(body_need_eff),
        "age0_body_min": float(age0_body_min),
        "age0_vol_min": float(age0_vol_min),
        "age0_move_evidence": float(age0_move_evidence),
        "age0_live_vol_min": float(age0_live_vol_min),
        "age0_alt_impulse": bool(age0_has_alt_impulse),
        "breakout_age_bars": age_v,
        "max_age_bars": int(max_age_bars),
        "breakout_move_atr": move_v,
        "max_move_atr": float(max_move_atr),
        "dist_to_zone_atr": dist_atr_v,
        "dist_to_zone_pct": float(dist_pct_v),
        "hard_flags": list(active_hard_flags),
        "smc_priority": int(smc_priority),
        "smc_overlap": bool(smc_overlap),
        "smc_htf_ltf": bool(smc_htf_ltf),
        "smc_breakout_poi": bool(smc_breakout_poi),
        "smc_displacement": bool(smc_displacement),
        "smc_dual_fvg": bool(smc_dual_fvg),
        "smc_entry_kind": str(smc.get("entry_kind") or "—"),
        "smc_entry_confluence": int(smc.get("entry_confluence") or 0),
    })

    reasons: list[str] = []
    if active_hard_flags:
        reasons.append(f"origin_fast_flags:{','.join(active_hard_flags)}")
    if allowed_regimes and reg_u not in allowed_regimes:
        reasons.append(f"origin_fast_regime:{reg_u or '-'}")
    if conf_v < float(conf_need):
        reasons.append(f"origin_fast_conf:{int(round(conf_v))}<{int(conf_need)}")
    if atr_v < float(atr_need):
        reasons.append(f"origin_fast_atr:{atr_v:.3f}<{atr_need:.3f}")
    if vol_v < float(vol_need_eff):
        reasons.append(f"origin_fast_vol:{vol_v:.2f}<{vol_need_eff:.2f}")
    if bo_ok and age_v is not None and age_v <= 0 and body_atr_v <= 0.0 and (not age0_has_alt_impulse) and smc_priority < 2:
        _move_disp = "-" if move_v is None else f"{float(move_v):.2f}"
        reasons.append(f"origin_fast_no_impulse:body={body_atr_v:.2f}|vol={vol_v:.2f}|move={_move_disp}")
    _body_soft_bypass = False
    try:
        _allow_zero_body_breakout = str(os.getenv("MID_SMART_SETUP_ORIGIN_ALLOW_ZERO_BODY_BREAKOUT_META", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        _allow_zero_body_breakout = True
    try:
        _allow_zero_body_age0_live = str(os.getenv("MID_SMART_SETUP_ORIGIN_ALLOW_ZERO_BODY_AGE0_LIVE", "0") or "0").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        _allow_zero_body_age0_live = True
    try:
        _body_soft_bypass = bool(
            (
                _allow_zero_body_breakout
                and bo_ok
                and age_v is not None
                and age_v <= 0
                and str(meta.get("body_source") or "").startswith("breakout_")
                and body_atr_v <= 0.0
                and age0_has_alt_impulse
            )
            or (
                _allow_zero_body_age0_live
                and bo_ok
                and age_v is not None
                and age_v <= 0
                and body_atr_v <= 0.0
                and age0_has_alt_impulse
                and vol_v >= float(age0_live_vol_min)
            )
        )
    except Exception:
        _body_soft_bypass = False
    meta["body_soft_bypass"] = bool(_body_soft_bypass)
    if body_atr_v < float(body_need_eff) and not _body_soft_bypass:
        reasons.append(f"origin_fast_body:{body_atr_v:.2f}<{body_need_eff:.2f}")
    if age_v is not None and max_age_bars >= 0 and age_v > max_age_bars:
        reasons.append(f"origin_fast_age:{int(age_v)}>{int(max_age_bars)}")
    if move_v is not None and max_move_atr > 0 and move_v > max_move_atr:
        reasons.append(f"origin_fast_move:{move_v:.2f}>{max_move_atr:.2f}")
    if not (bo_ok or sweep_ok):
        reasons.append(f"origin_fast_no_trigger:{bo or '-'}")

    if reasons:
        meta["fail_reasons"] = list(reasons)
        meta["primary_reason"] = str(reasons[0])
        meta["all_reasons"] = "|".join(reasons)
        return (False, str(reasons[0]), meta)

    src_bits: list[str] = []
    if bo_ok:
        src_bits.append("bo")
    if sweep_ok:
        src_bits.append("sweep")
    if not src_bits:
        src_bits.append("reclaim")
    pass_reason = f"origin_fastpass:{'+'.join(src_bits)}"
    meta["primary_reason"] = pass_reason
    meta["all_reasons"] = pass_reason
    return (True, pass_reason, meta)


def _mid_smart_setup_breakout_fastpath(*,
                                      market: str,
                                      direction: str,
                                      confidence: float,
                                      atr_pct: float | None,
                                      vol_x: float | None,
                                      regime: str | None,
                                      bo_rt_label: str | None,
                                      dist_to_zone_atr: float | None,
                                      dist_to_zone_pct: float | None,
                                      risk_flags=None,
                                      smc_snapshot: dict | None = None) -> tuple[bool, str, dict]:
    """Allow smart-setup to emit on a fresh breakout before the retest.

    Default behavior is conservative: only fresh directional BO labels with adequate
    volatility/volume and limited distance from the planned zone may bypass the usual
    "wait for zone touch" logic. This targets the exact case where a strong impulse
    starts and the setup should not be forced into pending mode first.
    """
    meta: dict[str, object] = {}
    try:
        enabled = str(os.getenv("MID_SMART_SETUP_BREAKOUT_ENABLED", "1") or "1").strip().lower() in ("1", "true", "yes", "on")
    except Exception:
        enabled = True
    if not enabled:
        return (False, "breakout_fast_disabled", meta)

    diru = str(direction or "").upper().strip()
    bo = str(bo_rt_label or "").strip().upper()
    reg_u = str(regime or "").upper().strip()
    flags = {str(x).strip().lower() for x in _mid_gate_listify(risk_flags) if str(x).strip()}

    try:
        conf_need = int(float(os.getenv("MID_SMART_SETUP_BREAKOUT_CONF", os.getenv("MID_SMART_SETUP_EMIT_CONF", "90")) or 90))
    except Exception:
        conf_need = 90
    try:
        conf_relax = int(float(os.getenv("MID_SMART_SETUP_BREAKOUT_CONF_RELAX", "0") or 0))
    except Exception:
        conf_relax = 0
    conf_need = max(0, int(conf_need) - int(max(0, conf_relax)))

    min_atr, min_vol = _mid_instant_emit_market_thresholds(market)
    try:
        atr_mult = float(os.getenv("MID_SMART_SETUP_BREAKOUT_ATR_MULT", "1.00") or 1.00)
    except Exception:
        atr_mult = 1.00
    try:
        vol_mult = float(os.getenv("MID_SMART_SETUP_BREAKOUT_VOL_MULT", "1.00") or 1.00)
    except Exception:
        vol_mult = 1.00
    atr_need = max(0.0, float(min_atr) * max(0.0, float(atr_mult)))
    vol_need = max(0.0, float(min_vol) * max(0.0, float(vol_mult)))

    try:
        max_dist_atr = float(os.getenv("MID_SMART_SETUP_BREAKOUT_MAX_ZONE_DIST_ATR", "0.35") or 0.35)
    except Exception:
        max_dist_atr = 0.35
    try:
        max_dist_pct = float(os.getenv("MID_SMART_SETUP_BREAKOUT_MAX_ZONE_DIST_PCT", "0.006") or 0.006)
    except Exception:
        max_dist_pct = 0.006

    try:
        allowed_regimes = {str(x).strip().upper() for x in _mid_gate_listify(os.getenv("MID_SMART_SETUP_BREAKOUT_ALLOWED_REGIMES", "TREND,TRENDING,EXPANSION")) if str(x).strip()}
    except Exception:
        allowed_regimes = {"TREND", "TRENDING", "EXPANSION"}
    smc = dict(smc_snapshot or {})
    smc_priority = int(smc.get("priority") or 0)
    smc_overlap = bool(smc.get("overlap"))
    smc_breakout_poi = bool(smc.get("breakout_retest_poi"))
    smc_htf_ltf = bool(smc.get("htf_ltf"))
    smc_dual_fvg = bool(smc.get("dual_fvg_hint"))
    hard_flags = {"far_zone", "scale_mismatch", "blocked", "structure_mismatch", "regime_range_no_breakout"}
    active_hard_flags = sorted([x for x in flags if x in hard_flags])
    if (smc_overlap or smc_breakout_poi or smc_htf_ltf or smc_dual_fvg) and ("regime_range_no_breakout" in active_hard_flags):
        active_hard_flags = [x for x in active_hard_flags if x != "regime_range_no_breakout"]
    if smc_priority >= 2:
        try:
            conf_need = min(int(conf_need), int(float(os.getenv("MID_SMC_BREAKOUT_CONF", "82") or 82)))
        except Exception:
            conf_need = min(int(conf_need), 82)
        try:
            vol_mult = min(float(vol_mult), float(os.getenv("MID_SMC_BREAKOUT_VOL_MULT", "0.70") or 0.70))
        except Exception:
            pass
        try:
            max_dist_atr = max(float(max_dist_atr), float(os.getenv("MID_SMC_BREAKOUT_MAX_ZONE_DIST_ATR", "0.75") or 0.75))
        except Exception:
            pass

    bo_ok = False
    if diru == "LONG":
        bo_ok = bo.startswith("BO↑") or bo.startswith("BOUP") or bo.startswith("BO+")
    elif diru == "SHORT":
        bo_ok = bo.startswith("BO↓") or bo.startswith("BODN") or bo.startswith("BO-")

    atr_v = float(atr_pct or 0.0)
    vol_v = float(vol_x or 0.0)
    conf_v = float(confidence or 0.0)
    dist_atr_v = None if dist_to_zone_atr is None else float(dist_to_zone_atr)
    dist_pct_v = float(dist_to_zone_pct or 0.0)
    if dist_atr_v is None:
        dist_ok = dist_pct_v <= float(max_dist_pct)
    else:
        dist_ok = (dist_atr_v <= float(max_dist_atr)) or (dist_pct_v <= float(max_dist_pct))

    meta.update({
        "enabled": bool(enabled),
        "bo_rt": bo,
        "bo_ok": bool(bo_ok),
        "regime": reg_u,
        "allowed_regimes": sorted(allowed_regimes),
        "conf": int(round(conf_v)),
        "conf_need": int(conf_need),
        "atr_pct": float(atr_v),
        "atr_need": float(atr_need),
        "vol_x": float(vol_v),
        "vol_need": float(vol_need),
        "dist_to_zone_atr": dist_atr_v,
        "dist_to_zone_pct": float(dist_pct_v),
        "max_dist_atr": float(max_dist_atr),
        "max_dist_pct": float(max_dist_pct),
        "hard_flags": list(active_hard_flags),
        "smc_priority": int(smc_priority),
        "smc_overlap": bool(smc_overlap),
        "smc_breakout_poi": bool(smc_breakout_poi),
        "smc_htf_ltf": bool(smc_htf_ltf),
        "smc_dual_fvg": bool(smc_dual_fvg),
        "smc_entry_kind": str(smc.get("entry_kind") or "—"),
        "smc_entry_confluence": int(smc.get("entry_confluence") or 0),
    })

    reasons: list[str] = []
    if not bo_ok:
        reasons.append(f"breakout_fast_no_bo:{bo or '-'}")
    if allowed_regimes and reg_u not in allowed_regimes:
        reasons.append(f"breakout_fast_regime:{reg_u or '-'}")
    if conf_v < float(conf_need):
        reasons.append(f"breakout_fast_conf:{int(round(conf_v))}<{int(conf_need)}")
    if atr_v < float(atr_need):
        reasons.append(f"breakout_fast_atr:{atr_v:.3f}<{atr_need:.3f}")
    if vol_v < float(vol_need):
        reasons.append(f"breakout_fast_vol:{vol_v:.2f}<{vol_need:.2f}")
    if active_hard_flags:
        reasons.append(f"breakout_fast_flags:{','.join(active_hard_flags)}")
    if not dist_ok:
        if dist_atr_v is None:
            reasons.append(f"breakout_fast_zone_dist_pct:{dist_pct_v:.4f}>{max_dist_pct:.4f}")
        else:
            reasons.append(f"breakout_fast_zone_dist:{dist_atr_v:.2f}>{max_dist_atr:.2f}")

    if reasons:
        meta["fail_reasons"] = list(reasons)
        meta["primary_reason"] = str(reasons[0])
        meta["all_reasons"] = "|".join(reasons)
        return (False, str(reasons[0]), meta)

    meta["primary_reason"] = "breakout_fastpass"
    meta["all_reasons"] = "breakout_fastpass"
    return (True, "breakout_fastpass", meta)




def _mid_smc_route_emit_gate(*,
                              route: str | None = None,
                              market: str,
                              direction: str,
                              confidence: float,
                              sig: "Signal" | None,
                              atr_pct: float | None,
                              vol_x: float | None,
                              regime: str | None,
                              risk_flags=None,
                              zone_valid: bool,
                              in_zone_now: bool,
                              allow_no_zone_breakout: bool,
                              near_extreme_ok: bool,
                              near_extreme_reason: str = "",
                              micro_trap_ok: bool = False,
                              micro_trap_reason: str = "",
                              late_entry_ok: bool = True,
                              late_entry_reason: str = "",
                              anti_bounce_ok: bool = True,
                              anti_bounce_reason: str = "",
                              breakout_fresh_ok: bool = False,
                              breakout_fresh_reason: str = "",
                              breakout_bypass_zone: bool = False,
                              breakout_bypass_near_extreme: bool = False,
                              breakout_bypass_late_entry: bool = False,
                              origin_fast_ok: bool = False,
                              origin_fast_reason: str = "",
                              origin_bypass_zone: bool = False,
                              origin_bypass_near_extreme: bool = False,
                              origin_bypass_late_entry: bool = False,
                              origin_bypass_anti_bounce: bool = False,
                              origin_conf_need: float | None = None,
                              smart_setup_trap_ok: bool = True,
                              smart_setup_trap_reason: str = "",
                              smart_setup_trap_meta: dict | None = None,
                              zone_src: str | None = None,
                              bo_rt_label: str | None = None,
                              origin_body_atr: float | None = None,
                              current_body_atr: float | None = None,
                              origin_body_soft_bypass: bool = False,
                              macd_hist: float | None = None) -> tuple[bool, str, dict]:
    """Direct SMC emit gate.

    High-priority SMC routes must not be reduced to a score bonus only.
    For recognized SMC routes we keep only hard safety blocks and bypass the
    generic instant gate. If no SMC route is present, we fall back to the
    legacy _mid_instant_emit_gate.
    """
    route_s = str(route or "").strip()
    if not route_s:
        return _mid_instant_emit_gate(
            market=market,
            direction=direction,
            confidence=confidence,
            sig=sig,
            atr_pct=atr_pct,
            vol_x=vol_x,
            regime=regime,
            risk_flags=risk_flags,
            zone_valid=zone_valid,
            in_zone_now=in_zone_now,
            allow_no_zone_breakout=allow_no_zone_breakout,
            near_extreme_ok=near_extreme_ok,
            near_extreme_reason=near_extreme_reason,
            micro_trap_ok=micro_trap_ok,
            micro_trap_reason=micro_trap_reason,
            late_entry_ok=late_entry_ok,
            late_entry_reason=late_entry_reason,
            anti_bounce_ok=anti_bounce_ok,
            anti_bounce_reason=anti_bounce_reason,
            breakout_fresh_ok=breakout_fresh_ok,
            breakout_fresh_reason=breakout_fresh_reason,
            breakout_bypass_zone=breakout_bypass_zone,
            breakout_bypass_near_extreme=breakout_bypass_near_extreme,
            breakout_bypass_late_entry=breakout_bypass_late_entry,
            origin_fast_ok=origin_fast_ok,
            origin_fast_reason=origin_fast_reason,
            origin_bypass_zone=origin_bypass_zone,
            origin_bypass_near_extreme=origin_bypass_near_extreme,
            origin_bypass_late_entry=origin_bypass_late_entry,
            origin_bypass_anti_bounce=origin_bypass_anti_bounce,
            origin_conf_need=origin_conf_need,
            smart_setup_trap_ok=smart_setup_trap_ok,
            smart_setup_trap_reason=smart_setup_trap_reason,
            smart_setup_trap_meta=smart_setup_trap_meta,
            zone_src=zone_src,
            bo_rt_label=bo_rt_label,
            origin_body_atr=origin_body_atr,
            current_body_atr=current_body_atr,
            origin_body_soft_bypass=origin_body_soft_bypass,
            macd_hist=macd_hist,
        )

    meta: dict[str, object] = {"route": route_s, "gate": "smc_direct_emit", "smc_direct_route": True}
    blocks: list[str] = []
    flags = {str(x).strip().lower() for x in _mid_gate_listify(risk_flags) if str(x).strip()}
    diru = str(direction or "").upper().strip()
    reg_u = str(regime or "").upper().strip()
    route_prof = _mid_smc_route_requirement_profile(route_s, reg_u)
    rr_val = None
    try:
        rr_val = float(getattr(sig, 'rr', None) if sig is not None else None)
    except Exception:
        rr_val = None
    if diru not in ("LONG", "SHORT"):
        blocks.append("direction_missing")
    if rr_val is not None and rr_val < 1.15:
        blocks.append("rr_too_low")
    if not smart_setup_trap_ok and any(k in str(smart_setup_trap_reason or '').lower() for k in ('hard', 'invalid', 'conflict', 'against')):
        blocks.append(f"trap:{smart_setup_trap_reason}")
    if not micro_trap_ok and any(k in str(micro_trap_reason or '').lower() for k in ('hard', 'invalid', 'conflict', 'against')):
        blocks.append(f"micro_trap:{micro_trap_reason}")
    if 'direction_conflict' in flags or 'directional_contradiction' in flags or 'structure_mismatch' in flags:
        blocks.append('direction_conflict')
    if 'invalid_zone' in flags or 'dead_zone' in flags:
        blocks.append('invalid_zone')

    route_need_origin = route_s in ('smc_displacement_origin', 'smc_dual_fvg_origin')
    route_need_zone = route_s in ('smc_ob_fvg_overlap', 'smc_htf_ob_ltf_fvg')
    route_need_breakout = route_s == 'smc_bos_retest_confirm'
    route_liq = route_s == 'smc_liquidity_reclaim'

    if route_need_origin and not bool(origin_fast_ok):
        blocks.append('origin_not_ready')
    try:
        conf_need_direct = int(float(route_prof.get("min_conf_direct", 0) or 0))
    except Exception:
        conf_need_direct = 0
    if conf_need_direct > 0 and float(confidence or 0.0) < float(conf_need_direct):
        blocks.append(f"direct_conf_low:{int(conf_need_direct)}")
    if route_need_origin and (not bool(route_prof.get("allow_direct_emit", True))):
        blocks.append('origin_wait_confirm')
    if route_need_origin and (("CHOPPY" in reg_u) or ("RANGE" in reg_u)):
        blocks.append('origin_range_block')
    if route_need_breakout and not bool(zone_valid and in_zone_now):
        blocks.append('breakout_retest_not_ready')
    if route_need_zone and not bool(zone_valid and in_zone_now):
        blocks.append('zone_retest_not_ready')
    if route_liq and not bool(zone_valid and in_zone_now):
        blocks.append('liquidity_retest_not_ready')

    if blocks:
        meta['blocked_by'] = list(blocks)
        meta['soft_bypassed'] = ['score', 'confidence', 'vol_x', 'atr_pct', 'late_entry', 'near_extreme', 'anti_bounce', 'macd_hist', 'regime', 'generic_trap']
        return (False, f"smc_hard_block:{route_s}", meta)

    try:
        if sig is not None:
            setattr(sig, 'emit_route', route_s)
            if not getattr(sig, 'smc_setup_route', ''):
                setattr(sig, 'smc_setup_route', route_s)
            if not getattr(sig, 'smc_setup_label', ''):
                setattr(sig, 'smc_setup_label', _mid_smc_emit_route_label(route_s))
            if not getattr(sig, 'ui_setup_label', ''):
                setattr(sig, 'ui_setup_label', _mid_compose_setup_label(getattr(sig, 'setup_source', ''), route_s))
    except Exception:
        pass

    if route_need_origin:
        meta['fast_path'] = 'origin'
        return (True, f"smc_direct_emit:{route_s}", meta)
    if route_liq:
        meta['fast_path'] = 'liquidity_reclaim'
        return (True, f"smc_direct_emit:{route_s}", meta)
    if route_need_breakout:
        meta['fast_path'] = 'breakout'
        return (True, f"smc_direct_emit:{route_s}", meta)
    if route_need_zone:
        meta['fast_path'] = 'zone_retest'
        return (True, f"smc_direct_emit:{route_s}", meta)
    return (True, f"smc_direct_emit:{route_s}", meta)

def _mid_instant_emit_gate(*,
                           market: str,
                           direction: str,
                           confidence: float,
                           sig: "Signal" | None,
                           atr_pct: float | None,
                           vol_x: float | None,
                           regime: str | None,
                           risk_flags=None,
                           zone_valid: bool,
                           in_zone_now: bool,
                           allow_no_zone_breakout: bool,
                           near_extreme_ok: bool,
                           near_extreme_reason: str = "",
                           micro_trap_ok: bool = False,
                           micro_trap_reason: str = "",
                           late_entry_ok: bool = True,
                           late_entry_reason: str = "",
                           anti_bounce_ok: bool = True,
                           anti_bounce_reason: str = "",
                           breakout_fresh_ok: bool = False,
                           breakout_fresh_reason: str = "",
                           breakout_bypass_zone: bool = False,
                           breakout_bypass_near_extreme: bool = False,
                           breakout_bypass_late_entry: bool = False,
                           origin_fast_ok: bool = False,
                           origin_fast_reason: str = "",
                           origin_bypass_zone: bool = False,
                           origin_bypass_near_extreme: bool = False,
                           origin_bypass_late_entry: bool = False,
                           origin_bypass_anti_bounce: bool = False,
                           origin_conf_need: float | None = None,
                           smart_setup_trap_ok: bool = True,
                           smart_setup_trap_reason: str = "",
                           smart_setup_trap_meta: dict | None = None,
                           zone_src: str | None = None,
                           bo_rt_label: str | None = None,
                           origin_body_atr: float | None = None,
                           current_body_atr: float | None = None,
                           origin_body_soft_bypass: bool = False,
                           macd_hist: float | None = None) -> tuple[bool, str, dict]:
    """Strict VIP gate for smart_setup_emit / pending instant emit.

    This is intentionally *stricter* than the normal pending pipeline.
    For instant emit we must respect late-entry / anti-bounce immediately,
    because there is no extra retest stage left to normalize the setup.
    """
    meta: dict[str, object] = {}
    try:
        conf_need = int(float(os.getenv("MID_SMART_SETUP_EMIT_CONF", "90") or 90))
    except Exception:
        conf_need = 90
    try:
        no_zone_extra_conf = int(float(os.getenv("MID_INSTANT_EMIT_NO_ZONE_EXTRA_CONF", "5") or 5))
    except Exception:
        no_zone_extra_conf = 5
    if origin_fast_ok:
        try:
            if origin_conf_need is not None:
                conf_need = min(int(conf_need), int(float(origin_conf_need)))
        except Exception:
            pass
    def _env_on(name: str, default: str = "1") -> bool:
        try:
            return str(os.getenv(name, default) or default).strip().lower() in ("1", "true", "yes", "on")
        except Exception:
            return str(default).strip().lower() in ("1", "true", "yes", "on")

    origin_ignore_profit = bool(origin_fast_ok and _env_on("MID_SMART_SETUP_ORIGIN_BYPASS_PROFIT", "1"))
    origin_soft_macd = bool(origin_fast_ok and _env_on("MID_SMART_SETUP_ORIGIN_SOFT_MACD", "1"))
    origin_soft_vol = bool(origin_fast_ok and _env_on("MID_SMART_SETUP_ORIGIN_SOFT_VOL", "1"))
    origin_soft_atr = bool(origin_fast_ok and _env_on("MID_SMART_SETUP_ORIGIN_SOFT_ATR", "1"))
    origin_bypass_trap = bool(origin_fast_ok and _env_on("MID_SMART_SETUP_ORIGIN_BYPASS_TRAP", "0"))
    origin_relax_regime = bool(origin_fast_ok and _env_on("MID_SMART_SETUP_ORIGIN_RELAX_REGIME", "1"))
    zone_first_soft_gate = bool(zone_valid and in_zone_now and _env_on("MID_ZONE_FIRST_SOFTEN_INSTANT_GATE", "1"))
    zone_first_ignore_late = bool(zone_first_soft_gate and _env_on("MID_ZONE_FIRST_IGNORE_LATE_ENTRY_IN_ZONE", "1"))
    try:
        zone_src_s = str(zone_src or "").strip().lower()
    except Exception:
        zone_src_s = ""
    zone_first_fallback_guard = bool(zone_first_soft_gate and zone_src_s.startswith("fallback") and _env_on("MID_ZONE_FIRST_BLOCK_FALLBACK_WEAK", "1"))
    zone_first_spot_guard = bool(zone_first_soft_gate and (market or "SPOT").upper().strip() == "SPOT" and _env_on("MID_ZONE_FIRST_BLOCK_SPOT_WEAK", "1"))
    try:
        bo_rt_s = str(bo_rt_label or "").strip()
    except Exception:
        bo_rt_s = ""
    body_atr_now = max(float(current_body_atr or 0.0), float(origin_body_atr or 0.0))
    fut_short_anti_bounce_relief = _mid_futures_short_anti_bounce_relief_ok(
        market=market,
        direction=direction,
        in_zone_now=bool(in_zone_now),
        zone_src=zone_src_s,
        bo_rt_label=bo_rt_s,
        vol_x=vol_x,
    )
    weak_short_emit_reason = _mid_futures_short_weak_emit_reason(
        market=market,
        direction=direction,
        risk_flags=risk_flags,
        vol_x=vol_x,
        body_atr=body_atr_now,
        bo_rt_label=bo_rt_s,
        breakout_fresh_ok=bool(breakout_fresh_ok),
        micro_trap_ok=bool(micro_trap_ok),
        macd_hist=macd_hist,
    )


    def _origin_trap_bypass_allowed(reason: str, trap_meta: dict | None) -> bool:
        if not origin_bypass_trap:
            return False
        hard_tokens = (
            "smart_setup_trap_vwap_ext",
            "smart_setup_trap_impulse",
            "smart_setup_trap_bb_extreme",
            "smart_setup_trap_bb_stretch",
        )
        try:
            reason_s = str(reason or "").strip().lower()
        except Exception:
            reason_s = ""
        if any(tok in reason_s for tok in hard_tokens):
            return False
        try:
            for _r in _mid_gate_listify((trap_meta or {}).get("fail_reasons")):
                _rs = str(_r or "").strip().lower()
                if any(tok in _rs for tok in hard_tokens):
                    return False
        except Exception:
            pass
        return True

    try:
        profit_need = float(os.getenv("MID_INSTANT_EMIT_MIN_PROFIT_PCT", "1.0") or 1.0)
        if _MID_EARLY_ENTRY_GUARD and _mid_soft_blocks_enabled():
            profit_need = min(float(profit_need), float(_mid_instant_profit_cap(market)))
        profit_need = max(0.0, float(profit_need))
    except Exception:
        profit_need = float(_mid_instant_profit_cap(market)) if _MID_EARLY_ENTRY_GUARD else 1.0
    if origin_ignore_profit:
        try:
            profit_need = min(float(profit_need), float(os.getenv("MID_SMART_SETUP_ORIGIN_MIN_PROFIT_PCT", "0") or 0.0))
        except Exception:
            profit_need = 0.0
    if zone_first_soft_gate:
        try:
            profit_need = min(float(profit_need), float(os.getenv("MID_ZONE_FIRST_MIN_PROFIT_PCT", "0.25") or 0.25))
        except Exception:
            pass

    flags = {str(x).strip().lower() for x in _mid_gate_listify(risk_flags) if str(x).strip()}
    hard_flags = {"far_zone", "scale_mismatch", "blocked", "structure_mismatch", "regime_range_no_breakout", "block:directional_contradiction"}

    conf_v = float(confidence or 0.0)
    atr_v = float(atr_pct or 0.0)
    vol_v = float(vol_x or 0.0)
    min_atr, min_vol = _mid_instant_emit_market_thresholds(market)
    profit_v = signal_expected_profit_pct(sig) if sig is not None else 0.0
    rr_ok, rr_v, rr_need = signal_rr_gate(sig) if sig is not None else (False, 0.0, 0.0)
    reg_u = str(regime or "").upper().strip()

    _origin_trap_bypass_ok = _origin_trap_bypass_allowed(smart_setup_trap_reason, smart_setup_trap_meta)

    meta.update({
        "conf": int(round(conf_v)),
        "conf_need": int(conf_need),
        "atr_pct": float(atr_v),
        "atr_need": float(min_atr),
        "vol_x": float(vol_v),
        "vol_need": float(min_vol),
        "profit_pct": float(profit_v),
        "profit_need": float(profit_need),
        "origin_ignore_profit": bool(origin_ignore_profit),
        "origin_soft_macd": bool(origin_soft_macd),
        "origin_soft_vol": bool(origin_soft_vol),
        "origin_soft_atr": bool(origin_soft_atr),
        "origin_bypass_trap": bool(origin_bypass_trap),
        "origin_trap_bypass_allowed": bool(_origin_trap_bypass_ok),
        "origin_relax_regime": bool(origin_relax_regime),
        "zone_first_soft_gate": bool(zone_first_soft_gate),
        "zone_first_ignore_late": bool(zone_first_ignore_late),
        "zone_src": str(zone_src_s or "-"),
        "bo_rt_label": str(bo_rt_s or "-"),
        "origin_body_atr": float(origin_body_atr or 0.0),
        "current_body_atr": float(body_atr_now or 0.0),
        "fut_short_anti_bounce_relief": bool(fut_short_anti_bounce_relief),
        "origin_body_soft_bypass": bool(origin_body_soft_bypass),
        "rr": float(rr_v),
        "rr_need": float(rr_need),
        "regime": reg_u,
        "zone_valid": bool(zone_valid),
        "in_zone_now": bool(in_zone_now),
        "allow_no_zone_breakout": bool(allow_no_zone_breakout),
        "near_extreme_ok": bool(near_extreme_ok),
        "micro_trap_ok": bool(micro_trap_ok),
        "late_entry_ok": bool(late_entry_ok),
        "anti_bounce_ok": bool(anti_bounce_ok),
        "risk_flags": sorted(flags),
        "risk_flags_input": sorted(flags),
        "breakout_fresh_ok": bool(breakout_fresh_ok),
        "breakout_fresh_reason": str(breakout_fresh_reason or ""),
        "breakout_bypass_zone": bool(breakout_bypass_zone),
        "breakout_bypass_near_extreme": bool(breakout_bypass_near_extreme),
        "breakout_bypass_late_entry": bool(breakout_bypass_late_entry),
        "origin_fast_ok": bool(origin_fast_ok),
        "origin_fast_reason": str(origin_fast_reason or ""),
        "origin_bypass_zone": bool(origin_bypass_zone),
        "origin_bypass_near_extreme": bool(origin_bypass_near_extreme),
        "origin_bypass_late_entry": bool(origin_bypass_late_entry),
        "origin_bypass_anti_bounce": bool(origin_bypass_anti_bounce),
        "origin_conf_need": (None if origin_conf_need is None else int(float(origin_conf_need))),
        "smart_setup_trap_ok": bool(smart_setup_trap_ok),
        "smart_setup_trap_reason": str(smart_setup_trap_reason or ""),
        "smart_setup_trap_meta": dict(smart_setup_trap_meta or {}),
        "macd_hist": _mid_macd_hist_display4(macd_hist) or "—",
    })

    fail_reasons: list[str] = []
    applied_risk_flags: list[str] = []
    ignored_risk_flags: list[str] = []
    ignored_checks: list[str] = []

    def _add_fail(reason: str) -> None:
        try:
            s = str(reason or "").strip()
        except Exception:
            s = "instant_gate_unknown"
        if s and s not in fail_reasons:
            fail_reasons.append(s)

    if weak_short_emit_reason:
        _add_fail(str(weak_short_emit_reason))

    if conf_v < float(conf_need):
        _add_fail(f"instant_conf_low:{int(round(conf_v))}<{conf_need}")

    # Instant emit must never bypass a scan-stage directional contradiction.
    # Example: LONG + BO↓ / BO↓ + Retest should be rejected immediately even when
    # smart setup emit is otherwise allowed.
    if "block:directional_contradiction" in flags:
        _add_fail("directional_contradiction")

    _instant_macd_reason = _mid_macd_hist_emit_block_reason(direction, macd_hist)
    if _instant_macd_reason:
        if origin_soft_macd:
            ignored_checks.append(_instant_macd_reason)
        else:
            _add_fail(_instant_macd_reason)

    # Only keep generic scan-stage flags here when they are still relevant *now*.
    # ATR/VOL have dedicated current-metric checks below, so we do not duplicate them
    # via stale risk_flags from scan stage.
    for _flag in sorted(flags):
        if _flag in ("vol_low",):
            ignored_risk_flags.append(_flag)
            continue
        if _flag in ("atrpct_low", "atr_low", "volatility_low"):
            ignored_risk_flags.append(_flag)
            continue
        if _flag == "regime_range_no_breakout":
            if origin_fast_ok and origin_relax_regime:
                ignored_risk_flags.append(_flag)
            elif reg_u in {"RANGE", "CHOPPY", "COMPRESSION", "SIDEWAYS", "-", ""}:
                applied_risk_flags.append(_flag)
            else:
                ignored_risk_flags.append(_flag)
            continue
        if _flag in hard_flags:
            applied_risk_flags.append(_flag)
            continue
        ignored_risk_flags.append(_flag)

    if applied_risk_flags:
        _add_fail(f"instant_risk_flags:{','.join(applied_risk_flags)}")
    if not smart_setup_trap_ok:
        _trap_reason_now = str(smart_setup_trap_reason or "smart_setup_trap")
        _softened_zone_trap = False
        if zone_first_soft_gate and ("smart_setup_trap_vwap_ext" in _trap_reason_now or "smart_setup_trap_bb_stretch" in _trap_reason_now):
            try:
                _trap_meta_now = dict(smart_setup_trap_meta or {})
            except Exception:
                _trap_meta_now = {}
            try:
                _trap_vwap_now = float(_trap_meta_now.get("vwap_dist_atr") or 0.0)
            except Exception:
                _trap_vwap_now = 0.0
            try:
                _trap_max_now = float(_trap_meta_now.get("max_vwap_dist_atr") or 0.0)
            except Exception:
                _trap_max_now = 0.0
            try:
                _zone_trap_soft_mult = float(os.getenv("MID_ZONE_FIRST_TRAP_SOFT_VWAP_HARD_MULT", "2.40") or 2.40)
            except Exception:
                _zone_trap_soft_mult = 2.40
            try:
                _zone_trap_soft_strong_mult = float(os.getenv("MID_ZONE_FIRST_TRAP_SOFT_STRONG_ZONE_MULT", "2.60") or 2.60)
            except Exception:
                _zone_trap_soft_strong_mult = 2.60
            _zone_is_strong = zone_src_s.startswith("ob30") or zone_src_s.startswith("ch1h")
            _zone_trap_soft_limit = float(_trap_max_now) * (float(_zone_trap_soft_strong_mult) if _zone_is_strong else float(_zone_trap_soft_mult))
            try:
                if _trap_max_now > 0 and _trap_vwap_now > 0 and _trap_vwap_now <= float(_zone_trap_soft_limit):
                    ignored_checks.append(f"zone_first_trap_soft:{_trap_reason_now}")
                    _softened_zone_trap = True
            except Exception:
                _softened_zone_trap = False
        if (not _softened_zone_trap) and _origin_trap_bypass_ok:
            ignored_checks.append(f"origin_trap_ignored:{_trap_reason_now}")
        elif not _softened_zone_trap:
            _add_fail(_trap_reason_now)
    if profit_v < float(profit_need):
        if origin_ignore_profit or zone_first_soft_gate:
            ignored_checks.append(f"instant_profit_low:{profit_v:.3f}<{profit_need:.3f}")
        else:
            _add_fail(f"instant_profit_low:{profit_v:.3f}<{profit_need:.3f}")
    if not rr_ok:
        _add_fail(f"instant_rr_low:{rr_v:.2f}<{rr_need:.2f}")
    _instant_atr_need = float(min_atr)
    if origin_fast_ok and origin_soft_atr:
        try:
            _instant_atr_need = min(float(_instant_atr_need), float(os.getenv("MID_SMART_SETUP_ORIGIN_INSTANT_MIN_ATR", "0.0") or 0.0))
        except Exception:
            _instant_atr_need = 0.0
    if atr_v < float(_instant_atr_need):
        _add_fail(f"instant_atr_low:{atr_v:.3f}<{_instant_atr_need:.3f}")
    _instant_vol_need = float(min_vol)
    if origin_fast_ok and origin_soft_vol:
        try:
            _instant_vol_need = min(float(_instant_vol_need), float(os.getenv("MID_SMART_SETUP_ORIGIN_INSTANT_MIN_VOL_X", "0.0") or 0.0))
        except Exception:
            _instant_vol_need = 0.0
    if vol_v < float(_instant_vol_need):
        _add_fail(f"instant_vol_low:{vol_v:.2f}<{_instant_vol_need:.2f}")
    if not near_extreme_ok:
        if (breakout_fresh_ok and breakout_bypass_near_extreme) or (origin_fast_ok and origin_bypass_near_extreme):
            ignored_checks.append(str(near_extreme_reason or "instant_near_extreme"))
        else:
            _add_fail(str(near_extreme_reason or "instant_near_extreme"))
    if not micro_trap_ok:
        _add_fail(str(micro_trap_reason or "instant_micro_trap"))
    if not late_entry_ok:
        _late_reason_now = str(late_entry_reason or "instant_late_entry")
        if zone_first_ignore_late and _late_reason_now.startswith("late_entry_atr="):
            ignored_checks.append(f"zone_first_late_ignored:{_late_reason_now}")
        elif (breakout_fresh_ok and breakout_bypass_late_entry) or (origin_fast_ok and origin_bypass_late_entry):
            ignored_checks.append(_late_reason_now)
        else:
            _add_fail(_late_reason_now)
    if not anti_bounce_ok:
        if fut_short_anti_bounce_relief:
            ignored_checks.append(f"fut_short_anti_bounce_relief:{str(anti_bounce_reason or 'instant_anti_bounce')}")
        elif origin_fast_ok and origin_bypass_anti_bounce:
            ignored_checks.append(str(anti_bounce_reason or "instant_anti_bounce"))
        else:
            _add_fail(str(anti_bounce_reason or "instant_anti_bounce"))

    if zone_first_fallback_guard:
        fallback_fail = []
        try:
            fallback_min_vol = float(os.getenv("MID_ZONE_FIRST_FALLBACK_MIN_VOL_X", "0.20") or 0.20)
        except Exception:
            fallback_min_vol = 0.20
        _fallback_vol_need = max(float(min_vol), float(fallback_min_vol))
        if ("vol_low" in flags) or (vol_v < float(_fallback_vol_need)):
            fallback_fail.append(f"vol={vol_v:.2f}<{_fallback_vol_need:.2f}")
        if _env_on("MID_ZONE_FIRST_BLOCK_FALLBACK_RRLOW", "1") and ("rr_low" in flags):
            fallback_fail.append("rr_low")
        if _env_on("MID_ZONE_FIRST_BLOCK_FALLBACK_SCORELOW", "0") and ("score_low" in flags):
            fallback_fail.append("score_low")
        try:
            _zero_body_max_vol = float(os.getenv("MID_ZONE_FIRST_FALLBACK_ZERO_BODY_MAX_VOL_X", "0.30") or 0.30)
        except Exception:
            _zero_body_max_vol = 0.30
        try:
            zero_body_guard = _env_on("MID_ZONE_FIRST_BLOCK_FALLBACK_ZERO_BODY", "1") and bool(origin_body_soft_bypass) and float(origin_body_atr or 0.0) <= 0.0 and vol_v < float(_zero_body_max_vol)
        except Exception:
            zero_body_guard = False
        if zero_body_guard:
            fallback_fail.append("zero_body")
        if fallback_fail:
            _add_fail("zone_first_fallback_weak:" + ",".join(fallback_fail))

    if zone_first_spot_guard:
        spot_fail = []
        try:
            spot_min_vol = float(os.getenv("MID_ZONE_FIRST_SPOT_MIN_VOL_X", "0.15") or 0.15)
        except Exception:
            spot_min_vol = 0.15
        _spot_vol_need = max(float(min_vol), float(spot_min_vol))
        if ("vol_low" in flags) or (vol_v < float(_spot_vol_need)):
            spot_fail.append(f"vol={vol_v:.2f}<{_spot_vol_need:.2f}")
        try:
            _spot_compression_block = _env_on("MID_ZONE_FIRST_SPOT_BLOCK_COMPRESSION_WEAK", "1")
        except Exception:
            _spot_compression_block = True
        if _spot_compression_block and reg_u in {"COMPRESSION", "RANGE", "CHOPPY", "SIDEWAYS"} and vol_v < float(_spot_vol_need):
            spot_fail.append(f"regime={reg_u}")
        if spot_fail:
            _add_fail("zone_first_spot_weak:" + ",".join(spot_fail))

    if (market or "SPOT").upper().strip() == "FUTURES":
        allowed_regimes = {str(x).strip().upper() for x in _mid_gate_listify(os.getenv("MID_INSTANT_EMIT_ALLOWED_REGIMES_FUTURES", "TREND,TRENDING,EXPANSION")) if str(x).strip()}
        if reg_u not in allowed_regimes:
            if origin_relax_regime and reg_u in {"", "-", "—"}:
                ignored_checks.append(f"instant_regime_block:{reg_u or '-'}")
            else:
                _add_fail(f"instant_regime_block:{reg_u or '-'}")

    if bool(zone_valid):
        if not bool(in_zone_now):
            if (breakout_fresh_ok and breakout_bypass_zone) or (origin_fast_ok and origin_bypass_zone):
                ignored_checks.append("instant_zone_wait")
            else:
                _add_fail("instant_zone_wait")
    else:
        if not bool(allow_no_zone_breakout or breakout_fresh_ok or origin_fast_ok):
            _add_fail("instant_zone_missing")
        if (not origin_fast_ok) and conf_v < float(conf_need + no_zone_extra_conf):
            _add_fail(f"instant_no_zone_conf:{int(round(conf_v))}<{conf_need + no_zone_extra_conf}")
        if atr_v < float(min_atr * 1.05):
            _add_fail(f"instant_no_zone_atr:{atr_v:.3f}<{(min_atr * 1.05):.3f}")
        if vol_v < float(min_vol * 1.10):
            _add_fail(f"instant_no_zone_vol:{vol_v:.2f}<{(min_vol * 1.10):.2f}")

    meta["applied_risk_flags"] = list(applied_risk_flags)
    meta["ignored_risk_flags"] = list(ignored_risk_flags)
    meta["ignored_checks"] = list(ignored_checks)
    meta["ignored_checks_text"] = ",".join([str(x) for x in ignored_checks if str(x).strip()]) if ignored_checks else "-"
    meta["applied_risk_flags_text"] = ",".join(applied_risk_flags) if applied_risk_flags else "-"
    meta["ignored_risk_flags_text"] = ",".join(ignored_risk_flags) if ignored_risk_flags else "-"

    if fail_reasons:
        fail_reasons = sorted(fail_reasons, key=_mid_instant_emit_reason_priority)
        meta["fail_reasons"] = list(fail_reasons)
        meta["fail_reason_count"] = len(fail_reasons)
        meta["all_reasons"] = "|".join(fail_reasons)
        meta["primary_reason"] = str(fail_reasons[0])
        return (False, str(fail_reasons[0]), meta)

    meta["fail_reasons"] = []
    meta["fail_reason_count"] = 0
    meta["all_reasons"] = "pass"
    meta["primary_reason"] = "pass"
    return (True, "pass", meta)



def _price_debug_block(uid: int, *, price: float, source: str, side: str, sl: float | None, tp1: float | None, tp2: float | None, sl_label_key: str | None = None) -> str:
    """Human-readable debug block for a trade.

    Important: all visible labels must come from i18n (see i18n.json keys).
    """
    try:
        price_f = float(price)
    except Exception:
        return ""

    side_u = (side or "LONG").upper()

    def hit_tp(lvl: float) -> bool:
        return price_f >= lvl if side_u == "LONG" else price_f <= lvl

    def hit_sl(lvl: float) -> bool:
        return price_f <= lvl if side_u == "LONG" else price_f >= lvl

    lines = [
        f"💹 {_tr(uid, 'lbl_price_now')}: {price_f:.6f}",
        f"🔌 {_tr(uid, 'lbl_price_src')}: {source}",
    ]

    checks: list[str] = []

    # SL / BE label override (e.g. after TP1 we may want to show BE instead of SL)
    sl_key = (sl_label_key or "lbl_sl").strip() if isinstance(sl_label_key, str) else "lbl_sl"
    sl_lbl = _tr(uid, sl_key)

    if sl is not None and float(sl) > 0:
        lvl = float(sl)
        checks.append(f"{sl_lbl}: {lvl:.6f} {'✅' if hit_sl(lvl) else '❌'}")

    if tp1 is not None and float(tp1) > 0:
        lvl = float(tp1)
        checks.append(f"{_tr(uid, 'lbl_tp1')}: {lvl:.6f} {'✅' if hit_tp(lvl) else '❌'}")

    if tp2 is not None and float(tp2) > 0:
        lvl = float(tp2)
        checks.append(f"{_tr(uid, 'lbl_tp2')}: {lvl:.6f} {'✅' if hit_tp(lvl) else '❌'}")

    if checks:
        lines.append(f"🧪 {_tr(uid, 'lbl_check')}:")
        lines.extend(["• " + c for c in checks])

    return "\n".join(lines)


from zoneinfo import ZoneInfo
MSK = ZoneInfo("Europe/Moscow")

def fmt_dt_msk(d):
    if not d:
        return "—"
    import datetime as dt
    if isinstance(d, dt.datetime):
        if d.tzinfo is None:
            d = d.replace(tzinfo=dt.timezone.utc)
        return d.astimezone(MSK).strftime("%d.%m.%Y %H:%M")
    return "—"

def fmt_pnl_pct(p: float) -> str:
    try:
        p = float(p)
        sign = "+" if p > 0 else ""
        return f"{sign}{p:.1f}%"
    except Exception:
        return "0.0%"

TOP_N = _env_int("TOP_N", 50)
# TOP_N controls how many USDT symbols to scan. Set TOP_N=0 to scan ALL USDT pairs.
SCAN_INTERVAL_SECONDS = max(30, _env_int("SCAN_INTERVAL_SECONDS", 150))
CONFIDENCE_MIN = max(0, min(100, _env_int("CONFIDENCE_MIN", 80)))
# --- TA Quality mode (strict/medium) ---
SIGNAL_MODE = (os.getenv("SIGNAL_MODE", "").strip().lower() or "strict")
if SIGNAL_MODE not in ("strict", "medium"):
    SIGNAL_MODE = "strict"

# Per-market minimum TA score (0..100). Can be overridden via env.
_def_spot = 78 if SIGNAL_MODE == "strict" else 65
_def_fut = 74 if SIGNAL_MODE == "strict" else 62
TA_MIN_SCORE_SPOT = max(0, min(100, _env_int("TA_MIN_SCORE_SPOT", _def_spot)))
TA_MIN_SCORE_FUTURES = max(0, min(100, _env_int("TA_MIN_SCORE_FUTURES", _def_fut)))

# Trend strength filter (ADX)
TA_MIN_ADX = max(0.0, _env_float("TA_MIN_ADX", 22.0 if SIGNAL_MODE == "strict" else 17.0))

# Volume confirmation: require volume >= SMA(volume,20) * X
TA_MIN_VOL_X = max(0.5, _env_float("TA_MIN_VOL_X", 1.25 if SIGNAL_MODE == "strict" else 1.05))

# MACD histogram threshold (momentum). For LONG require hist >= +X, for SHORT <= -X
TA_MIN_MACD_H = max(0.0, _env_float("TA_MIN_MACD_H", 0.0 if SIGNAL_MODE == "strict" else 0.0))

# Bollinger rule: if 1, require breakout/cross of midline in direction of trend on the last candle
TA_BB_REQUIRE_BREAKOUT = _env_bool("TA_BB_REQUIRE_BREAKOUT", True if SIGNAL_MODE == "strict" else False)

# RSI guard rails
TA_RSI_MAX_LONG = max(1.0, _env_float("TA_RSI_MAX_LONG", 68.0 if SIGNAL_MODE == "strict" else 72.0))
TA_RSI_MIN_SHORT = max(0.0, _env_float("TA_RSI_MIN_SHORT", 32.0 if SIGNAL_MODE == "strict" else 28.0))

# Multi-timeframe confirmation: if 1, require 4h and 1h trend alignment (recommended).
# If 0, allow 4h trend only (more signals).
TA_REQUIRE_1H_TREND = _env_bool("TA_REQUIRE_1H_TREND", True if SIGNAL_MODE == "strict" else False)

COOLDOWN_MINUTES = max(1, _env_int("COOLDOWN_MINUTES", 180))

USE_REAL_PRICE = _env_bool("USE_REAL_PRICE", True)
# Price source selection per market: BINANCE / BYBIT / MEDIAN
SPOT_PRICE_SOURCE = (os.getenv("SPOT_PRICE_SOURCE", "MEDIAN").strip().upper() or "MEDIAN")
FUTURES_PRICE_SOURCE = (os.getenv("FUTURES_PRICE_SOURCE", "MEDIAN").strip().upper() or "MEDIAN")
TRACK_INTERVAL_SECONDS = max(1, _env_int("TRACK_INTERVAL_SECONDS", 3))
# Backward-compatible default partial close percent (legacy)
TP1_PARTIAL_CLOSE_PCT = max(0, min(100, _env_int("TP1_PARTIAL_CLOSE_PCT", 50)))

# New per-market settings
TP1_PARTIAL_CLOSE_PCT_SPOT = max(0, min(100, _env_int("TP1_PARTIAL_CLOSE_PCT_SPOT", TP1_PARTIAL_CLOSE_PCT)))
TP1_PARTIAL_CLOSE_PCT_FUTURES = max(0, min(100, _env_int("TP1_PARTIAL_CLOSE_PCT_FUTURES", TP1_PARTIAL_CLOSE_PCT)))

BE_AFTER_TP1_SPOT = _env_bool("BE_AFTER_TP1_SPOT", True)
BE_AFTER_TP1_FUTURES = _env_bool("BE_AFTER_TP1_FUTURES", True)

# Fee-protected BE: exit remaining position at entry +/- fee buffer so BE is not negative after fees (model)
BE_FEE_BUFFER = _env_bool("BE_FEE_BUFFER", True)
FEE_RATE_SPOT = max(0.0, _env_float("FEE_RATE_SPOT", 0.001))        # e.g. 0.001 = 0.10%
FEE_RATE_FUTURES = max(0.0, _env_float("FEE_RATE_FUTURES", 0.001))  # e.g. 0.001 = 0.10%
FEE_BUFFER_MULTIPLIER = max(0.0, _env_float("FEE_BUFFER_MULTIPLIER", 2.0))  # 2 = entry+exit fees
ATR_MULT_SL = max(0.5, _env_float("ATR_MULT_SL", 1.5))
TP1_R = max(0.5, _env_float("TP1_R", 1.5))
TP2_R = max(1.0, _env_float("TP2_R", 3.0))
# --- Upgrades: Adaptive TP2 + delayed BE arming (optional) ---
ADAPTIVE_TP2 = _env_bool("ADAPTIVE_TP2", False)
ADAPTIVE_TP2_ADX_STRONG = _env_float("ADAPTIVE_TP2_ADX_STRONG", 30.0)
ADAPTIVE_TP2_ADX_MED = _env_float("ADAPTIVE_TP2_ADX_MED", 25.0)
ADAPTIVE_TP2_R_STRONG = _env_float("ADAPTIVE_TP2_R_STRONG", 2.8)
ADAPTIVE_TP2_R_MED = _env_float("ADAPTIVE_TP2_R_MED", 2.45)
ADAPTIVE_TP2_R_WEAK = _env_float("ADAPTIVE_TP2_R_WEAK", 2.2)

# When >0, BE (SL->BE) becomes "armed" only after price moves from TP1 towards TP2 by this fraction.
# Helps TP2 by reducing BE whipsaws after TP1. 0 = immediate BE (legacy behavior).
BE_ARM_PCT_TO_TP2 = max(0.0, min(1.0, _env_float("BE_ARM_PCT_TO_TP2", 0.0)))

# News filter
NEWS_FILTER = _env_bool("NEWS_FILTER", False)
CRYPTOPANIC_TOKEN = os.getenv("CRYPTOPANIC_TOKEN", "").strip()
CRYPTOPANIC_PUBLIC = _env_bool("CRYPTOPANIC_PUBLIC", False)
CRYPTOPANIC_REGIONS = os.getenv("CRYPTOPANIC_REGIONS", "en").strip() or "en"
CRYPTOPANIC_KIND = os.getenv("CRYPTOPANIC_KIND", "news").strip() or "news"
NEWS_LOOKBACK_MIN = max(5, _env_int("NEWS_LOOKBACK_MIN", 60))
NEWS_ACTION = os.getenv("NEWS_ACTION", "FUTURES_OFF").strip().upper()  # FUTURES_OFF / PAUSE_ALL

# Macro filter
MACRO_FILTER = _env_bool("MACRO_FILTER", False)

# Orderbook filter (optional)
ORDERBOOK_FILTER = _env_bool("ORDERBOOK_FILTER", False)
# ------------------ Orderbook filter (FUTURES only recommended) ------------------
# Backward compatible alias: ORDERBOOK_FILTER
USE_ORDERBOOK = _env_bool("USE_ORDERBOOK", ORDERBOOK_FILTER)
ORDERBOOK_EXCHANGES = [x.strip().lower() for x in _env_str("ORDERBOOK_EXCHANGES", "binance,bybit").split(",") if x.strip()]
ORDERBOOK_FUTURES_ONLY = _env_bool("ORDERBOOK_FUTURES_ONLY", True)

# Strict defaults (can be overridden via ENV)
ORDERBOOK_LEVELS = max(5, _env_int("ORDERBOOK_LEVELS", 20))
ORDERBOOK_IMBALANCE_MIN = max(1.0, _env_float("ORDERBOOK_IMBALANCE_MIN", 1.6))  # bids/asks ratio
ORDERBOOK_WALL_RATIO = max(1.0, _env_float("ORDERBOOK_WALL_RATIO", 4.0))  # max_level / avg_level
ORDERBOOK_WALL_NEAR_PCT = max(0.05, _env_float("ORDERBOOK_WALL_NEAR_PCT", 0.5))  # consider walls within X% from mid
ORDERBOOK_MAX_SPREAD_PCT = max(0.0, _env_float("ORDERBOOK_MAX_SPREAD_PCT", 0.08))  # block if spread too wide
MACRO_ACTION = os.getenv("MACRO_ACTION", "FUTURES_OFF").strip().upper()  # FUTURES_OFF / PAUSE_ALL
BLACKOUT_BEFORE_MIN = max(0, _env_int("BLACKOUT_BEFORE_MIN", 30))
BLACKOUT_AFTER_MIN = max(0, _env_int("BLACKOUT_AFTER_MIN", 45))
_tz_raw = (os.getenv("TZ_NAME", "Europe/Berlin") or "").strip()
# Normalize common non-IANA aliases (ZoneInfo requires IANA names)
_TZ_ALIASES = {
    "MSK": "Europe/Moscow",
    "MOSCOW": "Europe/Moscow",
    "EUROPE/MOSCOW": "Europe/Moscow",
    "UTC+3": "Europe/Moscow",
    "UTC+03:00": "Europe/Moscow",
    "GMT+3": "Europe/Moscow",
    "GMT+03:00": "Europe/Moscow",
}

TZ_NAME = _TZ_ALIASES.get(_tz_raw.upper(), _tz_raw) or "Europe/Berlin"

# If TZ_NAME is still invalid, fall back to a safe default
try:
    ZoneInfo(TZ_NAME)
except Exception:
    TZ_NAME = "Europe/Moscow" if TZ_NAME.upper() in _TZ_ALIASES else "UTC"

FOMC_DECISION_HOUR_ET = max(0, min(23, _env_int("FOMC_DECISION_HOUR_ET", 14)))
FOMC_DECISION_MINUTE_ET = max(0, min(59, _env_int("FOMC_DECISION_MINUTE_ET", 0)))

# ------------------ Models ------------------
def _mid_late_entry_anti_bounce_reasons(*,
                                      side: str,
                                      close: float,
                                      recent_low: float,
                                      recent_high: float,
                                      atr_30m: float,
                                      market: str = "SPOT",
                                      adx_30m: float | None = None) -> tuple[str | None, str | None]:
    """Shared late-entry / anti-bounce checks.

    Used by scan-stage soft penalties and by hard entry-time gates.
    """
    try:
        atr = float(atr_30m or 0.0)
        px = float(close or 0.0)
        rl = float(recent_low or 0.0)
        rh = float(recent_high or 0.0)
        if atr <= 0 or px <= 0:
            return (None, None)

        late_entry_max = _mid_effective_late_entry_max(market=market, adx_30m=adx_30m)
        mkt_u = (market or "SPOT").upper().strip()
        fut_late_mult = 1.0
        fut_bounce_mult = 1.0
        if mkt_u == "FUTURES" and os.getenv("MID_FUT_ADAPT_FILTERS", "1").strip().lower() in ("1","true","yes","on"):
            if adx_30m is not None and os.getenv("MID_FUT_ADAPT_BY_ADX", "1").strip().lower() in ("1","true","yes","on"):
                adx = float(adx_30m)
                adx_strong = _env_float("MID_FUT_ADX_STRONG", 30.0)
                adx_med = _env_float("MID_FUT_ADX_MED", 25.0)
                if adx >= adx_strong:
                    fut_late_mult = _env_float("MID_FUT_LATE_MULT_STRONG", 1.15)
                    fut_bounce_mult = _env_float("MID_FUT_BOUNCE_MULT_STRONG", 1.10)
                elif adx >= adx_med:
                    fut_late_mult = _env_float("MID_FUT_LATE_MULT_MED", 1.08)
                    fut_bounce_mult = _env_float("MID_FUT_BOUNCE_MULT_MED", 1.06)
                else:
                    fut_late_mult = _env_float("MID_FUT_LATE_MULT_WEAK", 0.98)
                    fut_bounce_mult = _env_float("MID_FUT_BOUNCE_MULT_WEAK", 0.98)
        late_entry_max *= float(fut_late_mult)

        bounce_scale = 1.0
        if os.getenv("MID_ADAPTIVE_FILTERS", "0").strip().lower() in ("1","true","yes","on") and atr > 0 and px > 0:
            atrp = (atr / px) * 100.0
            low = float(os.getenv("MID_ADAPT_ATR_PCT_LOW", "2.0") or 2.0)
            high = float(os.getenv("MID_ADAPT_ATR_PCT_HIGH", "6.0") or 6.0)
            if high <= low:
                t = 0.5
            else:
                t = (atrp - low) / (high - low)
            t = max(0.0, min(1.0, float(t)))
            late_tight = float(os.getenv("MID_ADAPT_LATE_TIGHTEN_MIN", "0.90") or 0.90)
            late_wide  = float(os.getenv("MID_ADAPT_LATE_WIDEN_MAX", "1.15") or 1.15)
            bounce_tight = float(os.getenv("MID_ADAPT_BOUNCE_TIGHTEN_MIN", "0.90") or 0.90)
            bounce_wide  = float(os.getenv("MID_ADAPT_BOUNCE_WIDEN_MAX", "1.30") or 1.30)
            late_scale = late_wide + t * (late_tight - late_wide)
            bounce_scale = bounce_wide + t * (bounce_tight - bounce_wide)
            late_entry_max *= float(late_scale)

        late_reason = None
        if str(side).upper() == "LONG":
            move_from_low = (px - rl) / atr
            if move_from_low > late_entry_max:
                late_reason = f"late_entry_atr={move_from_low:.2f} > {late_entry_max:g}"
        else:
            move_from_high = (rh - px) / atr
            if move_from_high > late_entry_max:
                late_reason = f"late_entry_atr={move_from_high:.2f} > {late_entry_max:g}"

        anti_reason = None
        if MID_ANTI_BOUNCE_ENABLED:
            bounce_atr_max = float(globals().get("MID_ANTI_BOUNCE_ATR_MAX", _env_float("MID_ANTI_BOUNCE_ATR_MAX", 1.8)))
            if mkt_u == "FUTURES":
                _fut_b = _env_float("MID_ANTI_BOUNCE_ATR_MAX_FUT", 0.0)
                if _fut_b and _fut_b > 0:
                    bounce_atr_max = float(_fut_b)
            _ab_short = _env_float("MID_ANTI_BOUNCE_SHORT_MAX", 0.0)
            _ab_long  = _env_float("MID_ANTI_BOUNCE_LONG_MAX", 0.0)
            bounce_short_max = (float(_ab_short) if _ab_short and _ab_short > 0 else bounce_atr_max) * (float(bounce_scale) * float(fut_bounce_mult))
            bounce_long_max = (float(_ab_long) if _ab_long and _ab_long > 0 else bounce_atr_max) * (float(bounce_scale) * float(fut_bounce_mult))
            if str(side).upper() == "SHORT":
                dist_low_atr = (px - rl) / atr
                if dist_low_atr > bounce_short_max:
                    anti_reason = f"anti_bounce_short dist_low_atr={dist_low_atr:.2f} > {bounce_short_max:g}"
            else:
                dist_high_atr = (rh - px) / atr
                if dist_high_atr > bounce_long_max:
                    anti_reason = f"anti_bounce_long dist_high_atr={dist_high_atr:.2f} > {bounce_long_max:g}"
        return (late_reason, anti_reason)
    except Exception:
        return (None, None)


def _mid_recent_extremes_for_late_entry(df5=None, df30=None, *, lookback: int | None = None) -> tuple[float, float]:
    """Compute recent_low/recent_high for late-entry/near-extreme checks.

    Use the same 5m lookback across scan and trigger paths to avoid inflated
    trigger-time distances caused by mixing a local 5m scan window with a broad
    30m trigger window.

    Fallbacks:
    - If 5m data is unavailable, use an equivalent 30m time horizon.
    - If all else fails, use the full available 30m frame.
    """
    try:
        late_lookback = int(float(lookback if lookback is not None else (os.getenv("MID_LATE_ENTRY_LOOKBACK", "48") or 48)))
    except Exception:
        late_lookback = 48
    if late_lookback < 10:
        late_lookback = 48

    try:
        if df5 is not None and not getattr(df5, "empty", True):
            w5 = df5.tail(late_lookback) if len(df5) >= late_lookback else df5
            return (
                float(w5["low"].astype(float).min()),
                float(w5["high"].astype(float).max()),
            )
    except Exception:
        pass

    try:
        if df30 is not None and not getattr(df30, "empty", True):
            bars30 = max(1, int(math.ceil(float(late_lookback) / 6.0)))
            w30 = df30.tail(bars30) if len(df30) >= bars30 else df30
            return (
                float(w30["low"].astype(float).min()),
                float(w30["high"].astype(float).max()),
            )
    except Exception:
        pass

    try:
        if df30 is not None and not getattr(df30, "empty", True):
            return (
                float(df30["low"].astype(float).min()),
                float(df30["high"].astype(float).max()),
            )
    except Exception:
        pass

    return (0.0, 0.0)


def _mid_block_reason(symbol: str, side: str, close: float, o: float, recent_low: float, recent_high: float,
                      atr_30m: float, rsi_5m: float, vwap: float, bb_pos: str | None,
                      ema20_5m: float | None, bos_down_5m: bool, two_red_5m: bool, lower_highs_5m: bool,
                      bos_up_5m: bool, two_green_5m: bool, higher_lows_5m: bool,
                      last_vol: float, avg_vol: float, last_body: float, climax_recent_bars: int,
                      market: str = "SPOT",
                      htf_dir_1h: str | None = None, htf_dir_30m: str | None = None, adx_30m: float | None = None) -> str | None:
    """Return human-readable MID BLOCKED reason (for logging + error-bot), or None if allowed."""
    try:
        # If MID pending-entry mode is enabled, we should NOT hard-block a candidate just because
        # the current price is already far from a recent extreme or far from VWAP.
        # In pending mode we store the setup and wait for price to come back into the entry zone,
        # so late_entry_atr / vwap_dist_atr would incorrectly kill most setups.
        #
        # Toggle:
        #   MID_PENDING_ENABLED=1
        #   MID_PENDING_SKIP_HARDBLOCKS=1   (default)
        _pending_enabled = os.getenv("MID_PENDING_ENABLED", "0").strip().lower() not in ("0", "false", "no", "off")
        _pending_skip_hb = os.getenv("MID_PENDING_SKIP_HARDBLOCKS", "1").strip().lower() not in ("0", "false", "no", "off")
        # When user wants *all* filters only after setup, we skip all hardblocks during the SCAN phase.
        # On TRIGGER phase we must enforce the filters again.
        _phase = "scan"
        try:
            _phase = str(_MID_EVAL_PHASE.get() or "scan")
        except Exception:
            _phase = "scan"
        _postsetup_only = os.getenv("MID_FILTERS_AFTER_SETUP", "1").strip().lower() not in ("0", "false", "no", "off")
        if _pending_enabled and _postsetup_only and _phase == "scan":
            return None

        # Skip only late-entry/vwap-distance blocks during SCAN when pending mode is enabled.
        _skip_late_vwap_blocks = bool((_phase == "scan") and _pending_enabled and _pending_skip_hb)

        # ULTRA SAFE: tighten filters dynamically for near-zero SL preference
        late_entry_max = _mid_effective_late_entry_max(market=market, adx_30m=adx_30m)
        vwap_dist_max = MID_ULTRA_VWAP_DIST_ATR_MAX if MID_ULTRA_SAFE else MID_VWAP_DIST_ATR_MAX
        rsi_long_max = MID_ULTRA_RSI_LONG_MAX if MID_ULTRA_SAFE else MID_RSI_LONG_MAX
        rsi_long_min = MID_ULTRA_RSI_LONG_MIN if MID_ULTRA_SAFE else MID_RSI_LONG_MIN
        rsi_short_min = MID_ULTRA_RSI_SHORT_MIN if MID_ULTRA_SAFE else MID_RSI_SHORT_MIN
        rsi_short_max = MID_ULTRA_RSI_SHORT_MAX if MID_ULTRA_SAFE else MID_RSI_SHORT_MAX
        confirm_body_min = MID_ULTRA_CONFIRM_CANDLE_BODY_ATR_MIN if MID_ULTRA_SAFE else MID_CONFIRM_CANDLE_BODY_ATR_MIN

        # --- FUTURES-specific adaptive thresholds (optional) ---
        mkt_u = (market or "SPOT").upper().strip()
        fut_late_mult = 1.0
        fut_vwap_mult = 1.0
        fut_bounce_mult = 1.0
        try:
            if mkt_u == "FUTURES" and os.getenv("MID_FUT_ADAPT_FILTERS", "1").strip().lower() in ("1","true","yes","on"):
                # Optional hard overrides (set >0 to take effect)
                _le_fut = _env_float("MID_LATE_ENTRY_ATR_MAX_FUT", 0.0)
                _vw_fut = _env_float("MID_VWAP_DIST_ATR_MAX_FUT", 0.0)
                # late_entry_max already includes FUT/ULTRA normalization via _mid_effective_late_entry_max()
                if _vw_fut and _vw_fut > 0:
                    vwap_dist_max = min(vwap_dist_max, float(_vw_fut)) if MID_ULTRA_SAFE else float(_vw_fut)

                # Adaptive scaling by ADX (expansion/trending -> allow a bit more distance without blocking)
                if adx_30m is not None and os.getenv("MID_FUT_ADAPT_BY_ADX", "1").strip().lower() in ("1","true","yes","on"):
                    adx = float(adx_30m)
                    adx_strong = _env_float("MID_FUT_ADX_STRONG", 30.0)
                    adx_med = _env_float("MID_FUT_ADX_MED", 25.0)

                    if adx >= adx_strong:
                        fut_late_mult = _env_float("MID_FUT_LATE_MULT_STRONG", 1.15)
                        fut_vwap_mult = _env_float("MID_FUT_VWAP_MULT_STRONG", 1.10)
                        fut_bounce_mult = _env_float("MID_FUT_BOUNCE_MULT_STRONG", 1.10)
                    elif adx >= adx_med:
                        fut_late_mult = _env_float("MID_FUT_LATE_MULT_MED", 1.08)
                        fut_vwap_mult = _env_float("MID_FUT_VWAP_MULT_MED", 1.06)
                        fut_bounce_mult = _env_float("MID_FUT_BOUNCE_MULT_MED", 1.06)
                    else:
                        # In weak/choppy conditions keep it tighter to avoid noise.
                        fut_late_mult = _env_float("MID_FUT_LATE_MULT_WEAK", 0.98)
                        fut_vwap_mult = _env_float("MID_FUT_VWAP_MULT_WEAK", 0.98)
                        fut_bounce_mult = _env_float("MID_FUT_BOUNCE_MULT_WEAK", 0.98)

                late_entry_max *= float(fut_late_mult)
                vwap_dist_max *= float(fut_vwap_mult)
        except Exception:
            mkt_u = (market or "SPOT").upper().strip()
            fut_late_mult = fut_vwap_mult = fut_bounce_mult = 1.0


        # --- Adaptive MID filter thresholds by ATR% regime (optional) ---
        try:
            if os.getenv("MID_ADAPTIVE_FILTERS", "0").strip().lower() in ("1","true","yes","on"):
                atrp = (float(atr_30m) / float(close) * 100.0) if (atr_30m and close) else 0.0
                low = float(os.getenv("MID_ADAPT_ATR_PCT_LOW", "2.0") or 2.0)
                high = float(os.getenv("MID_ADAPT_ATR_PCT_HIGH", "6.0") or 6.0)
                if high <= low:
                    t = 0.5
                else:
                    t = (atrp - low) / (high - low)
                if t < 0.0:
                    t = 0.0
                if t > 1.0:
                    t = 1.0

                try:
                    _mid_adapt_track(float(atrp or 0.0), float(t or 0.0), symbol)
                except Exception:
                    pass

                # When ATR% is LOW (t≈0) -> loosen filters a bit (more emitted in quiet markets).
                # When ATR% is HIGH (t≈1) -> tighten filters (avoid late/dirty entries in volatile markets).
                late_tight = float(os.getenv("MID_ADAPT_LATE_TIGHTEN_MIN", "0.90") or 0.90)
                late_wide  = float(os.getenv("MID_ADAPT_LATE_WIDEN_MAX", "1.15") or 1.15)
                vwap_tight = float(os.getenv("MID_ADAPT_VWAP_TIGHTEN_MIN", "0.90") or 0.90)
                vwap_wide  = float(os.getenv("MID_ADAPT_VWAP_WIDEN_MAX", "1.20") or 1.20)
                bounce_tight = float(os.getenv("MID_ADAPT_BOUNCE_TIGHTEN_MIN", "0.90") or 0.90)
                bounce_wide  = float(os.getenv("MID_ADAPT_BOUNCE_WIDEN_MAX", "1.30") or 1.30)

                near_strict = float(os.getenv("MID_ADAPT_NEAR_STRICT_MAX", "1.15") or 1.15)  # low ATR% => stricter (bigger)
                near_loose  = float(os.getenv("MID_ADAPT_NEAR_LOOSE_MIN", "0.70") or 0.70)    # high ATR% => looser (smaller)
                vol_strict  = float(os.getenv("MID_ADAPT_VOL_STRICT_MAX", "1.10") or 1.10)   # low ATR% => stricter (bigger)
                vol_loose   = float(os.getenv("MID_ADAPT_VOL_LOOSE_MIN", "0.95") or 0.95)    # high ATR% => looser (smaller)

                late_scale = late_wide + t * (late_tight - late_wide)
                vwap_scale = vwap_wide + t * (vwap_tight - vwap_wide)
                bounce_scale = bounce_wide + t * (bounce_tight - bounce_wide)

                # Apply to thresholds
                late_entry_max *= late_scale
                vwap_dist_max *= vwap_scale

                # Near-extreme threshold: bigger => more blocking (stricter) when ATR% high
                # Interpolate multiplier from near_loose (t=0) to near_strict (t=1)
                near_mult = near_loose + t * (near_strict - near_loose)

                # Min volume threshold: slightly stricter when ATR% high
                vol_mult = vol_loose + t * (vol_strict - vol_loose)

                # Save for later usage in this function (locals)
                _mid_adapt_near_mult = near_mult
                _mid_adapt_vol_mult = vol_mult
                _mid_adapt_bounce_scale = bounce_scale
            else:
                _mid_adapt_near_mult = 1.0
                _mid_adapt_vol_mult = 1.0
                _mid_adapt_bounce_scale = 1.0
        except Exception:
            _mid_adapt_near_mult = 1.0
            _mid_adapt_vol_mult = 1.0
            _mid_adapt_bounce_scale = 1.0

        if atr_30m and atr_30m > 0:
            late_reason, anti_bounce_reason = _mid_late_entry_anti_bounce_reasons(
                side=side,
                close=close,
                recent_low=recent_low,
                recent_high=recent_high,
                atr_30m=atr_30m,
                market=market,
                adx_30m=adx_30m,
            )
            if late_reason and not _skip_late_vwap_blocks:
                return str(late_reason)
            if anti_bounce_reason:
                return str(anti_bounce_reason)

            # --- Near-extremes: avoid LONG right under resistance / SHORT right above support ---
            try:
                if MID_BLOCK_NEAR_EXTREMES and atr_30m and atr_30m > 0:
                    thr = (MID_ULTRA_NEAR_EXTREME_ATR_MIN if MID_ULTRA_SAFE else MID_NEAR_EXTREME_ATR_MIN) * (_mid_adapt_near_mult if '_mid_adapt_near_mult' in locals() else 1.0)
                    if side.upper() == "LONG":
                        dist_to_high = (recent_high - close) / atr_30m
                        if dist_to_high >= 0 and dist_to_high < thr:
                            return f"near_recent_high dist_atr={dist_to_high:.2f} < {thr:g}"
                    else:
                        dist_to_low = (close - recent_low) / atr_30m
                        if dist_to_low >= 0 and dist_to_low < thr:
                            return f"near_recent_low dist_atr={dist_to_low:.2f} < {thr:g}"
            except Exception:
                if MID_FAIL_CLOSED:
                    return "mid_near_extreme_error"
                pass
            # Late-entry / anti-bounce are evaluated via _mid_late_entry_anti_bounce_reasons().

            # --- HTF alignment guard (ULTRA SAFE): block countertrend entries in strong trends ---
            try:
                if MID_HTF_ALIGN_GUARD and (adx_30m is not None) and (htf_dir_1h or htf_dir_30m):
                    strong = False
                    try:
                        strong = float(adx_30m) >= float(MID_HTF_STRONG_ADX_MIN)
                    except Exception:
                        strong = False

                    if strong:
                        h1 = (htf_dir_1h or "").upper()
                        h30 = (htf_dir_30m or "").upper()
                        s = side.upper()

                        # determine if this is countertrend vs HTF bias (both tf agree)
                        if h1 in ("LONG","SHORT") and h30 in ("LONG","SHORT") and h1 == h30 and s != h1:
                            # allow countertrend only if 5m shows clear reversal structure
                            if MID_ALLOW_COUNTERTREND_WITH_5M_REVERSAL:
                                if s == "SHORT":
                                    # need bearish reversal on 5m: BOS down + red candles + lower highs
                                    if not (bos_down_5m and two_red_5m and lower_highs_5m):
                                        return f"htf_align_block strong_adx={float(adx_30m):.1f} htf={h1} need_5m_reversal"
                                else:  # LONG
                                    if not (bos_up_5m and two_green_5m and higher_lows_5m):
                                        return f"htf_align_block strong_adx={float(adx_30m):.1f} htf={h1} need_5m_reversal"
                            else:
                                return f"htf_align_block strong_adx={float(adx_30m):.1f} htf={h1}"
            except Exception:
                pass

            # --- BB bounce guard (mirror): avoid entries away from BB extremes ---
            # For quality entries (less SL), we prefer:
            #   LONG  only near/below lower band (bb_pos == '↓low')
            #   SHORT only near/above upper band (bb_pos == '↑high')
            # Everything inside the bands is treated as "bounce zone" and blocked.
            if MID_BLOCK_BB_BOUNCE and bb_pos:
                b = str(bb_pos)
                if side.upper() == "SHORT":
                    if b in ("mid→high", "low→mid", "↓low"):
                        return f"bb_bounce_zone={bb_pos}"
                else:  # LONG
                    if b in ("mid→high", "low→mid", "↑high"):
                        return f"bb_bounce_zone={bb_pos}"

            if not _skip_late_vwap_blocks:
                dist = abs(close - vwap) / atr_30m if vwap is not None else 0.0
                if dist > vwap_dist_max:
                    return f"vwap_dist_atr={dist:.2f} > {vwap_dist_max:g}"

            body_atr = (abs(close - o) / atr_30m) if o is not None else 0.0
            if avg_vol and avg_vol > 0:
                vol_x = last_vol / avg_vol
            else:
                vol_x = 0.0

            try:
                min_vol = float(MID_MIN_VOL_X) * (_mid_adapt_vol_mult if '_mid_adapt_vol_mult' in locals() else 1.0)
                if min_vol and vol_x < min_vol:
                    return f"vol_x={vol_x:.2f} < {min_vol:g}"
            except Exception:
                pass
            # "climax": big vol + big body; block next N bars
            if climax_recent_bars > 0 or (vol_x > MID_CLIMAX_VOL_X and body_atr > MID_CLIMAX_BODY_ATR):
                return f"climax vol_x={vol_x:.2f} > {MID_CLIMAX_VOL_X:g} and body_atr={body_atr:.2f} > {MID_CLIMAX_BODY_ATR:g}"

        # RSI filter (works even if ATR missing)
        if rsi_5m is not None:
            if side.upper() == "LONG":
                if rsi_5m >= rsi_long_max:
                    return f"rsi_long={rsi_5m:.1f} >= {rsi_long_max:g}"
                if rsi_5m < rsi_long_min:
                    return f"rsi_long={rsi_5m:.1f} < {rsi_long_min:g}"
            else:  # SHORT
                if rsi_5m <= rsi_short_min:
                    return f"rsi_short={rsi_5m:.1f} <= {rsi_short_min:g}"
                if rsi_5m >= rsi_short_max:
                    return f"rsi_short={rsi_5m:.1f} >= {rsi_short_max:g}"

        # --- Extra quality guards (to reduce immediate SL after entry) ---
        try:
            if MID_REQUIRE_VWAP_SIDE and vwap is not None:
                if side.upper() == "LONG" and close < float(vwap):
                    return f"vwap_side_long close<{float(vwap):.6g}"
                if side.upper() == "SHORT" and close > float(vwap):
                    return f"vwap_side_short close>{float(vwap):.6g}"
        except Exception:
            pass

        try:
            if MID_CONFIRM_CANDLE_ENABLED:
                # Direction-aligned candle
                if MID_CONFIRM_CANDLE_REQUIRE_DIRECTION and o is not None:
                    if side.upper() == "LONG" and close <= float(o):
                        return "confirm_candle_long close<=open"
                    if side.upper() == "SHORT" and close >= float(o):
                        return "confirm_candle_short close>=open"
                # Minimal body vs ATR to avoid chop
                if atr_30m and atr_30m > 0 and o is not None:
                    body_atr2 = abs(float(close) - float(o)) / float(atr_30m)
                    if body_atr2 < confirm_body_min:
                        return f"small_body_atr={body_atr2:.2f} < {confirm_body_min:g}"
        except Exception:
            pass


        # --- Anti-countertrend guards (5m structure) ---
        try:
            if side.upper() == "LONG":
                if MID_BLOCK_LONG_BOS_DOWN and bos_down_5m:
                    return "bos_down_5m"
                if MID_BLOCK_LONG_BELOW_EMA20_5M and (ema20_5m is not None) and close < float(ema20_5m):
                    return f"below_ema20_5m close<{float(ema20_5m):.6g}"
                if MID_BLOCK_LONG_2_RED_CANDLES and two_red_5m:
                    return "two_red_candles_5m"
                if MID_BLOCK_LONG_LOWER_HIGHS and lower_highs_5m:
                    return "lower_highs_5m"
            elif side.upper() == "SHORT":
                if MID_BLOCK_SHORT_BOS_UP and bos_up_5m:
                    return "bos_up_5m"
                if MID_BLOCK_SHORT_ABOVE_EMA20_5M and (ema20_5m is not None) and close > float(ema20_5m):
                    return f"above_ema20_5m close>{float(ema20_5m):.6g}"
                if MID_BLOCK_SHORT_2_GREEN_CANDLES and two_green_5m:
                    return "two_green_candles_5m"
                if MID_BLOCK_SHORT_HIGHER_LOWS and higher_lows_5m:
                    return "higher_lows_5m"
        except Exception:
            pass
        # --- Require 5m confirmation (prevents SHORT into bullish microtrend / LONG into bearish microtrend) ---
        try:

            if MID_REQUIRE_5M_CONFIRM:
                s = side.upper()
                if MID_ULTRA_SAFE:
                    # ULTRA SAFE: require real continuation/reversal structure, not just EMA touch
                    if s == "SHORT":
                        score = 0
                        if bos_down_5m: score += 1
                        if lower_highs_5m: score += 1
                        if two_red_5m: score += 1
                        if score < 2:
                            return "no_bear_5m_structure"
                        if (ema20_5m is not None) and not (close < float(ema20_5m)):
                            return "short_above_ema20_5m"
                    elif s == "LONG":
                        score = 0
                        if bos_up_5m: score += 1
                        if higher_lows_5m: score += 1
                        if two_green_5m: score += 1
                        if score < 2:
                            return "no_bull_5m_structure"
                        if (ema20_5m is not None) and not (close > float(ema20_5m)):
                            return "long_below_ema20_5m"
                else:
                    if s == "SHORT":
                        bear = bool(bos_down_5m) or bool(two_red_5m) or bool(lower_highs_5m) or ((ema20_5m is not None) and (close < float(ema20_5m)))
                        if not bear:
                            return "no_bear_5m_confirm"
                    elif s == "LONG":
                        bull = bool(bos_up_5m) or bool(two_green_5m) or bool(higher_lows_5m) or ((ema20_5m is not None) and (close > float(ema20_5m)))
                        if not bull:
                            return "no_bull_5m_confirm"
        except Exception:
            # if confirmation calc fails, respect fail-closed flag
            if MID_FAIL_CLOSED:
                return "mid_5m_confirm_error"
            pass


    except Exception:
        # if filter computation fails, respect fail-closed flag
        return "mid_filter_error" if MID_FAIL_CLOSED else None
    return None
def _signal_levels_sanity_gate(sig: "Signal") -> tuple[bool, str]:
    """Return (ok, reason) for basic signal-level sanity.

    Used by zone-touch alerts so obviously broken anchored levels never reach
    users. This is intentionally lightweight and direction-aware:
      - entry/sl/tp must be positive and on the correct side of entry
      - relative SL/TP distance must stay within a generous cap
    """
    try:
        direction = str(getattr(sig, "direction", "") or getattr(sig, "side", "") or "").upper().strip()
        entry = float(getattr(sig, "entry", 0.0) or 0.0)
        sl = float(getattr(sig, "sl", 0.0) or 0.0)
        tp1 = float(getattr(sig, "tp1", 0.0) or 0.0)
        tp2 = float(getattr(sig, "tp2", 0.0) or 0.0)
        if entry <= 0:
            return (False, "entry<=0")
        if sl <= 0:
            return (False, "sl<=0")
        target = tp2 if tp2 > 0 else tp1
        if target <= 0:
            return (False, "tp<=0")

        is_short = ("SHORT" in direction)
        eps = max(1e-12, abs(entry) * 1e-9)
        if is_short:
            if sl <= entry + eps:
                return (False, f"sl_not_above_entry:{sl:.6g}<={entry:.6g}")
            if target >= entry - eps:
                return (False, f"tp_not_below_entry:{target:.6g}>={entry:.6g}")
        else:
            if sl >= entry - eps:
                return (False, f"sl_not_below_entry:{sl:.6g}>={entry:.6g}")
            if target <= entry + eps:
                return (False, f"tp_not_above_entry:{target:.6g}<={entry:.6g}")

        try:
            max_rel = float(os.getenv("MID_ZONE_TOUCH_SANITY_MAX_REL_DIST", "0.50") or 0.50)
        except Exception:
            max_rel = 0.50
        if max_rel > 0:
            sl_rel = abs(sl - entry) / max(entry, eps)
            tp_rel = abs(target - entry) / max(entry, eps)
            if sl_rel > max_rel:
                return (False, f"sl_rel_too_large:{sl_rel:.3f}>{max_rel:.3f}")
            if tp_rel > max_rel:
                return (False, f"tp_rel_too_large:{tp_rel:.3f}>{max_rel:.3f}")

        return (True, "")
    except Exception as e:
        return (False, f"levels_sanity_error:{type(e).__name__}")


def _normalize_signal_levels_inplace(sig) -> None:
    """Make signal levels direction-consistent.

    Guards against malformed SHORT/LONG layouts where SL/TP are on the wrong
    side of entry (for example after market conversion or partial overrides).
    The function preserves absolute distances from entry and only flips the
    level orientation to match the signal direction.
    """
    try:
        direction = str(getattr(sig, "direction", "") or getattr(sig, "side", "") or "").upper()
        entry = float(getattr(sig, "entry", 0.0) or 0.0)
        sl = float(getattr(sig, "sl", 0.0) or 0.0)
        tp1 = float(getattr(sig, "tp1", 0.0) or 0.0)
        tp2 = float(getattr(sig, "tp2", 0.0) or 0.0)
        if entry <= 0:
            return

        is_short = ("SHORT" in direction)
        eps = max(1e-12, abs(entry) * 1e-9)

        def _is_bad_layout() -> bool:
            if is_short:
                return ((sl > 0 and sl <= entry + eps) or
                        (tp1 > 0 and tp1 >= entry - eps) or
                        (tp2 > 0 and tp2 >= entry - eps))
            return ((sl > 0 and sl >= entry - eps) or
                    (tp1 > 0 and tp1 <= entry + eps) or
                    (tp2 > 0 and tp2 <= entry + eps))

        if not _is_bad_layout():
            # Still enforce TP ordering if both targets exist.
            if tp1 > 0 and tp2 > 0:
                if is_short and tp2 > tp1:
                    sig.tp1, sig.tp2 = tp2, tp1
                elif (not is_short) and tp2 < tp1:
                    sig.tp1, sig.tp2 = tp2, tp1
            target = float(getattr(sig, "tp2", 0.0) or getattr(sig, "tp1", 0.0) or 0.0)
            risk = abs(entry - sl)
            keep_rr = False
            try:
                keep_rr = _mid_preserve_precomputed_rr() and float(getattr(sig, "rr", 0.0) or 0.0) > 0
            except Exception:
                keep_rr = False
            if (not keep_rr) and target > 0 and risk > eps:
                sig.rr = abs(target - entry) / risk
            return

        risk = abs(entry - sl) if sl > 0 else 0.0
        tp1_dist = abs(tp1 - entry) if tp1 > 0 else 0.0
        tp2_dist = abs(tp2 - entry) if tp2 > 0 else 0.0

        if risk <= eps:
            # fall back to any available target distance, otherwise leave as-is
            risk = tp1_dist or tp2_dist
        if risk <= eps:
            return

        if tp1_dist <= eps and tp2_dist > eps:
            tp1_dist = tp2_dist
        if tp2_dist <= eps and tp1_dist > eps:
            tp2_dist = tp1_dist
        if tp1_dist > eps and tp2_dist > eps:
            near_dist = min(tp1_dist, tp2_dist)
            far_dist = max(tp1_dist, tp2_dist)
        else:
            near_dist = tp1_dist or risk
            far_dist = tp2_dist or near_dist

        if is_short:
            sig.sl = entry + risk
            sig.tp1 = entry - near_dist if near_dist > eps else 0.0
            sig.tp2 = entry - far_dist if far_dist > eps else 0.0
        else:
            sig.sl = entry - risk
            sig.tp1 = entry + near_dist if near_dist > eps else 0.0
            sig.tp2 = entry + far_dist if far_dist > eps else 0.0

        target = float(getattr(sig, "tp2", 0.0) or getattr(sig, "tp1", 0.0) or 0.0)
        keep_rr = False
        try:
            keep_rr = _mid_preserve_precomputed_rr() and float(getattr(sig, "rr", 0.0) or 0.0) > 0
        except Exception:
            keep_rr = False
        if (not keep_rr) and target > 0 and risk > eps:
            sig.rr = abs(target - entry) / risk
    except Exception:
        return

@dataclass
class Signal:
    # NOTE: All fields have defaults to avoid dataclass ordering issues
    # (non-default argument follows default argument) if earlier fields
    # are given defaults in some deployments.
    signal_id: int = 0
    market: str = ""
    symbol: str = ""
    direction: str = ""
    timeframe: str = ""
    entry: float = 0.0
    sl: float = 0.0
    tp1: float = 0.0
    tp2: float = 0.0
    rr: float = 0.0
    confidence: int = 0
    confirmations: str = ""
    # Exchange metadata (used for display/routing)
    source_exchange: str = ""
    available_exchanges: str = ""
    risk_note: str = ""
    ts: float = 0.0
    setup_source: str = ""
    setup_source_label: str = ""
    ui_setup_label: str = ""
    smc_setup_label: str = ""
    emit_route: str = ""
    smc_setup_route: str = ""

    def __post_init__(self):
        try:
            src = _mid_setup_source_normalize(getattr(self, "setup_source", "") or getattr(self, "setup_source_label", ""))
        except Exception:
            src = ""
        try:
            self.setup_source = src
        except Exception:
            pass
        try:
            self.setup_source_label = _mid_setup_source_label(src) if src else ""
        except Exception:
            pass
        try:
            route = str(getattr(self, "smc_setup_route", "") or getattr(self, "emit_route", "") or "").strip()
        except Exception:
            route = ""
        try:
            smc_label = str(getattr(self, "smc_setup_label", "") or "").strip()
        except Exception:
            smc_label = ""
        try:
            ui_label = str(getattr(self, "ui_setup_label", "") or "").strip()
        except Exception:
            ui_label = ""
        try:
            if route and not getattr(self, "emit_route", ""):
                self.emit_route = route
        except Exception:
            pass
        try:
            if route and not getattr(self, "smc_setup_route", ""):
                self.smc_setup_route = route
        except Exception:
            pass
        try:
            if route and not smc_label:
                smc_label = _mid_smc_emit_route_label(route)
                self.smc_setup_label = smc_label
        except Exception:
            pass
        try:
            if not ui_label:
                ui_label = _mid_compose_setup_label(src, route, smc_label)
                if ui_label:
                    self.ui_setup_label = ui_label
        except Exception:
            pass
        _normalize_signal_levels_inplace(self)


def _mid_setup_source_normalize(source: str | None) -> str:
    """Canonical smart-setup categories used across live cards and report cards.

    Canonical values:
      - origin
      - breakout
      - zone_retest
      - normal_pending_trigger
      - liquidity_reclaim

    We also accept legacy Russian labels / loose variants so old rows and
    previously saved orig_text still normalize to the new canonical values.
    """
    try:
        s = str(source or "").strip().lower().replace('-', '_')
    except Exception:
        s = ""
    aliases = {
        "origin": "origin",
        "начало движения": "origin",
        "breakout": "breakout",
        "пробой": "breakout",
        "zone": "zone_retest",
        "zone_retest": "zone_retest",
        "zone retest": "zone_retest",
        "возврат в зону": "zone_retest",
        "zone_touch": "zone_retest",
        "zone touch": "zone_retest",
        "zone_touch_retest": "zone_retest",
        "zone-touch": "zone_retest",
        "normal_pending_trigger": "normal_pending_trigger",
        "normal pending trigger": "normal_pending_trigger",
        "обычный trigger": "normal_pending_trigger",
        "обычный триггер": "normal_pending_trigger",
        "обычный pending trigger": "normal_pending_trigger",
        "pending": "normal_pending_trigger",
        "pending_trigger": "normal_pending_trigger",
        "liquidity_reclaim": "liquidity_reclaim",
        "liquidity reclaim": "liquidity_reclaim",
        "liquidity_reclaim_emit": "liquidity_reclaim",
        "reclaim": "liquidity_reclaim",
        "liquidity sweep reclaim": "liquidity_reclaim",
        "возврат после снятия ликвидности": "liquidity_reclaim",
    }
    return aliases.get(s, s if s in {"origin", "breakout", "zone_retest", "normal_pending_trigger", "liquidity_reclaim"} else "")


def _mid_setup_source_label(source: str | None) -> str:
    """Human-facing Smart-setup label.

    User requested exact English labels in signal cards.
    Keep these title-cased so Telegram messages preserve the intended final label.
    """
    src = _mid_setup_source_normalize(source)
    labels = {
        "origin": "Origin",
        "breakout": "Breakout",
        "zone_retest": "Zone retest",
        "normal_pending_trigger": "Normal pending trigger",
        "liquidity_reclaim": "Liquidity reclaim",
    }
    return labels.get(src, "")


def _mid_resolve_signal_setup_label(ta: dict | None = None, sig: object | None = None) -> str:
    """Best-effort resolver for the final Smart-setup label shown in signal cards.

    Priority:
      1) explicit UI label stored on TA/signal
      2) explicit route + setup_source
      3) infer route from TA snapshot when only generic setup_source survived
      4) fall back to canonical setup_source label
    """
    t = ta if isinstance(ta, dict) else {}

    def _get_attr(name: str):
        try:
            return getattr(sig, name, "") if sig is not None else ""
        except Exception:
            return ""

    try:
        setup_source = str(t.get("setup_source") or t.get("smart_emit_source") or _get_attr("setup_source") or "").strip()
    except Exception:
        setup_source = ""
    try:
        ui_label = str(t.get("ui_setup_label") or _get_attr("ui_setup_label") or "").strip()
    except Exception:
        ui_label = ""
    if ui_label:
        return ui_label
    try:
        smc_label = str(t.get("smc_setup_label") or _get_attr("smc_setup_label") or "").strip()
    except Exception:
        smc_label = ""
    try:
        setup_route = str(
            t.get("smc_setup_route")
            or t.get("emit_route")
            or _get_attr("smc_setup_route")
            or _get_attr("emit_route")
            or ""
        ).strip()
    except Exception:
        setup_route = ""

    if setup_route:
        composed = _mid_compose_setup_label(setup_source, setup_route, smc_label)
        if composed:
            return composed
    if smc_label:
        composed = _mid_compose_setup_label(setup_source, "", smc_label)
        if composed:
            return composed
        return smc_label

    try:
        direction = str(t.get("direction") or t.get("dir") or "").upper().strip()
        source_norm = _mid_setup_source_normalize(setup_source or t.get("setup_source_label") or _get_attr("setup_source_label") or "")
        smc_snapshot = _mid_collect_smc_snapshot(
            direction=direction,
            ta=t,
            rec=t,
            bo_rt_label=(t.get("bo_rt") or t.get("breakout_retest") or ""),
        )
        inferred = _mid_pick_smc_emit_route(
            direction=direction,
            smc_snapshot=smc_snapshot,
            origin_fast_ok=bool(source_norm == "origin"),
            breakout_fast_ok=bool(source_norm == "breakout"),
            zone_valid=bool(source_norm in {"zone_retest", "liquidity_reclaim"} or t.get("ob_retest") or t.get("entry_low") is not None or t.get("entry_high") is not None),
            in_zone_now=bool(source_norm == "zone_retest"),
            liquidity_reclaim_ok=bool(source_norm == "liquidity_reclaim"),
        )
        inferred_label = str((inferred or {}).get("setup_label") or "").strip()
        if inferred_label:
            return inferred_label
    except Exception:
        pass

    fallback = _mid_setup_source_label(setup_source or t.get("setup_source_label") or _get_attr("setup_source_label") or "")
    return str(fallback or "").strip()


def _mid_apply_signal_setup_source(sig: Signal | None, source: str | None) -> str:
    src = _mid_setup_source_normalize(source)
    if sig is None or not src:
        return src
    try:
        sig.setup_source = src
    except Exception:
        pass
    try:
        sig.setup_source_label = _mid_setup_source_label(src)
    except Exception:
        pass
    return src


def _mid_embed_setup_source_in_orig_text(orig_text: str | None, sig: Signal | None = None) -> str:
    """Persist Smart-setup source in stored orig_text for future report cards.

    This enriches the DB payload only. It does not change the live Telegram message that
    was already shown to the opener. The report bot later parses this line from orig_text
    when setup_source/setup_source_label are not available in the track row.
    """
    try:
        text = str(orig_text or "")
    except Exception:
        text = ""
    try:
        if re.search(r"(?:^|\n)\s*(?:🧭\s*)?Smart-setup:\s*[^\n\r]+", text, flags=re.IGNORECASE):
            return text
    except Exception:
        pass
    label = ""
    try:
        if sig is not None:
            label = str(getattr(sig, "ui_setup_label", "") or "").strip()
            if not label:
                emit_route = str(getattr(sig, "emit_route", "") or "").strip()
                if emit_route in {"liquidity_reclaim_emit", "smc_liquidity_reclaim"}:
                    label = _mid_compose_setup_label("liquidity_reclaim", "smc_liquidity_reclaim")
            if not label:
                label = str(getattr(sig, "setup_source_label", "") or "").strip()
            if not label:
                raw = _mid_setup_source_normalize(getattr(sig, "setup_source", "") or "")
                label = _mid_setup_source_label(raw)
    except Exception:
        label = ""
    if not label:
        return text
    line = f"🧭 Smart-setup: {label}"
    if not text.strip():
        return line
    try:
        marker = "Нажми кнопку ниже после того, как открыл сделку:"
        idx = text.find(marker)
        if idx >= 0:
            head = text[:idx].rstrip()
            tail = text[idx:].lstrip("\n")
            return f"{head}\n{line}\n\n{tail}".strip()
    except Exception:
        pass
    return f"{text.rstrip()}\n{line}".strip()

def _mid_pick_scan_setup_source(*, origin_fast_ok: bool = False, breakout_fast_ok: bool = False, zone_valid: bool = False, in_zone_now: bool = False, smc_snapshot: dict | None = None) -> str:
    """Return canonical setup_source while SMC details are preserved separately."""
    info = _mid_pick_smc_emit_route(
        direction='',
        smc_snapshot=smc_snapshot,
        origin_fast_ok=origin_fast_ok,
        breakout_fast_ok=breakout_fast_ok,
        zone_valid=zone_valid,
        in_zone_now=in_zone_now,
        liquidity_reclaim_ok=False,
    )
    return str(info.get('setup_source') or '')


def _mid_liquidity_reclaim_ready(ta: dict, rec: dict | None = None, *, now_ts: float | None = None) -> tuple[bool, str, dict]:
    """Best-effort readiness check for standalone liquidity_reclaim_emit sidecar route.

    IMPORTANT:
    - This route is opportunistic only.
    - It MUST NOT mutate pending state or reject counters when not ready.
    - It MUST NOT change canonical setup_source labels.
    """
    t = ta if isinstance(ta, dict) else {}
    r = rec if isinstance(rec, dict) else {}
    meta: dict[str, object] = {}
    try:
        direction = str(t.get("direction") or r.get("direction") or "").upper().strip()
        if direction not in ("LONG", "SHORT"):
            return (False, "direction_missing", meta)

        try:
            entry_low = float(r.get("entry_low")) if r.get("entry_low") is not None else None
        except Exception:
            entry_low = None
        try:
            entry_high = float(r.get("entry_high")) if r.get("entry_high") is not None else None
        except Exception:
            entry_high = None
        zone_valid = bool(entry_low is not None and entry_high is not None and entry_high >= entry_low and entry_low > 0)
        meta["zone_valid"] = bool(zone_valid)
        if not zone_valid:
            return (False, "zone_missing", meta)

        sweep_ok = bool(t.get("sweep_long")) if direction == "LONG" else bool(t.get("sweep_short"))
        meta["sweep_ok"] = bool(sweep_ok)
        if not sweep_ok:
            return (False, "sweep_missing", meta)

        try:
            close5 = float(t.get("close") or t.get("c") or t.get("entry") or r.get("entry") or 0.0)
        except Exception:
            close5 = float(r.get("entry") or 0.0)
        try:
            reclaim_eps = float(os.getenv("MID_LIQ_RECLAIM_RECLAIM_EPS_PCT", os.getenv("MID_INST_RECLAIM_EPS_PCT", "0.0006")) or 0.0006)
        except Exception:
            reclaim_eps = 0.0006
        if direction == "LONG":
            reclaim_ok = bool(close5 >= float(entry_high) * (1.0 + reclaim_eps))
        else:
            reclaim_ok = bool(close5 <= float(entry_low) * (1.0 - reclaim_eps))
        meta["reclaim_ok"] = bool(reclaim_ok)
        if not reclaim_ok:
            return (False, "reclaim_missing", meta)

        bos_ok = bool(t.get("bos_up_5m")) if direction == "LONG" else bool(t.get("bos_down_5m"))
        try:
            disp_x = float(t.get("disp_body_atr") or 0.0)
        except Exception:
            disp_x = 0.0
        try:
            disp_min = float(os.getenv("MID_LIQ_RECLAIM_DISP_MIN", os.getenv("MID_INST_DISP_MIN", "0.25")) or 0.25)
        except Exception:
            disp_min = 0.25
        disp_ok = bool(disp_x >= disp_min)
        meta["bos_ok"] = bool(bos_ok)
        meta["disp_ok"] = bool(disp_ok)
        meta["disp_x"] = float(disp_x)
        if not (bos_ok or disp_ok):
            return (False, "bos_or_displacement_missing", meta)

        dir_contra = str(_mid_directional_contradiction_reason(t, r) or "").strip()
        if dir_contra:
            meta["directional_contradiction"] = dir_contra
            return (False, "directional_contradiction", meta)

        trap_reason = ""
        try:
            trap_ok = bool(t.get("trap_ok", True))
            if not trap_ok:
                trap_reason = str(t.get("trap_reason") or "trap_block")
        except Exception:
            trap_ok = True
        meta["trap_ok"] = bool(trap_ok)
        if not trap_ok:
            meta["trap_reason"] = trap_reason
            return (False, trap_reason or "trap_block", meta)

        try:
            price_now = float(t.get("entry") or t.get("close") or r.get("entry") or 0.0)
        except Exception:
            price_now = float(r.get("entry") or 0.0)
        try:
            entry_ref, anchor_too_far, anchor_slip_atr = _mid_pending_entry_ref(r, price=price_now, ta=t)
        except Exception:
            entry_ref, anchor_too_far, anchor_slip_atr = (0.0, False, 0.0)
        meta["entry_ref"] = float(entry_ref or 0.0)
        meta["anchor_slip_atr"] = float(anchor_slip_atr or 0.0)
        if anchor_too_far:
            return (False, "anchor_too_far", meta)

        return (True, "ok", meta)
    except Exception as e:
        try:
            meta["error"] = f"{type(e).__name__}:{e}"
        except Exception:
            pass
        return (False, "error", meta)


def _mid_pick_pending_setup_source(it: dict | None = None, *, zone_touch: bool = False, zone_first: bool = False, in_zone_now: bool = False) -> str:
    """Pick the display category for a pending-trigger entry.

    Rules requested by user:
      - origin — only when entry is taken from the very start of the move
      - breakout — only when entry is taken on the breakout itself
      - zone retest — only when there was an explicit real return / retest of the zone
      - normal pending trigger — for a regular pending trigger without an explicit retest

    Therefore, a revalidated trigger or an in-zone confirmation by itself is NOT a
    reason to rewrite the setup into ``zone_retest``.
    """
    rec = it if isinstance(it, dict) else {}

    # A real zone retest must be explicit in the trigger route. Do not infer it
    # just because price happened to be inside the saved zone when the pending fired.
    if bool(zone_touch) or bool(zone_first) or bool(rec.get("_trig_zone_first")):
        return "zone_retest"

    return "normal_pending_trigger"

@dataclass

class UserTrade:
    user_id: int
    signal: Signal
    tp1_hit: bool = False
    sl_moved_to_be: bool = False
    be_price: float = 0.0
    active: bool = True
    result: str = "ACTIVE"  # ACTIVE / TP1 / WIN / LOSS / BE / CLOSED
    last_price: float = 0.0
    opened_ts: float = 0.0


# ------------------ Trade performance stats (spot/futures) ------------------
TRADE_STATS_FILE = Path("trade_stats.json")

# structure:
# {
#   "spot": {"days": {"YYYY-MM-DD": {...}}, "weeks": {"YYYY-WNN": {...}}},
#   "futures": {...}
# }
def _empty_bucket() -> Dict[str, float]:
    return {
        "trades": 0,
        "wins": 0,
        "losses": 0,
        "be": 0,
        "tp1_hits": 0,
        "sum_pnl_pct": 0.0,
    }

def _safe_pct(x: float) -> float:
    if not math.isfinite(x):
        return 0.0
    return float(x)

def _market_key(market: str) -> str:
    m = (market or "FUTURES").strip().upper()
    return "spot" if m == "SPOT" else "futures"


def _tp1_partial_close_pct(market: str) -> float:
    mk = _market_key(market)
    return float(TP1_PARTIAL_CLOSE_PCT_SPOT if mk == "spot" else TP1_PARTIAL_CLOSE_PCT_FUTURES)


# Backward-compat alias (older code referenced _partial_close_pct)
def _partial_close_pct(market: str) -> float:
    return _tp1_partial_close_pct(market)


# Backward-compat alias (older code referenced _be_enabled)
def _be_enabled(market: str) -> bool:
    return _be_after_tp1(market)


def _be_after_tp1(market: str) -> bool:
    mk = _market_key(market)
    return bool(BE_AFTER_TP1_SPOT if mk == "spot" else BE_AFTER_TP1_FUTURES)

def _fee_rate(market: str) -> float:
    mk = _market_key(market)
    return float(FEE_RATE_SPOT if mk == "spot" else FEE_RATE_FUTURES)

def _be_exit_price(entry: float, side: str, market: str) -> float:
    """Return modeled BE exit price that covers fees on remaining position."""
    entry = float(entry)
    if not BE_FEE_BUFFER:
        return entry
    fr = max(0.0, _fee_rate(market))
    buf = max(0.0, float(FEE_BUFFER_MULTIPLIER)) * fr
    side = (side or "LONG").upper()
    # IMPORTANT:
    # BE after TP1 is used as a *protective stop* on the remaining position.
    # Therefore the BE level must be on the "risk" side of the current price:
    #   - LONG: stop triggers when price falls back -> BE below entry
    #   - SHORT: stop triggers when price rises back -> BE above entry
    # Otherwise (e.g., SHORT with BE below entry) the condition (price >= BE)
    # would be true immediately and the trade would auto-close right after TP1.
    if side == "SHORT":
        return entry * (1.0 + buf)
    return entry * (1.0 - buf)


def _day_key_tz(ts: float) -> str:
    d = dt.datetime.fromtimestamp(ts, tz=ZoneInfo(TZ_NAME)).date()
    return d.isoformat()

def _week_key_tz(ts: float) -> str:
    d = dt.datetime.fromtimestamp(ts, tz=ZoneInfo(TZ_NAME)).date()
    y, w, _ = d.isocalendar()
    return f"{y}-W{int(w):02d}"

def _calc_effective_pnl_pct(trade: "UserTrade", close_price: float, close_reason: str) -> float:
    s = trade.signal
    entry = float(s.entry or 0.0)
    if entry <= 0:
        return 0.0

    side = (s.direction or "LONG").upper()
    def pnl_pct_for(price: float) -> float:
        price = float(price)
        if side == "SHORT":
            return (entry - price) / entry * 100.0
        return (price - entry) / entry * 100.0

    # No TP1 hit => full position closes at close_price
    if not trade.tp1_hit:
        return _safe_pct(pnl_pct_for(close_price))

    # TP1 hit => partial close at TP1, rest closes at BE or TP2 (or manual)
    p = max(0.0, min(100.0, float(_tp1_partial_close_pct(s.market))))
    a = p / 100.0
    tp1_price = float(s.tp1 or close_price)

    pnl_tp1 = pnl_pct_for(tp1_price) * a

    # Remaining portion:
    if close_reason == "WIN":
        # rest closes at TP2 (if provided), else close_price
        tp2_price = float(s.tp2 or close_price)
        pnl_rest = pnl_pct_for(tp2_price) * (1.0 - a)
    elif close_reason == "BE":
        pnl_rest = 0.0
    else:
        # manual close / unknown: use close_price for remaining
        pnl_rest = pnl_pct_for(close_price) * (1.0 - a)

    return _safe_pct(pnl_tp1 + pnl_rest)

def _calc_rr_str(entry: float, sl: float, tp1: float, tp2: float) -> str:
    """Return Risk/Reward as 'X.XX' where reward uses TP2 if present else TP1."""
    try:
        entry = float(entry or 0.0)
        sl = float(sl or 0.0)
        tp1 = float(tp1 or 0.0)
        tp2 = float(tp2 or 0.0)
        if entry <= 0 or sl <= 0:
            return "-"
        risk = abs(entry - sl)
        if risk <= 0:
            return "-"
        target = tp2 if tp2 > 0 else tp1
        if target <= 0:
            return "-"
        reward = abs(target - entry)
        rr = reward / risk if risk > 0 else 0.0
        if rr <= 0:
            return "-"
        return f"{rr:.2f}"
    except Exception:
        return "-"


# ------------------ Human-friendly close reasons (i18n) ------------------

def _human_close_reason(uid: int, code: str | None, **kv: Any) -> str:
    """Return a short, user-friendly reason string using i18n.

    `code` is a stable internal identifier (e.g. 'TP2_REACHED').
    We map codes to i18n keys, and keep optional numeric details in `kv`.
    """
    if not code:
        return ""
    c = str(code).upper().strip()

    # Full close at TP1 is a WIN, not a partial-TP1/TP2 event.
    if c in ("TP1_REACHED", "FULL_TP1", "FULL_TP1_NO_TP2"):
        return "Цена дошла до TP1 — фиксируем прибыль."

    # Map internal codes to i18n keys (keep keys stable)
    key_map = {
        "TP2_REACHED": "reason_tp2_reached",
        "TP2": "reason_tp2_reached",
        "SL_REACHED": "reason_sl_reached",
        "SL": "reason_sl_reached",
        "SL_AFTER_TP1": "reason_sl_after_tp1",
        "TP1_PARTIAL": "reason_tp1_partial",
        "TP1_HOLD": "reason_tp1_hold_to_tp2",
        "SMART_BE": "reason_smart_be",
        "SMART_HARD_SL": "reason_smart_hard_sl",
        "TRAIL_EXIT": "reason_trail_exit",
        "REVERSAL_EXIT": "reason_reversal_exit",
        "TP2_RUNNER": "reason_tp2_runner_exit",
        "FULL_TP1": "reason_tp2_reached",
        "FULL_TP1_NO_TP2": "reason_tp2_reached",
        "BE": "reason_smart_be",
        "EARLY_EXIT": "reason_early_exit_momentum",
        "WEAKNESS_EXIT": "reason_early_exit_momentum",
        "MANUAL_CLOSE": "reason_volume_dropped",
        "SYNC_CLOSE": "reason_volume_dropped",
        "EXECUTION_ERROR": "reason_structure_break",
        "EARLY_EXIT_MOM": "reason_early_exit_momentum",
        "STRUCTURE_BREAK": "reason_structure_break",
        "TRAP_DETECTED": "reason_trap_detected",
        "VOLUME_DROPPED": "reason_volume_dropped",
        "BOS_AGAINST": "reason_bos_against",
    }

    k = key_map.get(c)
    if not k:
        # fallback: show code as-is (still better than nothing)
        return str(code)
    try:
        return _trf(uid, k, **kv)
    except Exception:
        try:
            return _trf(uid, k)
        except Exception:
            return str(code)

def _lvl_line(label: str, value: float) -> str:
    try:
        v = float(value or 0.0)
        if v > 0:
            return f"{label}: {v:.6f}\n"
    except Exception:
        pass
    return ""


def _safe_json_obj(raw: Any) -> dict:
    try:
        if isinstance(raw, dict):
            return dict(raw)
        if raw is None:
            return {}
        return json.loads(str(raw) or "{}") or {}
    except Exception:
        return {}


AUTOTRADE_CLOSED_REASON_CANON = {
    "SL",
    "FULL_TP1",
    "FULL_TP1_NO_TP2",
    "TP2",
    "TP2_RUNNER",
    "BE",
    "REVERSAL_EXIT",
    "TRAIL_EXIT",
    "EARLY_EXIT",
    "WEAKNESS_EXIT",
    "MANUAL_CLOSE",
    "SYNC_CLOSE",
    "EXECUTION_ERROR",
}


def _normalize_autotrade_close_reason(reason: str | None) -> str:
    r = str(reason or "").upper().strip()
    if not r:
        return ""
    aliases = {
        "TP1_FULL": "FULL_TP1",
        "TP1_FULL_NO_TP2": "FULL_TP1_NO_TP2",
        "TP2_REACHED": "TP2",
        "USER_CLOSE": "MANUAL_CLOSE",
        "API_ERROR": "EXECUTION_ERROR",
        "EXEC_ERROR": "EXECUTION_ERROR",
        "ERROR": "EXECUTION_ERROR",
        "MANUAL_BE": "BE",
        "HARD_SL": "SL",
        "STRUCTURE_BREAK": "SL",
        "EARLY_EXIT_MOM": "EARLY_EXIT",
        "WEAKNESS_EXIT_PRE_TP1": "WEAKNESS_EXIT",
        "ERROR_UNSUPPORTED_SIDE": "EXECUTION_ERROR",
    }
    if r in aliases:
        return aliases[r]
    if r.startswith("ERROR"):
        return "EXECUTION_ERROR"
    return r if r in AUTOTRADE_CLOSED_REASON_CANON else r



def map_closed_reason_to_trade_result(reason: str | None, roi: float | None = None):
    """Single source of truth for autotrade close outcome mapping.

    Important business rule: SYNC_CLOSE is a technical sync close, not a semantic
    trade outcome. Do not reinterpret it from ROI into WIN/LOSS/BE here.
    """
    r = _normalize_autotrade_close_reason(reason)
    if not r:
        r = "SYNC_CLOSE"
    mapping = {
        "SL": {"trade_status": "LOSS", "trade_result": "LOSS", "card_reason": "SL", "close_price_source": "sl"},
        "FULL_TP1": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "FULL_TP1", "close_price_source": "tp1"},
        "FULL_TP1_NO_TP2": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "FULL_TP1_NO_TP2", "close_price_source": "tp1"},
        "TP2": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "TP2", "close_price_source": "tp2"},
        "TP2_RUNNER": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "TP2_RUNNER", "close_price_source": "market"},
        "BE": {"trade_status": "BE", "trade_result": "BE", "card_reason": "BE", "close_price_source": "be"},
        "REVERSAL_EXIT": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "REVERSAL_EXIT", "close_price_source": "market"},
        "TRAIL_EXIT": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "TRAIL_EXIT", "close_price_source": "market"},
        "EARLY_EXIT": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "EARLY_EXIT", "close_price_source": "market"},
        "WEAKNESS_EXIT": {"trade_status": "WIN", "trade_result": "WIN", "card_reason": "WEAKNESS_EXIT", "close_price_source": "market"},
        "MANUAL_CLOSE": {"trade_status": "CLOSED", "trade_result": "CLOSED", "card_reason": "MANUAL_CLOSE", "close_price_source": "market"},
        "SYNC_CLOSE": {"trade_status": "CLOSED", "trade_result": "CLOSED", "card_reason": "SYNC_CLOSE", "close_price_source": "market"},
        "EXECUTION_ERROR": {"trade_status": "CLOSED", "trade_result": "ERROR", "card_reason": "EXECUTION_ERROR", "close_price_source": "market"},
    }
    out = dict(mapping.get(r) or mapping["SYNC_CLOSE"])
    out["closed_reason"] = r
    return out



def _autotrade_reason_to_trade_status(reason: str, roi_percent: float | None = None, *, tp1_hit: bool = False) -> str:
    return str(map_closed_reason_to_trade_result(reason, roi_percent).get("trade_status") or "CLOSED")



def _bump_stats(store: dict, market: str, ts: float, close_reason: str, pnl_pct: float, tp1_hit: bool) -> None:
    mk = _market_key(market)
    dayk = _day_key_tz(ts)
    weekk = _week_key_tz(ts)

    mroot = store.setdefault(mk, {"days": {}, "weeks": {}})
    days = mroot.setdefault("days", {})
    weeks = mroot.setdefault("weeks", {})

    def get_bucket(root: dict, k: str) -> dict:
        b = root.get(k)
        if not isinstance(b, dict):
            b = _empty_bucket()
            root[k] = b
        # ensure keys
        for kk, vv in _empty_bucket().items():
            if kk not in b:
                b[kk] = vv
        return b

    bd = get_bucket(days, dayk)
    bw = get_bucket(weeks, weekk)

    def apply(bucket: dict) -> None:
        bucket["trades"] = int(bucket.get("trades", 0)) + 1
        # wins/losses based on pnl sign (если WIN но ушёл в минус — засчитываем как LOSS)
        if pnl_pct > 0:
            bucket["wins"] = int(bucket.get("wins", 0)) + 1
        elif pnl_pct < 0:
            bucket["losses"] = int(bucket.get("losses", 0)) + 1
        else:
            bucket["be"] = int(bucket.get("be", 0)) + 1

        if tp1_hit:
            bucket["tp1_hits"] = int(bucket.get("tp1_hits", 0)) + 1

        bucket["sum_pnl_pct"] = float(bucket.get("sum_pnl_pct", 0.0)) + float(pnl_pct)

    apply(bd)
    apply(bw)

@dataclass(frozen=True)

class MacroEvent:
    name: str
    type: str
    start_ts_utc: float

# ------------------ News risk filter (CryptoPanic) ------------------
class NewsFilter:
    # Use Developer v2 endpoint (matches API Reference in CryptoPanic Developers panel)
    BASE_URL = "https://cryptopanic.com/api/developer/v2/posts/"

    def __init__(self) -> None:
        self._last_block: tuple[str, float] | None = None
        self._cache: Dict[str, Tuple[float, str]] = {}
        self._cache_ttl = 60
        # prevent hanging network calls
        self._timeout = aiohttp.ClientTimeout(total=8)

    def enabled(self) -> bool:
        return NEWS_FILTER and bool(CRYPTOPANIC_TOKEN)

    def base_coin(self, symbol: str) -> str:
        # Accept formats: BTCUSDT, BTC/USDT, BTC-USDT, etc.
        s = str(symbol).upper().replace("/", "").replace("-", "").strip()
        for q in ("USDT", "USDC", "BUSD", "USD", "FDUSD", "TUSD", "DAI", "EUR", "BTC", "ETH"):
            if s.endswith(q) and len(s) > len(q):
                return s[:-len(q)]
        return s

    async def action_for_symbol(self, session: aiohttp.ClientSession, symbol: str) -> str:
        if not self.enabled():
            return "ALLOW"

        coin = self.base_coin(symbol)
        key = f"{coin}:{NEWS_ACTION}:{NEWS_LOOKBACK_MIN}"
        now = time.time()
        cached = self._cache.get(key)
        if cached and (now - cached[0]) < self._cache_ttl:
            return cached[1]

        action = "ALLOW"
        try:
            params = {
                "auth_token": CRYPTOPANIC_TOKEN,
                "currencies": coin,
                "filter": "important",
                # reduce noise; can be overridden via env if desired
                "kind": CRYPTOPANIC_KIND,
                "regions": CRYPTOPANIC_REGIONS,
            }
            if CRYPTOPANIC_PUBLIC:
                params["public"] = "true"

            async with session.get(self.BASE_URL, params=params, timeout=self._timeout) as r:
                if r.status != 200:
                    action = "ALLOW"
                else:
                    data = await r.json()
                    posts = (data or {}).get("results", []) or []
                    cutoff = now - (NEWS_LOOKBACK_MIN * 60)
                    recent = False
                    recent_post = None
                    for p in posts[:20]:
                        published_at = p.get("published_at") or p.get("created_at")
                        if not published_at:
                            continue
                        try:
                            ts = pd.to_datetime(published_at.replace("Z", "+00:00")).timestamp()
                        except Exception:
                            continue
                        if ts >= cutoff:
                            recent = True
                            recent_post = p
                            break
                    if recent:
                        action = NEWS_ACTION if NEWS_ACTION in ("FUTURES_OFF", "PAUSE_ALL") else "FUTURES_OFF"
                        # remember last block for status (reason, until_ts)
                        reason = coin
                        try:
                            if recent_post:
                                title = (recent_post.get("title") or recent_post.get("slug") or "").strip()
                                src = None
                                if isinstance(recent_post.get("source"), dict):
                                    src = (recent_post["source"].get("title") or recent_post["source"].get("name"))
                                if not src:
                                    src = (recent_post.get("domain") or recent_post.get("source") or "")
                                src = (src or "").strip()
                                # CryptoPanic 'important' filter is used; keep it in text for clarity
                                parts = []
                                if src:
                                    parts.append(src)
                                parts.append("Important")
                                if title:
                                    parts.append(title)
                                reason = "CryptoPanic — " + " / ".join(parts)
                        except Exception:
                            pass
                        self._last_block = (reason, now + NEWS_LOOKBACK_MIN * 60)
        except Exception:
            action = "ALLOW"

        self._cache[key] = (now, action)
        return action

# ------------------ Macro calendar (AUTO fetch) ------------------

    def last_block_info(self) -> tuple[str, float] | None:
        """Return (reason, until_ts) for the last time news filter triggered."""
        return self._last_block

class MacroCalendar:
    BLS_URL = "https://www.bls.gov/schedule/news_release/current_year.asp"
    FOMC_URL = "https://www.federalreserve.gov/monetarypolicy/fomccalendars.htm"

    def __init__(self) -> None:
        self._events: List[MacroEvent] = []
        self._last_fetch_ts: float = 0.0
        self._fetch_ttl: float = 6 * 60 * 60
        self._notified: Dict[str, float] = {}
        self._notify_cooldown = 6 * 60 * 60

    def enabled(self) -> bool:
        return MACRO_FILTER

    async def ensure_loaded(self, session: aiohttp.ClientSession) -> None:
        if not self.enabled():
            self._events = []
            return
        now = time.time()
        if self._events and (now - self._last_fetch_ts) < self._fetch_ttl:
            return
        await self.fetch(session)

    async def fetch(self, session: aiohttp.ClientSession) -> None:
        events: List[MacroEvent] = []

        # BLS schedule
        try:
            async with session.get(self.BLS_URL) as r:
                r.raise_for_status()
                html = await r.text()

            tables = pd.read_html(html)
            for t in tables:
                cols = [c.strip().lower() for c in t.columns.astype(str).tolist()]
                if not ("release" in cols and "date" in cols):
                    continue
                t2 = t.copy()
                t2.columns = cols
                for _, row in t2.iterrows():
                    release = str(row.get("release", "")).strip()
                    date_str = str(row.get("date", "")).strip()
                    time_str = str(row.get("time", "")).strip()
                    if not release or not date_str or not time_str:
                        continue

                    rel_l = release.lower()
                    if "consumer price index" in rel_l:
                        name = "CPI (US Inflation)"
                        etype = "CPI"
                    elif "employment situation" in rel_l:
                        name = "NFP (US Jobs)"
                        etype = "NFP"
                    else:
                        continue

                    try:
                        dt_et = pd.to_datetime(f"{date_str} {time_str}")
                    except Exception:
                        continue
                    dt_et = dt_et.tz_localize(ZoneInfo("America/New_York"), ambiguous="NaT", nonexistent="shift_forward")
                    dt_utc = dt_et.tz_convert(ZoneInfo("UTC")).timestamp()
                    events.append(MacroEvent(name=name, type=etype, start_ts_utc=float(dt_utc)))
                break
        except Exception:
            pass

        # FOMC calendar (best-effort parse)
        try:
            async with session.get(self.FOMC_URL) as r:
                r.raise_for_status()
                txt = await r.text()

            year = pd.Timestamp.utcnow().year
            months = ["January","February","March","April","May","June","July","August","September","October","November","December"]
            for m in months:
                pattern = rf"{m}\\s*\\n\\s*(\\d{{1,2}})\\s*[-–]\\s*(\\d{{1,2}})"
                m1 = re.search(pattern, txt, flags=re.IGNORECASE)
                if not m1:
                    continue
                d2 = int(m1.group(2))
                try:
                    dt_et = pd.Timestamp(year=year, month=months.index(m)+1, day=d2, hour=FOMC_DECISION_HOUR_ET, minute=FOMC_DECISION_MINUTE_ET, tz="America/New_York")
                except Exception:
                    continue
                events.append(MacroEvent(name="FOMC Rate Decision", type="FED", start_ts_utc=float(dt_et.tz_convert("UTC").timestamp())))
        except Exception:
            pass

        now = time.time()
        filtered = [e for e in events if (now - 2*24*3600) <= e.start_ts_utc <= (now + 370*24*3600)]
        filtered.sort(key=lambda e: e.start_ts_utc)
        self._events = filtered
        self._last_fetch_ts = time.time()

    def blackout_window(self, ev: MacroEvent) -> Tuple[float, float]:
        start = ev.start_ts_utc - (BLACKOUT_BEFORE_MIN * 60)
        end = ev.start_ts_utc + (BLACKOUT_AFTER_MIN * 60)
        return start, end

    def current_action(self) -> Tuple[str, Optional[MacroEvent], Optional[Tuple[float, float]]]:
        if not self.enabled():
            return "ALLOW", None, None
        now = time.time()
        for ev in self._events:
            w0, w1 = self.blackout_window(ev)
            if w0 <= now <= w1:
                act = MACRO_ACTION if MACRO_ACTION in ("FUTURES_OFF", "PAUSE_ALL") else "FUTURES_OFF"
                return act, ev, (w0, w1)
        return "ALLOW", None, None

    def status(self) -> tuple[str, MacroEvent | None, tuple[float, float] | None]:
        """Return (action, event, (w0,w1)) for current moment."""
        return self.current_action()

    def next_event(self) -> Optional[Tuple[MacroEvent, Tuple[float, float]]]:
        if not self.enabled():
            return None
        now = time.time()
        for ev in self._events:
            w0, w1 = self.blackout_window(ev)
            if now < w0:
                return ev, (w0, w1)
        return None

    def should_notify(self, ev: MacroEvent) -> bool:
        key = f"{ev.type}:{ev.start_ts_utc}"
        now = time.time()
        last = self._notified.get(key, 0.0)
        if (now - last) >= self._notify_cooldown:
            self._notified[key] = now
            return True
        return False

# ------------------ Price feed (WS, Binance) ------------------
class PriceFeed:
    """Lightweight WS price feed with per-exchange streams.

    Stores latest trade price and timestamp for (exchange, market, symbol).
    Backwards compatible: if exchange is omitted, defaults to BINANCE.
    """

    def __init__(self) -> None:
        self._prices: Dict[Tuple[str, str, str], float] = {}
        self._sources: Dict[Tuple[str, str, str], str] = {}
        self._ts: Dict[Tuple[str, str, str], float] = {}
        self._tasks: Dict[Tuple[str, str, str], asyncio.Task] = {}

    def _key(self, ex: str, market: str, symbol: str) -> Tuple[str, str, str]:
        return (str(ex or "binance").lower().strip(), market.upper(), symbol.upper())

    def get_latest(self, market: str, symbol: str, *, max_age_sec: float | None = None, ex: str = "binance") -> Optional[float]:
        key = self._key(ex, market, symbol)
        p = self._prices.get(key)
        if p is None:
            return None
        if max_age_sec is not None:
            ts = self._ts.get(key)
            if ts is None or (time.time() - ts) > float(max_age_sec):
                return None
        return float(p)

    def get_latest_source(self, market: str, symbol: str, *, ex: str = "binance") -> Optional[str]:
        return self._sources.get(self._key(ex, market, symbol))

    def _set_latest(self, market: str, symbol: str, price: float, *, source: str = "WS", ex: str = "binance") -> None:
        key = self._key(ex, market, symbol)
        self._prices[key] = float(price)
        self._sources[key] = str(source or "WS")
        self._ts[key] = time.time()

    async def ensure_stream(self, market: str, symbol: str, ex: str = "binance") -> None:
        key = self._key(ex, market, symbol)
        t = self._tasks.get(key)
        if t and not t.done():
            return
        self._tasks[key] = asyncio.create_task(self._run_stream(ex, market, symbol))

    # ---- WS helpers ----
    def _okx_inst(self, market: str, symbol: str) -> str:
        sym = (symbol or "").upper()
        # BTCUSDT -> BTC-USDT
        if sym.endswith("USDT"):
            base, quote = sym[:-4], "USDT"
        elif sym.endswith("USDC"):
            base, quote = sym[:-4], "USDC"
        else:
            # naive split: last 3/4 as quote. fallback: raw
            base, quote = sym[:-3], sym[-3:]
            if len(sym) >= 4 and sym[-4:] in ("USDT", "USDC"):
                base, quote = sym[:-4], sym[-4:]
        inst = f"{base}-{quote}"
        m = (market or "FUTURES").upper()
        if m != "SPOT":
            # OKX perpetual swap for USDT/USDC pairs is commonly *-SWAP
            inst = inst + "-SWAP"
        return inst

    async def _run_stream(self, ex: str, market: str, symbol: str) -> None:
        ex0 = str(ex or "binance").lower().strip()
        m = (market or "FUTURES").upper()
        sym_u = (symbol or "").upper()
        sym_l = sym_u.lower()

        backoff = 1
        while True:
            try:
                if ex0 == "binance":
                    url = f"wss://stream.binance.com:9443/ws/{sym_l}@trade" if m == "SPOT" else f"wss://fstream.binance.com/ws/{sym_l}@trade"
                    async with websockets.connect(url, ping_interval=20, ping_timeout=20) as ws:
                        backoff = 1
                        async for msg in ws:
                            data = json.loads(msg)
                            p = data.get("p")
                            if p is not None:
                                self._set_latest(m, sym_u, float(p), source="WS", ex="binance")

                elif ex0 == "bybit":
                    # Bybit v5 public streams. linear for futures, spot for spot.
                    url = "wss://stream.bybit.com/v5/public/spot" if m == "SPOT" else "wss://stream.bybit.com/v5/public/linear"
                    sub = {"op": "subscribe", "args": [f"publicTrade.{sym_u}"]}
                    async with websockets.connect(url, ping_interval=20, ping_timeout=20) as ws:
                        await ws.send(json.dumps(sub))
                        backoff = 1
                        async for msg in ws:
                            data = json.loads(msg)
                            # v5: {"topic":"publicTrade.BTCUSDT","data":[{"p":"..."}]}
                            arr = data.get("data")
                            if isinstance(arr, list) and arr:
                                p = arr[0].get("p") or arr[0].get("price")
                                if p is not None:
                                    self._set_latest(m, sym_u, float(p), source="WS", ex="bybit")

                elif ex0 == "okx":
                    url = "wss://ws.okx.com:8443/ws/v5/public"
                    inst = self._okx_inst(m, sym_u)
                    sub = {"op": "subscribe", "args": [{"channel": "trades", "instId": inst}]}
                    async with websockets.connect(url, ping_interval=20, ping_timeout=20) as ws:
                        await ws.send(json.dumps(sub))
                        backoff = 1
                        async for msg in ws:
                            data = json.loads(msg)
                            # {"arg":{"channel":"trades"...},"data":[{"px":"..."}]}
                            arr = data.get("data")
                            if isinstance(arr, list) and arr:
                                p = arr[0].get("px") or arr[0].get("price")
                                if p is not None:
                                    self._set_latest(m, sym_u, float(p), source="WS", ex="okx")

                elif ex0 == "gateio":
                    # Gate.io WS v4. Spot-only used in this project.
                    if m != "SPOT":
                        raise Exception("gateio ws only spot")
                    url = "wss://api.gateio.ws/ws/v4/"
                    sub = {"time": int(time.time()), "channel": "spot.trades", "event": "subscribe", "payload": [sym_u]}
                    async with websockets.connect(url, ping_interval=20, ping_timeout=20) as ws:
                        await ws.send(json.dumps(sub))
                        backoff = 1
                        async for msg in ws:
                            data = json.loads(msg)
                            res = data.get("result")
                            if isinstance(res, dict):
                                p = res.get("price")
                                if p is not None:
                                    self._set_latest(m, sym_u, float(p), source="WS", ex="gateio")
                            elif isinstance(res, list) and res:
                                # sometimes result is list of trades
                                p = res[0].get("price") if isinstance(res[0], dict) else None
                                if p is not None:
                                    self._set_latest(m, sym_u, float(p), source="WS", ex="gateio")

                elif ex0 == "mexc":
                    # MEXC public WS (spot). Futures not used here.
                    if m != "SPOT":
                        raise Exception("mexc ws only spot")
                    url = "wss://wbs.mexc.com/ws"
                    # channel: "spot@public.deals.v3.api@{symbol}"
                    sub = {"method": "SUBSCRIPTION", "params": [f"spot@public.deals.v3.api@{sym_u}"]}
                    async with websockets.connect(url, ping_interval=20, ping_timeout=20) as ws:
                        await ws.send(json.dumps(sub))
                        backoff = 1
                        async for msg in ws:
                            data = json.loads(msg)
                            d = data.get("data") or {}
                            deals = d.get("deals") if isinstance(d, dict) else None
                            if isinstance(deals, list) and deals:
                                p = deals[0].get("p") or deals[0].get("price")
                                if p is not None:
                                    self._set_latest(m, sym_u, float(p), source="WS", ex="mexc")
                else:
                    raise Exception(f"unknown exchange ws: {ex0}")

            except Exception:
                await asyncio.sleep(backoff)
                backoff = min(backoff * 2, 30)

    def mock_price(self, market: str, symbol: str, base: float | None = None) -> float:
        key = ("mock", market.upper(), symbol.upper())
        seed = (float(base) if base is not None and base > 0 else None)
        price = self._prices.get(key, seed if seed is not None else random.uniform(100, 50000))
        price *= random.uniform(0.996, 1.004)
        self._prices[key] = price
        self._sources[key] = "MOCK"
        return price

# ------------------ Price caching + REST limiting ------------------
class _RestLimiter:
    """Very lightweight per-exchange limiter to avoid REST storms/429.

    It enforces:
      - max concurrent in-flight REST requests per exchange
      - a minimum delay between request starts per exchange
    """

    def __init__(self) -> None:
        self._sem: dict[str, asyncio.Semaphore] = {}
        self._lock: dict[str, asyncio.Lock] = {}
        self._next_ts: dict[str, float] = {}

    def _cfg(self, ex: str) -> tuple[int, float]:
        exu = (ex or "").upper()
        mc = int(os.getenv(f"REST_MAX_CONCURRENT_{exu}", os.getenv("REST_MAX_CONCURRENT", "3")) or 3)
        if mc < 1:
            mc = 1
        if mc > 50:
            mc = 50
        mi_ms = float(os.getenv(f"REST_MIN_INTERVAL_MS_{exu}", os.getenv("REST_MIN_INTERVAL_MS", "150")) or 150.0)
        if mi_ms < 0:
            mi_ms = 0.0
        if mi_ms > 5000:
            mi_ms = 5000.0
        return mc, mi_ms / 1000.0

    async def run(self, ex: str, fn):
        exn = (ex or "").lower().strip() or "generic"
        mc, min_interval = self._cfg(exn)
        sem = self._sem.get(exn)
        if sem is None or sem._value + len(getattr(sem, "_waiters", []) or []) != mc:
            sem = asyncio.Semaphore(mc)
            self._sem[exn] = sem
        lk = self._lock.setdefault(exn, asyncio.Lock())
        async with sem:
            if min_interval > 0:
                async with lk:
                    now = time.time()
                    nxt = float(self._next_ts.get(exn, 0.0) or 0.0)
                    if nxt > now:
                        await asyncio.sleep(nxt - now)
                    self._next_ts[exn] = time.time() + min_interval
            return await fn()


class _AsyncPriceCache:
    """Cache for (exchange, market, symbol) -> (price, source, ts) with anti-storm in-flight dedupe."""

    def __init__(self, ttl_sec: float = 2.0) -> None:
        self.ttl_sec = float(ttl_sec)
        self._data: dict[tuple[str, str, str], tuple[float, str, float]] = {}
        # Negative cache for transient "no price" situations (timeouts/429/symbol not found).
        # Keeps the bot from hammering the same key and prevents noisy asyncio warnings.
        self._neg: dict[tuple[str, str, str], tuple[str, float]] = {}
        self._neg_ttl_sec = max(0.5, min(5.0, self.ttl_sec))
        self._inflight: dict[tuple[str, str, str], asyncio.Future] = {}
        self._mu = asyncio.Lock()

    def get(self, ex: str, market: str, symbol: str) -> tuple[float | None, str] | None:
        key = (ex.lower(), market.upper(), symbol.upper())
        # Negative cache hit
        nv = self._neg.get(key)
        if nv:
            nsrc, nts = nv
            if (time.time() - float(nts)) <= self._neg_ttl_sec:
                # caller expects (price, src); price=None indicates "not available"
                return None, str(nsrc)
            else:
                self._neg.pop(key, None)
        v = self._data.get(key)
        if not v:
            return None
        p, src, ts = v
        if (time.time() - float(ts)) <= self.ttl_sec:
            return float(p), str(src)
        return None

    async def get_or_fetch(self, ex: str, market: str, symbol: str, fetch_coro):
        key = (ex.lower(), market.upper(), symbol.upper())
        # Fast path: cache hit
        v = self.get(ex, market, symbol)
        if v is not None:
            return v

        async with self._mu:
            # Re-check under lock
            v = self.get(ex, market, symbol)
            if v is not None:
                return v
            fut = self._inflight.get(key)
            if fut is None or fut.done():
                fut = asyncio.get_running_loop().create_future()
                # If some caller launches work and later drops it (create_task / cancellation),
                # asyncio may warn "Future exception was never retrieved". Ensure we always
                # mark exceptions as retrieved.
                def _consume_future_exception(_f: asyncio.Future):
                    try:
                        _ = _f.exception()
                    except asyncio.CancelledError:
                        # Cancelled futures raise CancelledError on .exception(); ignore.
                        pass
                    except Exception:
                        pass


                fut.add_done_callback(_consume_future_exception)
                self._inflight[key] = fut
                owner = True
            else:
                owner = False

        if not owner:
            return await fut

        try:
            p, src = await fetch_coro()
            async with self._mu:
                now = time.time()
                if p is None:
                    # Negative cache instead of raising: this is a normal transient state.
                    self._neg[key] = (str(src), now)
                    if not fut.done():
                        fut.set_result((None, str(src)))
                    self._inflight.pop(key, None)
                    return None, str(src)

                self._data[key] = (float(p), str(src), now)
                # Clear negative cache on success
                self._neg.pop(key, None)
                if not fut.done():
                    fut.set_result((float(p), str(src)))
                self._inflight.pop(key, None)
            return float(p), str(src)
        except Exception as e:
            async with self._mu:
                if not fut.done():
                    fut.set_exception(e)
                self._inflight.pop(key, None)
            raise

# ------------------ Exchange data (candles) ------------------
class MultiExchangeData:
    BINANCE_SPOT = "https://api.binance.com"
    BINANCE_FUTURES = "https://fapi.binance.com"
    BYBIT = "https://api.bybit.com"
    OKX = "https://www.okx.com"
    MEXC = "https://api.mexc.com"
    GATEIO = "https://api.gateio.ws/api/v4"

    def __init__(self) -> None:
        self.session: Optional[aiohttp.ClientSession] = None

        # --- Candle/market caching (stability + less API spam) ---
        self._candles_cache: dict[tuple, tuple[float, pd.DataFrame]] = {}  # key -> (expires_mono, df)
        self._candles_inflight: dict[tuple, asyncio.Future] = {}  # key -> Future[df]
        self._markets_cache: dict[str, tuple[float, set[str]]] = {}  # exchange -> (expires_mono, set(symbols))
        self._unsupported_until: dict[tuple, float] = {}  # (exchange, market, symbol, interval) -> expires_mono

        # Limits / timeouts
        self._http_concurrency = int(os.getenv("HTTP_CONCURRENCY", "25") or "25")
        self._http_req_timeout_sec = float(os.getenv("HTTP_REQ_TIMEOUT_SEC", "6") or "6")
        if MID_CANDLES_LIGHT_MODE:
            # keep REST fast in light mode; fallback to other exchanges instead of waiting long
            try:
                self._http_req_timeout_sec = float(min(self._http_req_timeout_sec, MID_LIGHT_HTTP_TIMEOUT_SEC))
            except Exception:
                self._http_req_timeout_sec = self._http_req_timeout_sec
        self._http_sem = asyncio.Semaphore(max(1, self._http_concurrency))

        # Feature flags
        self._market_avail_check = (os.getenv("MID_MARKET_AVAIL_CHECK", "1") or "1").strip().lower() in ("1","true","yes","on")
        self._markets_cache_ttl = int(os.getenv("MID_MARKETS_CACHE_TTL_SEC", "21600") or "21600")  # 6h
        self._unsupported_ttl = int(os.getenv("MID_UNSUPPORTED_SYMBOL_TTL_SEC", "21600") or "21600")  # 6h

        # Candle cache counters (for [mid][summary])
        self._candle_cache_hit = 0
        self._candle_cache_miss = 0
        self._candle_inflight_wait = 0

    async def __aenter__(self):
        self.session = aiohttp.ClientSession(timeout=aiohttp.ClientTimeout(total=20))
        return self

    async def __aexit__(self, exc_type, exc, tb):
        if self.session:
            await self.session.close()

    def candle_counters_snapshot(self) -> tuple[int,int,int]:
        """Return (hit, miss, inflight_wait) counters."""
        try:
            return (int(self._candle_cache_hit), int(self._candle_cache_miss), int(self._candle_inflight_wait))
        except Exception:
            return (0,0,0)


    def _norm_top_symbol(self, s: str) -> str:
        s = (s or "").upper().strip()
        s = s.replace("-", "").replace("_", "").replace("/", "")
        return s

    def _is_ok_top_symbol(self, sym: str) -> bool:
        if not sym.endswith("USDT"):
            return False
        if any(x in sym for x in ("UPUSDT", "DOWNUSDT", "BULLUSDT", "BEARUSDT")):
            return False
        return True

    async def _top_from_binance(self) -> list[tuple[float, str]]:
        assert self.session is not None
        url = f"{self.BINANCE_SPOT}/api/v3/ticker/24hr"
        data = await self._get_json(url)
        out: list[tuple[float, str]] = []
        for t in data or []:
            sym = self._norm_top_symbol(t.get("symbol", ""))
            if not self._is_ok_top_symbol(sym):
                continue
            try:
                qv = float(t.get("quoteVolume", "0") or 0)
            except Exception:
                qv = 0.0
            out.append((qv, sym))
        return out

    async def _top_from_mexc(self) -> list[tuple[float, str]]:
        assert self.session is not None
        url = f"{self.MEXC}/api/v3/ticker/24hr"
        data = await self._get_json(url)
        out: list[tuple[float, str]] = []
        for t in data or []:
            sym = self._norm_top_symbol(t.get("symbol", ""))
            if not self._is_ok_top_symbol(sym):
                continue
            try:
                # MEXC uses quoteVolume too
                qv = float(t.get("quoteVolume", "0") or 0)
            except Exception:
                qv = 0.0
            out.append((qv, sym))
        return out

    async def _top_from_bybit(self) -> list[tuple[float, str]]:
        # Bybit v5 spot tickers
        url = f"{self.BYBIT}/v5/market/tickers"
        data = await self._get_json(url, params={"category": "spot"})
        lst = (((data or {}).get("result") or {}).get("list") or []) if isinstance(data, dict) else []
        out: list[tuple[float, str]] = []
        for t in lst:
            sym = self._norm_top_symbol(t.get("symbol", ""))
            if not self._is_ok_top_symbol(sym):
                continue
            # turnover24h is quote turnover (in USDT for USDT pairs)
            qv = 0.0
            for k in ("turnover24h", "quoteVolume", "volume24h"):
                try:
                    if t.get(k) is not None:
                        qv = float(t.get(k) or 0.0)
                        break
                except Exception:
                    continue
            out.append((qv, sym))
        return out

    async def _top_from_okx(self) -> list[tuple[float, str]]:
        url = f"{self.OKX}/api/v5/market/tickers"
        data = await self._get_json(url, params={"instType": "SPOT"})
        lst = (data.get("data") or []) if isinstance(data, dict) else []
        out: list[tuple[float, str]] = []
        for t in lst:
            sym = self._norm_top_symbol(t.get("instId", ""))
            if not self._is_ok_top_symbol(sym):
                continue
            qv = 0.0
            # volCcy24h is quote volume
            for k in ("volCcy24h", "volCcy", "vol24h"):
                try:
                    if t.get(k) is not None:
                        qv = float(t.get(k) or 0.0)
                        break
                except Exception:
                    continue
            out.append((qv, sym))
        return out

    async def _top_from_gateio(self) -> list[tuple[float, str]]:
        url = f"{self.GATEIO}/spot/tickers"
        data = await self._get_json(url)
        out: list[tuple[float, str]] = []
        for t in data or []:
            sym = self._norm_top_symbol(t.get("currency_pair", ""))
            if not self._is_ok_top_symbol(sym):
                continue
            qv = 0.0
            # quote_volume is quote volume; some accounts use "quote_volume" / "quote_volume_24h"
            for k in ("quote_volume", "quote_volume_24h", "base_volume", "base_volume_24h"):
                try:
                    if t.get(k) is not None:
                        qv = float(t.get(k) or 0.0)
                        break
                except Exception:
                    continue
            out.append((qv, sym))
        return out

    async def get_top_usdt_symbols(self, n: int) -> List[str]:
        """Return Binance-style symbols (e.g. BTCUSDT) sorted by quote turnover.
    
        IMPORTANT: Binance may be unreachable (DNS/ban/region). We fall back to other exchanges.
        This method also uses a short TTL cache + provider cooldown to prevent REST storms.
        """
        assert self.session is not None
    
        # Fast path: return cached list (shared module-level cache) to avoid hitting REST every tick
        cached = _top_cache_get(n)
        if cached:
            try:
                self.last_top_provider = str(_TOP_SYMBOLS_CACHE.get("provider") or "CACHE")
            except Exception:
                pass
            return cached
    
        providers = [
            ("BINANCE", self._top_from_binance),
            ("BYBIT", self._top_from_bybit),
            ("OKX", self._top_from_okx),
            ("MEXC", self._top_from_mexc),
            ("GATEIO", self._top_from_gateio),
        ]
    
        last_err: Exception | None = None
        items: list[tuple[float, str]] = []
    
        for name, fn in providers:
            # Skip provider during cooldown (ban/rate limit backoff)
            if _top_provider_is_cooled(name):
                continue
            try:
                items = await fn()
                if items:
                    try:
                        self.last_top_provider = str(name)
                    except Exception:
                        pass
                    break
            except Exception as e:
                last_err = e
                # Set cooldown so we don't hammer the same provider again next tick
                try:
                    cd = int(_top_cooldown_for_error(name, e))
                    _top_set_provider_cooldown(name, cd)
                except Exception:
                    pass
                logger.warning("get_top_usdt_symbols: %s failed: %s", name, e)
                continue
    
        if not items:
            if last_err is not None:
                raise last_err
            return []
    
        items.sort(reverse=True, key=lambda x: float(x[0] or 0.0))
        syms = [sym for _, sym in items if sym]
    
        # Deduplicate while preserving order
        seen: set[str] = set()
        dedup: list[str] = []
        for s in syms:
            if s in seen:
                continue
            seen.add(s)
            dedup.append(s)
    
        # Save to TTL cache (shared across scanner ticks)
        try:
            _top_cache_set(dedup, getattr(self, "last_top_provider", ""))
        except Exception:
            pass
    
        if n <= 0:
            return dedup
        return dedup[:n]
    
    async def _get_json(self, url: str, params: Optional[Dict[str, str]] = None) -> Any:
        """HTTP GET JSON with concurrency limit + per-request timeout.

        Many exchanges (especially Binance) return HTTP 400 with a JSON error payload.
        aiohttp's raise_for_status() would hide that payload, making `no_candles` impossible
        to debug. We always read the body and include a short snippet in the exception.
        """
        assert self.session is not None
        async with self._http_sem:
            async def _do():
                try:
                    async with self.session.get(url, params=params) as r:
                        body_txt = await r.text()
                        if r.status >= 400:
                            snippet = (body_txt or "")[:300].replace("\n", " ").replace("\r", " ")
                            raise ExchangeAPIError(f"HTTP {r.status} url={str(r.url)} body={snippet}")

                        if not body_txt:
                            return None
                        try:
                            return json.loads(body_txt)
                        except Exception:
                            return None
                except asyncio.TimeoutError as e:
                    raise ExchangeAPIError(f"HTTP timeout url={url}") from e
                except (aiohttp.ClientError, OSError, ConnectionResetError) as e:
                    raise ExchangeAPIError(f"HTTP error url={url} err={type(e).__name__}: {e}") from e

            return await asyncio.wait_for(_do(), timeout=self._http_req_timeout_sec)




    def _interval_cache_ttl(self, interval: str) -> float:
        """TTL for candle cache, seconds."""
        s = (interval or "").strip().lower()
        if s == "5m":
            return float(os.getenv("CANDLE_CACHE_TTL_5M_SEC", "15") or "15")
        if s == "15m":
            return float(os.getenv("CANDLE_CACHE_TTL_15M_SEC", "30") or "30")
        if s == "30m":
            return float(os.getenv("CANDLE_CACHE_TTL_30M_SEC", "90") or "90")
        if s in ("1h","60m"):
            return float(os.getenv("CANDLE_CACHE_TTL_1H_SEC", "180") or "180")
        if s in ("4h","240m"):
            return float(os.getenv("CANDLE_CACHE_TTL_4H_SEC", "600") or "600")
        return float(os.getenv("CANDLE_CACHE_TTL_DEFAULT_SEC", "30") or "30")

    def _is_unsupported_cached(self, exchange: str, market: str, symbol: str, interval: str) -> bool:
        key = (exchange.upper(), (market or "").upper(), symbol.upper(), (interval or "").lower())
        until = self._unsupported_until.get(key)
        if until is None:
            return False
        if time.monotonic() >= until:
            self._unsupported_until.pop(key, None)
            return False
        return True

    def _mark_unsupported(self, exchange: str, market: str, symbol: str, interval: str) -> None:
        key = (exchange.upper(), (market or "").upper(), symbol.upper(), (interval or "").lower())
        self._unsupported_until[key] = time.monotonic() + float(self._unsupported_ttl)

    async def _get_gateio_markets(self) -> set[str]:
        now = time.monotonic()
        cached = self._markets_cache.get("GATEIO")
        if cached and now < cached[0]:
            return cached[1]
        url = f"{self.GATEIO}/spot/currency_pairs"
        try:
            raw = await self._get_json(url, params=None)
            s: set[str] = set()
            if isinstance(raw, list):
                for r in raw:
                    if isinstance(r, dict):
                        pid = (r.get("id") or r.get("currency_pair") or "").strip()
                        if pid:
                            s.add(pid.upper())
            self._markets_cache["GATEIO"] = (now + float(self._markets_cache_ttl), s)
            return s
        except Exception:
            if cached:
                return cached[1]
            return set()

    async def _get_mexc_markets(self) -> set[str]:
        now = time.monotonic()
        cached = self._markets_cache.get("MEXC")
        if cached and now < cached[0]:
            return cached[1]
        url = f"{self.MEXC}/api/v3/exchangeInfo"
        try:
            raw = await self._get_json(url, params=None)
            s: set[str] = set()
            if isinstance(raw, dict):
                for r in (raw.get("symbols") or []):
                    if isinstance(r, dict):
                        sym = (r.get("symbol") or "").strip()
                        if sym:
                            s.add(sym.upper())
            self._markets_cache["MEXC"] = (now + float(self._markets_cache_ttl), s)
            return s
        except Exception:
            if cached:
                return cached[1]
            return set()


    async def _get_binance_futures_markets(self) -> set[str]:
        """Cached set of BINANCE USDT-M futures symbols (canonical like BTCUSDT)."""
        now = time.monotonic()
        cached = self._markets_cache.get("BINANCE_FUTURES")
        if cached and now < cached[0]:
            return cached[1]
        url = f"{self.BINANCE_FUTURES}/fapi/v1/exchangeInfo"
        try:
            raw = await self._get_json(url, params=None)
            s: set[str] = set()
            if isinstance(raw, dict):
                for r in (raw.get("symbols") or []):
                    if isinstance(r, dict):
                        sym = (r.get("symbol") or "").strip()
                        if not sym:
                            continue
                        stt = str(r.get("status") or "").upper()
                        if stt and stt not in ("TRADING", "1"):
                            continue
                        s.add(sym.upper())
            self._markets_cache["BINANCE_FUTURES"] = (now + float(self._markets_cache_ttl), s)
            return s
        except Exception:
            if cached:
                return cached[1]
            return set()

