        """Cached set of BINANCE spot symbols (canonical like BTCUSDT)."""
        now = time.monotonic()
        cached = self._markets_cache.get("BINANCE_SPOT")
        if cached and now < cached[0]:
            return cached[1]
        url = f"{self.BINANCE_SPOT}/api/v3/exchangeInfo"
