    async def orderbook_binance_futures(self, symbol: str, limit: int = 100) -> Dict[str, Any]:
        """Binance USDT-M futures orderbook."""
        assert self.session is not None
        url = f"{self.BINANCE_FUTURES}/fapi/v1/depth"
