# --- Institutional token analysis (multi-timeframe) ---
_ANALYSIS_I18N_CACHE = {"data": None, "mtime": 0.0}

def _load_i18n_dict() -> dict:
    """Loads i18n.json next to this file. Cached by mtime.

    Important: this cache must stay isolated from the generic backend i18n cache
    defined earlier in the file. Reusing the same global name breaks analysis
    cards after any regular translation lookup warms the main cache.
    """
    import os, json
    try:
        p = os.path.join(os.path.dirname(__file__), "i18n.json")
        st = os.stat(p)
        if _ANALYSIS_I18N_CACHE["data"] is None or float(st.st_mtime) != float(_ANALYSIS_I18N_CACHE["mtime"]):
            with open(p, "r", encoding="utf-8") as fh:
                data = json.load(fh)
            if not isinstance(data, dict):
                return {}
            _ANALYSIS_I18N_CACHE["data"] = data
            _ANALYSIS_I18N_CACHE["mtime"] = float(st.st_mtime)
        return _ANALYSIS_I18N_CACHE["data"] or {}
    except Exception:
        try:
            legacy = globals().get("_I18N_CACHE")
            if isinstance(legacy, dict) and ("ru" in legacy or "en" in legacy):
                return legacy
        except Exception:
            pass
        return {}

def _tr_i18n(lang: str, key: str, **kwargs) -> str:
    d = _load_i18n_dict()
    lang = (lang or "ru").lower()
    if lang not in d:
        lang = "ru"
    s = None
    try:
        s = d.get(lang, {}).get(key)
        if s is None:
            # fallback to EN, then key
            s = d.get("en", {}).get(key, key)
        if kwargs:
            return str(s).format(**kwargs)
        return str(s)
    except Exception:
        try:
            return str(s) if s is not None else key
        except Exception:
            return key

def _fmt_int_space(x) -> str:
    """Human-friendly price/level formatter with adaptive precision.

    Keep higher precision for sub-100 instruments so scenario levels on assets
    like CAKE do not collapse into the same rounded text value.
    """
    try:
        v = float(x)
        if not (v == v) or v in (float("inf"), float("-inf")):
            return "—"

        av = abs(v)
        if av >= 1000:
            s = f"{v:,.0f}"
        elif av >= 100:
            s = f"{v:,.2f}"
        elif av >= 1:
            s = f"{v:,.3f}"
        elif av >= 0.1:
            s = f"{v:.4f}"
        elif av >= 0.01:
            s = f"{v:.5f}"
        elif av >= 0.0001:
            s = f"{v:.6f}"
        else:
            s = f"{v:.8f}"

        return s.replace(",", " ")
    except Exception:
        return "—"

def _fmt_float(x, nd=2) -> str:
    try:
        return f"{float(x):.{nd}f}"
    except Exception:
        return "—"



