def _inst_swing_points(df, left=3, right=3):
    """Return swing highs/lows as list of (idx, price)."""
    try:
        n = len(df)
        if n < left + right + 5:
            return [], []
        highs = df["high"].astype(float).values
        lows = df["low"].astype(float).values
        sh, sl = [], []
        for i in range(left, n - right):
            h = highs[i]
            if h == max(highs[i-left:i+right+1]):
                sh.append((i, float(h)))
            l = lows[i]
            if l == min(lows[i-left:i+right+1]):
                sl.append((i, float(l)))
        return sh, sl
    except Exception:
        return [], []

def _inst_detect_bos_anchor(df, side_hint="LONG", left=3, right=3):
    """Detect a simple BOS on the given df and return (anchor_idx, anchor_label)."""
    try:
        sh, sl = _inst_swing_points(df, left=left, right=right)
        close = df["close"].astype(float).values
        if side_hint.upper() == "LONG":
            # last swing high that gets broken
            for (si, lvl) in reversed(sh):
                for j in range(si+1, len(df)):
                    if close[j] > float(lvl):
                        return int(j), "BOS break (1h)"
        else:
            for (si, lvl) in reversed(sl):
                for j in range(si+1, len(df)):
                    if close[j] < float(lvl):
                        return int(j), "BOS break (1h)"
    except Exception:
        pass
    return None, None

def _inst_volume_profile_hvn_lvn(df, bins=72, value_area=0.7):
    """Volume profile by typical price; returns POC/VAH/VAL and HVN/LVN bins."""
    try:
        if df is None or getattr(df, "empty", True) or len(df) < 50:
            return None
        tp = (df["high"].astype(float) + df["low"].astype(float) + df["close"].astype(float)) / 3.0
        vol = df["volume"].astype(float).clip(lower=0.0)
        lo, hi = float(tp.min()), float(tp.max())
        if not (hi > lo):
            return None
        step = (hi - lo) / float(bins)
        if step <= 0:
            return None
        # bin volumes
        bvol = [0.0] * bins
        for p, v in zip(tp.values, vol.values):
            idx = int((float(p) - lo) / step)
            if idx < 0: idx = 0
            if idx >= bins: idx = bins - 1
            bvol[idx] += float(v)
        total = float(sum(bvol))
        if total <= 0:
            return None
        poc_i = int(max(range(bins), key=lambda i: bvol[i]))
        poc = lo + (poc_i + 0.5) * step

        # value area around POC by expanding to neighbors with higher volume
        target = total * float(value_area)
        va_i = {poc_i}
        acc = float(bvol[poc_i])
        l = poc_i - 1
        r = poc_i + 1
        while acc < target and (l >= 0 or r < bins):
            lv = bvol[l] if l >= 0 else -1.0
            rv = bvol[r] if r < bins else -1.0
            if rv >= lv:
                if r < bins:
                    va_i.add(r); acc += float(bvol[r]); r += 1
                else:
                    va_i.add(l); acc += float(bvol[l]); l -= 1
            else:
                if l >= 0:
                    va_i.add(l); acc += float(bvol[l]); l -= 1
                else:
                    va_i.add(r); acc += float(bvol[r]); r += 1
        vah_i, val_i = max(va_i), min(va_i)
        vah = lo + (vah_i + 1.0) * step
        val = lo + (val_i + 0.0) * step

        # HVN/LVN (top/bottom non-zero bins)
        ranked = sorted([(i, bvol[i]) for i in range(bins)], key=lambda x: x[1], reverse=True)
        hvn = []
        for i, v in ranked:
            if v <= 0: 
                continue
            lvl = lo + (i + 0.5) * step
            hvn.append(float(lvl))
            if len(hvn) >= 3:
                break
        ranked2 = sorted([(i, bvol[i]) for i in range(bins)], key=lambda x: x[1])
        lvn = []
        for i, v in ranked2:
            if v <= 0:
                continue
            lvl = lo + (i + 0.5) * step
            lvn.append(float(lvl))
            if len(lvn) >= 3:
                break

        return {
            "poc": float(poc),
            "vah": float(vah),
            "val": float(val),
            "hvn": hvn,
            "lvn": lvn,
            "bins": int(bins),
        }
    except Exception:
        return None

def _inst_detect_liquidity_voids(df, topk=2):
    """Detect imbalance/void zones using simple 3-candle FVG logic; returns list of zones."""
    zones = []
    try:
        if df is None or getattr(df, "empty", True) or len(df) < 10:
            return zones
        h = df["high"].astype(float).values
        l = df["low"].astype(float).values
        c = df["close"].astype(float).values
        v = df["volume"].astype(float).clip(lower=0.0).values if "volume" in df.columns else None
        medv = float(statistics.median(v)) if v is not None and len(v) > 0 else None
        for i in range(2, len(df)):
            # bullish imbalance: low[i] > high[i-2]
            if l[i] > h[i-2]:
                strength = float(l[i] - h[i-2])
                vol_ok = True
                if medv is not None:
                    vol_ok = float(v[i]) <= 1.2 * medv
                zones.append({"side":"BULL", "lo": float(h[i-2]), "hi": float(l[i]), "strength": strength, "i": i, "vol_ok": vol_ok})
            # bearish imbalance: high[i] < low[i-2]
            if h[i] < l[i-2]:
                strength = float(l[i-2] - h[i])
                vol_ok = True
                if medv is not None:
                    vol_ok = float(v[i]) <= 1.2 * medv
                zones.append({"side":"BEAR", "lo": float(h[i]), "hi": float(l[i-2]), "strength": strength, "i": i, "vol_ok": vol_ok})
        zones.sort(key=lambda z: z["strength"], reverse=True)
        return zones[: int(topk)]
    except Exception:
        return zones

def _inst_detect_sweep(df, eq_hi=None, eq_lo=None):
    """Detect latest buy-side/sell-side sweep vs EQH/EQL."""
    try:
        if df is None or getattr(df, "empty", True) or len(df) < 5:
            return None
        last = df.iloc[-1]
        hi = float(last["high"]); lo = float(last["low"]); cl = float(last["close"])
        out = {"buy_sweep": False, "sell_sweep": False}
        if eq_hi is not None:
            eqh = float(eq_hi)
            if hi > eqh and cl < eqh:
                out["buy_sweep"] = True
        if eq_lo is not None:
            eql = float(eq_lo)
            if lo < eql and cl > eql:
                out["sell_sweep"] = True
        return out
    except Exception:
        return None

def _inst_stop_hunt_probability(sweep, whale_score=None, ofp=None, late_trend=False):
    """0..100 probability of stop-hunt based on sweeps + context."""
    try:
        p = 15.0
        if sweep:
            if sweep.get("buy_sweep") or sweep.get("sell_sweep"):
                p += 35.0
        if whale_score is not None:
            p += min(25.0, float(whale_score) * 5.0)
        if ofp:
            mood = str(ofp.get("mood","")).upper()
            idx = float(ofp.get("index",0))
            # pressure against breakout supports hunt
            if (sweep and sweep.get("buy_sweep") and mood == "SELL") or (sweep and sweep.get("sell_sweep") and mood == "BUY"):
                p += 15.0 + min(10.0, (idx/100.0)*10.0)
        if late_trend:
            p += 10.0
        if p > 100.0: p = 100.0
        if p < 0.0: p = 0.0
        return int(round(p))
    except Exception:
        return 0

def _inst_trap_score(divergence=False, sweep_prob=0, ofp=None, rr_ok=True, weak_volume=False):
    """0..5 trap score."""
    try:
        s = 0
        if divergence:
            s += 1
        if sweep_prob >= 60:
            s += 2
        elif sweep_prob >= 40:
            s += 1
        if ofp:
            idx = float(ofp.get("index",0))
            if idx >= 70:
                s += 1
        if not rr_ok:
            s += 1
        if weak_volume:
            s += 1
        if s > 5: s = 5
        return int(s)
    except Exception:
        return 0

async def analyze_symbol_institutional(self, symbol: str, market: str = "FUTURES", lang: str = "ru", return_bundle: bool = False) -> str | dict:
    """
    Institutional-style TA analysis.
    Output format is Telegram Markdown and follows the required template.
    Uses 5m/1h/4h candles + indicators from _add_indicators().
    Includes lightweight "pro" extras: structure, swing levels, trendlines, channel, breakout/retest, liquidity, regime.
    """
    sym = (symbol or "").strip().upper()
    if not sym:
        return "⚠️ empty symbol"
    # allow entering BTC or BTCUSDT
    if not sym.endswith("USDT") and sym.isalnum() and len(sym) <= 12:
        sym = sym + "USDT"
    mkt = (market or "FUTURES").strip().upper()
    lang = (lang or "ru").lower()

    def _df_valid(df) -> bool:
        """Strict validation to prevent fake 0-valued analysis when candles fetch fails."""
        try:
            if df is None or getattr(df, "empty", True):
                return False
            if len(df) < 60:
                return False
            # Guard against placeholder frames (all zeros)
            for col in ("close", "high", "low"):
                if col in df.columns:
                    try:
                        mx = float(df[col].astype(float).max())
                    except Exception:
                        return False
                    if mx <= 0:
                        return False
            if "close" in df.columns:
                try:
                    if float(df["close"].astype(float).iloc[-1]) <= 0:
                        return False
                except Exception:
                    return False
            return True
        except Exception:
            return False

    async def _safe_load_tf(sym_: str, tf_: str, market_: str, *, critical: bool = False):
        """Best-effort candle loader for institutional analysis.

        5m is critical because it defines the live price / trigger context.
        Higher timeframes should degrade gracefully instead of killing the whole report.
        """
        try:
            df_ = await self.load_candles(sym_, tf_, market_)
            try:
                df_ = _mid_norm_ohlcv(df_) if df_ is not None else df_
            except Exception:
                pass
            if critical and not _df_valid(df_):
                return None
            return df_
        except Exception:
            return None

    # --------- AUTO market selection (SPOT priority -> FUTURES fallback) ---------
    if mkt == "AUTO":
        candidates: list[tuple[str, str]] = [("SPOT", sym), ("FUTURES", sym)]

        # Meme-contract alias: futures may use 1000x contract tickers (e.g., 1000PEPEUSDT)
        if sym.endswith("USDT"):
            base = sym[:-4]
            if base in ("PEPE",):
                candidates.append(("FUTURES", f"1000{base}USDT"))

        chosen_mkt = None
        chosen_sym = None
        df5 = None
        df1 = None
        df4 = None

        for cmkt, csym in candidates:
            t5 = await _safe_load_tf(csym, "5m", cmkt, critical=True)
            if _df_valid(t5):
                chosen_mkt, chosen_sym = cmkt, csym
                df5 = t5
                # load higher TFs best-effort
                df1 = await _safe_load_tf(csym, "1h", cmkt)
                df4 = await _safe_load_tf(csym, "4h", cmkt)
                break

        if chosen_mkt is None or chosen_sym is None or not _df_valid(df5):
            hint = ""
            if sym.endswith("USDT") and sym[:-4] == "PEPE":
                hint = "\n\nПодсказка: для PEPE фьючерса часто используется 1000PEPEUSDT"
            return f"❌ Нет данных для {sym} (AUTO).{hint}"

        # apply chosen
        mkt = chosen_mkt
        sym = chosen_sym

    else:
        # ---------- load candles ----------
        df5 = await _safe_load_tf(sym, "5m", mkt, critical=True)
        df1 = await _safe_load_tf(sym, "1h", mkt)
        df4 = await _safe_load_tf(sym, "4h", mkt)

    # Validate candles (avoid fake 0-valued analysis)
    if not _df_valid(df5):
        hint = ""
        if sym.endswith("USDT") and sym[:-4] == "PEPE":
            hint = "\n\nПодсказка: для PEPE фьючерса часто используется 1000PEPEUSDT"
        return f"❌ Нет свечей/цены для {sym} ({mkt}).{hint}"

    # ---------- indicators ----------
    df5 = _add_indicators(df5)
    if df1 is not None and not getattr(df1, "empty", True) and len(df1) >= 60:
        df1 = _add_indicators(df1)
    if df4 is not None and not getattr(df4, "empty", True) and len(df4) >= 60:
        df4 = _add_indicators(df4)

    price = float(df5["close"].astype(float).iloc[-1])

    # Pick base df for "structure/pro": prefer 1h, else 5m
    df_struct = df1 if (df1 is not None and not getattr(df1, "empty", True) and len(df1) >= 120) else df5
    df_struct_w = df_struct.tail(240).reset_index(drop=True)

    # ---------- levels (support/resistance + pivots) ----------
    try:
        d1w = df1.tail(120) if (df1 is not None and not getattr(df1, "empty", True) and len(df1) >= 120) else df5.tail(240)
        support1 = float(d1w["low"].astype(float).min())
        resistance1 = float(d1w["high"].astype(float).max())
        last_close_1h = float(d1w["close"].astype(float).iloc[-1])
    except Exception:
        d1w = df5.tail(240)
        support1 = float(d1w["low"].astype(float).min())
        resistance1 = float(d1w["high"].astype(float).max())
        last_close_1h = float(d1w["close"].astype(float).iloc[-1])

    rng = max(1e-9, (resistance1 - support1))
    support2 = support1 - rng * 0.5
    resistance2 = resistance1 + rng * 0.5
    pivot = (support1 + resistance1) / 2.0

    # Classic pivot points (using last ~24 1h candles, fallback to 5m window)
    try:
        piv_src = (df1.tail(24) if (df1 is not None and not getattr(df1, "empty", True) and len(df1) >= 24) else df5.tail(288))
        H = float(piv_src["high"].astype(float).max())
        L = float(piv_src["low"].astype(float).min())
        C = float(piv_src["close"].astype(float).iloc[-2]) if len(piv_src) >= 2 else float(piv_src["close"].astype(float).iloc[-1])
        P = (H + L + C) / 3.0
        R1 = 2 * P - L
        S1 = 2 * P - H
        R2 = P + (H - L)
        S2 = P - (H - L)
    except Exception:
        P = pivot
        R1, R2 = resistance1, resistance2
        S1, S2 = support1, support2

    # ---------- indicators (5m) ----------
    rsi = float(df5["rsi"].iloc[-1]) if "rsi" in df5.columns else 50.0
    macd = float(df5["macd_hist"].iloc[-1]) if "macd_hist" in df5.columns else 0.0
    adx5 = float(df5["adx"].iloc[-1]) if "adx" in df5.columns else 0.0
    atr_pct = float(df5["atr_pct"].iloc[-1]) if "atr_pct" in df5.columns else 0.0
    # ATR for SL using ENV-configurable timeframe
    atr_abs, atr_tf = pick_atr_for_sl(df5, df1, df4)

    # volume relative (current volume / avg prev 40)
    vol_rel = 1.0
    try:
        if "volume" in df5.columns:
            v = df5["volume"].astype(float)
            if len(v) >= 50:
                base = float(v.tail(41).head(40).mean())
                cur = float(v.iloc[-1])
                if base > 0:
                    vol_rel = cur / base
    except Exception:
        vol_rel = 1.0

    # Volume trend + spikes
    vol_trend = "—"
    vol_spike = "—"
    try:
        if "volume" in df5.columns and len(df5) >= 60:
            v = df5["volume"].astype(float).tail(60)
            ma_short = float(v.tail(10).mean())
            ma_long = float(v.tail(40).mean())
            if ma_long > 0:
                ratio = ma_short / ma_long
                if ratio >= 1.15:
                    vol_trend = "↑"
                elif ratio <= 0.87:
                    vol_trend = "↓"
                else:
                    vol_trend = "→"
            # spike
            spike_thr = float(v.tail(40).mean()) * 1.8 if float(v.tail(40).mean()) > 0 else 0
            if spike_thr > 0 and float(v.iloc[-1]) >= spike_thr:
                vol_spike = "SPIKE"
    except Exception:
        pass

    # ---------- trend labels (multi-timeframe) ----------
    def _trend_label(df):
        try:
            ema50 = float(df["ema50"].iloc[-1])
            ema200 = float(df["ema200"].iloc[-1])
            adx = float(df["adx"].iloc[-1])
        except Exception:
            return _tr_i18n(lang, "analysis_trend_pullback")
        if ema50 > ema200 and adx >= 25:
            return _tr_i18n(lang, "analysis_trend_strong_up")
        if ema50 > ema200:
            return _tr_i18n(lang, "analysis_trend_up")
        if ema50 < ema200 and adx >= 25:
            return _tr_i18n(lang, "analysis_trend_strong_down")
        return _tr_i18n(lang, "analysis_trend_pullback")

    trend4 = _trend_label(df4) if (df4 is not None and not getattr(df4, "empty", True)) else "—"
    trend1 = _trend_label(df1) if (df1 is not None and not getattr(df1, "empty", True)) else "—"
    trend5 = _trend_label(df5)

    # ---------- swings / structure ----------
    def _swing_points(_df: pd.DataFrame, left: int = 3, right: int = 3):
        """Return (swing_highs, swing_lows) as lists of tuples (idx, price)."""
        try:
            if _df is None or getattr(_df, "empty", True) or len(_df) < (left + right + 10):
                return [], []
            highs = _df["high"].astype(float).values
            lows = _df["low"].astype(float).values
            sh, sl = [], []
            for i in range(left, len(_df) - right):
                h = highs[i]
                l = lows[i]
                if h == max(highs[i-left:i+right+1]):
                    sh.append((i, float(h)))
                if l == min(lows[i-left:i+right+1]):
                    sl.append((i, float(l)))
            return sh, sl
        except Exception:
            return [], []

    def _structure_label(_sh, _sl) -> str:
        """HH/HL vs LH/LL using last 2 swings."""
        try:
            if len(_sh) < 2 or len(_sl) < 2:
                return "RANGE"
            h1, h2 = _sh[-2][1], _sh[-1][1]
            l1, l2 = _sl[-2][1], _sl[-1][1]
            if h2 > h1 and l2 > l1:
                return "HH/HL"
            if h2 < h1 and l2 < l1:
                return "LH/LL"
            return "RANGE"
        except Exception:
            return "RANGE"

    sh, sl = _swing_points(df_struct_w, left=3, right=3)
    struct_lbl = _structure_label(sh, sl)

    swing_hi = sh[-1][1] if len(sh) else resistance1
    swing_lo = sl[-1][1] if len(sl) else support1

    # ---------- trendlines + channel (swing-based, fallback to regression) ----------
    def _line_from_two(p1, p2, x):
        try:
            (x1, y1), (x2, y2) = p1, p2
            if x2 == x1:
                return float(y2)
            m = (y2 - y1) / (x2 - x1)
            return float(y1 + m * (x - x1))
        except Exception:
            return float("nan")

    tl_support = None
    tl_resist = None
    chan_type = None
    chan_support = support1
    chan_resist = resistance1
    chan_mid = pivot

    try:
        last_x = len(df_struct_w) - 1

        # Trendlines from last 2 swing lows/highs
        if len(sl) >= 2:
            tl_support = _line_from_two(sl[-2], sl[-1], last_x)
        if len(sh) >= 2:
            tl_resist = _line_from_two(sh[-2], sh[-1], last_x)

        # 1) Prefer swing-based channel when both trendlines exist and form a sane band
        if (tl_support is not None and tl_support == tl_support) and (tl_resist is not None and tl_resist == tl_resist):
            if tl_support < tl_resist:
                chan_support = float(tl_support)
                chan_resist = float(tl_resist)
                chan_mid = (chan_support + chan_resist) / 2.0

                # type from slope of support line (last 2 swing lows)
                try:
                    (x1, y1), (x2, y2) = sl[-2], sl[-1]
                    slope = (y2 - y1) / max(1e-9, (x2 - x1))
                except Exception:
                    slope = 0.0

                if slope > 0:
                    chan_type = "Восходящий канал" if lang.startswith("ru") else "Ascending channel"
                elif slope < 0:
                    chan_type = "Нисходящий канал" if lang.startswith("ru") else "Descending channel"
                else:
                    chan_type = "Боковой канал" if lang.startswith("ru") else "Range channel"

        # 2) Fallback: regression channel on closes (useful when swings are sparse)
        if chan_type is None:
            y = df_struct_w["close"].astype(float).values
            x = np.arange(len(y), dtype=float)
            if len(y) >= 80:
                x_mean = float(x.mean())
                y_mean = float(y.mean())
                denom = float(((x - x_mean) ** 2).sum())
                slope = float((((x - x_mean) * (y - y_mean)).sum()) / denom) if denom > 0 else 0.0
                intercept = y_mean - slope * x_mean
                y_hat = intercept + slope * x
                resid = y - y_hat
                band = float(np.std(resid)) * 2.0  # ~2 sigma
                ch_mid = float(y_hat[-1])
                ch_up = float(ch_mid + band)
                ch_dn = float(ch_mid - band)

                if ch_dn < ch_up and abs(ch_mid) > 0:
                    chan_support = ch_dn
                    chan_resist = ch_up
                    chan_mid = ch_mid

                if slope > 0:
                    chan_type = "Восходящий канал" if lang.startswith("ru") else "Ascending channel"
                elif slope < 0:
                    chan_type = "Нисходящий канал" if lang.startswith("ru") else "Descending channel"
                else:
                    chan_type = "Боковой канал" if lang.startswith("ru") else "Range channel"
            else:
                chan_type = "Канал" if lang.startswith("ru") else "Channel"
                chan_mid = (chan_support + chan_resist) / 2.0
    except Exception:
        chan_support = support1
        chan_resist = resistance1
        chan_mid = pivot
        chan_type = "Канал" if lang.startswith("ru") else "Channel"

    # Price position inside channel (near support / mid / resistance)
    chan_pos = "—"
    try:
        tol_pos = max(atr_abs * 0.6, price * 0.001)
        if abs(price - chan_support) <= tol_pos:
            chan_pos = "у поддержки" if lang.startswith("ru") else "near support"
        elif abs(price - chan_resist) <= tol_pos:
            chan_pos = "у сопротивления" if lang.startswith("ru") else "near resistance"
        elif abs(price - chan_mid) <= tol_pos:
            chan_pos = "у середины" if lang.startswith("ru") else "near midpoint"
        else:
            chan_pos = "внутри канала" if lang.startswith("ru") else "inside channel"
    except Exception:
        pass

# ---------- breakout / retest ----------
    brk = "—"
    try:
        last_close = float(df5["close"].astype(float).iloc[-1])
        tol = max(atr_abs * 0.6, (last_close * 0.001))  # ~0.1% or 0.6 ATR
        if last_close > max(resistance1, chan_resist) + tol:
            brk = "Пробой ↑" if lang.startswith("ru") else "Breakout ↑"
        elif last_close < min(support1, chan_support) - tol:
            brk = "Пробой ↓" if lang.startswith("ru") else "Breakout ↓"
        else:
            if abs(last_close - resistance1) <= tol:
                brk = "Ретест R1" if lang.startswith("ru") else "Retest R1"
            elif abs(last_close - support1) <= tol:
                brk = "Ретест S1" if lang.startswith("ru") else "Retest S1"
            elif abs(last_close - chan_resist) <= tol:
                brk = "Ретест канала" if lang.startswith("ru") else "Channel retest"
            elif abs(last_close - chan_support) <= tol:
                brk = "Ретест канала" if lang.startswith("ru") else "Channel retest"
    except Exception:
        pass

    # ---------- liquidity zones (equal highs/lows) ----------
    liq = "—"
    try:
        atr_abs_s = float(df_struct_w["atr"].iloc[-1]) if "atr" in df_struct_w.columns and df_struct_w["atr"].iloc[-1] == df_struct_w["atr"].iloc[-1] else atr_abs
        tol2 = max(atr_abs_s * 0.4, price * 0.001)
        if len(sh) >= 2 and abs(sh[-1][1] - sh[-2][1]) <= tol2:
            lvl = (sh[-1][1] + sh[-2][1]) / 2.0
            liq = ("Равные хаи" if lang.startswith("ru") else "Equal Highs") + f" ~{_fmt_int_space(lvl)}"
        elif len(sl) >= 2 and abs(sl[-1][1] - sl[-2][1]) <= tol2:
            lvl = (sl[-1][1] + sl[-2][1]) / 2.0
            liq = ("Равные лои" if lang.startswith("ru") else "Equal Lows") + f" ~{_fmt_int_space(lvl)}"
    except Exception:
        pass



    # ---------- SMC-lite: BOS / CHOCH (based on swing breaks) ----------
    smc_event = "—"
    try:
        last_close = float(df5["close"].astype(float).iloc[-1])
        tol_smc = max(atr_abs * 0.35, last_close * 0.0008)  # ~0.08% or 0.35 ATR
        # latest swing levels from structure TF
        last_swing_hi = float(swing_hi)
        last_swing_lo = float(swing_lo)

        # BOS: break in trend direction
        if last_close > last_swing_hi + tol_smc:
            smc_event = "BOS ↑" if not lang.startswith("ru") else "BOS вверх"
            # If structure was bearish -> this is CHOCH
            if struct_lbl == "LH/LL":
                smc_event = "CHOCH ↑" if not lang.startswith("ru") else "CHOCH вверх"
        elif last_close < last_swing_lo - tol_smc:
            smc_event = "BOS ↓" if not lang.startswith("ru") else "BOS вниз"
            if struct_lbl == "HH/HL":
                smc_event = "CHOCH ↓" if not lang.startswith("ru") else "CHOCH вниз"
    except Exception:
        pass

    # ---------- FVG (Fair Value Gap) ----------
    fvg_txt = "—"
    try:
        _df = df_struct_w.tail(220).reset_index(drop=True)
        if len(_df) >= 20:
            h = _df["high"].astype(float).values
            l = _df["low"].astype(float).values

            last_zone = None  # (kind, z_lo, z_hi, idx)
            for i in range(2, len(_df)):
                # bullish FVG: current low > high 2 bars back
                if l[i] > h[i-2]:
                    z_lo, z_hi = float(h[i-2]), float(l[i])
                    last_zone = ("BULL", z_lo, z_hi, i)
                # bearish FVG: current high < low 2 bars back
                elif h[i] < l[i-2]:
                    z_lo, z_hi = float(h[i]), float(l[i-2])
                    last_zone = ("BEAR", z_lo, z_hi, i)

            if last_zone is not None:
                kind, z_lo, z_hi, idx = last_zone
                # active/unfilled heuristic
                if kind == "BULL":
                    filled = (l[idx+1:] <= z_lo).any() if idx+1 < len(_df) else False
                else:
                    filled = (h[idx+1:] >= z_hi).any() if idx+1 < len(_df) else False

                side = ("Bullish" if kind=="BULL" else "Bearish") if not lang.startswith("ru") else ("Бычья" if kind=="BULL" else "Медвежья")
                st = ("active" if not filled else "filled") if not lang.startswith("ru") else ("активна" if not filled else "заполнена")
                fvg_txt = f"{side} FVG [{_fmt_int_space(z_lo)}–{_fmt_int_space(z_hi)}] ({st})"
    except Exception:
        pass

    # ---------- momentum extras (divergence + slope) ----------
    div = "—"
    try:
        if "rsi" in df5.columns and len(df5) >= 80:
            p = df5["close"].astype(float).tail(60).values
            r = df5["rsi"].astype(float).tail(60).values
            # compare last swing-like points (simple)
            p1, p2 = float(p[-40]), float(p[-1])
            r1, r2 = float(r[-40]), float(r[-1])
            if p2 > p1 and r2 < r1:
                div = "Bearish divergence" if not lang.startswith("ru") else "Медвежья дивергенция"
            elif p2 < p1 and r2 > r1:
                div = "Bullish divergence" if not lang.startswith("ru") else "Бычья дивергенция"
    except Exception:
        pass

    slope_ema = "—"
    try:
        if "ema20" in df5.columns and len(df5) >= 30:
            e = df5["ema20"].astype(float).tail(20).values
            slope = float(e[-1] - e[0])
            if abs(slope) < (atr_abs * 0.2):
                slope_ema = "flat"
            elif slope > 0:
                slope_ema = "up"
            else:
                slope_ema = "down"
    except Exception:
        pass

    # ---------- patterns (lightweight heuristics) ----------
    pattern = "—"
    try:
        if len(sh) >= 3 and len(sl) >= 3:
            # Double top/bottom
            tol_p = max(atr_abs * 0.6, price * 0.001)
            if abs(sh[-1][1] - sh[-2][1]) <= tol_p and sh[-1][1] > sl[-1][1]:
                pattern = "Double Top" if not lang.startswith("ru") else "Двойная вершина"
            elif abs(sl[-1][1] - sl[-2][1]) <= tol_p and sl[-1][1] < sh[-1][1]:
                pattern = "Double Bottom" if not lang.startswith("ru") else "Двойное дно"
            else:
                # Triangle: lower highs + higher lows over last swings
                if sh[-1][1] < sh[-2][1] and sl[-1][1] > sl[-2][1]:
                    pattern = "Triangle" if not lang.startswith("ru") else "Треугольник"
    except Exception:
        pass

    # ---------- smart money zones (simplified order block) ----------
    smz = "—"
    try:
        df_ob = df1 if (df1 is not None and not getattr(df1, "empty", True) and len(df1) >= 80) else df5
        w = df_ob.tail(120).reset_index(drop=True)
        c = w["close"].astype(float).values
        o = w["open"].astype(float).values
        h = w["high"].astype(float).values
        l = w["low"].astype(float).values
        # find recent impulse: candle range vs ATR
        atr_ob = float(w["atr"].iloc[-1]) if "atr" in w.columns else 0.0
        thr = max(atr_ob * 1.2, price * 0.002)
        idx = None
        dir_up = None
        for i in range(len(w)-3, 10, -1):
            if abs(c[i] - o[i]) >= thr:
                idx = i
                dir_up = (c[i] > o[i])
                break
        if idx is not None:
            # order block: last opposite candle before impulse
            ob_idx = None
            if dir_up:
                for j in range(idx-1, max(idx-12, 0), -1):
                    if c[j] < o[j]:  # bearish candle
                        ob_idx = j
                        break
            else:
                for j in range(idx-1, max(idx-12, 0), -1):
                    if c[j] > o[j]:  # bullish candle
                        ob_idx = j
                        break
            if ob_idx is not None:
                z_hi = max(o[ob_idx], c[ob_idx])
                z_lo = min(o[ob_idx], c[ob_idx])
                smz = ("OB " + ("Demand" if dir_up else "Supply")) if not lang.startswith("ru") else ("OB " + ("Спрос" if dir_up else "Предложение"))
                smz += f" [{_fmt_int_space(z_lo)}–{_fmt_int_space(z_hi)}]"
    except Exception:
        pass

    # ---------- market regime ----------
    regime = "—"
    try:
        adx_s = float(df_struct_w["adx"].iloc[-1]) if "adx" in df_struct_w.columns else adx5
        atrp_s = float(df_struct_w["atr_pct"].iloc[-1]) if "atr_pct" in df_struct_w.columns else atr_pct
        # expansion/contraction: compare last atr% to avg
        atrp_avg = float(df_struct_w["atr_pct"].astype(float).tail(80).mean()) if "atr_pct" in df_struct_w.columns and len(df_struct_w) >= 80 else atrp_s
        expansion = (atrp_s > atrp_avg * 1.25) if atrp_avg > 0 else False
        if expansion:
            regime = "EXPANSION"
        elif adx_s >= 25 and struct_lbl in ("HH/HL", "LH/LL"):
            regime = "TRENDING"
        elif adx_s < 18 and struct_lbl == "RANGE":
            regime = "RANGING"
        else:
            regime = "CHOPPY"
    except Exception:
        regime = "—"



    # ---------- volatility analysis (ATR% expansion/contraction) ----------
    vola_state = "—"
    vola_risk = "—"
    try:
        atrp_series = df_struct_w["atr_pct"].astype(float) if (df_struct_w is not None and "atr_pct" in df_struct_w.columns) else None
        if atrp_series is not None and len(atrp_series) >= 60:
            cur = float(atrp_series.iloc[-1])
            avg40 = float(atrp_series.tail(40).mean())
            avg10 = float(atrp_series.tail(10).mean())
            if avg40 > 0:
                if avg10 > avg40 * 1.15:
                    vola_state = "volatility rising" if not lang.startswith("ru") else "волатильность растёт"
                    vola_risk = "unstable / breakout risk" if not lang.startswith("ru") else "рынок нестабильный / риск breakout"
                elif avg10 < avg40 * 0.88:
                    vola_state = "volatility falling" if not lang.startswith("ru") else "волатильность падает"
                    vola_risk = "compression / wait" if not lang.startswith("ru") else "сжатие / ждать импульс"
                else:
                    vola_state = "volatility stable" if not lang.startswith("ru") else "волатильность стабильна"
                    vola_risk = "normal" if not lang.startswith("ru") else "нормально"
    except Exception:
        pass

    # ---------- volume analysis (accumulation / distribution) ----------
    vol_phase = "neutral" if not lang.startswith("ru") else "нейтрально"
    try:
        if "volume" in df5.columns and len(df5) >= 60:
            # price change vs volume trend
            delta = float(df5["close"].astype(float).iloc[-1] - df5["close"].astype(float).iloc[-20])
            if vol_trend == "↑" and vol_rel >= 1.2:
                if delta > 0:
                    vol_phase = "accumulation" if not lang.startswith("ru") else "аккумуляция"
                elif delta < 0:
                    vol_phase = "distribution" if not lang.startswith("ru") else "дистрибуция"
    except Exception:
        pass

    # ---------- probability engine (enhanced) ----------
    long_score = 0.0
    short_score = 0.0

    # EMA trend
    try:
        if float(df5["ema50"].iloc[-1]) > float(df5["ema200"].iloc[-1]):
            long_score += 3
        else:
            short_score += 3
    except Exception:
        pass

    # RSI
    if rsi > 55:
        long_score += 2
    elif rsi < 45:
        short_score += 2

    # MACD
    if macd > 0:
        long_score += 1
    else:
        short_score += 1

    # ADX -> confidence, not direction (adds to both)
    if adx5 >= 25:
        long_score += 1
        short_score += 1

    # Structure bias
    if struct_lbl == "HH/HL":
        long_score += 1
    elif struct_lbl == "LH/LL":
        short_score += 1

    # Breakout bias
    if "↑" in brk:
        long_score += 1
    elif "↓" in brk:
        short_score += 1

    total = long_score + short_score
    long_p = int(round(100.0 * long_score / total)) if total > 0 else 50
    long_p = max(0, min(100, long_p))
    short_p = 100 - long_p

    bias = "LONG" if long_p > short_p else "SHORT"
    diff = abs(long_p - short_p)
    if lang.startswith("ru"):
        confidence = "ВЫСОКАЯ" if diff >= 30 else ("СРЕДНЯЯ" if diff >= 15 else "НИЗКАЯ")
    else:
        confidence = "HIGH" if diff >= 30 else ("MEDIUM" if diff >= 15 else "LOW")

    # ---------- trading plan (ATR + structure aware) ----------
    entry = price
    sl_pad = max(atr_abs * 0.6, entry * 0.001)  # 0.1% or 0.6 ATR

    def _plan_targets(entry_v, sl_v, base_tp1, base_tp2, *, direction):
        risk = abs(float(entry_v) - float(sl_v))
        if risk <= 0:
            return float(base_tp1), float(base_tp2)
        try:
            atr_unit = max(float(atr_abs), abs(float(entry_v)) * 0.0028, 1e-9)
        except Exception:
            atr_unit = max(abs(float(entry_v)) * 0.0028, 1e-9)
        sign = 1.0 if direction == "LONG" else -1.0
        tp1_floor = float(entry_v) + sign * max(abs(float(base_tp1) - float(entry_v)), risk * 1.15, atr_unit * 1.35)
        tp2_floor = float(entry_v) + sign * max(abs(float(base_tp2) - float(entry_v)), risk * 2.55, atr_unit * 3.25)
        min_gap = max(risk * 0.80, atr_unit * 0.90)
        if direction == "LONG":
            if tp2_floor <= tp1_floor:
                tp2_floor = tp1_floor + min_gap
        else:
            if tp2_floor >= tp1_floor:
                tp2_floor = tp1_floor - min_gap
        return float(tp1_floor), float(tp2_floor)

    if bias == "LONG":
        base_sl = min(support1, float(swing_lo), float(chan_support))
        sl = base_sl - sl_pad

        base_tp1 = min(resistance1, float(chan_resist))
        base_tp2 = max(resistance2, float(chan_resist))
        tp1, tp2 = _plan_targets(entry, sl, base_tp1, base_tp2, direction="LONG")

        rr = (tp2 - entry) / max(1e-9, (entry - sl))
    else:
        base_sl = max(resistance1, float(swing_hi), float(chan_resist))
        sl = base_sl + sl_pad

        base_tp1 = max(support1, float(chan_support))
        base_tp2 = min(support2, float(chan_support))
        tp1, tp2 = _plan_targets(entry, sl, base_tp1, base_tp2, direction="SHORT")

        rr = (entry - tp2) / max(1e-9, (sl - entry))

    # ---------- formatting ----------
    line = "━━━━━━━━━━━━━━━━━━━"
    price_s = _fmt_int_space(price)

    s1_s = _fmt_int_space(support1)
    s2_s = _fmt_int_space(support2)
    r1_s = _fmt_int_space(resistance1)
    r2_s = _fmt_int_space(resistance2)
    piv_s = _fmt_int_space(pivot)

    P_s = _fmt_int_space(P)
    R1_s = _fmt_int_space(R1)
    R2_s = _fmt_int_space(R2)
    S1_s = _fmt_int_space(S1)
    S2_s = _fmt_int_space(S2)

    entry_s = _fmt_int_space(entry)
    sl_s = _fmt_int_space(sl)
    tp1_s = _fmt_int_space(tp1)
    tp2_s = _fmt_int_space(tp2)

    chan_type_txt = (chan_type or (_tr_i18n(lang, "analysis_channel_type") if "analysis_channel_type" in I18N.get(lang, {}) else ("Channel" if not lang.startswith("ru") else "Канал")))
    chan_s_s = _fmt_int_space(chan_support)
    chan_m_s = _fmt_int_space(chan_mid)
    chan_r_s = _fmt_int_space(chan_resist)

    tl_s_txt = _fmt_int_space(tl_support) if (tl_support is not None and tl_support == tl_support) else "—"
    tl_r_txt = _fmt_int_space(tl_resist) if (tl_resist is not None and tl_resist == tl_resist) else "—"

    rsi_i = int(round(rsi)) if rsi == rsi else 0
    adx_i = int(round(adx5)) if adx5 == adx5 else 0
    atr_s = _fmt_float(atr_pct, 1)
    vol_s = _fmt_float(vol_rel, 2)

    macd_label = "🟢 bullish" if macd > 0 else "🔴 bearish"
    vol_status = _tr_i18n(lang, "analysis_volume_status_acc") if float(vol_rel) >= 1.2 else _tr_i18n(lang, "analysis_volume_status_neu")

    # ---------- report (RU template) ----------
    # ---------- localized report context (RU/EN) ----------
    is_ru = lang.startswith("ru")
    # Better labels for market
    mkt_label = (("ФЬЮЧЕРСЫ" if mkt == "FUTURES" else "СПОТ") if is_ru else mkt)

    # Regime strength (use structure TF ADX when possible)
    try:
        adx_reg = float(df_struct_w["adx"].iloc[-1]) if "adx" in df_struct_w.columns else adx5
    except Exception:
        adx_reg = adx5
    adx_reg_i = int(round(float(adx_reg))) if adx_reg == adx_reg else adx_i
    trend_strength = "high" if adx_reg_i >= 30 else ("medium" if adx_reg_i >= 22 else "low")

    # Volatility text mapping
    vola_txt = "Стабильна"
    if isinstance(vola_state, str):
        vs = vola_state.lower()
        if "раст" in vs or "rising" in vs:
            vola_txt = "Растёт"
        elif "пад" in vs or "fall" in vs:
            vola_txt = "Падает"
    risk_txt = "Нормальный"
    if isinstance(vola_risk, str):
        vr = vola_risk.lower()
        if "breakout" in vr or "проб" in vr or "нестабил" in vr:
            risk_txt = "Высокий"
        elif "сжат" in vr or "compression" in vr:
            risk_txt = "Низкий"
    compression_txt = "Да" if (isinstance(vola_risk, str) and ("сжат" in vola_risk.lower() or "compression" in vola_risk.lower())) else "Нет"

    # Momentum text mapping
    rsi_mood = (("бычий импульс" if rsi >= 55 else ("медвежий импульс" if rsi <= 45 else "нейтрально")) if is_ru else ("bullish momentum" if rsi >= 55 else ("bearish momentum" if rsi <= 45 else "neutral")))
    macd_mood = (("Бычий импульс ↑" if macd > 0 else "Медвежий импульс ↓") if is_ru else ("Bullish momentum ↑" if macd > 0 else "Bearish momentum ↓"))
    slope_txt = (("Вверх ↗" if slope_ema == "up" else ("Вниз ↘" if slope_ema == "down" else "Флет →")) if is_ru else ("Up ↗" if slope_ema == "up" else ("Down ↘" if slope_ema == "down" else "Flat →")))
    div_txt = div if div not in ("—", "-", None) else ("Не обнаружена" if is_ru else "Not detected")

    # Volume text mapping
    vol_rel_txt = f"{_fmt_float(vol_rel,2)}x" if vol_rel == vol_rel else "—"
    vol_tr_txt = (("Растёт ↑" if vol_trend == "up" else ("Падает ↓" if vol_trend == "down" else "Флет →")) if is_ru else ("Rising ↑" if vol_trend == "up" else ("Falling ↓" if vol_trend == "down" else "Flat →")))
    spike_txt = (("Да" if (isinstance(vol_spike, str) and ("spike" in vol_spike.lower() or "всплеск" in vol_spike.lower() or "⚡" in vol_spike)) else "Нет") if is_ru else ("Yes" if (isinstance(vol_spike, str) and ("spike" in vol_spike.lower() or "всплеск" in vol_spike.lower() or "⚡" in vol_spike)) else "No"))

    # Breakout/retest status for the header line
    status_txt = "—"
    try:
        b = (brk or "").lower()
        if "ретест" in b or "retest" in b:
            if "s1" in b or "support" in b or "поддерж" in b:
                status_txt = "Retest поддержки (бычий сигнал)" if is_ru else "Support retest (bullish signal)"
            elif "r1" in b or "resist" in b or "сопрот" in b:
                status_txt = "Retest сопротивления (медвежий сигнал)" if is_ru else "Resistance retest (bearish signal)"
            else:
                status_txt = "Retest уровня" if is_ru else "Level retest"
        elif "пробой" in b or "breakout" in b:
            status_txt = "Пробой (импульс)" if is_ru else "Breakout (impulse)"
    except Exception:
        pass

    # Liquidity zones: try to output both Equal Highs and Equal Lows

    # Liquidity zones: detect Equal Highs/Lows as clusters of swing points (not only last 2)
    eq_hi = None
    eq_lo = None
    eq_hi_touches = 0
    eq_lo_touches = 0
    eq_hi_strength = 0
    eq_lo_strength = 0
    eq_hi_dist_pct = None
    eq_lo_dist_pct = None
    eq_hi_dist_atr = None
    eq_lo_dist_atr = None
    try:
        atr_abs_s = float(df_struct_w["atr"].iloc[-1]) if "atr" in df_struct_w.columns and df_struct_w["atr"].iloc[-1] == df_struct_w["atr"].iloc[-1] else atr_abs
        tol_atr = float(os.getenv("LIQ_EQ_TOL_ATR_MULT", "0.35") or 0.35)
        tol_pct = float(os.getenv("LIQ_EQ_TOL_PCT", "0.0010") or 0.0010)  # 0.10%
        tol2 = max(atr_abs_s * tol_atr, price * tol_pct)

        max_swings = int(os.getenv("LIQ_EQ_MAX_SWINGS", "12") or 12)
        min_sep_pct = float(os.getenv("LIQ_EQ_MIN_SEP_PCT", "0.0002") or 0.0002)  # avoid classifying "near price" as liquidity

        def _median(vals: list[float]) -> float:
            s = sorted(vals)
            return float(s[len(s)//2])

        def _best_eq(swings: list[tuple[int, float]] | None, side: str):
            # side: "high" (liquidity above) or "low" (liquidity below)
            if not swings:
                return None
            pts = swings[-max_swings:]
            clusters: list[dict] = []
            for ix, v in pts:
                v = float(v)
                placed = False
                for c in clusters:
                    if abs(v - float(c["level"])) <= tol2:
                        c["vals"].append(v)
                        c["idxs"].append(int(ix))
                        c["level"] = _median(c["vals"])
                        placed = True
                        break
                if not placed:
                    clusters.append({"vals": [v], "idxs": [int(ix)], "level": v})

            # filter by side relative to current price (we care about resting liquidity away from price)
            if side == "high":
                cand = [c for c in clusters if float(c["level"]) >= price * (1.0 + min_sep_pct)]
            else:
                cand = [c for c in clusters if float(c["level"]) <= price * (1.0 - min_sep_pct)]

            if not cand:
                return None

            # best = most touches, then most recent touch
            cand.sort(key=lambda c: (len(c["vals"]), max(c["idxs"])), reverse=True)
            c = cand[0]
            level = float(c["level"])
            touches = int(len(c["vals"]))
            last_touch = int(max(c["idxs"]))
            spread = float(max(c["vals"]) - min(c["vals"])) if touches >= 2 else 0.0

            # strength (1..5): touches + recency - dispersion
            strength = min(5, max(1, touches))
            try:
                age = (len(df_struct_w) - 1) - last_touch
                if age <= int(os.getenv("LIQ_EQ_RECENT_BONUS_BARS", "60") or 60):
                    strength = min(5, strength + 1)
            except Exception:
                pass
            if spread > tol2 * float(os.getenv("LIQ_EQ_SPREAD_PENALTY", "0.8") or 0.8):
                strength = max(1, strength - 1)

            dist = abs(level - price)
            dist_pct = (dist / price * 100.0) if price > 0 else None
            dist_atr = (dist / atr_abs_s) if atr_abs_s and atr_abs_s > 0 else None
            return (level, touches, strength, dist_pct, dist_atr)

        hi = _best_eq(sh, "high")
        if hi:
            eq_hi, eq_hi_touches, eq_hi_strength, eq_hi_dist_pct, eq_hi_dist_atr = hi

        lo = _best_eq(sl, "low")
        if lo:
            eq_lo, eq_lo_touches, eq_lo_strength, eq_lo_dist_pct, eq_lo_dist_atr = lo

    except Exception:
        pass

    def _liq_line(prefix: str, level: float | None, dist_pct: float | None, dist_atr: float | None, strength: int, touches: int, side: str) -> str:
        if level is None:
            return f"{prefix}: Не обнаружены" if is_ru else f"{prefix}: Not detected"
        try:
            dp = f"{dist_pct:.2f}%" if dist_pct is not None and dist_pct == dist_pct else "n/a"
        except Exception:
            dp = "n/a"
        try:
            da = f"{dist_atr:.2f} ATR" if dist_atr is not None and dist_atr == dist_atr else "n/a"
        except Exception:
            da = "n/a"
        arrow = "↑" if side == "high" else "↓"
        return f"{prefix}: {_fmt_int_space(level)} {arrow} | dist: {dp} ({da}) | strength: {int(strength)}/5 | touches: {int(touches)}"

    eq_hi_line = _liq_line(("Equal Highs (ликвидность сверху)" if is_ru else "Equal Highs (liquidity above)"), eq_hi, eq_hi_dist_pct, eq_hi_dist_atr, eq_hi_strength, eq_hi_touches, "high")
    eq_lo_line = _liq_line(("Equal Lows (ликвидность снизу)" if is_ru else "Equal Lows (liquidity below)"), eq_lo, eq_lo_dist_pct, eq_lo_dist_atr, eq_lo_strength, eq_lo_touches, "low")
    # ---- Multi-TF liquidity map (5m/1h/4h) + общий "магнит" ----
    mtf_liq_lines: list[str] = []
    magnet_level = None
    magnet_side = None  # "high" or "low"
    try:
        def _tf_atr(_df: pd.DataFrame) -> float:
            try:
                if _df is not None and "atr" in _df.columns:
                    v = float(_df["atr"].astype(float).iloc[-1])
                    if v == v and v > 0:
                        return v
            except Exception:
                pass
            return float(atr_abs_s) if atr_abs_s and atr_abs_s > 0 else float(atr_abs) if atr_abs else 0.0

        def _best_eq_mtf(_df: pd.DataFrame, _sh: list[tuple[int, float]], _sl: list[tuple[int, float]], _label: str):
            try:
                if _df is None or getattr(_df, "empty", True) or (not _sh and not _sl):
                    return None, None
                _price = float(price)
                _atr = _tf_atr(_df)
                _tol_atr = float(os.getenv("LIQ_EQ_TOL_ATR_MULT", "0.35") or 0.35)
                _tol_pct = float(os.getenv("LIQ_EQ_TOL_PCT", "0.0010") or 0.0010)
                _tol = max(_atr * _tol_atr, _price * _tol_pct)
                _max_sw = int(os.getenv("LIQ_EQ_MAX_SWINGS", "12") or 12)
                _min_sep = float(os.getenv("LIQ_EQ_MIN_SEP_PCT", "0.0002") or 0.0002)

                def _median(vals: list[float]) -> float:
                    s = sorted(vals)
                    return float(s[len(s)//2])

                def _cluster(swings: list[tuple[int, float]], side: str):
                    if not swings:
                        return None
                    pts = swings[-_max_sw:]
                    clusters: list[dict] = []
                    for ix, v in pts:
                        v = float(v)
                        placed = False
                        for c in clusters:
                            if abs(v - float(c["level"])) <= _tol:
                                c["vals"].append(v)
                                c["idxs"].append(int(ix))
                                c["level"] = _median(c["vals"])
                                placed = True
                                break
                        if not placed:
                            clusters.append({"vals":[v], "idxs":[int(ix)], "level": v})
                    if side == "high":
                        cand = [c for c in clusters if float(c["level"]) >= _price * (1.0 + _min_sep)]
                    else:
                        cand = [c for c in clusters if float(c["level"]) <= _price * (1.0 - _min_sep)]
                    if not cand:
                        return None
                    cand.sort(key=lambda c: (len(c["vals"]), max(c["idxs"])), reverse=True)
                    c = cand[0]
                    level = float(c["level"])
                    touches = int(len(c["vals"]))
                    last_touch = int(max(c["idxs"]))
                    spread = float(max(c["vals"]) - min(c["vals"])) if touches >= 2 else 0.0
                    strength = min(5, max(1, touches))
                    try:
                        age = (len(_df) - 1) - last_touch
                        if age <= int(os.getenv("LIQ_EQ_RECENT_BONUS_BARS", "60") or 60):
                            strength = min(5, strength + 1)
                    except Exception:
                        pass
                    if spread > _tol * float(os.getenv("LIQ_EQ_SPREAD_PENALTY", "0.8") or 0.8):
                        strength = max(1, strength - 1)
                    dist = abs(level - _price)
                    dist_pct = (dist / _price * 100.0) if _price > 0 else None
                    dist_atr = (dist / _atr) if _atr and _atr > 0 else None
                    return (level, touches, strength, dist_pct, dist_atr)

                hi = _cluster(_sh, "high")
                lo = _cluster(_sl, "low")

                def _fmt_side(name: str, res):
                    if not res:
                        return f"{name}: —"
                    lvl, t, st, dp, da = res
                    dp_s = f"{dp:.2f}%" if dp is not None and dp == dp else "n/a"
                    da_s = f"{da:.2f} ATR" if da is not None and da == da else "n/a"
                    return f"{name}: {_fmt_int_space(lvl)} | dist: {dp_s} ({da_s}) | str: {int(st)}/5 | t: {int(t)}"

                line_hi = _fmt_side(f"{_label} EQH", hi)
                line_lo = _fmt_side(f"{_label} EQL", lo)

                return (hi, line_hi), (lo, line_lo)
            except Exception:
                return None, None

        sh5, sl5 = _swing_points(df5, left=3, right=3)
        sh1_, sl1_ = _swing_points(df1, left=3, right=3) if df1 is not None else ([], [])
        sh4_, sl4_ = _swing_points(df4, left=3, right=3) if df4 is not None else ([], [])

        for _df, _sh_, _sl_, _lab in ((df5, sh5, sl5, "5m"), (df1, sh1_, sl1_, "1h"), (df4, sh4_, sl4_, "4h")):
            hi_pack, lo_pack = _best_eq_mtf(_df, _sh_, _sl_, _lab)
            for pack, side in ((hi_pack, "high"), (lo_pack, "low")):
                if pack:
                    res, line_txt = pack
                    mtf_liq_lines.append(line_txt)
                    if res:
                        lvl = float(res[0])
                        d = abs(lvl - float(price))
                        if magnet_level is None or d < abs(float(magnet_level) - float(price)):
                            magnet_level = lvl
                            magnet_side = side

    except Exception:
        pass

    magnet_txt = "Magnet: —"
    try:
        if magnet_level is not None:
            arrow = "↑" if magnet_side == "high" else "↓"
            magnet_txt = f"Magnet: {_fmt_int_space(float(magnet_level))} {arrow}"
    except Exception:
        pass

    # ---- Anchored VWAP (1h) от swing low/high (proxy BOS anchor) ----
    avb = None
    try:
        _dfv = df1 if (df1 is not None and not getattr(df1, "empty", True)) else None
        if _dfv is not None and "volume" in _dfv.columns and len(_dfv) > 30:
            # Anchor selection: по приоритету (bias) -> последний swing low/high на 1h
            shA, slA = _swing_points(_dfv, left=3, right=3)
            use_long = True
            try:
                use_long = bool(long_p >= short_p)
            except Exception:
                pass
            # Prefer BOS anchor if detected (desk-level AVWAP)
            try:
                bos_idx, bos_label = _inst_detect_bos_anchor(_dfv, "LONG" if use_long else "SHORT", left=3, right=3)
            except Exception:
                bos_idx, bos_label = (None, None)
            anchor_idx = None
            anchor_name = None
            # If BOS exists, anchor AVWAP on BOS candle (higher priority than swing)
            if bos_idx is not None:
                anchor_idx = int(bos_idx)
                anchor_name = str(bos_label or "BOS break (1h)")
            else:
                if use_long and slA:
                    anchor_idx = int(slA[-1][0])
                    anchor_name = "swing low (1h)"
                elif (not use_long) and shA:
                    anchor_idx = int(shA[-1][0])
                    anchor_name = "swing high (1h)"
                elif slA:
                    anchor_idx = int(slA[-1][0]); anchor_name = "swing low (1h)"
                elif shA:
                    anchor_idx = int(shA[-1][0]); anchor_name = "swing high (1h)"

            if anchor_idx is not None and anchor_idx < (len(_dfv) - 5):
                seg = _dfv.iloc[anchor_idx:].copy()
                tp = (seg["high"].astype(float) + seg["low"].astype(float) + seg["close"].astype(float)) / 3.0
                vol = seg["volume"].astype(float).clip(lower=0.0)
                v_sum = float(vol.sum())
                if v_sum > 0:
                    vwap = float((tp * vol).sum() / v_sum)
                    # volume-weighted stdev
                    mu = vwap
                    var = float(((tp - mu) ** 2 * vol).sum() / v_sum)
                    sd = math.sqrt(var) if var >= 0 else 0.0
                    avb = {
                        "vwap": vwap,
                        "sd": sd,
                        "anchor": anchor_name,
                        "bands": {
                            "-1.0": vwap - 1.0 * sd,
                            "+1.0": vwap + 1.0 * sd,
                            "-2.0": vwap - 2.0 * sd,
                            "+2.0": vwap + 2.0 * sd,
                        },
                        "bars": int(len(seg)),
                    }
    except Exception:
        avb = None

    # Order block parsing: "OB Спрос [lo–hi]" -> lo/hi
    ob_side = "—"
    ob_lo = None
    ob_hi = None
    try:
        if isinstance(smz, str) and "[" in smz and "]" in smz:
            ob_side = "demand" if ("спрос" in smz.lower() or "demand" in smz.lower()) else "supply"
            inside = smz.split("[", 1)[1].split("]", 1)[0]
            inside = inside.replace("–", "-").replace("—", "-")
            a, b = inside.split("-", 1)
            ob_lo = float(str(a).replace(" ", ""))
            ob_hi = float(str(b).replace(" ", ""))
    except Exception:
        pass

    # FVG parsing: "Бычья FVG [lo–hi] (активна)" -> lo/hi
    fvg_side = None
    fvg_lo = None
    fvg_hi = None
    fvg_active = None
    try:
        if isinstance(fvg_txt, str) and "FVG" in fvg_txt and "[" in fvg_txt and "]" in fvg_txt:
            fvg_side = "bullish" if ("быч" in fvg_txt.lower() or "bull" in fvg_txt.lower()) else ("bearish" if ("медв" in fvg_txt.lower() or "bear" in fvg_txt.lower()) else None)
            inside = fvg_txt.split("[", 1)[1].split("]", 1)[0]
            inside = inside.replace("–", "-").replace("—", "-")
            a, b = inside.split("-", 1)
            fvg_lo = float(str(a).replace(" ", ""))
            fvg_hi = float(str(b).replace(" ", ""))
            fvg_active = ("актив" in fvg_txt.lower() or "active" in fvg_txt.lower())
    except Exception:
        pass

    # Trading plan extras
    # Entry Zone (идеально для институционального входа) строим НЕ от ATR вокруг цены,
    # а от зон спроса/предложения: Order Block + FVG + liquidity sweep + channel/support.
    # После зоны обязательно показываем Trigger (подтверждение) и Invalidation (отмена).
    try:
        entry_lo = None
        entry_hi = None
        entry_kind = "—"
        entry_confluence = 0
        entry_notes = []
        inv_lvl_out = None  # for entry status

        cs = float(chan_support) if chan_support is not None else None
        cm = float(chan_mid) if chan_mid is not None else None
        cr = float(chan_resist) if chan_resist is not None else None
        s1n = float(support1) if support1 is not None else None
        s2n = float(support2) if support2 is not None else None
        r1n = float(resistance1) if resistance1 is not None else None
        r2n = float(resistance2) if resistance2 is not None else None

        # базовые допуски "рядом" (для confluence)
        tol = max(atr_abs * 0.6, price * 0.002)

        # fallback ширина зоны, чтобы отчёт никогда не ломался
        w_fallback = max(atr_abs * 0.25, price * 0.001)

        # liquidity sweep detection (последние ~30 свечей 5м)
        sweep_long = False
        sweep_short = False
        try:
            recent = df5.tail(30)
            if eq_lo is not None and "low" in recent.columns and "close" in recent.columns:
                low_min = float(recent["low"].astype(float).min())
                close_last = float(recent["close"].astype(float).iloc[-1])
                sweep_long = (low_min < float(eq_lo) - tol * 0.15) and (close_last > float(eq_lo) + tol * 0.05)
            if eq_hi is not None and "high" in recent.columns and "close" in recent.columns:
                high_max = float(recent["high"].astype(float).max())
                close_last = float(recent["close"].astype(float).iloc[-1])
                sweep_short = (high_max > float(eq_hi) + tol * 0.15) and (close_last < float(eq_hi) - tol * 0.05)
        except Exception:
            pass


        def _overlap(a_lo, a_hi, b_lo, b_hi):
            lo = max(a_lo, b_lo)
            hi = min(a_hi, b_hi)
            return (lo, hi) if hi > lo else (None, None)

        def _near(x, lo, hi, tol_):
            if x is None:
                return False
            return (lo - tol_) <= x <= (hi + tol_)

        def _clamp_zone(zlo, zhi):
            zlo = max(0.0, float(zlo))
            zhi = max(zlo, float(zhi))
            return zlo, zhi

        # --- LONG: Demand zones ---
        if bias == "LONG":
            ob_ok = (ob_lo is not None and ob_hi is not None and ("demand" in str(ob_side).lower()))
            fvg_ok = (fvg_lo is not None and fvg_hi is not None and fvg_active is True and (str(fvg_side).lower().startswith("bull")))
            ch_ok = (cs is not None and cm is not None and cm > cs)

            # 1) лучший вариант: OB + FVG overlap (узкая зона)
            if ob_ok and fvg_ok:
                o_lo, o_hi = _overlap(float(ob_lo), float(ob_hi), float(fvg_lo), float(fvg_hi))
                if o_lo is not None:
                    entry_lo, entry_hi = _clamp_zone(o_lo, o_hi)
                    entry_kind = "OB+FVG"
                    entry_notes.append("Order Block + FVG")
                else:
                    # если не пересекаются — берём OB как базу (он сильнее)
                    entry_lo, entry_hi = _clamp_zone(float(ob_lo), float(ob_hi))
                    entry_kind = "OB"
                    entry_notes.append("Order Block")

            elif ob_ok:
                entry_lo, entry_hi = _clamp_zone(float(ob_lo), float(ob_hi))
                entry_kind = "OB"
                entry_notes.append("Order Block")

            elif fvg_ok:
                entry_lo, entry_hi = _clamp_zone(float(fvg_lo), float(fvg_hi))
                entry_kind = "FVG"
                entry_notes.append("FVG")

            elif ch_ok:
                # зона от поддержки канала к середине (консервативно)
                base = cs
                # если Support1 выше поддержки канала — используем его (лучше)
                if s1n is not None:
                    base = max(base, s1n)
                w = max(w_fallback, (cm - base) * 0.35)
                entry_lo, entry_hi = _clamp_zone(base, base + w)
                entry_kind = "CHANNEL"
                entry_notes.append("Support/Channel")

            # fallback: ATR band (если ничего нет)
            if entry_lo is None or entry_hi is None or not (entry_hi > entry_lo):
                entry_lo, entry_hi = _clamp_zone(price - atr_abs * 0.8, price - atr_abs * 0.1)
                entry_kind = "ATR"
                entry_notes.append("Fallback ATR")

            # --- confluence scoring (0..5) ---
            # OB присутствует (сильнейший фактор)
            if ob_ok and _near((float(ob_lo)+float(ob_hi))/2.0, entry_lo, entry_hi, tol):
                entry_confluence += 2
            # FVG рядом/внутри
            if fvg_ok and _near((float(fvg_lo)+float(fvg_hi))/2.0, entry_lo, entry_hi, tol):
                entry_confluence += 1
            # Support канала рядом с низом зоны
            if cs is not None and abs(cs - entry_lo) <= tol:
                entry_confluence += 1
            # Liquidity (Equal Lows) рядом
            if _near(eq_lo, entry_lo, entry_hi, tol):
                entry_confluence += 1
            # Pivot/S1 внутри/рядом
            try:
                if _near(float(S1), entry_lo, entry_hi, tol) or _near(float(pivot), entry_lo, entry_hi, tol):
                    entry_confluence += 1
            except Exception:
                pass
            entry_confluence = min(5, max(0, int(entry_confluence)))

            # --- Trigger & Invalidation for LONG ---
            # Обязательное подтверждение: Liquidity sweep снизу (Equal Lows) + возврат выше уровня
            entry_sweep_txt = ("Liquidity sweep (5м): " if is_ru else "Liquidity sweep (5m): ") + (("Да" if sweep_long else "Нет") if is_ru else ("Yes" if sweep_long else "No"))
            trig_parts = []
            trig_parts.append("Liquidity sweep снизу (Equal Lows) + reclaim" if is_ru else "Liquidity sweep below (Equal Lows) + reclaim")
            trig_parts.append("BOS 5м вверх (закрытие выше локального swing-high)" if is_ru else "5m BOS up (close above local swing high)")
            trig_parts.append((f"reclaim зоны (закрытие 5м выше {_fmt_int_space(entry_hi)})" if is_ru else f"zone reclaim (5m close above {_fmt_int_space(entry_hi)})"))
            trig_parts.append("объём > 1.2x" if is_ru else "volume > 1.2x")
            if not sweep_long:
                entry_trigger_txt = (("Триггер входа: СНАЧАЛА " + trig_parts[0] + " (сейчас: Нет), затем " + " + ".join(trig_parts[1:])) if is_ru else ("Entry trigger: FIRST " + trig_parts[0] + " (now: No), then " + " + ".join(trig_parts[1:])))
            else:
                entry_trigger_txt = (("Триггер входа: " + " + ".join(trig_parts)) if is_ru else ("Entry trigger: " + " + ".join(trig_parts)))

            inv_ref = float(entry_lo)
            try:
                if (not sweep_long) and eq_lo is not None:
                    inv_ref = min(inv_ref, float(eq_lo))
            except Exception:
                pass
            inv_lvl = max(0.0, inv_ref - max(atr_abs * 0.15, price * 0.0008))
            inv_lvl_out = float(inv_lvl)
            entry_inval_txt = (f"Инвалидация: закрепление 5м ниже {_fmt_int_space(inv_lvl)}" if is_ru else f"Invalidation: 5m close below {_fmt_int_space(inv_lvl)}")

            # Подгоняем SL под инвалидацию (SL должен быть ниже инвалидации)
            try:
                sl = min(float(sl), inv_lvl)
            except Exception:
                pass

        # --- SHORT: Supply zones ---
        else:
            ob_ok = (ob_lo is not None and ob_hi is not None and ("supply" in str(ob_side).lower()))
            fvg_ok = (fvg_lo is not None and fvg_hi is not None and fvg_active is True and (str(fvg_side).lower().startswith("bear")))
            ch_ok = (cr is not None and cm is not None and cr > cm)

            if ob_ok and fvg_ok:
                o_lo, o_hi = _overlap(float(ob_lo), float(ob_hi), float(fvg_lo), float(fvg_hi))
                if o_lo is not None:
                    entry_lo, entry_hi = _clamp_zone(o_lo, o_hi)
                    entry_kind = "OB+FVG"
                    entry_notes.append("Order Block + FVG")
                else:
                    entry_lo, entry_hi = _clamp_zone(float(ob_lo), float(ob_hi))
                    entry_kind = "OB"
                    entry_notes.append("Order Block")

            elif ob_ok:
                entry_lo, entry_hi = _clamp_zone(float(ob_lo), float(ob_hi))
                entry_kind = "OB"
                entry_notes.append("Order Block")

            elif fvg_ok:
                entry_lo, entry_hi = _clamp_zone(float(fvg_lo), float(fvg_hi))
                entry_kind = "FVG"
                entry_notes.append("FVG")

            elif ch_ok:
                top = cr
                if r1n is not None:
                    top = min(top, r1n)
                w = max(w_fallback, (top - cm) * 0.35)
                entry_lo, entry_hi = _clamp_zone(top - w, top)
                entry_kind = "CHANNEL"
                entry_notes.append("Resistance/Channel")

            if entry_lo is None or entry_hi is None or not (entry_hi > entry_lo):
                entry_lo, entry_hi = _clamp_zone(price + atr_abs * 0.1, price + atr_abs * 0.8)
                entry_kind = "ATR"
                entry_notes.append("Fallback ATR")

            # confluence scoring
            if ob_ok and _near((float(ob_lo)+float(ob_hi))/2.0, entry_lo, entry_hi, tol):
                entry_confluence += 2
            if fvg_ok and _near((float(fvg_lo)+float(fvg_hi))/2.0, entry_lo, entry_hi, tol):
                entry_confluence += 1
            if cr is not None and abs(cr - entry_hi) <= tol:
                entry_confluence += 1
            if _near(eq_hi, entry_lo, entry_hi, tol):
                entry_confluence += 1
            try:
                if _near(float(R1), entry_lo, entry_hi, tol) or _near(float(pivot), entry_lo, entry_hi, tol):
                    entry_confluence += 1
            except Exception:
                pass
            entry_confluence = min(5, max(0, int(entry_confluence)))

            entry_sweep_txt = ("Liquidity sweep (5м): " if is_ru else "Liquidity sweep (5m): ") + (("Да" if sweep_short else "Нет") if is_ru else ("Yes" if sweep_short else "No"))
            trig_parts = []
            trig_parts.append("Liquidity sweep сверху (Equal Highs) + reject" if is_ru else "Liquidity sweep above (Equal Highs) + reject")
            trig_parts.append("BOS 5м вниз (закрытие ниже локального swing-low)" if is_ru else "5m BOS down (close below local swing low)")
            trig_parts.append((f"reject зоны (закрытие 5м ниже {_fmt_int_space(entry_lo)})" if is_ru else f"zone reject (5m close below {_fmt_int_space(entry_lo)})"))
            trig_parts.append("объём > 1.2x" if is_ru else "volume > 1.2x")
            if not sweep_short:
                entry_trigger_txt = (("Триггер входа: СНАЧАЛА " + trig_parts[0] + " (сейчас: Нет), затем " + " + ".join(trig_parts[1:])) if is_ru else ("Entry trigger: FIRST " + trig_parts[0] + " (now: No), then " + " + ".join(trig_parts[1:])))
            else:
                entry_trigger_txt = (("Триггер входа: " + " + ".join(trig_parts)) if is_ru else ("Entry trigger: " + " + ".join(trig_parts)))

            inv_ref = float(entry_hi)
            try:
                if (not sweep_short) and eq_hi is not None:
                    inv_ref = max(inv_ref, float(eq_hi))
            except Exception:
                pass
            inv_lvl = inv_ref + max(atr_abs * 0.15, price * 0.0008)
            inv_lvl_out = float(inv_lvl)
            entry_inval_txt = (f"Инвалидация: закрепление 5м выше {_fmt_int_space(inv_lvl)}" if is_ru else f"Invalidation: 5m close above {_fmt_int_space(inv_lvl)}")

            try:
                sl = max(float(sl), inv_lvl)
            except Exception:
                pass

    except Exception:
        inv_lvl_out = None
        entry_lo, entry_hi = price, price
        entry_kind = "—"
        entry_confluence = 0
        entry_notes = []
        entry_sweep_txt = "Liquidity sweep (5м): —" if is_ru else "Liquidity sweep (5m): —"
        entry_trigger_txt = "Триггер входа: —" if is_ru else "Entry trigger: —"
        entry_inval_txt = "Инвалидация: —" if is_ru else "Invalidation: —"

    # ---- Entry status (READY / WAIT / CONFIRMED / INVALID) ----
    entry_status = "WAIT"
    try:
        p_now = float(price)
        zlo = float(entry_lo)
        zhi = float(entry_hi)
        inv = inv_lvl_out if (inv_lvl_out is not None) else None

        # invalidation check first
        if inv is not None:
            if bias == "LONG" and p_now <= float(inv):
                entry_status = "INVALID"
            elif bias == "SHORT" and p_now >= float(inv):
                entry_status = "INVALID"

        if entry_status != "INVALID":
            in_zone = (min(zlo, zhi) <= p_now <= max(zlo, zhi))
            entry_status = "READY" if in_zone else "WAIT"

            # "CONFIRMED" only when we're in zone AND confirmations are present
            try:
                sweep_ok = bool(sweep_long) if bias == "LONG" else bool(sweep_short)
            except Exception:
                sweep_ok = False
            try:
                vol_ok = float(vol_rel) >= 1.2
            except Exception:
                vol_ok = False
            try:
                dir_ok = (("↑" in str(brk)) if bias == "LONG" else ("↓" in str(brk)))
            except Exception:
                dir_ok = False

            if entry_status == "READY" and sweep_ok and vol_ok and dir_ok:
                entry_status = "CONFIRMED"
    except Exception:
        entry_status = "WAIT"

    # Human text via i18n (ru/en)
    entry_status_label = _tr_i18n(lang, "lbl_entry_status")
    entry_status_txt = _tr_i18n(lang, f"entry_status_{str(entry_status).lower()}")
    entry_status_line = f"{entry_status_label}: {entry_status_txt}"

    entry_zone_txt = f"{_fmt_int_space(entry_lo)} – {_fmt_int_space(entry_hi)}"
    entry_quality_txt = f"Качество зоны (confluence): {entry_confluence}/5"
    entry_kind_txt = f"Тип зоны: {entry_kind}" if entry_kind and entry_kind != "—" else "Тип зоны: —"
    entry_notes_txt = ("Основание: " + ", ".join(entry_notes)) if entry_notes else "Основание: —"
    # RR to TP1/TP2 (institutional: from entry midpoint when available)
    rr1 = None
    rr2 = None
    try:
        entry_mid = None
        if entry_lo is not None and entry_hi is not None:
            entry_mid = (float(entry_lo) + float(entry_hi)) / 2.0
        base_entry = entry_mid if entry_mid is not None else float(price)
        risk = max(1e-9, abs(base_entry - float(sl)))
        rr1 = abs(float(tp1) - base_entry) / risk
        rr2 = abs(float(tp2) - base_entry) / risk
    except Exception:
        pass
    rr1_txt = _fmt_float(rr1, 2) if rr1 is not None else "—"
    rr2_txt = _fmt_float(rr2, 2) if rr2 is not None else (_fmt_float(rr, 2) if rr is not None else "—")

    # Institutional metrics (OHLCV-only)
    conf_inst_txt = None
    risk_flags_inst = []
    trade_status_inst = None
    try:
        df_vp = df1.tail(240) if (df1 is not None and not df1.empty) else (df4.tail(180) if (df4 is not None and not df4.empty) else None)
        vp = volume_profile(df_vp, bins=int(os.getenv('ANALYSIS_VP_BINS','72') or 72), value_area=float(os.getenv('ANALYSIS_VP_VALUE_AREA','0.7') or 0.7)) if df_vp is not None else None
        vb = calc_vwap_bands(df1.tail(240) if (df1 is not None and not df1.empty) else df5.tail(120), stdev_mults=(1.0,2.0))
        ofp = orderflow_pressure(df5, lookback=int(os.getenv('ANALYSIS_OF_LOOKBACK','36') or 36))
        whale = whale_activity(df5, lookback=int(os.getenv('ANALYSIS_WHALE_LOOKBACK','180') or 180), z_thr=float(os.getenv('ANALYSIS_WHALE_Z','2.5') or 2.5))
        liqcls = liquidation_clusters(df5, lookback=int(os.getenv('ANALYSIS_LIQCL_LOOKBACK','180') or 180), topk=int(os.getenv('ANALYSIS_LIQCL_TOPK','2') or 2))

        # Ultimate desk-level extras: session/24h VP (HVN/LVN), voids, sweeps, stop-hunt/trap scores
        vp_sess = vp_24h = None
        voids_5m = voids_1h = []
        sweep_5m = None
        stop_hunt_p = None
        trap_score = None
        try:
            _bins = int(os.getenv('ANALYSIS_VP_BINS','72') or 72)
            _va = float(os.getenv('ANALYSIS_VP_VALUE_AREA','0.7') or 0.7)

            # Session VP (approx): last 12h on 5m (144 bars)
            if df5 is not None and not df5.empty and len(df5) >= 150:
                vp_sess = _inst_volume_profile_hvn_lvn(df5.tail(144), bins=_bins, value_area=_va)

            # 24h VP: last 24h on 5m (288 bars) if available, else fallback to 1h last 24 bars
            if df5 is not None and not df5.empty and len(df5) >= 300:
                vp_24h = _inst_volume_profile_hvn_lvn(df5.tail(288), bins=_bins, value_area=_va)
            elif df1 is not None and not df1.empty and len(df1) >= 60:
                vp_24h = _inst_volume_profile_hvn_lvn(df1.tail(24), bins=_bins, value_area=_va)

            # Liquidity voids / imbalance zones
            voids_5m = _inst_detect_liquidity_voids(df5.tail(400) if (df5 is not None and not df5.empty) else df5, topk=int(os.getenv('ANALYSIS_VOID_TOPK','2') or 2))
            voids_1h = _inst_detect_liquidity_voids(df1.tail(240) if (df1 is not None and not df1.empty) else df1, topk=int(os.getenv('ANALYSIS_VOID_TOPK','2') or 2))

            # Sweep detection (prefer 5m, fallback 1h)
            sweep_5m = _inst_detect_sweep(df5 if (df5 is not None and not df5.empty) else df1, eq_hi=eq_hi, eq_lo=eq_lo)

            # Stop-hunt probability & trap score
            late_trend_flag = bool(str(phase).upper() == "LATE_TREND")
            whale_score = whale.get("score") if isinstance(whale, dict) else None
            stop_hunt_p = _inst_stop_hunt_probability(sweep_5m, whale_score=whale_score, ofp=ofp, late_trend=late_trend_flag)

            div_flag = False
            try:
                _div_l = str(div_txt).lower()
                div_flag = (("диверг" in _div_l) or ("diverg" in _div_l)) and any(tok in _div_l for tok in ("есть", "обнаруж", "found", "present", "detected"))
            except Exception:
                div_flag = False

            min_rr = float(os.getenv("ANALYSIS_MIN_RR", "1.5") or 1.5)
            rr_ok = True
            try:
                rr_ok = (rr2 is not None and float(rr2) >= float(min_rr))
            except Exception:
                rr_ok = True

            min_vol = float(os.getenv("ANALYSIS_MIN_VOL_REL", "0.6") or 0.6)
            weak_vol = False
            try:
                weak_vol = float(vol_rel) < float(min_vol)
            except Exception:
                weak_vol = False

            trap_score = _inst_trap_score(divergence=div_flag, sweep_prob=int(stop_hunt_p or 0), ofp=ofp, rr_ok=rr_ok, weak_volume=weak_vol)
        except Exception:
            pass

        score = 50
        if regime in ('TRENDING','TREND','EXPANSION'):
            score += 10
        if trend_strength == 'high':
            score += 8
        if struct_lbl == 'HH/HL' and bias == 'LONG':
            score += 8
        if struct_lbl == 'LH/LL' and bias == 'SHORT':
            score += 8
        try:
            if float(vol_rel) >= 1.2: score += 8
            elif float(vol_rel) < 0.6: score -= 10
        except Exception:
            pass
        if ofp:
            if (bias=='LONG' and ofp['mood']=='BUY') or (bias=='SHORT' and ofp['mood']=='SELL'): score += 6
            elif ofp['mood']!='NEUTRAL': score -= 6
        if isinstance(div_txt, str) and any(tok in div_txt.lower() for tok in ('медв', 'bear')) and bias=='LONG': score -= 8
        if isinstance(div_txt, str) and any(tok in div_txt.lower() for tok in ('быч', 'bull')) and bias=='SHORT': score -= 8
        try:
            if float(adx_reg_i) >= 35 and isinstance(div_txt, str) and any(tok in div_txt.lower() for tok in ('диверг', 'diverg')): score -= 4
        except Exception:
            pass
        try:
            rrq = float(rr2) if rr2 is not None else None
            if rrq is not None:
                if rrq >= 2.0: score += 8
                elif rrq >= 1.5: score += 4
                elif rrq < 1.0: score -= 10
        except Exception:
            pass
        try:
            if eq_hi is not None and eq_hi_dist_atr is not None and eq_hi_dist_atr < 2.0: score += 3
            if eq_lo is not None and eq_lo_dist_atr is not None and eq_lo_dist_atr < 2.0: score += 3
        except Exception:
            pass
        if whale and whale.get('spike'): score -= 3

        score = max(0, min(100, int(round(score))))

        # --- Institutional validation flags (used to align probability/confidence) ---
        try:
            MIN_RR = float(os.getenv("ANALYSIS_MIN_RR", "1.5") or 1.5)
        except Exception:
            MIN_RR = 1.5
        try:
            MIN_VOL_REL = float(os.getenv("ANALYSIS_MIN_VOL_REL", "0.6") or 0.6)
        except Exception:
            MIN_VOL_REL = 0.6

        risk_flags_inst = []
        try:
            if rr2 is not None and float(rr2) < float(MIN_RR):
                risk_flags_inst.append("rr_too_low")
        except Exception:
            pass
        try:
            if float(vol_rel) < float(MIN_VOL_REL):
                risk_flags_inst.append("weak_volume")
        except Exception:
            pass
        try:
            # Trend exhaustion: high ADX + RSI divergence
            if float(adx_reg_i) >= 35 and isinstance(div_txt, str) and ("диверг" in div_txt.lower() or "diverg" in div_txt.lower()):
                risk_flags_inst.append("trend_exhaustion")
        except Exception:
            pass

        # Trade status: skip when key institutional constraints fail
        trade_status_inst = "NO TRADE" if ("rr_too_low" in risk_flags_inst or "weak_volume" in risk_flags_inst) else "OK"

        # Confidence is driven by institutional score (not by long/short diff)
        conf_inst_txt = (("Высокая" if score >= 75 else ("Средняя" if score >= 60 else "Низкая")) if is_ru else ("High" if score >= 75 else ("Medium" if score >= 60 else "Low")))

        if bias == 'LONG':
            long_p = max(5, min(95, int(round(50 + (score-50)*0.9))))
            short_p = 100 - long_p
        else:
            short_p = max(5, min(95, int(round(50 + (score-50)*0.9))))
            long_p = 100 - short_p


        # Probability correction under weak confirmation.
        # Keep the directional edge aligned with structural/institutional bias,
        # but compress the advantage toward 50/50 when confirmation is poor.
        try:
            if "weak_volume" in risk_flags_inst:
                fav = float(long_p if bias == "LONG" else short_p)
                fav = 50.0 + max(0.0, fav - 50.0) * 0.45
                fav = max(50.0, min(65.0, fav))
                if bias == "LONG":
                    long_p = int(round(fav))
                    short_p = 100 - long_p
                else:
                    short_p = int(round(fav))
                    long_p = 100 - short_p
            if "rr_too_low" in risk_flags_inst:
                fav = float(long_p if bias == "LONG" else short_p)
                fav = 50.0 + max(0.0, fav - 50.0) * 0.70
                fav = max(50.0, min(75.0, fav))
                if bias == "LONG":
                    long_p = int(round(fav))
                    short_p = 100 - long_p
                else:
                    short_p = int(round(fav))
                    long_p = 100 - short_p
            long_p = max(1, min(99, int(long_p)))
            short_p = 100 - long_p
        except Exception:
            pass

        phase = '—'
        try:
            adxv = float(adx_reg_i)
            if adxv < 18: phase = 'ACCUMULATION' if float(vol_rel) < 1.0 else 'RANGE'
            elif adxv < 28: phase = 'MARKUP' if bias=='LONG' else 'MARKDOWN'
            else: phase = 'EXPANSION'
            if isinstance(div_txt, str) and any(tok in div_txt.lower() for tok in ('диверг', 'diverg')) and adxv >= 30: phase = 'LATE_TREND'
        except Exception:
            phase = '—'
    except Exception:
        vp = vb = ofp = whale = liqcls = None
        score = None
        phase = '—'

    # Bias text
    bias_txt = _tr_i18n(lang, "analysis_bias_long") if bias == "LONG" else _tr_i18n(lang, "analysis_bias_short")
    conf_txt = conf_inst_txt if (score is not None and conf_inst_txt) else (("Высокая" if confidence in ("HIGH", "Высокая") else ("Средняя" if confidence in ("MED", "Средняя") else "Низкая")) if is_ru else ("High" if confidence in ("HIGH", "Высокая") else ("Medium" if confidence in ("MED", "Средняя") else "Low")))

    def _loc_conf(v: str) -> str:
        vv = str(v or "").strip().lower()
        if vv in ("высокая", "high"):
            return _tr_i18n(lang, "analysis_conf_high")
        if vv in ("средняя", "medium", "med"):
            return _tr_i18n(lang, "analysis_conf_medium")
        return _tr_i18n(lang, "analysis_conf_low")

    def _loc_trade_status(v: str) -> str:
        vv = str(v or "").strip().upper()
        return _tr_i18n(lang, "analysis_trade_status_no_trade") if vv == "NO TRADE" else _tr_i18n(lang, "analysis_trade_status_ok")

    def _clean_key(v: str) -> str:
        return re.sub(r"\s+", " ", str(v or "").replace("_", " ")).strip()

    def _join_nonempty(items):
        return ", ".join([str(x) for x in items if str(x or "").strip() and str(x).strip() not in ("—", "-")]) or "—"

    def _pick_level(candidates, *, side: str, ref: float, skip: set[float] | None = None):
        skip = skip or set()
        vals = []
        for v in candidates:
            try:
                fv = float(v)
            except Exception:
                continue
            if not (fv == fv) or fv <= 0:
                continue
            if any(abs(fv - s) <= max(1e-9, abs(ref) * 0.0005) for s in skip):
                continue
            if side == "below" and fv < ref:
                vals.append(fv)
            elif side == "above" and fv > ref:
                vals.append(fv)
        if not vals:
            return None
        return max(vals) if side == "below" else min(vals)

    def _fmt_lvl_or_dash(v):
        try:
            return _fmt_int_space(float(v))
        except Exception:
            return "—"

    def _stable_unique_levels(vals):
        out = []
        for v in vals or []:
            try:
                fv = float(v)
            except Exception:
                continue
            if not (fv == fv) or fv <= 0:
                continue
            if not any(abs(fv - ex) <= max(1e-9, abs(fv) * 1e-6) for ex in out):
                out.append(fv)
        return sorted(out)

    def _stable_swing_levels(_df, *, tail_n: int, left: int = 3, right: int = 3):
        try:
            if _df is None or getattr(_df, "empty", True) or len(_df) < (left + right + 10):
                return [], []
            src = _df.tail(max(tail_n, left + right + 10)).reset_index(drop=True)
            _sh, _sl = _swing_points(src, left=left, right=right)
            hi = _stable_unique_levels([p for _, p in _sh])
            lo = _stable_unique_levels([p for _, p in _sl])
            return hi, lo
        except Exception:
            return [], []

    anchor_hi_1h, anchor_lo_1h = _stable_swing_levels(
        df1 if (df1 is not None and not getattr(df1, "empty", True) and len(df1) >= 60) else None,
        tail_n=120,
        left=3,
        right=3,
    )
    anchor_hi_4h, anchor_lo_4h = _stable_swing_levels(
        df4 if (df4 is not None and not getattr(df4, "empty", True) and len(df4) >= 30) else None,
        tail_n=45,
        left=2,
        right=2,
    )
    anchor_hi_pool = _stable_unique_levels((anchor_hi_4h or []) + (anchor_hi_1h or []))
    anchor_lo_pool = _stable_unique_levels((anchor_lo_4h or []) + (anchor_lo_1h or []))
    anchor_support_near = _pick_level(anchor_lo_pool, side="below", ref=float(price))
    anchor_support_deep = _pick_level(
        anchor_lo_pool,
        side="below",
        ref=float(anchor_support_near if anchor_support_near is not None else price),
        skip={float(anchor_support_near)} if anchor_support_near is not None else None,
    )
    anchor_resist_near = _pick_level(anchor_hi_pool, side="above", ref=float(price))
    anchor_resist_high = _pick_level(
        anchor_hi_pool,
        side="above",
        ref=float(anchor_resist_near if anchor_resist_near is not None else price),
        skip={float(anchor_resist_near)} if anchor_resist_near is not None else None,
    )

    local_support_lvl = _pick_level([
        anchor_support_near,
        support1, chan_support,
        (vp_sess.get('val') if isinstance(vp_sess, dict) else None),
        (vb.get('bands', {}).get('-1.0') if isinstance(vb, dict) else None),
    ], side="below", ref=float(price))
    local_resist_lvl = _pick_level([
        anchor_resist_near,
        pivot,
        (vb.get('vwap') if isinstance(vb, dict) else None),
        (vb.get('bands', {}).get('+1.0') if isinstance(vb, dict) else None),
        entry_lo,
        resistance1,
    ], side="above", ref=float(price))
    deeper_support_lvl = _pick_level([
        anchor_support_deep,
        support2, support1, chan_support,
        (vp.get('val') if isinstance(vp, dict) else None),
        (vp_sess.get('val') if isinstance(vp_sess, dict) else None),
    ], side="below", ref=float(local_support_lvl if local_support_lvl is not None else price), skip={float(local_support_lvl)} if local_support_lvl is not None else None)
    higher_resist_lvl = _pick_level([
        anchor_resist_high,
        entry_hi, resistance1, resistance2, chan_resist,
        (vp.get('vah') if isinstance(vp, dict) else None),
        (vp_sess.get('vah') if isinstance(vp_sess, dict) else None),
    ], side="above", ref=float(local_resist_lvl if local_resist_lvl is not None else price), skip={float(local_resist_lvl)} if local_resist_lvl is not None else None)

    local_support_s = _fmt_lvl_or_dash(local_support_lvl if local_support_lvl is not None else support1)
    local_resist_s = _fmt_lvl_or_dash(local_resist_lvl if local_resist_lvl is not None else pivot)
    deeper_support_s = _fmt_lvl_or_dash(deeper_support_lvl if deeper_support_lvl is not None else support2)
    higher_resist_s = _fmt_lvl_or_dash(higher_resist_lvl if higher_resist_lvl is not None else resistance1)
    entry_lo_s = _fmt_lvl_or_dash(entry_lo)
    entry_hi_s = _fmt_lvl_or_dash(entry_hi)

    if bias == "LONG":
        bullish_lines = [
            (f"Удержание {local_support_s} / возврат выше {local_resist_s} → {higher_resist_s}" if is_ru else f"Hold {local_support_s} / reclaim {local_resist_s} → {higher_resist_s}"),
            (f"Закрепление выше {higher_resist_s} → {r2_s}" if is_ru else f"Break and hold above {higher_resist_s} → {r2_s}"),
        ]
        bearish_lines = [
            (f"Потеря {local_support_s} → {deeper_support_s}" if is_ru else f"Loss of {local_support_s} → {deeper_support_s}"),
            (f"Потеря {deeper_support_s} → {s2_s}" if (is_ru and deeper_support_s not in ("—", s2_s)) else (f"Loss of {deeper_support_s} → {s2_s}" if (not is_ru and deeper_support_s not in ("—", s2_s)) else None)),
        ]
        bearish_lines = [x for x in bearish_lines if x]
        primary_scenario = _tr_i18n(lang, "analysis_primary_long")
    else:
        bullish_lines = [
            (f"Удержание {local_support_s} / возврат выше {local_resist_s} → {entry_lo_s if entry_lo_s != '—' else higher_resist_s}" if is_ru else f"Hold {local_support_s} / reclaim {local_resist_s} → {entry_lo_s if entry_lo_s != '—' else higher_resist_s}"),
            (f"Закрепление выше {entry_hi_s if entry_hi_s != '—' else higher_resist_s} → {r2_s}" if is_ru else f"Break and hold above {entry_hi_s if entry_hi_s != '—' else higher_resist_s} → {r2_s}"),
        ]
        bearish_lines = [
            (f"Потеря {local_support_s} → {deeper_support_s}" if is_ru else f"Loss of {local_support_s} → {deeper_support_s}"),
            (f"Потеря {deeper_support_s} → {s2_s}" if (is_ru and deeper_support_s not in ("—", s2_s)) else (f"Loss of {deeper_support_s} → {s2_s}" if (not is_ru and deeper_support_s not in ("—", s2_s)) else None)),
        ]
        bearish_lines = [x for x in bearish_lines if x]
        primary_scenario = _tr_i18n(lang, "analysis_primary_short")

    resistance_txt = f"{r1_s} / {r2_s}"
    support_txt = f"{s1_s} / {s2_s}"
    channel_txt = f"{chan_s_s} — {chan_r_s}" if chan_s_s not in ("—", "-") and chan_r_s not in ("—", "-") else "—"
    liq_eqh_txt = eq_hi_line.replace("Equal Highs: ", "").replace("EQH: ", "") if isinstance(eq_hi_line, str) else "—"
    liq_magnet_txt = magnet_txt.replace("Magnet: ", "") if isinstance(magnet_txt, str) else "—"
    ob_txt = (f"{_fmt_int_space(ob_lo)} – {_fmt_int_space(ob_hi)}" if (ob_lo is not None and ob_hi is not None) else "—")
    bos_txt = _tr_i18n(lang, "analysis_bos_bull") if (isinstance(smc_event, str) and "bos" in smc_event.lower() and ("вверх" in smc_event.lower() or "↑" in smc_event)) else (_tr_i18n(lang, "analysis_bos_bear") if (isinstance(smc_event, str) and "bos" in smc_event.lower()) else "—")
    fvg_short_txt = (f"{_fmt_int_space(fvg_lo)} – {_fmt_int_space(fvg_hi)}" + (f" ({_tr_i18n(lang, 'analysis_active')})" if fvg_active else "")) if (fvg_lo is not None and fvg_hi is not None) else "—"

    risk_flags_txt = _join_nonempty([_tr_i18n(lang, f"analysis_risk_flag_{_clean_key(x).replace(' ', '_')}") if _clean_key(x).replace(' ', '_') in {
        'rr_too_low','weak_volume','trend_exhaustion'
    } else _clean_key(x) for x in (risk_flags_inst or [])])

    ob_state = _tr_i18n(lang, "analysis_conclusion_ob_present") if ob_txt not in ("—", "-") else _tr_i18n(lang, "analysis_conclusion_ob_absent")
    fvg_state = _tr_i18n(lang, "analysis_conclusion_fvg_active") if (fvg_lo is not None and fvg_hi is not None and fvg_active) else (_tr_i18n(lang, "analysis_conclusion_fvg_present") if (fvg_lo is not None and fvg_hi is not None) else _tr_i18n(lang, "analysis_conclusion_fvg_absent"))
    concl = [
        _tr_i18n(lang, "analysis_conclusion_market_phase", phase=str(phase or "—"), regime=str(regime or "—")),
        _tr_i18n(lang, "analysis_conclusion_structure", structure=str(struct_lbl or "—"), bias=str(bias_txt or "—")),
        _tr_i18n(lang, "analysis_conclusion_ob", status=ob_state),
        _tr_i18n(lang, "analysis_conclusion_fvg", status=fvg_state),
    ]

    report_lines = [
        _tr_i18n(lang, "analysis_header", symbol=sym, market=mkt_label),
        _tr_i18n(lang, "analysis_price_line", price=price_s),
        "",
        line,
        _tr_i18n(lang, "analysis_section_structure"),
        "",
        _tr_i18n(lang, "analysis_tf_4h", value=trend4),
        _tr_i18n(lang, "analysis_tf_1h", value=trend1),
        _tr_i18n(lang, "analysis_tf_5m", value=trend5),
        _tr_i18n(lang, "analysis_structure_line", value=struct_lbl),
        _tr_i18n(lang, "analysis_regime_line", regime=regime, adx=adx_reg_i),
        "",
        line,
        _tr_i18n(lang, "analysis_section_momentum_volume"),
        "",
        _tr_i18n(lang, "analysis_rsi_line", value=rsi_i, mood=rsi_mood),
        _tr_i18n(lang, "analysis_macd_line", value=macd_mood),
        _tr_i18n(lang, "analysis_ema20_line", value=slope_txt),
        _tr_i18n(lang, "analysis_volume_line", value=vol_rel_txt),
        "",
        line,
        _tr_i18n(lang, "analysis_section_levels"),
        "",
        _tr_i18n(lang, "analysis_resistance_line", value=resistance_txt),
        _tr_i18n(lang, "analysis_support_line", value=support_txt),
        _tr_i18n(lang, "analysis_pivot_line", value=piv_s),
        _tr_i18n(lang, "analysis_channel_line", value=channel_txt),
        "",
        line,
        _tr_i18n(lang, "analysis_section_liquidity"),
        "",
        _tr_i18n(lang, "analysis_eqh_line", value=liq_eqh_txt),
        _tr_i18n(lang, "analysis_magnet_line", value=liq_magnet_txt),
        _tr_i18n(lang, "analysis_sweep_line", value=("да" if lang.startswith('ru') else "yes") if (sweep_long or sweep_short) else ("нет" if lang.startswith('ru') else "no")),
        "",
        line,
        _tr_i18n(lang, "analysis_section_smc"),
        "",
        _tr_i18n(lang, "analysis_ob_line", value=ob_txt),
        _tr_i18n(lang, "analysis_bos_line", value=bos_txt),
        _tr_i18n(lang, "analysis_fvg_line", value=fvg_short_txt),
        "",
        line,
        _tr_i18n(lang, "analysis_section_institutional"),
        "",
        _tr_i18n(lang, "analysis_market_phase_line", value=phase),
        _tr_i18n(lang, "analysis_inst_score_line", value=(f"{score}/100" if score is not None else "—")),
        _tr_i18n(lang, "analysis_orderflow_line", value=(f"{ofp['mood']} | {ofp['index']}/100" if ofp else "—")),
        _tr_i18n(lang, "analysis_vwap_line", value=(f"{_fmt_int_space(vb['vwap'])} | ±1σ: {_fmt_int_space(vb['bands']['-1.0'])} – {_fmt_int_space(vb['bands']['+1.0'])}" if vb else "—")),
        _tr_i18n(lang, "analysis_session_vp_line", value=(f"POC { _fmt_int_space(vp_sess['poc']) } | VAH { _fmt_int_space(vp_sess['vah']) } | VAL { _fmt_int_space(vp_sess['val']) }" if vp_sess else "—")),
        _tr_i18n(lang, "analysis_voids_line", value=(("5m: " + "; ".join([f"{z['side']} {_fmt_int_space(z['lo'])}–{_fmt_int_space(z['hi'])}" for z in voids_5m])) if voids_5m else "—")),
        "",
        line,
        _tr_i18n(lang, "analysis_section_probability"),
        "",
        _tr_i18n(lang, "analysis_long_prob_line", value=f"{long_p}%"),
        _tr_i18n(lang, "analysis_short_prob_line", value=f"{short_p}%"),
        _tr_i18n(lang, "analysis_priority_line", value=bias_txt),
        _tr_i18n(lang, "analysis_confidence_line", value=_loc_conf(conf_txt)),
        "",
        line,
        _tr_i18n(lang, "analysis_section_trade_plan"),
        "",
        _tr_i18n(lang, "analysis_trade_status_line", value=_loc_trade_status(trade_status_inst if trade_status_inst else '—')),
        _tr_i18n(lang, "analysis_entry_line", value=entry_zone_txt),
        _tr_i18n(lang, "analysis_trigger_title"),
        str(entry_trigger_txt),
        _tr_i18n(lang, "analysis_invalidation_title"),
        str(entry_inval_txt),
        "",
        _tr_i18n(lang, "analysis_sl_line", value=sl_s),
        _tr_i18n(lang, "analysis_tp1_line", value=f"{tp1_s} ({_tr_i18n(lang, 'analysis_rr_short', value=rr1_txt)})"),
        _tr_i18n(lang, "analysis_tp2_line", value=f"{tp2_s} ({_tr_i18n(lang, 'analysis_rr_short', value=rr2_txt)})"),
        "",
        line,
        _tr_i18n(lang, "analysis_section_conclusion"),
        "",
        *concl,
        "",
        _tr_i18n(lang, "analysis_primary_line", value=primary_scenario),
        _tr_i18n(lang, "analysis_preference_line", value=bias),
    ]
    report = "\n".join([x for x in report_lines if x is not None])

    def _is_valid_level(v):
        try:
            fv = float(v)
        except Exception:
            return False
        return fv == fv and fv > 0

    def _clean_level(v):
        try:
            fv = float(v)
        except Exception:
            return None
        return fv if (fv == fv and fv > 0) else None

    def _dedupe_levels(*values):
        out = []
        for v in values:
            seq = list(v) if isinstance(v, (list, tuple, set)) else [v]
            for item in seq:
                fv = _clean_level(item)
                if fv is None:
                    continue
                if not any(abs(fv - ex) <= max(1e-9, abs(ex) * 1e-6) for ex in out):
                    out.append(fv)
        return out

    def _fmt_range(lo, hi):
        vals = _dedupe_levels(lo, hi)
        if len(vals) >= 2:
            lo_v, hi_v = min(vals), max(vals)
            if hi_v > lo_v:
                lo_s = _fmt_int_space(lo_v)
                hi_s = _fmt_int_space(hi_v)
                if lo_s != hi_s:
                    return f"{lo_s} – {hi_s}"

                av = max(abs(lo_v), abs(hi_v))
                if av >= 1000:
                    start_nd = 1
                elif av >= 100:
                    start_nd = 3
                elif av >= 1:
                    start_nd = 4
                elif av >= 0.1:
                    start_nd = 5
                elif av >= 0.01:
                    start_nd = 6
                else:
                    start_nd = 7

                for nd in range(start_nd, 9):
                    lo_s = _fmt_float(lo_v, nd)
                    hi_s = _fmt_float(hi_v, nd)
                    if lo_s != hi_s:
                        return f"{lo_s} – {hi_s}"
                return lo_s
        if len(vals) == 1:
            return _fmt_int_space(vals[0])
        return "—"

    def _first_above(ref, *groups):
        rv = _clean_level(ref)
        cands = sorted(_dedupe_levels(*groups))
        if rv is None:
            return cands[0] if cands else None
        for v in cands:
            if v > rv + max(1e-9, abs(rv) * 1e-6):
                return v
        return None

    def _first_below(ref, *groups):
        rv = _clean_level(ref)
        cands = sorted(_dedupe_levels(*groups), reverse=True)
        if rv is None:
            return cands[0] if cands else None
        for v in cands:
            if v < rv - max(1e-9, abs(rv) * 1e-6):
                return v
        return None

    def _fmt_tp_chain(*values):
        ordered = []
        for v in values:
            fv = _clean_level(v)
            if fv is None:
                continue
            if not any(abs(fv - ex) <= max(1e-9, abs(ex) * 1e-6) for ex in ordered):
                ordered.append(fv)
        return " / ".join(_fmt_int_space(v) for v in ordered) if ordered else "—"

    def _buffer_from(anchor, *, pct=0.0035, atr_mult=0.35, minimum=0.0):
        av = _clean_level(anchor)
        if av is None:
            av = float(price) if _is_valid_level(price) else 0.0
        try:
            atr_part = float(atr_abs) * float(atr_mult)
        except Exception:
            atr_part = 0.0
        pct_part = av * float(pct)
        return max(float(minimum), atr_part, pct_part)

    def _level_plus(anchor, *, pct=0.0035, atr_mult=0.35, minimum=0.0):
        av = _clean_level(anchor)
        if av is None:
            return None
        return av + _buffer_from(av, pct=pct, atr_mult=atr_mult, minimum=minimum)

    def _level_minus(anchor, *, pct=0.0035, atr_mult=0.35, minimum=0.0):
        av = _clean_level(anchor)
        if av is None:
            return None
        out = av - _buffer_from(av, pct=pct, atr_mult=atr_mult, minimum=minimum)
        return out if out > 0 else None

    session_vah = None
    session_val = None
    try:
        if isinstance(vp_sess, dict):
            session_vah = _clean_level(vp_sess.get('vah'))
            session_val = _clean_level(vp_sess.get('val'))
    except Exception:
        session_vah = None
        session_val = None

    low_conf = str(conf_txt or '').strip().lower() in ('низкая', 'low')
    try:
        weak_volume_now = float(vol_rel) < 0.5
    except Exception:
        weak_volume_now = True
    scenarios_wait = bool(low_conf or weak_volume_now or entry_status in ('WAIT', 'READY', 'INVALID'))
    scenario_hard_anchor = str(os.getenv("SCENARIO_STABLE_HARD_ANCHOR", "1") or "1").strip().lower() not in ("0", "false", "no", "off")

    entry_zone_lo = _clean_level(entry_lo) or _first_below(price, local_resist_lvl, higher_resist_lvl, resistance1)
    entry_zone_hi = _clean_level(entry_hi) or _first_above(entry_zone_lo or price, local_resist_lvl, higher_resist_lvl, resistance1)
    scenario_entry_zone = _fmt_range(entry_zone_lo, entry_zone_hi)
    entry_zone_width = 0.0
    try:
        if entry_zone_lo is not None and entry_zone_hi is not None and entry_zone_hi > entry_zone_lo:
            entry_zone_width = max(0.0, float(entry_zone_hi) - float(entry_zone_lo))
    except Exception:
        entry_zone_width = 0.0

    if scenario_hard_anchor:
        try:
            stable_zone_cap = max(float(atr_abs) * 1.8, float(price) * 0.0045)
        except Exception:
            stable_zone_cap = max(float(price) * 0.0045, 0.0)
        try:
            snap_tol = max(float(atr_abs) * 1.25, float(price) * 0.0045)
        except Exception:
            snap_tol = max(float(price) * 0.0045, 0.0)
        anchor_hi_ref = _clean_level(anchor_resist_near) or _clean_level(higher_resist_lvl) or _clean_level(local_resist_lvl)
        anchor_lo_ref = _clean_level(anchor_support_near) or _clean_level(local_support_lvl)
        if anchor_hi_ref is not None and (entry_zone_hi is None or abs(float(entry_zone_hi) - float(anchor_hi_ref)) <= snap_tol):
            entry_zone_hi = float(anchor_hi_ref)
        if entry_zone_hi is not None:
            base_lo = _clean_level(entry_zone_lo)
            if anchor_lo_ref is not None:
                base_lo = max(float(anchor_lo_ref), float(entry_zone_hi) - float(stable_zone_cap))
            elif base_lo is None:
                base_lo = float(entry_zone_hi) - float(stable_zone_cap)
            if base_lo is not None and float(entry_zone_hi) > float(base_lo):
                entry_zone_lo = float(base_lo)
        scenario_entry_zone = _fmt_range(entry_zone_lo, entry_zone_hi)
        try:
            if entry_zone_lo is not None and entry_zone_hi is not None and entry_zone_hi > entry_zone_lo:
                entry_zone_width = max(0.0, float(entry_zone_hi) - float(entry_zone_lo))
        except Exception:
            entry_zone_width = 0.0

    # Trigger-based retest shorts should invalidate just above the rejection/zone,
    # not at a distant structural resistance. This keeps scenario SL logical after
    # BOS confirmation and prevents very wide, unrealistic stop placement.
    short_retest_sl = _clean_level(inv_lvl_out)
    short_retest_sl_cap = _level_plus(
        entry_zone_hi or price,
        pct=0.0045,
        atr_mult=0.35,
        minimum=max(entry_zone_width * 1.2, _buffer_from(entry_zone_hi or price, pct=0.0025, atr_mult=0.2)),
    )
    short_retest_sl_tight = _level_plus(
        entry_zone_hi or price,
        pct=0.0022,
        atr_mult=0.18,
        minimum=max(entry_zone_width * 0.55, _buffer_from(entry_zone_hi or price, pct=0.0012, atr_mult=0.08)),
    )
    if short_retest_sl is None or (short_retest_sl_cap is not None and short_retest_sl > short_retest_sl_cap):
        short_retest_sl = short_retest_sl_tight or short_retest_sl_cap or _first_above(entry_zone_hi or price, higher_resist_lvl, resistance1, eq_hi)
    if short_retest_sl is None:
        short_retest_sl = _level_plus(entry_zone_hi or price, pct=0.0032, atr_mult=0.28, minimum=max(entry_zone_width * 0.8, 0.0))

    eqh_level = _clean_level(eq_hi) or _first_above(entry_zone_hi or price, resistance1, higher_resist_lvl)
    sweep_zone_hi = eqh_level or _first_above(entry_zone_hi or price, resistance1, higher_resist_lvl, resistance2)
    sweep_zone_lo = None
    if sweep_zone_hi is not None:
        sweep_zone_lo = _level_minus(sweep_zone_hi, pct=0.003, atr_mult=0.18, minimum=((sweep_zone_hi - (entry_zone_hi or sweep_zone_hi)) * 0.25 if entry_zone_hi is not None and sweep_zone_hi > entry_zone_hi else 0.0))
        if sweep_zone_lo is not None and entry_zone_hi is not None and sweep_zone_lo < entry_zone_hi:
            sweep_zone_lo = max(entry_zone_hi, sweep_zone_hi - max((sweep_zone_hi - entry_zone_hi) * 0.25, _buffer_from(sweep_zone_hi, pct=0.002, atr_mult=0.12)))
    scenario_short_sweep_zone = _fmt_range(sweep_zone_lo, sweep_zone_hi)

    sweep_width = 0.0
    try:
        if _clean_level(sweep_zone_lo) is not None and _clean_level(sweep_zone_hi) is not None:
            sweep_width = max(0.0, float(sweep_zone_hi) - float(sweep_zone_lo))
    except Exception:
        sweep_width = 0.0
    short_sweep_sl_lo = _clean_level(inv_lvl_out)
    if short_sweep_sl_lo is None:
        short_sweep_sl_lo = _level_plus(
            sweep_zone_hi or price,
            pct=0.008,
            atr_mult=0.75,
            minimum=max(sweep_width * 1.6, _buffer_from(sweep_zone_hi or price, pct=0.005, atr_mult=0.4)),
        )
    short_sweep_sl_hi = _level_plus(
        short_sweep_sl_lo or sweep_zone_hi or price,
        pct=0.0045,
        atr_mult=0.5,
        minimum=max(sweep_width * 0.9, _buffer_from(short_sweep_sl_lo or sweep_zone_hi or price, pct=0.003, atr_mult=0.25)),
    )
    if short_sweep_sl_hi is not None and short_sweep_sl_lo is not None and short_sweep_sl_hi <= short_sweep_sl_lo:
        short_sweep_sl_hi = _level_plus(short_sweep_sl_lo, pct=0.003, atr_mult=0.25, minimum=max(sweep_width * 0.6, 0.0))
    scenario_short_sweep_sl = _fmt_range(short_sweep_sl_lo, short_sweep_sl_hi)

    short_break_entry = _clean_level(local_support_lvl) or _first_below(price, support1, deeper_support_lvl, session_val)
    short_break_cap = _first_above(short_break_entry or price, pivot, entry_zone_lo, entry_zone_hi, local_resist_lvl)
    short_break_sl_lo = None
    short_break_sl_hi = None
    if short_break_cap is not None and short_break_entry is not None and short_break_cap > short_break_entry:
        short_break_span = float(short_break_cap) - float(short_break_entry)
        short_break_sl_lo = float(short_break_entry) + (short_break_span * 0.55)
        short_break_sl_hi = float(short_break_entry) + (short_break_span * 0.8)
    else:
        short_break_sl_lo = _level_plus(
            short_break_entry or price,
            pct=0.004,
            atr_mult=0.35,
            minimum=_buffer_from(short_break_entry or price, pct=0.0025, atr_mult=0.2),
        )
        short_break_sl_hi = _level_plus(
            short_break_sl_lo or short_break_entry or price,
            pct=0.0025,
            atr_mult=0.2,
            minimum=_buffer_from(short_break_sl_lo or short_break_entry or price, pct=0.0015, atr_mult=0.12),
        )
    if short_break_sl_hi is not None and short_break_sl_lo is not None and short_break_sl_hi <= short_break_sl_lo:
        short_break_sl_hi = _level_plus(short_break_sl_lo, pct=0.002, atr_mult=0.15, minimum=0.0)
    scenario_short_break_sl = _fmt_range(short_break_sl_lo, short_break_sl_hi) if short_break_sl_hi is not None else _fmt_int_space(short_break_sl_lo) if short_break_sl_lo is not None else '—'

    short_tp1 = _clean_level(local_support_lvl) or _first_below(entry_zone_lo or price, session_val, support1)
    short_tp2 = _clean_level(deeper_support_lvl) or _first_below(short_tp1 or entry_zone_lo or price, support1, support2)
    short_tp3 = _first_below(short_tp2 or short_tp1 or price, support1, support2)
    if short_tp3 is None:
        short_tp3 = _clean_level(support2)

    # Confirmed reclaim longs should invalidate on loss of the reclaimed zone,
    # not on a deep support far below the trigger. Cap SL depth to keep the
    # scenario usable after hold-above + BOS confirmation.
    long_reclaim_sl = _clean_level(local_resist_lvl) or _clean_level(entry_zone_lo)
    long_reclaim_sl_floor = _level_minus(
        entry_zone_lo or price,
        pct=0.0045,
        atr_mult=0.35,
        minimum=max(entry_zone_width * 1.2, _buffer_from(entry_zone_lo or price, pct=0.0025, atr_mult=0.2)),
    )
    _deep_long_reclaim_sl = _first_below(entry_zone_lo or price, local_resist_lvl, session_val, support1, deeper_support_lvl)
    if _deep_long_reclaim_sl is not None and (long_reclaim_sl_floor is None or _deep_long_reclaim_sl >= long_reclaim_sl_floor):
        long_reclaim_sl = _deep_long_reclaim_sl
    if long_reclaim_sl is None:
        long_reclaim_sl = _level_minus(
            entry_zone_lo or price,
            pct=0.0022,
            atr_mult=0.18,
            minimum=max(entry_zone_width * 0.55, _buffer_from(entry_zone_lo or price, pct=0.0012, atr_mult=0.08)),
        )

    long_tp1 = _first_above(entry_zone_hi or price, session_vah, higher_resist_lvl, resistance1)
    long_tp2 = _first_above(long_tp1 or entry_zone_hi or price, eqh_level, higher_resist_lvl, resistance1, resistance2)
    long_tp3 = _first_above(long_tp2 or long_tp1 or entry_zone_hi or price, resistance2)
    if long_tp3 is None:
        long_tp3 = _first_above(long_tp2 or long_tp1 or entry_zone_hi or price, resistance2, eqh_level)

    bounce_zone_lo = _clean_level(deeper_support_lvl) or _first_below(price, support1, support2, session_val)
    bounce_zone_hi = _clean_level(local_support_lvl) or _first_above(bounce_zone_lo or price, session_val, entry_zone_lo, pivot)
    scenario_long_bounce_entry = _fmt_range(bounce_zone_lo, bounce_zone_hi)
    long_bounce_sl = _clean_level(deeper_support_lvl) or _first_below(bounce_zone_lo or price, support1, support2)
    long_bounce_tp1 = _first_above(bounce_zone_hi or price, local_resist_lvl, entry_zone_lo, entry_zone_hi, session_vah)
    long_bounce_tp2 = _first_above(long_bounce_tp1 or bounce_zone_hi or price, entry_zone_hi, higher_resist_lvl, resistance1)
    long_bounce_tp3 = _first_above(long_bounce_tp2 or long_bounce_tp1 or bounce_zone_hi or price, eqh_level, resistance1, resistance2)

    discount_zone_lo = _clean_level(support2) or _first_below(bounce_zone_lo or price, support1, deeper_support_lvl)
    discount_zone_hi = _clean_level(deeper_support_lvl) or _clean_level(support1) or _first_above(discount_zone_lo or price, bounce_zone_lo, bounce_zone_hi)
    scenario_long_discount_zone = _fmt_range(discount_zone_lo, discount_zone_hi)
    long_discount_sl = _level_minus(discount_zone_lo or price, pct=0.002, atr_mult=0.15)
    long_discount_tp1 = _clean_level(local_support_lvl) or _first_above(discount_zone_hi or price, bounce_zone_hi, session_val)
    long_discount_tp2 = _clean_level(local_resist_lvl) or _first_above(long_discount_tp1 or discount_zone_hi or price, entry_zone_lo, entry_zone_hi)
    long_discount_tp3 = _clean_level(entry_zone_hi) or _first_above(long_discount_tp2 or long_discount_tp1 or discount_zone_hi or price, higher_resist_lvl)

    scenario_eqh = _fmt_int_space(eqh_level) if eqh_level is not None else '—'
    scenario_eql_source = _clean_level(eq_lo) or bounce_zone_lo or discount_zone_hi
    scenario_eql = _fmt_int_space(scenario_eql_source) if scenario_eql_source is not None else '—'
    scenario_short_break_entry = _fmt_int_space(short_break_entry) if short_break_entry is not None else '—'

    status_title = "Статус сценариев" if is_ru else "Scenario status"
    status_value = "WAIT / NO TRADE" if scenarios_wait else ("SETUP WATCH" if entry_status in ('WAIT', 'READY') else entry_status_txt)
    reason_title = "Комментарий" if is_ru else "Comment"
    reasons = []
    if low_conf:
        reasons.append("низкая уверенность" if is_ru else "low confidence")
    if weak_volume_now:
        reasons.append(("объем ниже нормы" if is_ru else "volume below normal") + f" ({vol_rel_txt})")
    if entry_status in ('WAIT', 'READY'):
        reasons.append("нужен триггер" if is_ru else "trigger still required")
    if entry_status == 'INVALID':
        reasons.append("идея сейчас неактуальна" if is_ru else "setup invalid right now")
    scenario_comment = "; ".join(reasons) if reasons else ("можно отслеживать триггер" if is_ru else "watch for trigger")

    def _dedupe_levels(values, *, direction=None):
        out = []
        for raw in values:
            v = _clean_level(raw)
            if v is None:
                continue
            if any(abs(v - prev) <= max(1e-12, abs(prev) * 0.0008) for prev in out):
                continue
            out.append(v)
        if direction == 'asc':
            out = sorted(out)
        elif direction == 'desc':
            out = sorted(out, reverse=True)
        return out

    def _fmt_tp_values(values, *, direction=None):
        vals = _dedupe_levels(values, direction=direction)
        return _fmt_tp_chain(*vals) if vals else '—'

    def _rr_target_ladder(entry_ref, sl, values, *, direction, rr_steps=(1.0, 2.0, 3.0)):
        vals = _dedupe_levels(values, direction=direction)
        entry_v = _clean_level(entry_ref)
        sl_v = _clean_level(sl)
        if entry_v is None or sl_v is None:
            return vals[:3]
        risk = abs(float(entry_v) - float(sl_v))
        if risk <= 0:
            return vals[:3]
        try:
            atr_unit = max(float(atr_abs), abs(float(entry_v)) * 0.0025, 1e-9)
        except Exception:
            atr_unit = max(abs(float(entry_v)) * 0.0025, 1e-9)
        sign = 1.0 if direction == 'asc' else -1.0
        candidates = list(vals)
        for idx, rr in enumerate(rr_steps, start=1):
            floor_move = max(risk * float(rr), atr_unit * (0.9 + 0.7 * idx))
            candidates.append(float(entry_v) + sign * floor_move)
        ordered = _dedupe_levels(candidates, direction=direction)
        ladder = []
        for idx, rr in enumerate(rr_steps, start=1):
            threshold = float(entry_v) + sign * max(risk * float(rr), atr_unit * (0.9 + 0.7 * idx))
            chosen = None
            if direction == 'asc':
                for v in ordered:
                    if float(v) >= threshold:
                        chosen = float(v)
                        break
            else:
                for v in ordered:
                    if float(v) <= threshold:
                        chosen = float(v)
                        break
            if chosen is None:
                chosen = threshold
            ladder.append(chosen)
        return _dedupe_levels(ladder, direction=direction)

    def _filter_targets_by_rr(entry_ref, sl, values, *, direction, min_rr_first=0.0):
        vals = _dedupe_levels(values, direction=direction)
        entry_v = _clean_level(entry_ref)
        sl_v = _clean_level(sl)
        if entry_v is None or sl_v is None:
            return vals
        risk = abs(float(entry_v) - float(sl_v))
        if risk <= 0:
            return vals
        kept = []
        for tp in vals:
            reward = (float(tp) - float(entry_v)) if direction == 'asc' else (float(entry_v) - float(tp))
            if reward <= 0:
                continue
            rr_now = reward / risk if risk > 0 else 0.0
            if not kept and rr_now < float(min_rr_first):
                continue
            kept.append(float(tp))
        if kept:
            return kept
        return vals[-1:] if vals else []

    def _scenario_entry_mid(lo=None, hi=None, entry=None):
        lo_v = _clean_level(lo)
        hi_v = _clean_level(hi)
        entry_v = _clean_level(entry)
        if lo_v is not None and hi_v is not None and hi_v > lo_v:
            return (float(lo_v) + float(hi_v)) / 2.0
        if entry_v is not None:
            return float(entry_v)
        return float(hi_v) if hi_v is not None else (float(lo_v) if lo_v is not None else None)

    def _scenario_rr_max(entry_ref, sl, tp_vals, direction):
        entry_v = _clean_level(entry_ref)
        sl_v = _clean_level(sl)
        vals = _dedupe_levels(tp_vals, direction=direction)
        if entry_v is None or sl_v is None or not vals:
            return 0.0
        risk = abs(float(entry_v) - float(sl_v))
        if risk <= 0:
            return 0.0
        out = 0.0
        for tp in vals:
            reward = (float(tp) - float(entry_v)) if direction == 'asc' else (float(entry_v) - float(tp))
            if reward > 0:
                out = max(out, reward / risk)
        return float(out)

    def _scenario_pack(*, side, title_ru, title_en, entry_text, trigger_ru, trigger_en, sl_ru, sl_en, tp_vals, direction, entry_lo=None, entry_hi=None, entry_ref=None, sl=None, priority=0.0, bucket='near'):
        entry_mid = _scenario_entry_mid(entry_lo, entry_hi, entry_ref)
        dist_abs = abs(float(entry_mid) - float(price)) if entry_mid is not None else 1e18
        dist_pct = dist_abs / max(abs(float(price)), 1e-9) if entry_mid is not None else 1e9
        item = {
            'title_ru': title_ru,
            'title_en': title_en,
            'entry': entry_text,
            'trigger_ru': trigger_ru,
            'trigger_en': trigger_en,
            'sl_ru': sl_ru,
            'sl_en': sl_en,
            'tp': _fmt_tp_values(tp_vals, direction=direction),
            '_side': str(side),
            '_entry_mid': float(entry_mid) if entry_mid is not None else None,
            '_entry_lo': _clean_level(entry_lo),
            '_entry_hi': _clean_level(entry_hi),
            '_entry_ref': _clean_level(entry_ref),
            '_sl': _clean_level(sl),
            '_tp_vals': _dedupe_levels(tp_vals, direction=direction),
            '_rr_max': _scenario_rr_max(entry_ref if entry_ref is not None else entry_mid, sl, tp_vals, direction),
            '_priority': float(priority),
            '_distance_abs': float(dist_abs),
            '_distance_pct': float(dist_pct),
            '_bucket': str(bucket),
        }
        return item

    def _scenario_score(item):
        try:
            dist_pct = float(item.get('_distance_pct') or 1e9)
        except Exception:
            dist_pct = 1e9
        try:
            rr_max = float(item.get('_rr_max') or 0.0)
        except Exception:
            rr_max = 0.0
        try:
            priority = float(item.get('_priority') or 0.0)
        except Exception:
            priority = 0.0
        score = priority + min(2.8, rr_max * 0.45)
        score += max(0.0, 2.6 - dist_pct * 160.0)
        if dist_pct <= 0.0075:
            score += 0.8
        if dist_pct <= 0.0035:
            score += 0.4
        side = str(item.get('_side') or '').lower()
        bias_l = str(bias_txt or '').lower()
        if side == 'long' and any(tok in bias_l for tok in ('long', 'bull', 'buy')):
            score += 0.5
        elif side == 'short' and any(tok in bias_l for tok in ('short', 'bear', 'sell')):
            score += 0.5
        return float(score)

    def _filter_side_scenarios(items, side):
        if not items:
            return []
        ranked = sorted(list(items), key=lambda it: (-_scenario_score(it), float(it.get('_distance_abs') or 1e18)))
        primary = dict(ranked[0])
        primary['contingency'] = False
        out = [primary]
        primary_mid = _clean_level(primary.get('_entry_mid'))
        try:
            far_gap = max(float(atr_abs) * 3.2, float(price) * 0.018)
        except Exception:
            far_gap = max(float(price) * 0.018, 0.0)
        contingency = None
        for cand in ranked[1:]:
            cand_mid = _clean_level(cand.get('_entry_mid'))
            if cand_mid is None:
                continue
            if primary_mid is not None and abs(float(cand_mid) - float(primary_mid)) < far_gap:
                continue
            if float(cand.get('_distance_pct') or 0.0) < 0.014 and str(cand.get('_bucket') or '') != 'deep':
                continue
            contingency = dict(cand)
            contingency['contingency'] = True
            break
        if contingency is not None:
            out.append(contingency)
        return out

    def _resolve_cross_side_conflicts(short_items, long_items):
        if not short_items or not long_items:
            return short_items, long_items
        short_primary = dict(short_items[0])
        long_primary = dict(long_items[0])
        short_mid = _clean_level(short_primary.get('_entry_mid'))
        long_mid = _clean_level(long_primary.get('_entry_mid'))
        if short_mid is None or long_mid is None:
            return short_items, long_items
        try:
            conflict_gap = max(float(atr_abs) * 2.0, float(price) * 0.0075)
        except Exception:
            conflict_gap = max(float(price) * 0.0075, 0.0)
        if abs(float(short_mid) - float(long_mid)) > conflict_gap:
            return short_items, long_items
        short_score = _scenario_score(short_primary)
        long_score = _scenario_score(long_primary)
        keep = 'short' if short_score >= long_score else 'long'
        if abs(short_score - long_score) < 0.35:
            bias_l = str(bias_txt or '').lower()
            if any(tok in bias_l for tok in ('long', 'bull', 'buy')):
                keep = 'long'
            elif any(tok in bias_l for tok in ('short', 'bear', 'sell')):
                keep = 'short'
        if keep == 'short':
            long_items = [it for it in long_items if bool(it.get('contingency'))][:1]
        else:
            short_items = [it for it in short_items if bool(it.get('contingency'))][:1]
        return short_items, long_items

    def _valid_range(lo, hi):
        lo_v = _clean_level(lo)
        hi_v = _clean_level(hi)
        return lo_v is not None and hi_v is not None and hi_v > lo_v

    def _valid_short_range(lo, hi, sl, tps, *, require_near_price=False, require_above=None):
        lo_v = _clean_level(lo)
        hi_v = _clean_level(hi)
        sl_v = _clean_level(sl)
        if lo_v is None or hi_v is None or hi_v <= lo_v:
            return False
        if sl_v is None or sl_v <= hi_v:
            return False
        if require_near_price and hi_v < float(price) * 0.995:
            return False
        if require_above is not None and hi_v <= float(require_above):
            return False
        return any(tp < lo_v for tp in _dedupe_levels(tps, direction='desc'))

    def _valid_short_break(entry, sl, tps, *, require_below_price=True):
        entry_v = _clean_level(entry)
        sl_v = _clean_level(sl)
        if entry_v is None or sl_v is None:
            return False
        if sl_v <= entry_v:
            return False
        if require_below_price and entry_v >= float(price) * 0.999:
            return False
        return any(tp < entry_v for tp in _dedupe_levels(tps, direction='desc'))

    def _valid_long_range(lo, hi, sl, tps, *, require_near_price=False, require_below_price=False, require_below=None):
        lo_v = _clean_level(lo)
        hi_v = _clean_level(hi)
        sl_v = _clean_level(sl)
        if lo_v is None or hi_v is None or hi_v <= lo_v:
            return False
        if sl_v is None or sl_v >= lo_v:
            return False
        if require_near_price and hi_v < float(price) * 0.995:
            return False
        if require_below_price and lo_v > float(price) * 1.01:
            return False
        if require_below is not None and lo_v >= float(require_below):
            return False
        return any(tp > hi_v for tp in _dedupe_levels(tps, direction='asc'))

    # Professional mode: fresh scenario generation must win over stale cache.
    # Stable reuse is still available, but now disabled by default and much shorter-lived.
    scenario_stable_mode = str(os.getenv("SCENARIO_STABLE_5D", "0") or "0").strip().lower() not in ("0", "false", "no", "off")
    scenario_use_price_filters = str(os.getenv("SCENARIO_STABLE_USE_PRICE_FILTERS", "1") or "1").strip().lower() not in ("0", "false", "no", "off")
    try:
        scenario_ttl_sec = int(float(os.getenv("SCENARIO_STABLE_TTL_SEC", str(6 * 3600))) or (6 * 3600))
    except Exception:
        scenario_ttl_sec = 6 * 3600
    scenario_ttl_sec = max(1800, min(7 * 24 * 3600, int(scenario_ttl_sec)))

    def _scenario_state_path() -> Path:
        try:
            base = os.getenv("SCENARIO_STABLE_DIR")
            root = Path(base).expanduser() if base else (Path(__file__).resolve().parent / ".scenario_state")
        except Exception:
            root = Path(".scenario_state")
        try:
            root.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        safe_sym = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(sym or "UNKNOWN"))
        safe_mkt = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(mkt or "SPOT"))
        return root / f"{safe_mkt}_{safe_sym}_scenario_5d.json"

    def _scenario_state_load():
        try:
            path = _scenario_state_path()
            if not path.exists():
                return None
            raw = json.loads(path.read_text(encoding="utf-8"))
            return raw if isinstance(raw, dict) else None
        except Exception:
            return None

    def _scenario_state_bounds() -> tuple[float | None, float | None]:
        vals = _dedupe_levels([
            entry_zone_lo, entry_zone_hi,
            short_retest_sl,
            sweep_zone_lo, sweep_zone_hi, short_sweep_sl_lo, short_sweep_sl_hi,
            short_break_entry, short_break_sl_lo, short_break_sl_hi,
            short_tp1, short_tp2, short_tp3,
            long_reclaim_sl, long_tp1, long_tp2, long_tp3,
            bounce_zone_lo, bounce_zone_hi, long_bounce_sl, long_bounce_tp1, long_bounce_tp2, long_bounce_tp3,
            discount_zone_lo, discount_zone_hi, long_discount_sl, long_discount_tp1, long_discount_tp2, long_discount_tp3,
        ], direction='asc')
        if not vals:
            return (None, None)
        return (float(vals[0]), float(vals[-1]))

    def _scenario_state_can_reuse(st) -> bool:
        if not scenario_stable_mode or not isinstance(st, dict):
            return False
        try:
            if int(st.get("version") or 0) < 10:
                return False
            if str(st.get("symbol") or "") != str(sym) or str(st.get("market") or "") != str(mkt):
                return False
            ts = float(st.get("ts") or 0.0)
            if ts <= 0 or (time.time() - ts) > float(scenario_ttl_sec):
                return False

            prev_price_anchor = _clean_level(st.get("price_anchor"))
            if prev_price_anchor is not None:
                price_anchor_drift = abs(float(price) - float(prev_price_anchor))
                price_anchor_limit = max(float(atr_abs) * (5.0 if scenario_hard_anchor else 3.0), float(price) * (0.018 if scenario_hard_anchor else 0.010))
                if price_anchor_drift > price_anchor_limit:
                    return False

            lo = _clean_level(st.get("min_level"))
            hi = _clean_level(st.get("max_level"))
            pad = max(float(atr_abs) * 3.5, float(price) * 0.018)
            if lo is not None and price < (float(lo) - pad):
                return False
            if hi is not None and price > (float(hi) + pad):
                return False
            prev_anchor_sup = _clean_level(st.get("anchor_support_near"))
            prev_anchor_res = _clean_level(st.get("anchor_resist_near"))
            cur_anchor_sup = _clean_level(anchor_support_near) or _clean_level(local_support_lvl) or _clean_level(support1)
            cur_anchor_res = _clean_level(anchor_resist_near) or _clean_level(local_resist_lvl) or _clean_level(resistance1)
            anchor_pad = max(float(atr_abs) * 4.5, float(price) * 0.018)
            if prev_anchor_sup is not None and price < (float(prev_anchor_sup) - anchor_pad):
                return False
            if prev_anchor_res is not None and price > (float(prev_anchor_res) + anchor_pad * 1.25):
                return False
            if prev_anchor_sup is not None and cur_anchor_sup is not None:
                if abs(float(prev_anchor_sup) - float(cur_anchor_sup)) > max(float(atr_abs) * 6.0, float(price) * 0.03):
                    return False
            if prev_anchor_res is not None and cur_anchor_res is not None:
                if abs(float(prev_anchor_res) - float(cur_anchor_res)) > max(float(atr_abs) * 6.0, float(price) * 0.03):
                    return False
            prev_s1 = _clean_level(st.get("range_low"))
            prev_r1 = _clean_level(st.get("range_high"))
            if prev_s1 is not None and prev_r1 is not None and resistance1 is not None and support1 is not None and prev_r1 > prev_s1:
                old_mid = (float(prev_s1) + float(prev_r1)) / 2.0
                new_mid = (float(support1) + float(resistance1)) / 2.0
                drift = abs(new_mid - old_mid)
                max_drift = max(float(atr_abs) * (8.0 if scenario_hard_anchor else 4.5), float(price) * (0.032 if scenario_hard_anchor else 0.018))
                if drift > max_drift:
                    return False
                old_rng = max(1e-9, float(prev_r1) - float(prev_s1))
                new_rng = max(1e-9, float(resistance1) - float(support1))
                if abs(new_rng - old_rng) / old_rng > (0.60 if scenario_hard_anchor else 0.30):
                    return False
            return True
        except Exception:
            return False

    def _scenario_state_save(short_items, long_items):
        if not scenario_stable_mode:
            return
        try:
            lo_b, hi_b = _scenario_state_bounds()
            payload = {
                "version": 10,
                "ts": time.time(),
                "symbol": str(sym),
                "market": str(mkt),
                "structure": str(struct_lbl or ""),
                "range_low": float(support1) if support1 is not None else None,
                "range_high": float(resistance1) if resistance1 is not None else None,
                "price_anchor": float(price),
                "anchor_support_near": float(anchor_support_near) if anchor_support_near is not None else None,
                "anchor_support_deep": float(anchor_support_deep) if anchor_support_deep is not None else None,
                "anchor_resist_near": float(anchor_resist_near) if anchor_resist_near is not None else None,
                "anchor_resist_high": float(anchor_resist_high) if anchor_resist_high is not None else None,
                "min_level": lo_b,
                "max_level": hi_b,
                "short_scenarios": list(short_items or []),
                "long_scenarios": list(long_items or []),
            }
            _scenario_state_path().write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        except Exception:
            pass

    short_scenarios = []
    long_scenarios = []

    short_a_tps = _rr_target_ladder(entry_zone_lo or price, short_retest_sl, [short_tp1, short_tp2, short_tp3], direction='desc', rr_steps=(1.20, 2.50, 3.80))
    if _valid_short_range(entry_zone_lo, entry_zone_hi, short_retest_sl, short_a_tps, require_near_price=scenario_use_price_filters):
        short_scenarios.append(_scenario_pack(
            side='short',
            title_ru='ретест supply',
            title_en='retest supply',
            entry_text=scenario_entry_zone,
            trigger_ru='возврат в зону -> rejection -> BOS 5m вниз -> объем подтверждает',
            trigger_en='reclaim into zone -> rejection -> 5m BOS down -> volume confirms',
            sl_ru=_fmt_int_space(short_retest_sl) if short_retest_sl is not None else '—',
            sl_en=_fmt_int_space(short_retest_sl) if short_retest_sl is not None else '—',
            tp_vals=short_a_tps,
            direction='desc',
            entry_lo=entry_zone_lo,
            entry_hi=entry_zone_hi,
            entry_ref=entry_zone_lo or entry_zone_hi or price,
            sl=short_retest_sl,
            priority=2.35,
            bucket='near',
        ))

    short_b_tps = _rr_target_ladder(sweep_zone_lo or entry_zone_lo or price, short_sweep_sl_hi or short_sweep_sl_lo, [entry_zone_lo, short_tp1, short_tp2, short_tp3], direction='desc', rr_steps=(1.35, 2.70, 4.10))
    if _valid_short_range(sweep_zone_lo, sweep_zone_hi, short_sweep_sl_hi or short_sweep_sl_lo, short_b_tps, require_near_price=scenario_use_price_filters, require_above=entry_zone_hi):
        short_scenarios.append(_scenario_pack(
            side='short',
            title_ru='sweep liquidity сверху',
            title_en='sweep liquidity above',
            entry_text=scenario_short_sweep_zone,
            trigger_ru=f'съем ликвидности выше {scenario_eqh} -> быстрый возврат под зону -> BOS 5m вниз',
            trigger_en=f'take liquidity above {scenario_eqh} -> fast return below zone -> 5m BOS down',
            sl_ru=scenario_short_sweep_sl,
            sl_en=scenario_short_sweep_sl,
            tp_vals=short_b_tps,
            direction='desc',
            entry_lo=sweep_zone_lo,
            entry_hi=sweep_zone_hi,
            entry_ref=sweep_zone_lo or sweep_zone_hi or price,
            sl=short_sweep_sl_hi or short_sweep_sl_lo,
            priority=2.55,
            bucket='near',
        ))

    short_break_sl_anchor = short_break_sl_lo or short_break_sl_hi
    short_c_tps = _rr_target_ladder(short_break_entry or price, short_break_sl_anchor, [short_tp1, short_tp2, short_tp3], direction='desc', rr_steps=(1.45, 2.90, 4.40))
    if _valid_short_break(short_break_entry, short_break_sl_anchor, short_c_tps, require_below_price=scenario_use_price_filters):
        short_scenarios.append(_scenario_pack(
            side='short',
            title_ru='пробой поддержки',
            title_en='support breakdown',
            entry_text=(f'ретест {scenario_short_break_entry} снизу' if is_ru else f'retest {scenario_short_break_entry} from below'),
            trigger_ru=f'потеря {scenario_short_break_entry} -> закрепление ниже на 5m/15m -> слабый ретест',
            trigger_en=f'loss of {scenario_short_break_entry} -> 5m/15m close below -> weak retest',
            sl_ru=scenario_short_break_sl,
            sl_en=scenario_short_break_sl,
            tp_vals=short_c_tps,
            direction='desc',
            entry_ref=short_break_entry or price,
            sl=short_break_sl_anchor,
            priority=3.15,
            bucket='near',
        ))

    long_a_tps = _rr_target_ladder(
        entry_zone_hi or entry_zone_lo or price,
        long_reclaim_sl,
        _filter_targets_by_rr(
            entry_zone_hi or entry_zone_lo or price,
            long_reclaim_sl,
            [long_tp1, long_tp2, long_tp3],
            direction='asc',
            min_rr_first=1.00,
        ),
        direction='asc',
        rr_steps=(1.20, 2.50, 3.80),
    )
    if _valid_long_range(entry_zone_lo, entry_zone_hi, long_reclaim_sl, long_a_tps, require_near_price=scenario_use_price_filters):
        long_scenarios.append(_scenario_pack(
            side='long',
            title_ru='reclaim зоны',
            title_en='reclaim zone',
            entry_text=scenario_entry_zone,
            trigger_ru=f'возврат выше {local_resist_s} -> закрепление выше {entry_hi_s} -> BOS 5m вверх',
            trigger_en=f'reclaim above {local_resist_s} -> hold above {entry_hi_s} -> 5m BOS up',
            sl_ru=_fmt_int_space(long_reclaim_sl) if long_reclaim_sl is not None else '—',
            sl_en=_fmt_int_space(long_reclaim_sl) if long_reclaim_sl is not None else '—',
            tp_vals=long_a_tps,
            direction='asc',
            entry_lo=entry_zone_lo,
            entry_hi=entry_zone_hi,
            entry_ref=entry_zone_hi or entry_zone_lo or price,
            sl=long_reclaim_sl,
            priority=2.45,
            bucket='near',
        ))

    long_b_tps = _rr_target_ladder(bounce_zone_hi or bounce_zone_lo or price, long_bounce_sl, [long_bounce_tp1, long_bounce_tp2, long_bounce_tp3], direction='asc', rr_steps=(1.30, 2.60, 4.00))
    if _valid_long_range(bounce_zone_lo, bounce_zone_hi, long_bounce_sl, long_b_tps, require_below_price=scenario_use_price_filters):
        long_scenarios.append(_scenario_pack(
            side='long',
            title_ru='отскок от поддержки',
            title_en='support bounce',
            entry_text=scenario_long_bounce_entry,
            trigger_ru=f'удержание {local_support_s} или ложный пробой -> BOS 5m вверх -> рост объема',
            trigger_en=f'hold {local_support_s} or false break -> 5m BOS up -> volume expansion',
            sl_ru=_fmt_int_space(long_bounce_sl) if long_bounce_sl is not None else '—',
            sl_en=_fmt_int_space(long_bounce_sl) if long_bounce_sl is not None else '—',
            tp_vals=long_b_tps,
            direction='asc',
            entry_lo=bounce_zone_lo,
            entry_hi=bounce_zone_hi,
            entry_ref=bounce_zone_hi or bounce_zone_lo or price,
            sl=long_bounce_sl,
            priority=2.10,
            bucket='near',
        ))

    long_c_tps = _rr_target_ladder(discount_zone_hi or discount_zone_lo or price, long_discount_sl, [long_discount_tp1, long_discount_tp2, long_discount_tp3], direction='asc', rr_steps=(1.55, 3.10, 4.70))
    if _valid_long_range(discount_zone_lo, discount_zone_hi, long_discount_sl, long_c_tps, require_below=bounce_zone_lo or price):
        long_scenarios.append(_scenario_pack(
            side='long',
            title_ru='deep discount long',
            title_en='deep discount long',
            entry_text=scenario_long_discount_zone,
            trigger_ru=f'сильный выкуп из зоны {scenario_long_discount_zone} -> база на 5m/15m -> BOS вверх',
            trigger_en=f'strong reaction from zone {scenario_long_discount_zone} -> base on 5m/15m -> BOS up',
            sl_ru=('ниже ' + _fmt_int_space(long_discount_sl)) if long_discount_sl is not None else 'ниже поддержки',
            sl_en=('below ' + _fmt_int_space(long_discount_sl)) if long_discount_sl is not None else 'below support',
            tp_vals=long_c_tps,
            direction='asc',
            entry_lo=discount_zone_lo,
            entry_hi=discount_zone_hi,
            entry_ref=discount_zone_hi or discount_zone_lo or price,
            sl=long_discount_sl,
            priority=1.35,
            bucket='deep',
        ))

    short_scenarios = _filter_side_scenarios(short_scenarios, 'short')
    long_scenarios = _filter_side_scenarios(long_scenarios, 'long')
    short_scenarios, long_scenarios = _resolve_cross_side_conflicts(short_scenarios, long_scenarios)

    prev_scenarios_state = _scenario_state_load()
    if _scenario_state_can_reuse(prev_scenarios_state):
        prev_short = prev_scenarios_state.get('short_scenarios') if isinstance(prev_scenarios_state, dict) else None
        prev_long = prev_scenarios_state.get('long_scenarios') if isinstance(prev_scenarios_state, dict) else None
        # Fresh scenarios always have priority. Reuse cached scenarios only as a fallback
        # when the current side is empty due to temporary data quality / structure issues.
        if (not short_scenarios) and isinstance(prev_short, list) and prev_short:
            short_scenarios = prev_short
        if (not long_scenarios) and isinstance(prev_long, list) and prev_long:
            long_scenarios = prev_long

    _scenario_state_save(short_scenarios, long_scenarios)

    def _scenario_plan_name(item, idx):
        if bool(item.get('contingency')):
            return ('Альтернативный сценарий' if is_ru else 'Alternative scenario')
        return ('Основной сценарий' if is_ru else 'Main scenario')

    def _scenario_invalidation_text(side_key, item):
        sl_level = _clean_level(item.get('_sl'))
        sl_text = str((item.get('sl_ru') if is_ru else item.get('sl_en')) or '').strip()
        if sl_level is not None:
            lvl = _fmt_int_space(sl_level)
            if side_key == 'short':
                return (f'сценарий отменяется при возврате и закреплении выше {lvl}' if is_ru else f'setup invalidates on reclaim and hold above {lvl}')
            return (f'сценарий отменяется при потере и закреплении ниже {lvl}' if is_ru else f'setup invalidates on loss and hold below {lvl}')
        if not sl_text or sl_text == '—':
            return ('сценарий отменяется при явном сломе структуры против идеи' if is_ru else 'setup invalidates on clear structure break against the idea')
        if side_key == 'short':
            return (f'сценарий отменяется при возврате выше {sl_text}' if is_ru else f'setup invalidates on reclaim above {sl_text}')
        return (f'сценарий отменяется при уходе ниже {sl_text}' if is_ru else f'setup invalidates on move below {sl_text}')

    def _scenario_execution_rules(side_key, item):
        if is_ru:
            return 'вход только после триггера; подтверждение желательно на 5m/15m; если цена ушла без ретеста, сценарий пропускается; после invalidation идея не исполняется'
        return 'enter only after trigger; prefer 5m/15m confirmation; skip the setup if price runs away without retest; do not execute after invalidation'

    def _render_side_block(side_key, items):
        if not items:
            return []
        header = 'СЦЕНАРИЙ SHORT' if (is_ru and side_key == 'short') else ('СЦЕНАРИЙ LONG' if is_ru else ('SHORT SCENARIO' if side_key == 'short' else 'LONG SCENARIO'))
        lines = ['', header]
        for idx, item in enumerate(items):
            title = (item.get('title_ru') if is_ru else item.get('title_en')) or '—'
            trigger = (item.get('trigger_ru') if is_ru else item.get('trigger_en')) or '—'
            invalidation = _scenario_invalidation_text(side_key, item)
            rules_text = _scenario_execution_rules(side_key, item)
            plan_name = _scenario_plan_name(item, idx)
            entry_label = 'Зона входа' if is_ru else 'Entry zone'
            idea_label = 'Идея' if is_ru else 'Setup'
            trigger_label = 'Триггер' if is_ru else 'Trigger'
            targets_label = 'Цели' if is_ru else 'Targets'
            rules_label = 'Правила исполнения' if is_ru else 'Execution rules'
            lines.extend([
                plan_name,
                f"{idea_label}: {title}",
                f"{entry_label}: {item.get('entry') or '—'}",
                f"{trigger_label}: {trigger}",
                f"Invalidation: {invalidation}",
                f"{targets_label}: {item.get('tp') or '—'}",
                f"{rules_label}: {rules_text}",
            ])
            if idx != len(items) - 1:
                lines.append('')
        return lines

    scenario_lines = [
        (f"🧠 Сценарии — {sym}" if is_ru else f"🧠 Scenarios — {sym}"),
        (f"Рынок: {mkt_label}" if is_ru else f"Market: {mkt_label}"),
        (f"Цена: {price_s} USDT" if is_ru else f"Price: {price_s} USDT"),
        f"{status_title}: {status_value}",
        f"{reason_title}: {scenario_comment}",
        '',
        ('Контекст:' if is_ru else 'Context:'),
        f"• 4H: {trend4}",
        f"• 1H: {trend1}",
        f"• 5M: {trend5}",
        (f"• Структура: {struct_lbl}" if is_ru else f"• Structure: {struct_lbl}"),
        (f"• Приоритет: {bias_txt}" if is_ru else f"• Bias: {bias_txt}"),
    ]

    scenario_lines.extend(_render_side_block('short', short_scenarios))
    scenario_lines.extend(_render_side_block('long', long_scenarios))

    if not short_scenarios and not long_scenarios:
        scenario_lines.extend([
            '',
            ('Реальных сценариев сейчас нет.' if is_ru else 'No actionable scenarios right now.'),
        ])

    scenario_lines.extend([
        '',
        ('Общие правила исполнения:' if is_ru else 'General execution rules:'),
        ('• Без триггера = NO TRADE' if is_ru else '• No trigger = NO TRADE'),
        ('• Основной сценарий исполняется первым; альтернативный — только если основной не реализовался' if is_ru else '• Execute the main scenario first; use the alternative only if the main scenario does not trigger'),
        ('• При invalidation сценарий отменяется и не доусредняется' if is_ru else '• Once invalidated, the setup is cancelled and must not be averaged into'),
        ('• Файл дополняет основной анализ и не заменяет его' if is_ru else '• This file supplements the main analysis and does not replace it'),
    ])
    scenario_text = "\n".join([x for x in scenario_lines if x is not None])

    if return_bundle:
        return {
            "report": report,
            "scenario_text": scenario_text,
            "scenario_filename": f"{sym}_scenarios.txt",
            "symbol": sym,
            "market": mkt_label,
        }

    # Default user-facing mode should include the professional scenario block,
    # otherwise the analysis silently generates scenarios but never shows them.
    scenario_enabled = str(os.getenv("ANALYSIS_APPEND_SCENARIOS", "1") or "1").strip().lower() not in ("0", "false", "no", "off")
    if scenario_enabled and scenario_text:
        return f"{report}\n\n{scenario_text}"
    return report




